# 1. OPENING TEXT / PROLOGUE PAGE
# =============================================================================

# --- Opening / prologue pagination -------------------------------------------
# A graphic-novel opening is a designed text spread, not one cramped block. When
# the narration wants more room than a single page allows, we paginate it into
# several first-class pages rather than truncating it — each page gets its own
# image. These are word targets (a comfortable full-page prose spread), with a
# hard ceiling that forces a split so no single rendered page overflows.
OPENING_PAGE_TARGET_WORDS = 350
OPENING_PAGE_MAX_WORDS = 480


def _split_sentences(text: str) -> List[str]:
    """Cheap sentence splitter used only as a fallback for over-long paragraphs."""
    import re as _re
    parts = _re.split(r'(?<=[.!?])\s+', (text or "").strip())
    return [p for p in parts if p]


def paginate_opening_text(text: str,
                          target_words: int = OPENING_PAGE_TARGET_WORDS,
                          max_words: int = OPENING_PAGE_MAX_WORDS) -> List[str]:
    """Split a long opening passage into page-sized segments.

    Breaks on paragraph boundaries first (preserving the author's paragraphing),
    accumulating paragraphs until the next would push the page past ``target_words``.
    A single paragraph longer than ``max_words`` is itself split on sentence
    boundaries. Returns a list of segment strings (>=1). Never cuts mid-word.
    """
    text = (text or "").strip()
    if not text:
        return []
    paragraphs = [p.strip() for p in re.split(r'\n\s*\n', text) if p.strip()]
    if not paragraphs:
        paragraphs = [text]

    # Pre-split any paragraph that alone exceeds the hard ceiling.
    units: List[str] = []
    for para in paragraphs:
        if len(para.split()) <= max_words:
            units.append(para)
            continue
        sent, cur = _split_sentences(para), []
        for s in sent:
            if cur and len((" ".join(cur + [s])).split()) > max_words:
                units.append(" ".join(cur))
                cur = [s]
            else:
                cur.append(s)
        if cur:
            units.append(" ".join(cur))

    pages: List[str] = []
    cur: List[str] = []
    cur_words = 0
    for unit in units:
        w = len(unit.split())
        if cur and cur_words + w > target_words:
            pages.append("\n\n".join(cur))
            cur, cur_words = [], 0
        cur.append(unit)
        cur_words += w
    if cur:
        pages.append("\n\n".join(cur))
    return pages or [text]


def _coerce_opening_segments(parsed: Dict, fallback_visual: str,
                             mood: str = "") -> List[Dict]:
    """Turn an LLM opening result into page-sized segments, each with an image.

    Accepts either the new ``pages: [{content, visual_note, title}]`` shape or a
    legacy single ``content`` blob, and guarantees every returned segment fits a
    page (further paginating any over-long one) and carries a visual_note so it
    can be rendered with its own associated image.
    """
    default_visual = (fallback_visual or "").strip() or (
        f"A quiet, atmospheric opening image"
        + (f" evoking {mood}" if mood else "")
        + ", generous negative space for text."
    )
    raw_pages: List[Dict] = []
    if isinstance(parsed.get("pages"), list) and parsed["pages"]:
        for pg in parsed["pages"]:
            if isinstance(pg, dict) and str(pg.get("content", "")).strip():
                raw_pages.append(pg)
            elif isinstance(pg, str) and pg.strip():
                raw_pages.append({"content": pg})
    if not raw_pages:
        blob = str(parsed.get("content", "")).strip()
        if blob:
            raw_pages = [{"content": blob,
                          "visual_note": parsed.get("visual_note", "")}]

    segments: List[Dict] = []
    for i, pg in enumerate(raw_pages):
        content = str(pg.get("content", "")).strip()
        if not content:
            continue
        vnote = str(pg.get("visual_note", "")).strip() or default_visual
        title = str(pg.get("title", "")).strip()
        chunks = paginate_opening_text(content)
        for j, chunk in enumerate(chunks):
            segments.append({
                "content": chunk,
                # Vary the derived visual note slightly on forced sub-splits so
                # continuation pages don't render an identical image.
                "visual_note": vnote if j == 0 else (vnote + " (continued)"),
                "title": title if (i == 0 and j == 0) else "",
            })
    return segments


def generate_opening_text_page(
    story_idea,
    characters: List,
    story_idea_str: str,
    get_llm_response,
    parse_json,
    sanitize,
    llm_model: str = None,
    use_grok: bool = False,
) -> Dict:
    """Generate the book's opening text/prologue page.

    This page appears before page 1 of the story. It establishes tone,
    backstory, world-context, or an intriguing mystery. It can be:
      - A prose prologue (most literary graphic novels use this)
      - A "years earlier" cold-open scene description
      - A world-setting caption (like the Star Wars crawl, but better)
      - A character's opening monologue
      - An in-world document (letter, newspaper, prophecy)

    Returns a script page dict with _prologue=True and the text content.
    The assemble_docx / compose_page functions should render this as a
    full-page typeset text spread, not a panel-art page.
    """
    char_block = "\n".join(
        f"  {c.name} ({getattr(c, 'role', 'character')}): {c.backstory[:100] if hasattr(c, 'backstory') else ''}"
        for c in (characters or [])[:5]
    )

    prompt = (
        "You are writing the OPENING TEXT PAGE of a graphic novel — the words "
        "the reader encounters before the first panel of art. This is the "
        "literary threshold of the story, and its job is to SET UP THE STORY "
        "so the reader understands the world, the situation, and the stakes "
        "before the action begins — the way the opening crawl of a film orients "
        "an audience before the first scene.\n\n"
        "This page MUST do real explanatory work. By the end of it the reader "
        "should understand: WHERE and WHEN we are, WHAT the central situation "
        "or conflict is, WHO matters, and WHY they should care. Do not be "
        "coy or withholding — this is the reader's map into the story. Give "
        "them enough context to feel grounded and intrigued, not confused.\n\n"
        f"GENRE: {story_idea.genre}\n"
        f"MOOD: {story_idea.mood}\n"
        f"THEMES: {', '.join(story_idea.themes or [])}\n"
        f"PREMISE: {story_idea.premise[:400]}\n\n"
        f"CAST (first five):\n{char_block}\n\n"
        f"FULL CONCEPT (first 2000 chars):\n{sanitize(story_idea_str)}\n\n"
        "Choose the OPENING STYLE that best serves this story:\n\n"
        "  A) PROSE PROLOGUE — a literary passage that sets the "
        "world, tone, situation, and central question in the author's voice. "
        "Should leave the reader understanding the setup, not guessing at it.\n\n"
        "  B) IN-WORLD DOCUMENT — a letter, journal entry, news headline, "
        "prophecy, or report that drops the reader into the world sideways "
        "WHILE still conveying the essential setup.\n\n"
        "  C) CHARACTER MONOLOGUE — the protagonist's inner voice, establishing "
        "who they are, what they want/fear, and the situation they're in.\n\n"
        "  D) COLD EPIGRAPH — a brief quote, real or invented, "
        "that refracts the story's theme, followed by a substantial "
        "world-and-situation-setting passage.\n\n"
        "  E) WORLD ESTABLISHMENT CRAWL — a compressed 'state of this world' "
        "passage in the spirit of the Star Wars opening crawl: "
        "what has happened, what is happening now, what hangs in the balance. "
        "Best for SF/fantasy or any story with an unfamiliar setting or a "
        "backstory the reader needs before page 1. Prefer this when the world "
        "or the prior events are complex.\n\n"
        "LENGTH — write as much as the opening genuinely needs; do NOT cram or "
        "cut it short. A graphic novel is a book: a rich opening may run several "
        "pages. Break the opening into PAGES of roughly "
        f"{OPENING_PAGE_TARGET_WORDS} words each (never more than "
        f"{OPENING_PAGE_MAX_WORDS}), and give EACH page its own distinct visual "
        "concept so it can be illustrated with its own image. Most openings are "
        "1-3 pages; use more only if the story truly calls for it.\n\n"
        "Choose the best style and write the actual opening text. Lean toward "
        "GIVING THE READER CONTEXT over withholding it. Then design how each "
        "page looks.\n\n"
        "Return JSON:\n"
        "{\n"
        '  "style": "A|B|C|D|E",\n'
        '  "narrator_voice": "whose voice is this? (Author / CharacterName / '
        'Unknown / In-world)",\n'
        '  "purpose": "one sentence — what emotional/story job does this opening do?",\n'
        '  "font_note": "typographic direction: serif/sans, large/small, '
        'centered/left, tight/airy",\n'
        '  "pages": [\n'
        '    {\n'
        '      "title": "optional title for this page (or empty string)",\n'
        '      "content": "the full text for THIS page (~'
        f'{OPENING_PAGE_TARGET_WORDS} words)",\n'
        '      "visual_note": "the background image/texture for THIS page — a '
        'distinct, evocative concept with room for text (NOT the same image twice)"\n'
        '    }\n'
        '    // one object per page; add as many pages as the opening needs\n'
        "  ]\n"
        "}\n"
        "JSON only."
    )

    try:
        kwargs = {"temperature": 0.82, "max_completion_tokens": 8000}
        if llm_model:
            kwargs["openai_model"] = llm_model
        kwargs["use_grok"] = use_grok
        raw = get_llm_response(prompt, **kwargs)
        parsed = parse_json(raw) or {}
        segments = _coerce_opening_segments(
            parsed,
            fallback_visual=parsed.get("visual_note", ""),
            mood=getattr(story_idea, "mood", "") or "",
        )
        if segments:
            first = segments[0]
            logger.info(
                f"  [Opening Page] Generated {parsed.get('style','?')}-style "
                f"opening across {len(segments)} page(s): "
                f"{parsed.get('purpose','')[:80]}"
            )
            return {
                "page": 0,  # sentinel: inserted before page 1
                "title": first.get("title", ""),
                "setting": "Opening Text Page",
                "characters_present": [],
                "beat": "Prologue / Opening text page.",
                "beat_id": "prologue",
                "emotional_tone": story_idea.mood,
                "visual_hook": first.get("visual_note", ""),
                "cliffhanger": False,
                "importance": "standard",
                "act": "0",
                "_prologue": True,
                "_prologue_style": parsed.get("style", "A"),
                "_prologue_content": first.get("content", ""),
                "_prologue_font_note": parsed.get("font_note", ""),
                "_prologue_visual_note": first.get("visual_note", ""),
                "_prologue_narrator_voice": parsed.get("narrator_voice", ""),
                "_prologue_purpose": parsed.get("purpose", ""),
                # Full multi-page opening — one entry per page, each with its own
                # text segment and its own image concept.
                "_prologue_segments": segments,
                "panels": [],
            }
    except Exception as e:
        logger.warning(f"  [Opening Page] Generation failed ({e}); using default.")

    # Fallback: minimal prose prologue (single page)
    fallback_content = (
        f"In the world that follows, nothing is as simple as it seems.\n\n"
        f"{story_idea.premise[:300]}"
    )
    _fb_visual = "A quiet, atmospheric opening image with generous negative space for text."
    return {
        "page": 0,
        "title": "",
        "setting": "Opening Text Page",
        "characters_present": [],
        "beat": "Opening text page.",
        "beat_id": "prologue",
        "emotional_tone": story_idea.mood,
        "visual_hook": "",
        "cliffhanger": False,
        "importance": "standard",
        "act": "0",
        "_prologue": True,
        "_prologue_style": "A",
        "_prologue_content": fallback_content,
        "_prologue_font_note": "serif, centered, generous leading",
        "_prologue_visual_note": "",
        "_prologue_narrator_voice": "Author",
        "_prologue_purpose": "Establish world and tone.",
        "_prologue_segments": [{
            "content": fallback_content,
            "visual_note": _fb_visual,
            "title": "",
        }],
        "panels": [],
    }


