def generate_character_intros(
    characters: List,
    story_idea,
    get_llm_response,
    parse_json,
    llm_model: str = None,
    use_grok: bool = False,
) -> Dict[str, Dict]:
    """Generate intro caption data for every major character (tier 1 & 2).

    Returns a dict keyed by character name. Each entry contains:
      - intro_caption: the narrator's voice-over when the character first appears
      - intro_style: "dossier" | "cinematic" | "mythic"
      - first_appearance_hint: guidance for the panel description

    The script generation and narration weave then use these to enrich the
    panels where each character debuts in the story.
    """
    if not characters:
        return {}

    # Only generate intros for named, significant characters
    significant = [
        c for c in characters
        if getattr(c, "role", "").lower() not in ("background", "extra")
    ][:12]

    char_descs = []
    for c in significant:
        char_descs.append(
            f"Name: {c.name} | Role: {getattr(c,'role','')} | "
            f"Age: {getattr(c,'age','')} | Traits: {', '.join((c.traits or [])[:3])} | "
            f"Backstory hint: {(getattr(c,'backstory','') or '')[:100]}"
        )

    char_block = "\n".join(char_descs)
    prompt = (
        "You are a comics editor writing CHARACTER INTRODUCTION captions — the "
        "narrator's voice-over the first time a character appears in a graphic "
        "novel. These captions are printed in yellow caption boxes alongside "
        "or just above the character's debut panel.\n\n"
        f"GENRE: {story_idea.genre}\n"
        f"MOOD: {story_idea.mood}\n"
        f"PREMISE: {story_idea.premise[:300]}\n\n"
        "CHARACTERS TO INTRODUCE:\n"
        f"{char_block}\n\n"
        "For each character, write:\n"
        "  1. An intro caption (15-40 words) — literary, atmospheric. "
        "The narrator introduces this person. It should:\n"
        "     - Establish their role and essence without biographical recitation\n"
        "     - Hint at their inner life or what makes them dangerous/interesting\n"
        "     - Match the book's narrative voice (see genre/mood above)\n"
        "     - Feel like a film's title card for a character, not a résumé\n"
        "  2. An intro style: 'dossier' (factual, crime-thriller), "
        "'cinematic' (poetic, atmospheric), or 'mythic' (epic, symbolic)\n"
        "  3. A first-appearance hint: one sentence about how this character "
        "should LOOK in their debut panel — what posture, expression, context "
        "creates the best first impression\n\n"
        "Return JSON object keyed by character name:\n"
        '{"CharacterName": {\n'
        '  "intro_caption": "...",\n'
        '  "intro_style": "cinematic",\n'
        '  "first_appearance_hint": "..."\n'
        "},\n...}\n"
        "JSON only."
    )

    try:
        kwargs = {"temperature": 0.75, "max_completion_tokens": 3000}
        if llm_model:
            kwargs["openai_model"] = llm_model
        kwargs["use_grok"] = use_grok
        raw = get_llm_response(prompt, **kwargs)
        parsed = parse_json(raw) or {}
        if isinstance(parsed, dict) and parsed:
            count = sum(1 for v in parsed.values() if isinstance(v, dict) and v.get("intro_caption"))
            logger.info(f"  [CharIntros] Generated intro captions for {count} character(s).")
            return parsed
    except Exception as e:
        logger.warning(f"  [CharIntros] Generation failed ({e}); using empty intros.")

    return {}


def inject_character_intro_captions(
    script: List[Dict],
    character_intros: Dict[str, Dict],
    characters: List,
) -> List[Dict]:
    """Walk the script and annotate the first panel where each character appears.

    Adds '_char_intro_caption' to the panel dict. The narration weave and
    compose_panel_prompt pick this up and inject it as a yellow caption box
    above the character's dialogue (or as the first caption if no dialogue).

    Also adds '_first_appearance_hint' to the panel description to guide
    the image generator for cinematic debut composition.
    """
    if not character_intros:
        return script

    introduced = set()

    for page in script:
        if page.get("_act_break") or page.get("_prologue"):
            continue
        for panel in page.get("panels") or []:
            chars_in_frame = panel.get("characters_in_frame") or []
            if isinstance(chars_in_frame, str):
                chars_in_frame = [chars_in_frame]

            for char_name in chars_in_frame:
                if not char_name or char_name in introduced:
                    continue
                # Match character name (case-insensitive, partial OK)
                intro_data = None
                for k, v in character_intros.items():
                    if (k.lower() == char_name.lower() or
                            char_name.lower() in k.lower() or
                            k.lower() in char_name.lower()):
                        intro_data = v
                        break

                if intro_data and isinstance(intro_data, dict):
                    caption = intro_data.get("intro_caption", "")
                    hint = intro_data.get("first_appearance_hint", "")
                    if caption:
                        # Store as a sidecar — doesn't overwrite existing captions
                        existing = panel.get("_char_intro_captions") or {}
                        existing[char_name] = caption
                        panel["_char_intro_captions"] = existing
                    if hint:
                        existing_hints = panel.get("_char_first_appearance_hints") or {}
                        existing_hints[char_name] = hint
                        panel["_char_first_appearance_hints"] = existing_hints
                    introduced.add(char_name)

    if introduced:
        logger.info(
            f"  [CharIntros] Injected intro captions for: {', '.join(sorted(introduced))}"
        )
    return script


# =============================================================================
# 3. BACKSTORY / FLASHBACK BEATS
# =============================================================================

# Beat types that explicitly call for flashback or backstory content
_BACKSTORY_BEAT_KEYWORDS = (
    "flashback", "memory", "backstory", "origin", "childhood",
    "past", "years earlier", "before the", "when they were",
    "how it began", "first time", "young", "as a child",
)


def generate_character_backstory_beats(
    characters: List,
    story_idea,
    required_beats: List[Dict],
    target_pages: int,
    get_llm_response,
    parse_json,
    llm_model: str = None,
    use_grok: bool = False,
    max_backstory_beats: int = None,
) -> List[Dict]:
    """Generate backstory/flashback beats for major characters.

    These beats are interspersed into the story at dramatically appropriate
    moments — just before a character faces their greatest challenge, or
    just after a revelation that recontextualises their past.

    Returns a list of new beat dicts to be merged with required_beats.
    Each beat has beat_type='backstory' and is tagged with the character
    it illuminates.
    """
    if not characters or target_pages < 20:
        return []

    # Only create backstory beats for characters with actual backstory content.
    # Candidate and beat limits are dynamic so a long ensemble book can earn
    # more than the old fixed three flashbacks.
    all_candidates = [
        c for c in characters
        if (getattr(c, "backstory", "") or getattr(c, "arc", ""))
        and getattr(c, "role", "").lower() not in ("background", "extra", "minor")
    ]

    if not all_candidates:
        return []

    if max_backstory_beats is None:
        max_backstory_beats = _dynamic_backstory_limit(target_pages, all_candidates)
    max_backstory_beats = max(0, int(max_backstory_beats))
    if max_backstory_beats <= 0:
        return []

    candidates = all_candidates[:max(4, min(len(all_candidates), max_backstory_beats + 2))]

    # Build context from existing required beats to find good insertion points
    beat_spine = "\n".join(
        f"  {b.get('beat_id','?')} (pp.{b.get('page_range','?')}): "
        f"{str(b.get('description',''))[:100]}"
        for b in required_beats[:15]
    )

    char_block = "\n".join(
        f"  {c.name} | Role: {getattr(c,'role','')} | "
        f"Backstory: {(getattr(c,'backstory','') or '')[:150]} | "
        f"Arc: {(getattr(c,'arc','') or '')[:100]}"
        for c in candidates
    )

    prompt = (
        f"{_SINGLE_IMAGE_RULE}\n\n"
        "You are a master graphic novelist deciding WHERE and HOW to weave "
        "character backstory/flashback moments into the main story.\n\n"
        "The best graphic novels never dump backstory as exposition. Instead "
        "they EARN flashbacks by placing them at moments of maximum dramatic "
        "relevance:\n"
        "  - Just BEFORE a character faces their biggest challenge (so we "
        "understand the weight of what they're risking)\n"
        "  - Just AFTER a revelation that casts their past in new light\n"
        "  - During a quiet moment after a loss, when memory intrudes\n"
        "  - At the precise page where the reader is asking 'why are they like this?'\n\n"
        f"MAIN STORY BEATS (for context):\n{beat_spine}\n\n"
        f"CHARACTERS WITH RICH BACKSTORY:\n{char_block}\n\n"
        f"TOTAL PAGES: {target_pages}\n\n"
        f"Generate as many backstory/flashback beats as genuinely serve the story. "
        f"Use {max_backstory_beats} as a practical upper target, not a mandatory fill. "
        "Return fewer if a beat would feel like padding; use the full allowance when "
        "multiple characters have past events the reader must feel on-page. Each should:\n"
        "  1. Illuminate a SPECIFIC moment from the character's past that "
        "explains a present behavior, fear, or choice\n"
        "  2. Be placed at a page number that maximises dramatic impact\n"
        "  3. Run 1-2 pages (brief, impactful, not a detour)\n"
        "  4. Have a temporal marker: 'X years earlier', 'Before [event]', etc.\n"
        "  5. Feel like a REVELATION, not a biography lesson\n\n"
        "Return JSON array. Each item:\n"
        "{\n"
        '  "beat_id": "backstory_01",\n'
        '  "character": "CharacterName",\n'
        '  "description": "2-3 sentence specific visual description of the '
        'flashback scene — what we SEE, not what we\'re told",\n'
        '  "temporal_marker": "Fourteen years earlier.",\n'
        '  "page_range": "18-19",\n'
        '  "dramatic_purpose": "Why here? One sentence on why this placement '
        'maximises impact.",\n'
        '  "visual_keywords": ["keyword1", "keyword2"],\n'
        '  "beat_type": "backstory",\n'
        '  "act": "2",\n'
        '  "must_include": true\n'
        "}\n"
        "JSON array only. Return [] if no backstory moments would genuinely "
        "serve this story."
    )

    try:
        kwargs = {"temperature": 0.72, "max_completion_tokens": max(3000, 650 * max_backstory_beats)}
        if llm_model:
            kwargs["openai_model"] = llm_model
        kwargs["use_grok"] = use_grok
        raw = get_llm_response(prompt, **kwargs)
        parsed = parse_json(raw) or []
        if isinstance(parsed, list):
            beats = [b for b in parsed if isinstance(b, dict) and b.get("description")][:max_backstory_beats]
            if beats:
                logger.info(
                    f"  [Backstory] Generated {len(beats)} backstory beat(s): "
                    + ", ".join(b.get("character", "?") for b in beats)
                )
            return beats
    except Exception as e:
        logger.warning(f"  [Backstory] Generation failed ({e}).")

    return []


# =============================================================================
# 4. SIDE STORY / CHARACTER SHOWCASE BEATS
# =============================================================================

def generate_character_showcase_beats(
    characters: List,
    story_idea,
    required_beats: List[Dict],
    target_pages: int,
    get_llm_response,
    parse_json,
    llm_model: str = None,
    use_grok: bool = False,
    max_showcase_beats: int = None,
) -> List[Dict]:
    """Generate character showcase / side story beats.

    These are brief scenes that show a character outside the main plot —
    their daily life, hobby, a relationship with a minor character, a
    private moment that reveals personality. They:
      - Increase reader attachment BEFORE the character faces danger
      - Reveal traits the main plot never shows
      - Create breathing room and texture between action beats
      - Make the world feel inhabited by real people

    Returns a list of new beat dicts with beat_type='character_showcase'.
    """
    if not characters or target_pages < 30:
        return []

    # Only create showcases for lead/major characters. Limit dynamically rather
    # than hard-capping to three candidates / two scenes.
    all_candidates = [
        c for c in characters
        if getattr(c, "role", "").lower() not in ("background", "extra", "minor")
        and len(getattr(c, "traits", []) or []) >= 2
    ]

    if not all_candidates:
        return []

    if max_showcase_beats is None:
        max_showcase_beats = _dynamic_showcase_limit(target_pages, all_candidates)
    max_showcase_beats = max(0, int(max_showcase_beats))
    if max_showcase_beats <= 0:
        return []

    candidates = all_candidates[:max(3, min(len(all_candidates), max_showcase_beats + 2))]

    beat_spine = "\n".join(
        f"  {b.get('beat_id','?')} (pp.{b.get('page_range','?')}): "
        f"{str(b.get('description',''))[:80]}"
        for b in required_beats[:12]
    )

    char_block = "\n".join(
        f"  {c.name} | Traits: {', '.join((c.traits or [])[:5])} | "
        f"Arc: {(getattr(c,'arc','') or '')[:100]} | "
        f"Speech: {(getattr(c,'speech_pattern','') or '')[:60]}"
        for c in candidates
    )

    prompt = (
        f"{_SINGLE_IMAGE_RULE}\n\n"
        "You are a graphic novel editor designing CHARACTER SHOWCASE moments — "
        "brief, self-contained scenes that let the reader fall in love with a "
        "character outside the main plot.\n\n"
        "The best character showcases:\n"
        "  - Show a character doing something they LOVE or something that reveals "
        "a surprising side of them\n"
        "  - Feature natural dialogue and small, human moments (not grand speeches)\n"
        "  - Reveal a character trait that the main plot never has time to show\n"
        "  - Plant seeds of attachment so the reader CARES when this person is "
        "threatened later\n"
        "  - Work as complete micro-stories (setup, beat, resonant ending)\n\n"
        f"STORY BEATS (for placement context):\n{beat_spine}\n\n"
        f"CHARACTERS:\n{char_block}\n\n"
        f"TOTAL PAGES: {target_pages}\n\n"
        f"Generate as many character showcase / side-story scenes as genuinely "
        f"serve the story. Use {max_showcase_beats} as a practical upper target, "
        "not a mandatory fill. Return fewer if a scene would feel like padding; "
        "use the full allowance when the ensemble needs attachment, humor, or "
        "private-life texture before the stakes hit. Each should:\n"
        "  1. Be placed in a lull between major beats (ideally after a high-tension "
        "scene, giving the reader a breath)\n"
        "  2. Run 1-3 pages\n"
        "  3. Feature a specific, visual activity (not 'walks around thinking')\n"
        "  4. Include at least one moment of genuine character voice\n"
        "  5. End on a small, resonant image that the reader will carry forward\n\n"
        "Return JSON array. Each item:\n"
        "{\n"
        '  "beat_id": "showcase_01",\n'
        '  "character": "CharacterName",\n'
        '  "description": "2-3 sentence specific visual description — what we '
        'SEE in these panels. Specific activity, location, interaction.",\n'
        '  "page_range": "22-23",\n'
        '  "trait_revealed": "The specific character trait this scene reveals",\n'
        '  "closing_image": "The final panel\'s resonant image",\n'
        '  "visual_keywords": ["keyword1", "keyword2"],\n'
        '  "beat_type": "character_showcase",\n'
        '  "act": "2",\n'
        '  "must_include": true\n'
        "}\n"
        "JSON array only."
    )

    try:
        kwargs = {"temperature": 0.78, "max_completion_tokens": max(2500, 600 * max_showcase_beats)}
        if llm_model:
            kwargs["openai_model"] = llm_model
        kwargs["use_grok"] = use_grok
        raw = get_llm_response(prompt, **kwargs)
        parsed = parse_json(raw) or []
        if isinstance(parsed, list):
            beats = [b for b in parsed if isinstance(b, dict) and b.get("description")][:max_showcase_beats]
            if beats:
                logger.info(
                    f"  [Showcase] Generated {len(beats)} character showcase beat(s): "
                    + ", ".join(b.get("character", "?") for b in beats)
                )
            return beats
    except Exception as e:
        logger.warning(f"  [Showcase] Generation failed ({e}).")

    return []


# =============================================================================
# 5. WORLD-BUILDING SPREAD BEATS
# =============================================================================

def generate_worldbuilding_spread_beats(
    story_idea,
    story_idea_str: str,
    required_beats: List[Dict],
    target_pages: int,
    get_llm_response,
    parse_json,
    sanitize,
    llm_model: str = None,
    use_grok: bool = False,
    max_worldbuilding_spreads: int = None,
) -> List[Dict]:
    """Generate world-building / environment showcase beats.

    These are dedicated 1-2 page spreads that establish a location, culture,
    technology, or piece of world-history that the plot visits. They give
    the story a sense of place and scale beyond just the characters.

    Only generated for books >= 40 pages (shorter books can't afford the
    real estate).
    """
    if target_pages < 40:
        return []

    if max_worldbuilding_spreads is None:
        max_worldbuilding_spreads = _dynamic_worldbuilding_limit(target_pages, story_idea)
    max_worldbuilding_spreads = max(0, int(max_worldbuilding_spreads))
    if max_worldbuilding_spreads <= 0:
        return []

    genres_needing_worldbuilding = (
        "fantasy", "science fiction", "sci-fi", "space opera", "steampunk",
        "cyberpunk", "horror", "supernatural", "alternate history", "dystopia",
        "post-apocalyptic", "epic", "adventure",
    )
    genre_lower = (story_idea.genre or "").lower()
    if not any(g in genre_lower for g in genres_needing_worldbuilding):
        # Still do one world-building beat for any sufficiently long story
        if target_pages < 60:
            return []

    beat_spine = "\n".join(
        f"  pp.{b.get('page_range','?')}: {str(b.get('description',''))[:80]}"
        for b in required_beats[:10]
    )

    prompt = (
        f"{_SINGLE_IMAGE_RULE}\n\n"
        "You are designing WORLD-BUILDING SPREADS for a graphic novel — "
        "dedicated pages that establish place, culture, history, or technology "
        "through pure visual storytelling. No dialogue. Just environment.\n\n"
        "Great world-building spreads:\n"
        "  - Show a location at its most CHARACTERISTIC moment\n"
        "  - Include at least one visual detail that surprises and implies history\n"
        "  - Are placed when the reader first needs to understand a new space\n"
        "  - Work as a visual breath between plot-heavy sequences\n"
        "  - Sometimes include a small caption that names or contextualises "
        "the location (optional)\n\n"
        f"GENRE: {story_idea.genre}\n"
        f"PREMISE: {story_idea.premise[:300]}\n"
        f"CONCEPT (excerpt):\n{sanitize(story_idea_str)}\n\n"
        f"EXISTING BEATS:\n{beat_spine}\n\n"
        f"TOTAL PAGES: {target_pages}\n\n"
        f"Identify as many locations, cultures, technologies, histories, or symbolic "
        f"environments as genuinely deserve a dedicated world-building spread. Use "
        f"{max_worldbuilding_spreads} as a practical upper target, not a mandatory fill. "
        "Return fewer if the story is already clear; use the full allowance when the "
        "world is strange, epic, spiritual, futuristic, mythic, or politically complex.\n\n"
        "Return JSON array:\n"
        "{\n"
        '  "beat_id": "world_01",\n'
        '  "location": "Name of the location",\n'
        '  "description": "2-3 sentence visual description of this spread — '
        'what does the reader SEE? Focus on environment, not characters.",\n'
        '  "page_range": "8-9",\n'
        '  "visual_keywords": ["keyword1", "keyword2", "keyword3"],\n'
        '  "caption_note": "Optional one-line caption/title for this spread '
        '(or empty string if no caption needed)",\n'
        '  "beat_type": "world_building",\n'
        '  "act": "1",\n'
        '  "must_include": true\n'
        "}\n"
        "JSON array only. Return [] if world-building spreads are not needed."
    )

    try:
        kwargs = {"temperature": 0.72, "max_completion_tokens": max(2000, 550 * max_worldbuilding_spreads)}
        if llm_model:
            kwargs["openai_model"] = llm_model
        kwargs["use_grok"] = use_grok
        raw = get_llm_response(prompt, **kwargs)
        parsed = parse_json(raw) or []
        if isinstance(parsed, list):
            beats = [b for b in parsed if isinstance(b, dict) and b.get("description")][:max_worldbuilding_spreads]
            if beats:
                logger.info(
                    f"  [WorldBuilding] Generated {len(beats)} world-building spread(s): "
                    + ", ".join(b.get("location", "?") for b in beats)
                )
            return beats
    except Exception as e:
        logger.warning(f"  [WorldBuilding] Generation failed ({e}).")

    return []


# =============================================================================
# 6. BEAT MERGING — integrate new beats with required_beats
# =============================================================================
#
# Design principles
# -----------------
# • The required_beats list represents the NARRATIVE SEQUENCE the author and
#   storyboard AI have already decided on. That sequence is the ground truth
#   and must not be reordered. Some stories are non-linear by design — a
#   Pulp Fiction–style structure has act 2 before act 1; a time-travel story
#   may have beats whose page numbers jump in any direction; a flashback beat
#   sits at one page position but depicts a chronologically earlier event.
#   Sorting by page start number destroys all of that intentionality.
#
# • Enrichment beats (backstory, showcase, world-building) are generated by
#   the LLM with a suggested page range that represents "near here, after
#   this required beat". We honour that suggestion by inserting each
#   enrichment beat immediately after its nearest required-beat anchor in
#   the LIST (not by page number) and nudging the page range only to avoid
#   overlap with its immediate neighbours. The rest of the list is untouched.
#
# • If no clear anchor exists (the LLM gave a page range that doesn't map
#   near any required beat), we append the enrichment beat at the end so it
#   still appears in the script without disturbing anything.
#
# The only guarantee this function makes is:
#   1. No two beats share overlapping page ranges.
#   2. Required beats appear in their original list order.
#   3. Enrichment beats are inserted adjacent to their narrative anchor.
#   4. No global re-sort is ever performed.
# =============================================================================

def _parse_beat_range(pr: str, target_pages: int) -> Tuple[int, int]:
    """Parse a beat page_range string into (start, end) integers.

    Handles: 'N-M', 'N-end', 'N', '', None.
    Returns (0, 0) when the range is unparseable.
    """
    pr = (pr or "").replace("end", str(target_pages)).strip()
    parts = re.findall(r"\d+", pr)
    if len(parts) >= 2:
        return int(parts[0]), int(parts[1])
    if len(parts) == 1:
        v = int(parts[0])
        return v, v
    return 0, 0


def _beats_overlap(s1: int, e1: int, s2: int, e2: int) -> bool:
    """Return True when two page ranges [s1,e1] and [s2,e2] overlap."""
    return not (e1 < s2 or s1 > e2)


# =============================================================================
# CONTENT-AWARE PAGE ALLOCATION
# =============================================================================
# Problem this solves
# -------------------
# Page budgets and beat counts used to be decided INDEPENDENTLY:
#   * acts were given pages by a uniform  round(target_pages * i/num_acts)  split
#     (a 5-page epilogue act got as many pages as a 50-page middle act);
#   * each act's beats were assigned page_ranges by the LLM and then merely
#     CLAMPED into the act window -- never re-tiled.
# When the LLM emitted more beats than the act had pages, clamping collapsed the
# overflow onto the final pages: many beats landed on the same 1-2 pages, i.e.
# "there aren't enough pages for some beats."
#
# The functions below replace clamp-only logic with a content-driven model in
# which THE BOOK GROWS to give every beat its own pages -- no beat is merged,
# dropped, or starved:
#   1. _beat_content_weight    -- estimate how much page each beat deserves from
#                                 its own storyboard content (no LLM call).
#   2. _content_page_counts    -- turn weights into an integer page count per
#                                 beat (each >= a floor), sizing the book to fit.
#   3. tile_beats_across_pages -- lay those page counts down end-to-end so beats
#                                 tile contiguously with no gaps/overlaps; the
#                                 span grows to whatever the content needs.
#   4. normalize_beats_to_pages-- apply one global content scale across the whole
#                                 book; acts naturally span the sum of their
#                                 beats' pages. Callers snap target_pages up to
#                                 the grown span via _max_beat_end.
# All are pure/deterministic and unit-tested.
# =============================================================================

# beat_type multiplier: structural role of the beat within the act.
_BEAT_TYPE_WEIGHT = {
    "climax":        1.8,   # the high-stakes turn deserves room to breathe
    "setpiece":      1.6,
    "action":        1.4,   # choreography needs panels
    "reveal":        1.3,
    "confrontation": 1.4,
    "main":          1.0,   # default narrative beat
    "intimate":      1.15,  # intimate/emotional beats benefit from more panels
    "quiet":         1.1,
    "texture":       0.8,   # world-texture / mood -- lighter
    "enrichment":    0.8,
    "aside":         0.6,   # philosophical aside / bridge -- lightest
    "transition":    0.6,
    "bridge":        0.6,
}

# panel_type additive bonus: cosmic / scenic shots tend to want full pages or
# spreads; character shots are the baseline.
_PANEL_TYPE_BONUS = {
    "cosmic":    1.0,
    "scenic":    0.6,
    "splash":    1.2,
    "character": 0.0,
}

# Technique fragments that imply a full-page or double-page image. Drawn from
# the master-technique vocabulary used in the storyboard prompt
# (e.g. "Eisner:silent-page", "McCloud:eloquent-gutter").
_SPREAD_TECHNIQUE_HINTS = (
    "silent-page", "splash", "atmospheric-reveal", "beautiful-and-terrible",
    "unhurried-world", "eloquent-gutter", "earned-payoff", "secondary-world",
    "cascade-of-dread",
)

# Words inside the description that explicitly call for a big image.
_SPREAD_DESC_HINTS = (
    "splash", "full-page", "full page", "double-page", "double page",
    "spread", "two-page", "wide vista", "panorama", "establishing",
)


def _beat_content_weight(beat: Dict, panels_per_page_avg: int = 4) -> float:
    """Estimate how many pages of weight a beat carries, from its content.

    Returns a RELATIVE weight (not a page count). The allocator converts the
    vector of weights into integer page counts that sum to the page budget.

    Signals (all from storyboard content, no LLM call):
      * description length  -- denser beats hold more drawable events
      * visual_keywords     -- more distinct visual hooks -> more panels
      * beat_type           -- structural role (climax vs. transition)
      * panel_type          -- cosmic/scenic shots want big images
      * adult_content       -- intimate sequences typically span more pages
      * technique           -- some techniques imply a full-page/spread image
      * explicit spread cues in the description text
    """
    desc = str(beat.get("description", "") or "")
    # Base + length signal. A typical 2-3 sentence beat is ~180-360 chars.
    # Cap the length contribution so one runaway paragraph can't dominate.
    weight = 1.0 + min(2.0, len(desc) / 180.0)

    kws = beat.get("visual_keywords") or []
    if isinstance(kws, (list, tuple)):
        weight += 0.12 * min(len(kws), 5)

    low_desc = desc.lower()
    if any(h in low_desc for h in _SPREAD_DESC_HINTS):
        weight += 1.0

    ptype = str(beat.get("panel_type", "") or "").lower().strip()
    weight += _PANEL_TYPE_BONUS.get(ptype, 0.0)

    tech = str(beat.get("technique", "") or "").lower()
    if any(h in tech for h in _SPREAD_TECHNIQUE_HINTS):
        weight += 0.6

    # Intimate/mature sequences usually need more than one page to be told with
    # mood/intercutting rather than a single explicit panel.
    if beat.get("adult_content"):
        weight += 0.8

    # Very dense layouts pack more story per page -> slightly less page-hungry.
    if panels_per_page_avg and panels_per_page_avg >= 6:
        weight *= 0.9
    elif panels_per_page_avg and panels_per_page_avg <= 2:
        weight *= 1.15

    btype = str(beat.get("beat_type", "") or "main").lower().strip()
    weight *= _BEAT_TYPE_WEIGHT.get(btype, 1.0)

    # Never let a beat collapse to ~0 (it must still earn >= the floor).
    return max(0.25, weight)


def _largest_remainder_alloc(weights: List[float], budget: int,
                             floor: int = 1) -> List[int]:
    """Split `budget` whole units across items proportional to `weights`.

    Guarantees: every item gets at least `floor`, and the returned ints sum
    EXACTLY to `budget`. Caller must ensure budget >= len(weights) * floor.
    """
    n = len(weights)
    if n == 0:
        return []
    if budget <= n * floor:
        return [floor] * n

    reserved = n * floor
    distributable = budget - reserved
    total_w = sum(weights) or 1.0

    exact = [w / total_w * distributable for w in weights]
    base = [int(x) for x in exact]
    alloc = [floor + b for b in base]

    leftover = distributable - sum(base)
    remainders = sorted(range(n), key=lambda i: (exact[i] - base[i]), reverse=True)
    for k in range(leftover):
        alloc[remainders[k % n]] += 1
    return alloc


# Hard ceiling on a single book's page count (KDP-style print limit). Growth
# stops here; if there are literally more beats than this, the book still grows
# past it so no beat is ever starved of its own page.
_MAX_BOOK_PAGES = 400


def _content_scale(weights: List[float], target_pages: int,
                   n_beats: int, floor: int) -> float:
    """Pages-per-unit-weight, anchored to the recommended length.

    The scale is calibrated so that, at the recommended ``target_pages``, beats
    receive content-proportional page counts. It is anchored to at least
    ``n_beats * floor`` so that when a story has many beats the scale stays large
    enough for heavy beats to earn more than the floor (rather than every beat
    flattening to a single page). The book then GROWS to whatever this scale
    implies -- it is never squeezed.
    """
    total_w = sum(weights) or 1.0
    anchor = max(int(target_pages), n_beats * floor)
    return anchor / total_w


def _content_page_counts(weights: List[float], target_pages: int,
                         floor: int) -> List[int]:
    """Integer page count per beat, sized by content. Every beat gets >= floor.

    Pages = max(floor, round(weight * scale)). The sum is the (grown) book
    length. If that exceeds the hard ceiling, fall back to a largest-remainder
    split across the ceiling that still honours the floor (so no beat is lost).
    """
    n = len(weights)
    if n == 0:
        return []
    scale = _content_scale(weights, target_pages, n, floor)
    pages = [max(floor, int(round(w * scale))) for w in weights]
    budget = sum(pages)
    ceiling = max(_MAX_BOOK_PAGES, n * floor)  # never below n*floor
    if budget > ceiling:
        pages = _largest_remainder_alloc(weights, ceiling, floor=floor)
    return pages


def tile_beats_across_pages(
    beats: List[Dict],
    page_start: int,
    page_end: int = None,
    panels_per_page_avg: int = 4,
    min_pages_per_beat: int = 1,
) -> List[Dict]:
    """Assign every beat a contiguous, non-overlapping ``page_range``, growing.

    Page counts come from each beat's CONTENT WEIGHT and are laid down
    end-to-end starting at ``page_start`` -- no gaps, no overlaps, every beat
    gets at least ``min_pages_per_beat`` page. The span GROWS to fit the beats:
    no beat is ever merged away or starved.

    ``page_end`` is an optional TARGET length used only to calibrate the
    content scale; the returned tiling may extend beyond it when the beats need
    the room. Mutates each beat's ``page_range`` and returns the list in order.
    """
    if not beats:
        return beats

    floor = max(1, int(min_pages_per_beat))
    if page_end is not None:
        target_len = max(page_end - page_start + 1, len(beats) * floor)
    else:
        target_len = max(len(beats) * floor, len(beats) * 2)

    weights = [_beat_content_weight(b, panels_per_page_avg) for b in beats]
    pages = _content_page_counts(weights, target_len, floor)

    cursor = page_start
    for b, n_pages in zip(beats, pages):
        b["page_range"] = "{}-{}".format(cursor, cursor + n_pages - 1)
        cursor += n_pages
    return beats


def normalize_beats_to_pages(
    all_beats: List[Dict],
    target_pages: int,
    panels_per_page_avg: int = 4,
    min_pages_per_beat: int = 1,
    min_pages_per_act: int = 6,   # kept for call-site compatibility; unused
) -> List[Dict]:
    """Final pass: give every beat its own content-aware pages; grow to fit.

    One global content scale (anchored to ``target_pages``) is applied to every
    beat, so pages-per-beat is consistent across the whole book. Beats are then
    tiled in their existing order -- which is already act-ordered -- so each act
    naturally spans the sum of its beats' page counts and the book length grows
    to whatever the content needs. No beat is merged, dropped, or starved.

    The realised book length is ``max(end page across beats)``; callers should
    snap ``target_pages`` up to it (see ``_max_beat_end``).

    Mutates each beat's ``page_range`` and returns the flat list, in order.
    """
    if not all_beats:
        return all_beats

    floor = max(1, int(min_pages_per_beat))
    weights = [_beat_content_weight(b, panels_per_page_avg) for b in all_beats]
    pages = _content_page_counts(weights, target_pages, floor)

    cursor = 1
    for b, n_pages in zip(all_beats, pages):
        b["page_range"] = "{}-{}".format(cursor, cursor + n_pages - 1)
        cursor += n_pages

    grown = cursor - 1
    if grown != int(target_pages):
        logger.info(
            "  [PageAlloc] Book sized to %d pages (recommended %d) so every "
            "one of %d beats gets its own content-aware pages (min %d/beat).",
            grown, target_pages, len(all_beats), floor,
        )
    return all_beats


def _max_beat_end(beats: List[Dict]) -> int:
    """Highest end-page referenced across all beats (0 if none parseable)."""
    hi = 0
    for b in (beats or []):
        pr = str(b.get("page_range", "") or "")
        nums = re.findall(r"\d+", pr)
        if nums:
            hi = max(hi, max(int(x) for x in nums))
    return hi


def _find_gap_after(
    anchor_idx: int,
    merged: List[Dict],
    span: int,
    target_pages: int,
    desired_start: int,
    parse_fn,
) -> Tuple[int, int]:
    """Find the nearest collision-free page window for an enrichment beat.

    Search strategy (in priority order):
      1. Try the LLM's desired_start at full span.
      2. Search forward from just after the anchor beat ends.
      3. Search backward from desired_start toward page 1.
      4. If the full span can't fit anywhere near the anchor, try a 1-page
         window (minimum footprint) in the same search zones.
      5. Last resort: append right after the last occupied page.

    Returns (free_start, free_end) clamped to [1, target_pages].
    """
    # Build full occupancy from the current merged list
    occupied = []
    for b in merged:
        s, e = parse_fn(b.get("page_range", ""))
        if s > 0:
            occupied.append((s, e))

    def _clear(start: int, length: int) -> bool:
        end = start + length - 1
        if end > target_pages or start < 1:
            return False
        return not any(_beats_overlap(start, end, os, oe) for os, oe in occupied)

    # Anchor beat's end page (forward-search origin)
    anchor_end = 0
    if 0 <= anchor_idx < len(merged):
        _, anchor_end = parse_fn(merged[anchor_idx].get("page_range", ""))

    # Build search zone: window of ±8 pages around the desired start,
    # extended to include the area just after the anchor
    search_lo = max(1, min(desired_start - 4, anchor_end + 1))
    search_hi = min(target_pages, max(desired_start + 8, anchor_end + span + 4))

    for try_span in (span, 1):  # try full span first; fall back to 1-page minimum
        # 1. Try desired start
        if desired_start > 0 and _clear(desired_start, try_span):
            end = min(desired_start + try_span - 1, target_pages)
            return desired_start, end

        # 2. Forward search from just after anchor end
        for candidate in range(max(1, anchor_end + 1), search_hi + 1):
            if _clear(candidate, try_span):
                return candidate, min(candidate + try_span - 1, target_pages)

        # 3. Backward search from desired_start toward page 1
        for candidate in range(min(desired_start, search_hi), search_lo - 1, -1):
            if _clear(candidate, try_span):
                return candidate, min(candidate + try_span - 1, target_pages)

    # 4. Last resort: right after the last occupied end
    last_end = max((e for _, e in occupied), default=0)
    fallback = min(last_end + 1, target_pages)
    return fallback, min(fallback, target_pages)  # 1-page fallback


def _find_anchor_index(
    enrichment_beat: Dict,
    required_beats: List[Dict],
    target_pages: int,
) -> int:
    """Find the list index of the required beat that this enrichment beat
    should be inserted after.

    Resolution order:
      1. If the enrichment beat carries an 'anchor_beat_id' field, find the
         required beat with that beat_id.
      2. Find the required beat whose page range most closely precedes the
         enrichment beat's desired page start. "Most closely" means the
         largest required-beat start that is still ≤ desired_start.
      3. If the desired_start is before all required beats, return -1 (insert
         at the beginning of the list).

    This is purely list-position arithmetic — it never re-sorts anything.
    """
    anchor_id = (enrichment_beat.get("anchor_beat_id") or "").strip()
    if anchor_id:
        for i, rb in enumerate(required_beats):
            if rb.get("beat_id", "").strip() == anchor_id:
                return i
        # anchor_id given but not found — fall through to page-range approach

    desired_start, _ = _parse_beat_range(
        enrichment_beat.get("page_range", ""), target_pages
    )
    if desired_start <= 0:
        # No page hint at all — append after the last required beat
        return len(required_beats) - 1

    # Find the required beat whose page range start is closest to (and ≤)
    # desired_start, preserving list order. We do NOT sort required_beats —
    # we walk the list and keep track of the best candidate.
    best_idx = -1
    best_start = -1
    for i, rb in enumerate(required_beats):
        s, _ = _parse_beat_range(rb.get("page_range", ""), target_pages)
        if s <= desired_start and s > best_start:
            best_start = s
            best_idx = i

    return best_idx  # -1 means insert before everything


def _min_pages_per_beat_for_density(panels_per_page_avg: int) -> int:
    """Minimum pages a single beat should occupy, given page density.

    Mirrors the density thresholds used by ``_reconcile_target_pages_to_beats``
    so the whole pipeline agrees on what "enough room for a beat to breathe"
    means. Dense pages carry more story per page (so a beat needs fewer pages);
    sparse pages need more. Returned as an integer floor for the tiler.

      * panels_per_page_avg >= 6  (very dense)  -> 2 pages/beat
      * panels_per_page_avg <= 2  (very sparse) -> 3 pages/beat
      * otherwise (standard 3-5)                -> 2 pages/beat

    A floor of 2 (not 1) is the key change for enrichment: a backstory or
    side-event beat told in a single page reads as a throwaway; two pages let it
    land emotionally. This is what makes the book GROW when beats are added
    rather than cramming the new beats into the existing budget.
    """
    if not panels_per_page_avg:
        return 2
    if panels_per_page_avg <= 2:
        return 3
    return 2


def merge_enrichment_beats(
    required_beats: List[Dict],
    backstory_beats: List[Dict],
    showcase_beats: List[Dict],
    worldbuilding_beats: List[Dict],
    target_pages: int,
    journey_beats: List[Dict] = None,
) -> List[Dict]:
    """Merge enrichment beats into the required beats list without collision
    and without reordering the required beats.

    Insertion rules
    ---------------
    • Required beats are NEVER reordered. Their list order is the narrative
      order decided by the author and storyboard AI, which may be non-linear
      (Pulp Fiction structure, time-travel, in medias res, etc.).

    • Each enrichment beat is inserted immediately after the required beat it
      is most dramatically relevant to (its "anchor"). The anchor is found by
      page-range proximity in the list — not by global sort.

    • Page ranges are only adjusted when they overlap with an immediate
      neighbour. The adjustment is minimal (shift forward/backward to the
      nearest free window). The rest of the list is untouched.

    • No global sort is performed at any point.

    Returns the merged beat list in narrative sequence.
    """
    all_new = backstory_beats + showcase_beats + worldbuilding_beats + (journey_beats or [])
    if not all_new:
        return required_beats

    _parse = lambda pr: _parse_beat_range(pr, target_pages)

    # Work on a copy so we don't mutate the caller's list
    merged: List[Dict] = list(required_beats)

    # Track how many beats we've inserted at each list position so that
    # multiple enrichment beats anchored to the same required beat land in
    # the order we process them (not stacked on top of each other).
    insertion_offset: Dict[int, int] = {}  # anchor_idx → beats inserted so far

    added = 0
    for beat in all_new:
        # Find anchor in the ORIGINAL required_beats list
        anchor_in_required = _find_anchor_index(beat, required_beats, target_pages)

        # Translate to current position in merged (accounting for prior insertions)
        offset = sum(
            v for k, v in insertion_offset.items()
            if k <= anchor_in_required
        )
        insert_after = anchor_in_required + offset  # list index in merged

        # Resolve page range: find a collision-free window near the desired start
        desired_start, desired_end = _parse(beat.get("page_range", ""))
        span = max(1, desired_end - desired_start) if desired_start > 0 else 2
        if desired_start <= 0:
            # No page hint — place it right after the anchor's end page
            if 0 <= insert_after < len(merged):
                _, anchor_end_pg = _parse(merged[insert_after].get("page_range", ""))
                desired_start = max(1, anchor_end_pg + 1)
            else:
                desired_start = target_pages // 2

        free_start, free_end = _find_gap_after(
            insert_after, merged, span, target_pages, desired_start, _parse
        )
        beat = dict(beat)  # shallow copy so we don't mutate the source
        beat["page_range"] = f"{free_start}-{free_end}"

        # Insert immediately after anchor (or at beginning if anchor_idx == -1)
        insert_pos = insert_after + 1  # position AFTER anchor
        insert_pos = max(0, min(insert_pos, len(merged)))
        merged.insert(insert_pos, beat)

        # Record that we inserted one beat after this anchor
        insertion_offset[anchor_in_required] = (
            insertion_offset.get(anchor_in_required, 0) + 1
        )
        added += 1

    if added:
        beat_types = {}
        for b in merged:
            bt = b.get("beat_type", "required")
            beat_types[bt] = beat_types.get(bt, 0) + 1
        type_summary = ", ".join(f"{v}× {k}" for k, v in sorted(beat_types.items()))
        logger.info(
            f"  [BeatMerge] Inserted {added} enrichment beat(s) after their "
            f"narrative anchors (no reorder). Total {len(merged)} beats: {type_summary}."
        )
    return merged


# =============================================================================
# 7. ENHANCED NARRATION — FLASHBACK AND INTRO CAPTIONS
# =============================================================================

def inject_flashback_temporal_markers(script: List[Dict]) -> List[Dict]:
    """Walk the script and add temporal marker captions to flashback panels.

    Backstory beats tagged with beat_type='backstory' get a NARRATOR caption
    on their first panel reading the temporal_marker text (e.g. 'Fourteen
    years earlier.'). This is a visual grammar convention in graphic novels —
    the yellow box with white type that snaps the reader into the past.

    Also adds a 'PRESENT DAY.' return marker on the first panel after the
    flashback ends.
    """
    in_flashback = False
    last_flashback_page = -1

    for i, page in enumerate(script):
        if page.get("_act_break") or page.get("_prologue"):
            continue

        beat_type = page.get("beat_type", "") or ""
        is_flashback = (beat_type == "backstory") or (
            "flashback" in str(page.get("beat", "")).lower() or
            "years earlier" in str(page.get("setting", "")).lower()
        )

        panels = page.get("panels") or []
        if not panels:
            continue

        if is_flashback and not in_flashback:
            # Enter flashback — add temporal marker to first panel
            marker = page.get("_flashback_temporal_marker", "")
            if not marker:
                # Try to extract from description or beat
                beat_text = page.get("beat", "")
                m = re.search(r"(\d+\s+years?\s+earlier|before [^.]+)", beat_text, re.IGNORECASE)
                marker = m.group(0).capitalize() + "." if m else "Earlier."

            first_panel = panels[0]
            # Add as a dialogue entry with bubble_type='caption'
            dialogue = first_panel.get("dialogue") or []
            # Prepend the temporal marker as the first caption
            marker_entry = {
                "speaker": "NARRATOR",
                "text": marker,
                "bubble_type": "caption",
                "emphasis": "emphasized",
            }
            if not any(
                d.get("text", "") == marker and d.get("speaker") == "NARRATOR"
                for d in dialogue
            ):
                first_panel["dialogue"] = [marker_entry] + list(dialogue)
            in_flashback = True
            last_flashback_page = i

        elif not is_flashback and in_flashback:
            # Exit flashback — add 'PRESENT DAY.' to first panel of return page
            if i > 0 and last_flashback_page >= 0:
                first_panel = panels[0]
                dialogue = first_panel.get("dialogue") or []
                return_marker = {
                    "speaker": "NARRATOR",
                    "text": "Present day.",
                    "bubble_type": "caption",
                    "emphasis": "normal",
                }
                if not any(d.get("text", "").lower() == "present day." for d in dialogue):
                    first_panel["dialogue"] = [return_marker] + list(dialogue)
            in_flashback = False

    return script


def enrich_opening_page_captions(
    script: List[Dict],
    narrative_voice: str = "",
) -> List[Dict]:
    """Ensure the first story page always has a framing narrator caption.

    The opening caption is the most important in the book — it's the first
    words the reader encounters and sets the voice, tone, and implicit promise
    of the story. If the narration weave hasn't placed one here, this function
    adds a structural placeholder that the narration weave should fill.

    Also ensures every act-opening page has an orienting caption.
    """
    story_pages = [p for p in script if not p.get("_act_break") and not p.get("_prologue")]
    if not story_pages:
        return script

    # Mark the first story page's first panel for a framing caption
    first_page = story_pages[0]
    first_panels = first_page.get("panels") or []
    if first_panels:
        first_panels[0]["_needs_opening_caption"] = True
        logger.info("  [OpeningCaption] Marked first panel for framing caption.")

    # Mark first panel of each act for an orienting caption
    seen_acts = set()
    for page in story_pages:
        act = str(page.get("act", "1"))
        if act not in seen_acts:
            panels = page.get("panels") or []
            if panels:
                panels[0]["_needs_act_opening_caption"] = True
                panels[0]["_act_for_caption"] = act
            seen_acts.add(act)

    return script


# =============================================================================
# 8. CHAPTER TITLE SYSTEM
# =============================================================================

def generate_chapter_titles(
    script: List[Dict],
    story_idea,
    get_llm_response,
    parse_json,
    llm_model: str = None,
    use_grok: bool = False,
    pages_per_chapter: int = 5,
) -> Dict[int, str]:
    """Generate thematic chapter titles for groups of pages.

    Chapters are NOT separate printed pages — they're beat markers expressed
    as subtle title captions at the start of each chapter's first panel.
    This gives the story a sense of internal structure without the overhead
    of additional title pages.

    Returns a dict: {page_number: chapter_title_string}
    """
    story_pages = [p for p in script if not p.get("_act_break") and not p.get("_prologue")]
    if len(story_pages) < pages_per_chapter * 2:
        return {}  # Too short for chapters to add value

    # Group pages into chapters
    chapter_starts = list(range(0, len(story_pages), pages_per_chapter))
    if not chapter_starts:
        return {}

    # Build a brief description of each chapter's content
    chapter_summaries = []
    for i, start in enumerate(chapter_starts):
        end = min(start + pages_per_chapter, len(story_pages))
        pages_slice = story_pages[start:end]
        beats_in_chapter = " | ".join(
            str(p.get("beat", ""))[:60] for p in pages_slice if p.get("beat")
        )
        chapter_summaries.append(
            f"Chapter {i+1} (pages {pages_slice[0].get('page','?')}-"
            f"{pages_slice[-1].get('page','?')}): {beats_in_chapter[:200]}"
        )

    chapters_block = "\n".join(chapter_summaries)

    prompt = (
        "You are naming CHAPTERS of a graphic novel. Chapter titles in comics "
        "are evocative, short, and thematic — they hint at what the chapter "
        "means emotionally, not just what happens.\n\n"
        "Great chapter titles:\n"
        "  - Are 2-5 words (occasionally one striking word)\n"
        "  - Carry double meaning (literal and metaphorical)\n"
        "  - Belong to this story — they couldn't be a chapter title "
        "in any other book\n"
        "  - Build toward each other across the arc (they should feel like "
        "a sequence when read together)\n\n"
        f"GENRE: {story_idea.genre}\n"
        f"MOOD: {story_idea.mood}\n"
        f"THEMES: {', '.join(story_idea.themes or [])}\n\n"
        f"CHAPTER SUMMARIES:\n{chapters_block}\n\n"
        "Return JSON object mapping chapter number (as string) to title:\n"
        '{"1": "The Weight of Wings", "2": "Blood and Calculus", ...}\n'
        "JSON only."
    )

    try:
        kwargs = {"temperature": 0.82, "max_completion_tokens": 800}
        if llm_model:
            kwargs["openai_model"] = llm_model
        kwargs["use_grok"] = use_grok
        raw = get_llm_response(prompt, **kwargs)
        parsed = parse_json(raw) or {}
        if isinstance(parsed, dict) and parsed:
            # Map chapter number to page number
            page_to_chapter: Dict[int, str] = {}
            for i, start in enumerate(chapter_starts):
                chapter_num = str(i + 1)
                title = parsed.get(chapter_num, "")
                if title and start < len(story_pages):
                    page_num = story_pages[start].get("page", 0)
                    if page_num:
                        page_to_chapter[page_num] = title

            if page_to_chapter:
                logger.info(
                    f"  [Chapters] Generated {len(page_to_chapter)} chapter title(s): "
                    + " | ".join(f'"{t}"' for t in list(page_to_chapter.values())[:4])
                )
            return page_to_chapter
    except Exception as e:
        logger.warning(f"  [Chapters] Title generation failed ({e}).")

    return {}


def inject_chapter_titles(
    script: List[Dict],
    chapter_titles: Dict[int, str],
) -> List[Dict]:
    """Inject chapter titles as caption annotations on the relevant panels.

    The chapter title appears as a special caption box — distinct from
    yellow narrator captions — at the top of the chapter's opening panel.
    Stored as '_chapter_title' sidecar, rendered by compose_panel_prompt
    and overlay_panel_text.
    """
    if not chapter_titles:
        return script

    injected = 0
    for page in script:
        if page.get("_act_break") or page.get("_prologue"):
            continue
        page_num = page.get("page", 0)
        if page_num in chapter_titles:
            panels = page.get("panels") or []
            if panels:
                panels[0]["_chapter_title"] = chapter_titles[page_num]
                injected += 1

    if injected:
        logger.info(f"  [Chapters] Injected {injected} chapter title(s) into panels.")
    return script


# =============================================================================
# 9. IMPROVED STORYBOARD BEAT PROMPT ENHANCEMENT
# =============================================================================
# These strings are injected into _storyboard_act_beats() to ensure
# the LLM always includes backstory, showcase, and world-building beats.

ENRICHMENT_BEAT_INSTRUCTIONS = """
MANDATORY ENRICHMENT BEATS (include at least one per act for stories >= 4 acts):

  BACKSTORY BEAT — At least once per story, show a FLASHBACK to a significant
  moment in a major character's past. Choose the moment carefully:
    - Immediately before the character's greatest test (so we understand the stakes)
    - Immediately after a revelation that recontextualises who they are
    Label with beat_type='backstory' and include a "temporal_marker" field
    (e.g. "Eleven years earlier.").

  CHARACTER SHOWCASE — For every lead character, include at least one scene
  that shows them doing something they love or that reveals a surprising side
  of them, OUTSIDE the main plot pressure. 1-2 pages. The reader must care
  about this person before they're endangered.
  Label with beat_type='character_showcase'.

  WORLD-BUILDING BEAT — For every significant new location, include a
  dedicated 1-2 page visual spread that establishes the place BEFORE or
  AS the characters arrive. No dialogue required — just environment.
  Label with beat_type='world_building'.

These beat types must be interspersed among the main story beats, not
tacked on at the end. They earn their pages by making subsequent beats land harder.
"""

CHARACTER_DEVELOPMENT_CONTEXT_TEMPLATE = """
CHARACTER DEVELOPMENT CONTEXT:
Each major character in this story has:
  - An inner contradiction (they want X but believe Y about themselves)
  - A defining formative event (the wound that shapes all their choices)
  - A relationship that mirrors their arc (someone who sees the truth about them)
  - A private habit or ritual that reveals personality
  - A way their behaviour changes under pressure

When writing beats for these characters, honour these dimensions. Avoid beats
where characters only react to plot — they should also reveal WHO THEY ARE.
"""


# =============================================================================
# 10. RENDER SUPPORT — Prologue / text-page composition with auto-fit layout
# =============================================================================
#
# Design goals
# ------------
# • The text ALWAYS fits — font size is binary-searched downward until every
#   word lands inside the usable area, no matter how long the content is.
# • When content is genuinely too long even at the minimum readable size
#   (MIN_BODY_PT), the renderer spills naturally to as many continuation
#   pages as needed. Each page is returned in the list; the caller saves them
#   all, inserting them at the front of the book.
# • Line heights and paragraph gaps are derived from actual glyph metrics
#   (textbbox), not guessed multipliers, so the layout is pixel-accurate.
# • The title occupies its own vertical zone; body text starts below it,
#   leaving symmetrical top/bottom margins.
# =============================================================================

# Font-size limits (in points) for the body text.
# 300 DPI book page: 18 pt ≈ comfortable reading; 10 pt ≈ smallest legible.
_MAX_BODY_PT  = 28   # start search here
_MIN_BODY_PT  = 10   # never go smaller; spill to next page instead
_TITLE_SCALE  = 1.9  # title font is this multiple of the body size
_LINE_SPACING = 1.45 # leading multiplier (line height = glyph height × this)
_PARA_SPACING = 0.6  # extra gap between paragraphs as a fraction of line height


def _find_font_path(bold: bool = False) -> str:
    """Return the first available system font path, or '' for PIL default."""
    import os
    bold_candidates = [
        "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
        "/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf",
        "/Library/Fonts/Arial Bold.ttf",
        "C:\\Windows\\Fonts\\arialbd.ttf",
        "/System/Library/Fonts/Supplemental/Arial Bold.ttf",
    ]
    regular_candidates = [
        "/usr/share/fonts/truetype/dejavu/DejaVuSerif.ttf",
        "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
        "/usr/share/fonts/truetype/liberation/LiberationSerif-Regular.ttf",
        "/Library/Fonts/Georgia.ttf",
        "C:\\Windows\\Fonts\\georgia.ttf",
        "/System/Library/Fonts/Supplemental/Georgia.ttf",
    ]
    for path in (bold_candidates if bold else regular_candidates):
        if os.path.exists(path):
            return path
    return ""


def _load_font(path: str, size_pt: int):
    """Load a TrueType font at `size_pt`, falling back to PIL's bitmap default."""
    from PIL import ImageFont
    if path:
        try:
            return ImageFont.truetype(path, size_pt)
        except Exception:
            pass
    return ImageFont.load_default()


def _measure_line_height(font) -> int:
    """Return the pixel height of a typical capital letter using textbbox."""
    from PIL import Image, ImageDraw
    _probe_img = Image.new("RGB", (1, 1))
    _probe_draw = ImageDraw.Draw(_probe_img)
    try:
        bb = _probe_draw.textbbox((0, 0), "Hg|", font=font)
        return max(1, bb[3] - bb[1])
    except Exception:
        # textbbox unavailable on very old Pillow; use getsize fallback
        try:
            return max(1, font.getsize("Hg|")[1])
        except Exception:
            return 20


def _wrap_paragraphs(content: str, font, usable_w: int):
    """
    Wrap `content` into lines that fit within `usable_w` pixels using
    PIL's textlength (or textbbox fallback). Returns a list of
    (line_str, is_paragraph_end) tuples — is_paragraph_end is True on
    the blank gap line that follows each paragraph.
    """
    from PIL import Image, ImageDraw
    _probe_img = Image.new("RGB", (1, 1))
    _probe_draw = ImageDraw.Draw(_probe_img)

    def _line_w(text: str) -> int:
        if not text:
            return 0
        try:
            return int(_probe_draw.textlength(text, font=font))
        except AttributeError:
            try:
                bb = _probe_draw.textbbox((0, 0), text, font=font)
                return bb[2] - bb[0]
            except Exception:
                try:
                    return font.getsize(text)[0]
                except Exception:
                    return len(text) * 10

    result = []
    paragraphs = content.split("\n\n")
    for pi, para in enumerate(paragraphs):
        para = para.strip()
        if not para:
            continue
        words = para.split()
        current = ""
        for word in words:
            candidate = (current + " " + word).strip()
            if _line_w(candidate) <= usable_w:
                current = candidate
            else:
                if current:
                    result.append((current, False))
                current = word
        if current:
            # Last line of paragraph — mark paragraph end
            result.append((current, True))
        elif result:
            # Empty paragraph (rare) — still mark end of previous
            result[-1] = (result[-1][0], True)

    return result


def _layout_text_pages(
    title: str,
    content: str,
    page_w_px: int,
    page_h_px: int,
    bg: tuple,
    text_color: tuple,
    style: str,
    body_font_path: str,
    title_font_path: str,
) -> "List[Image]":
    """
    Core layout engine. Returns a list of PIL Images — one per page.

    Algorithm
    ---------
    1. Binary-search body font size from _MAX_BODY_PT down to _MIN_BODY_PT
       until all wrapped lines fit on a single page.
    2. If they still don't fit at _MIN_BODY_PT, accept that size and
       paginate: fill pages greedily until all lines are placed.
    3. Render each page with pixel-accurate line heights derived from
       textbbox, not guessed multipliers.
    """
    from PIL import Image, ImageDraw

    # ── Geometry ──────────────────────────────────────────────────────────
    margin_x = int(page_w_px * 0.10)   # 10% left/right margin
    margin_top = int(page_h_px * 0.10)
    margin_bot = int(page_h_px * 0.08)
    usable_w = page_w_px - 2 * margin_x

    # ── Title zone ────────────────────────────────────────────────────────
    # The title occupies a fixed zone at the top; body text starts below it.
    # We size the title font relative to the body font after body is solved.

    # ── Binary-search for best-fit body font size ─────────────────────────
    lo, hi = _MIN_BODY_PT, _MAX_BODY_PT
    best_size = _MIN_BODY_PT

    for _ in range(12):  # at most 12 bisection steps
        mid = (lo + hi) // 2
        if mid < _MIN_BODY_PT:
            break
        body_font = _load_font(body_font_path, mid)
        title_font = _load_font(title_font_path, max(_MIN_BODY_PT, int(mid * _TITLE_SCALE)))

        line_h = int(_measure_line_height(body_font) * _LINE_SPACING)
        para_gap = int(line_h * _PARA_SPACING)

        # Title zone height
        title_h = 0
        if title:
            title_line_h = _measure_line_height(title_font)
            title_h = int(title_line_h * 1.6) + int(page_h_px * 0.03)  # title + gap

        # Available body area on first page
        body_top = margin_top + title_h
        avail_h = page_h_px - body_top - margin_bot

        # Wrap and measure total height needed
        lines = _wrap_paragraphs(content, body_font, usable_w)
        total_h = 0
        for _line, is_para_end in lines:
            total_h += line_h
            if is_para_end:
                total_h += para_gap

        if total_h <= avail_h:
            best_size = mid
            lo = mid + 1   # try bigger
        else:
            hi = mid - 1   # try smaller

    # ── Final fonts at best_size ──────────────────────────────────────────
    body_font = _load_font(body_font_path, best_size)
    title_font = _load_font(title_font_path, max(_MIN_BODY_PT, int(best_size * _TITLE_SCALE)))

    line_h = int(_measure_line_height(body_font) * _LINE_SPACING)
    para_gap = int(line_h * _PARA_SPACING)

    title_h = 0
    if title:
        title_line_h = _measure_line_height(title_font)
        title_h = int(title_line_h * 1.6) + int(page_h_px * 0.03)

    lines = _wrap_paragraphs(content, body_font, usable_w)

    # ── Paginate ──────────────────────────────────────────────────────────
    pages_out: List = []
    rule_color = tuple(max(0, c - 60) if text_color[0] > 128 else min(255, c + 60)
                       for c in text_color)

    def _new_page(is_first: bool) -> tuple:
        img = Image.new("RGB", (page_w_px, page_h_px), bg)
        drw = ImageDraw.Draw(img)
        body_top_y = margin_top + (title_h if is_first else 0)
        avail = page_h_px - body_top_y - margin_bot
        return img, drw, body_top_y, avail

    img, drw, y, avail = _new_page(is_first=True)
    is_first_page = True

    # Render title on the first page
    if title:
        title_mid_y = margin_top + title_h // 2 - int(page_h_px * 0.015)
        drw.text(
            (page_w_px // 2, title_mid_y),
            title.upper(),
            fill=text_color,
            font=title_font,
            anchor="mm",
        )
        # Decorative rule under title
        rule_y = margin_top + title_h - int(page_h_px * 0.015)
        drw.line(
            [(margin_x, rule_y), (page_w_px - margin_x, rule_y)],
            fill=rule_color,
            width=max(1, int(page_w_px * 0.002)),
        )

    used_h = 0
    for line_text, is_para_end in lines:
        needed = line_h + (para_gap if is_para_end else 0)

        # Would this line overflow the current page?
        if used_h + needed > avail and used_h > 0:
            # Finish current page and start a new one
            pages_out.append(img)
            img, drw, y, avail = _new_page(is_first=False)
            is_first_page = False
            used_h = 0

        drw.text((margin_x, y + used_h), line_text, fill=text_color, font=body_font)
        used_h += line_h
        if is_para_end:
            used_h += para_gap

    # Add style rule on non-title pages too (if style B/C)
    if not title and style in ("B", "C"):
        rule_y = margin_top - int(page_h_px * 0.02)
        drw.line(
            [(margin_x, rule_y), (page_w_px - margin_x, rule_y)],
            fill=rule_color,
            width=max(1, int(page_w_px * 0.002)),
        )

    pages_out.append(img)  # flush last page

    logger.info(
        f"  [Prologue] Laid out {len(lines)} lines across {len(pages_out)} page(s) "
        f"at body font size {best_size}pt."
    )
    return pages_out


def compose_prologue_page(
    prologue_page: Dict,
    page_w_px: int,
    page_h_px: int,
    dialog_font=None,       # kept for API compatibility; ignored (we load our own)
    narration_font=None,    # kept for API compatibility; ignored
) -> "Optional[Any]":
    """Compose the opening text/prologue page(s) as PIL Image(s).

    Returns either:
      • A single PIL Image when the content fits on one page, OR
      • A list of PIL Images when the content spills to multiple pages.

    The font size is automatically chosen via binary search so all text fits
    within the usable area. If text is still too long at the minimum readable
    size (_MIN_BODY_PT), it flows onto continuation pages rather than being
    cut off or overflowing the margin.

    The caller should handle both return types:
        result = compose_prologue_page(...)
        pages = result if isinstance(result, list) else [result]
        for i, pg_img in enumerate(pages):
            if pg_img is not None:
                pg_img.save(f"prologue_{i}.jpg", ...)
    """
    try:
        style = prologue_page.get("_prologue_style", "A")
        title = (prologue_page.get("title") or "").strip()
        content = (prologue_page.get("_prologue_content") or "").strip()
        visual_note = (prologue_page.get("_prologue_visual_note") or "").strip().lower()

        if not content:
            logger.warning("  [Prologue] No content to render.")
            return None

        # Background and text colours
        dark_bg = any(w in visual_note for w in ("dark", "black", "night", "shadow", "void"))
        bg = (10, 10, 10) if dark_bg else (245, 240, 235)
        text_color = (235, 225, 210) if dark_bg else (20, 20, 20)

        body_font_path = _find_font_path(bold=False)
        title_font_path = _find_font_path(bold=True)

        pages = _layout_text_pages(
            title=title,
            content=content,
            page_w_px=page_w_px,
            page_h_px=page_h_px,
            bg=bg,
            text_color=text_color,
            style=style,
            body_font_path=body_font_path,
            title_font_path=title_font_path,
        )

        return pages[0] if len(pages) == 1 else pages

    except Exception as e:
        logger.warning(f"  [Prologue] Page composition failed ({e}).")
        return None


# =============================================================================
# MAIN INTEGRATION FUNCTION
# =============================================================================

def apply_all_improvements(
    story_idea,
    characters: List,
    story_idea_str: str,
    required_beats: List[Dict],
    script: List[Dict],
    target_pages: int,
    get_llm_response,
    parse_json,
    sanitize=None,
    llm_model: str = None,
    llm_model_large: str = None,
    use_grok: bool = False,
    narrative_voice: str = "",
    enable_prologue: bool = True,
    enable_char_intros: bool = True,
    enable_backstory: bool = True,
    enable_showcases: bool = True,
    enable_worldbuilding: bool = True,
    enable_chapters: bool = True,
    pages_per_chapter: int = 5,
) -> Tuple[List[Dict], List[Dict], Dict]:
    """Apply all improvements in the correct pipeline order.

    Call this AFTER script generation + narration design but BEFORE
    image generation.

    Returns:
      (updated_script, updated_required_beats, improvement_data)
      improvement_data contains prologue_page, chapter_titles, etc.
    """
    if sanitize is None:
        sanitize = lambda x: x  # noqa

    model = llm_model_large or llm_model
    improvement_data: Dict[str, Any] = {}

    # ── Step 1: Generate enrichment beats and merge with required_beats ──
    logger.info("  [Improvements] Generating enrichment beats...")

    backstory_beats = []
    if enable_backstory:
        backstory_beats = generate_character_backstory_beats(
            characters, story_idea, required_beats, target_pages,
            get_llm_response, parse_json, model, use_grok,
        )

    showcase_beats = []
    if enable_showcases:
        showcase_beats = generate_character_showcase_beats(
            characters, story_idea, required_beats, target_pages,
            get_llm_response, parse_json, model, use_grok,
        )

    wb_beats = []
    if enable_worldbuilding:
        wb_beats = generate_worldbuilding_spread_beats(
            story_idea, story_idea_str, required_beats, target_pages,
            get_llm_response, parse_json, sanitize, model, use_grok,
        )

    updated_beats = merge_enrichment_beats(
        required_beats, backstory_beats, showcase_beats, wb_beats, target_pages
    )
    improvement_data["enriched_required_beats"] = updated_beats

    # ── Step 2: Generate character intro captions ─────────────────────────
    if enable_char_intros:
        logger.info("  [Improvements] Generating character intro captions...")
        char_intros = generate_character_intros(
            characters, story_idea, get_llm_response, parse_json, model, use_grok
        )
        script = inject_character_intro_captions(script, char_intros, characters)
        improvement_data["character_intros"] = char_intros

    # ── Step 3: Inject flashback temporal markers ─────────────────────────
    script = inject_flashback_temporal_markers(script)

    # ── Step 4: Ensure opening page has a framing caption ────────────────
    script = enrich_opening_page_captions(script, narrative_voice)

    # ── Step 5: Generate and inject chapter titles ────────────────────────
    if enable_chapters and len([p for p in script if not p.get("_act_break")]) >= pages_per_chapter * 2:
        logger.info("  [Improvements] Generating chapter titles...")
        chapter_titles = generate_chapter_titles(
            script, story_idea, get_llm_response, parse_json, model, use_grok, pages_per_chapter
        )
        script = inject_chapter_titles(script, chapter_titles)
        improvement_data["chapter_titles"] = chapter_titles

    # ── Step 6: Generate prologue page ────────────────────────────────────
    prologue_page = None
    if enable_prologue:
        logger.info("  [Improvements] Generating opening text/prologue page...")
        prologue_page = generate_opening_text_page(
            story_idea, characters, story_idea_str,
            get_llm_response, parse_json, sanitize, model, use_grok,
        )
        improvement_data["prologue_page"] = prologue_page

    logger.info("  [Improvements] All improvements applied.")
    return script, updated_beats, improvement_data

logger = logging.getLogger(__name__)
logging.basicConfig(level=logging.INFO, format='%(message)s')

# =============================================================================
# COMIC-SPECIFIC CONFIGURATION
# =============================================================================

# Trim size: US Letter (8.5 x 11) — full-page comic layout
COMIC_PAGE_WIDTH_IN = 8.5
COMIC_PAGE_HEIGHT_IN = 11.0
COMIC_DPI = 300
COMIC_BLEED_IN = 0.125
COMIC_INSIDE_MARGIN_IN = 0.5    # gutter side
COMIC_OUTSIDE_MARGIN_IN = 0.5
COMIC_TOP_MARGIN_IN = 0.5
COMIC_BOTTOM_MARGIN_IN = 0.625  # extra for page numbers

# DOCX page margins (kept tight so the composed page art fills as much of the
# physical sheet as possible). The composed page IMAGE already carries its own
# interior margins/gutters (the COMIC_*_MARGIN_IN values above), so the DOCX
# only needs a thin safe border to stay inside the printer's non-printable edge.
#
# Amazon KDP margin requirements for interior pages:
#   Outside / top / bottom : 0.25" minimum (all page counts)
#   Gutter (inside/binding): scales with total page count —
#       24–150 pages  : 0.375"
#      151–300 pages  : 0.500"
#      301–500 pages  : 0.625"
#      501–700 pages  : 0.750"
#      701–828 pages  : 0.875"
# Source: KDP Content Guidelines (kdp.amazon.com/help/topic/G200645390)
#
# DOCX_PAGE_MARGIN_IN is the non-gutter margin (outside / top / bottom).
# DOCX_GUTTER_MIN_IN is the minimum gutter for the smallest supported print run.
# Use kdp_gutter_in(page_count) to get the correct gutter for a specific book.
DOCX_PAGE_MARGIN_IN = 0.25      # outside / top / bottom (all page counts)
DOCX_GUTTER_MIN_IN  = 0.375     # minimum gutter for ≤150 pages

# KDP gutter schedule: (max_pages, required_gutter_in)
_KDP_GUTTER_SCHEDULE = (
    (150,  0.375),
    (300,  0.500),
    (500,  0.625),
    (700,  0.750),
    (828,  0.875),
)

def kdp_gutter_in(page_count: int) -> float:
    """Return the KDP-required inside/gutter margin (inches) for `page_count`.

    Based on Amazon KDP Content Guidelines. Values are minimums; we always
    round up to the next 0.125" increment above the threshold so there is
    headroom for rounding and the book passes KDP preflight on the first try.

    Falls back to 0.875" for books over 828 pages (KDP's stated maximum).
    """
    for max_pages, gutter in _KDP_GUTTER_SCHEDULE:
        if page_count <= max_pages:
            return gutter
    return 0.875  # >828 pages — use maximum

# Panel layout
PANEL_GUTTER_PX = 24            # space between panels in pixels (at COMIC_DPI)
PANEL_BORDER_PX = 6             # black border around each panel
PANEL_BORDER_COLOR = (0, 0, 0)

# Image-model limitation: diffusion models reliably render at most a couple of
# distinct human figures per image. Beyond that, faces blend, limbs duplicate,
# and identities drift. We cap the number of DETAILED human characters depicted
# in any single panel to this number and stage the rest off-frame, which keeps
# every image clean and accurate. Group beats are told to the reader through
# two-shots, reaction shots, and cutaways instead of crowded frames.
MAX_HUMANS_PER_PANEL = 2
PAGE_BG_COLOR = (255, 255, 255)

# Image generation
PANEL_VARIANTS = 4              # 4 variants per panel
# Covers: generate several DISTINCT STYLE concepts, each rendered as a few
# images (different seeds) so you can pick the best image within the best style.
# 8 styles x 4 images = 32 candidate covers.
COVER_VARIANTS = 8             # number of DISTINCT cover styles/concepts
COVER_IMAGES_PER_STYLE = 4    # images generated per style (seeds) to choose from
ACT_BREAK_VARIANTS = 4          # 4 variants per act-break page
PANEL_BASE_WIDTH = 1024         # base panel image width before composition
PANEL_BASE_HEIGHT = 1024
COVER_WIDTH = 896
COVER_HEIGHT = 1280

# When True, the LLM rewrites each panel's assembled prompt components into
# vivid, model-optimised image prompt text before the prompt is formatted and
# sent to the image model.  The LLM receives the full context (characters,
# continuity, DNA, scene anchor, VFX) plus few-shot examples of high-quality
# image prompts so it can produce richer, more specific descriptions than the
# mechanical clause joins.  Set to False to skip this pass (faster but lower
# prompt quality).
LLM_PROMPT_REFINEMENT: bool = True

# ---------------------------------------------------------------------------
# Panel geometry: valid generation sizes for the diffusion model.
#
# Flux/SDXL-family models require dimensions that are multiples of 8.
# These are the tested sizes that stay within ~24 GB VRAM at fp16/bf16:
#   Landscape: (1280,704) (1152,768) (1024,768) (1152,640) (1024,640)
#   Square:    (1024,1024)
#   Portrait:  (768,1152) (768,1024) (704,1280) (640,1152) (640,1024)
#
# The matcher picks the candidate whose aspect ratio is closest to the
# panel's true aspect ratio on the page, with a preference for larger
# sizes on hero/splash panels.
# ---------------------------------------------------------------------------
# ---------------------------------------------------------------------------
# Panel geometry: per-model native generation sizing.
#
# Each diffusion model has its own native training resolution and pixel-multiple
# constraint (see novel_generator._MODEL_GEN_GEOMETRY):
#   LENS                    : 1440 native, sizes ÷16, max 1440
#   ZIMAGE / ERNIE / CHROMA : 1024 native, sizes ÷8 (CHROMA ÷16), max 1024
#
# To match a panel's aspect ratio at the best available resolution we anchor the
# LONGER side at the model's native base, scale the SHORTER side to the panel's
# aspect ratio, then round to the model's factor and clamp to [min_dim, max_dim].
# This keeps generation as close to native resolution as the aspect ratio allows
# for whichever model is active, instead of a one-size-fits-all candidate list.
# ---------------------------------------------------------------------------

def _round_to_factor(value: int, factor: int, lo: int, hi: int) -> int:
    """Round value to the nearest multiple of `factor`, clamped to [lo, hi]."""
    value = max(lo, min(int(value), hi))
    r = int(round(value / factor)) * factor
    r = max(lo, min(r, hi))
    # Guard: clamping after rounding can push below lo if lo isn't a multiple of
    # factor — snap up to the first multiple >= lo in that case.
    if r < lo:
        r = ((lo + factor - 1) // factor) * factor
    return r


def _nearest_gen_size(target_w: int, target_h: int,
                      image_model: str = None) -> Tuple[int, int]:
    """Return (gen_w, gen_h): a model-legal generation size whose aspect ratio
    equals the panel slot's aspect ratio, to within the model's pixel multiple.

    The whole point is that the generated image is *already* the exact shape of
    its panel, so composition is a pure resize — the image fills the slot with
    NO crop and NO letterbox space. We achieve this by scaling the panel's true
    pixel dimensions by a single factor (which preserves the aspect ratio
    exactly) so the longer side sits at the model's native resolution, then
    rounding each side to the model's required multiple (`factor`, e.g. 16).
    Rounding shifts the aspect ratio by less than one `factor` step (≤16 px),
    which is imperceptible and absorbed by a sub-pixel-scale resize at compose
    time — never a crop and never a pad.

    Note we deliberately do NOT clamp the shorter side up to `min_dim`. That
    clamp was the bug: on an extreme panel (a wide banner, a tall column) the
    derived short side would be raised to min_dim, which *changes the aspect
    ratio* and forces the image to be cropped or letterboxed into its slot.
    Honouring the panel's true proportions matters more than a soft resolution
    floor — the models accept any multiple-of-`factor` size, and the print
    upscale pass restores resolution afterwards. A hard floor of one `factor`
    step is kept only to avoid a degenerate zero/sliver dimension.

    Falls back to a square at the model's base if target dims are degenerate.
    """
    geo = get_model_gen_geometry(image_model)
    base    = int(geo['base'])
    factor  = int(geo['factor'])
    max_dim = int(geo['max_dim'])

    # The longest side we may generate: the model's native size, snapped down to
    # a legal multiple of `factor`.
    long_cap = max(factor, (min(base, max_dim) // factor) * factor)

    if target_h <= 0 or target_w <= 0:
        return (long_cap, long_cap)

    # Scale so the LONGER panel side maps to long_cap, preserving AR exactly.
    if target_w >= target_h:
        gen_w = float(long_cap)
        gen_h = long_cap * (target_h / target_w)
    else:
        gen_h = float(long_cap)
        gen_w = long_cap * (target_w / target_h)

    # Round each side to the nearest legal multiple of `factor`; never exceed
    # max_dim; never collapse below a single factor step.
    def _snap(v: float) -> int:
        r = int(round(v / factor)) * factor
        r = min(r, (max_dim // factor) * factor)
        return max(factor, r)

    return (_snap(gen_w), _snap(gen_h))


def _compute_page_panel_pixel_dims(
    layout: 'PageLayout',
    page_w_in: float = COMIC_PAGE_WIDTH_IN,
    page_h_in: float = COMIC_PAGE_HEIGHT_IN,
    dpi: int = COMIC_DPI,
    inside_margin_in: float = COMIC_INSIDE_MARGIN_IN,
    outside_margin_in: float = COMIC_OUTSIDE_MARGIN_IN,
    top_margin_in: float = COMIC_TOP_MARGIN_IN,
    bottom_margin_in: float = COMIC_BOTTOM_MARGIN_IN,
) -> List[Tuple[int, int]]:
    """Return a list of (panel_w_px, panel_h_px) for every panel slot in
    this layout, computed identically to compose_page's geometry.

    These are the *true* pixel dimensions of each panel slot on the printed
    page — after margins and gutters are applied. Passing these to the image
    generator means the generated image's aspect ratio matches its panel slot
    exactly, minimising content loss at composition time.
    """
    page_w = int(page_w_in * dpi)
    page_h = int(page_h_in * dpi)

    is_left_page = (layout.page_number % 2 == 0)
    if is_left_page:
        left_margin  = int(outside_margin_in * dpi)
        right_margin = int(inside_margin_in * dpi)
    else:
        left_margin  = int(inside_margin_in * dpi)
        right_margin = int(outside_margin_in * dpi)

    top_margin    = int(top_margin_in * dpi)
    bottom_margin = int(bottom_margin_in * dpi)

    printable_w = page_w - left_margin - right_margin
    printable_h = page_h - top_margin  - bottom_margin

    g = PANEL_GUTTER_PX // 2
    result: List[Tuple[int, int]] = []

    for (x_pct, y_pct, w_pct, h_pct) in layout.panel_boxes:
        panel_w = int(w_pct * printable_w)
        panel_h = int(h_pct * printable_h)

        left_inset   = g if x_pct > 0.005 else 0
        top_inset    = g if y_pct > 0.005 else 0
        right_inset  = g if (x_pct + w_pct) < 0.995 else 0
        bottom_inset = g if (y_pct + h_pct) < 0.995 else 0

        w_inset = max(64, panel_w - left_inset - right_inset)
        h_inset = max(64, panel_h - top_inset  - bottom_inset)
        result.append((w_inset, h_inset))

    return result
GUIDANCE_SCALE = 4
N_STEPS = 8

# cuDNN error signatures that trigger a CPU fallback retry.
_CUDNN_ERROR_PHRASES = (
    "CUDNN_STATUS_SUBLIBRARY_VERSION_MISMATCH",
    "cudnnFinalize failed",
    "CUDNN_BACKEND_TENSOR_DESCRIPTOR",
    "CUDA error",
    "CUDA out of memory",
)


def _pil_to_rgb_array(image) -> np.ndarray:
    """Coerce a pipeline image result to an H×W×3 uint8 RGB numpy array.

    The post-processing pipeline (comic_panel_pipeline) assumes 3-channel RGB
    uint8. Different diffusion pipelines can return slightly different things:
      - a PIL.Image in mode 'RGB' (ZIMAGE/ERNIE/CHROMA — the common case)
      - a PIL.Image in mode 'RGBA' or 'L' (possible from some pipelines)
      - a numpy array already (defensive)
    This normaliser guarantees a consistent shape so a stray mode/channel count
    can never silently break the save step for one model (e.g. LENS) while
    working for the others.
    """
    from PIL import Image as _PILImage
    if isinstance(image, np.ndarray):
        arr = image
        # Drop alpha if present; expand greyscale to 3 channels.
        if arr.ndim == 2:
            arr = np.stack([arr] * 3, axis=-1)
        elif arr.ndim == 3 and arr.shape[2] == 4:
            arr = arr[:, :, :3]
        if arr.dtype != np.uint8:
            arr = np.clip(arr, 0, 255).astype(np.uint8)
        return arr
    if isinstance(image, _PILImage.Image):
        if image.mode != 'RGB':
            image = image.convert('RGB')
        return np.array(image)
    # Last resort: let PIL/np try, then enforce RGB.
    arr = np.array(image)
    if arr.ndim == 2:
        arr = np.stack([arr] * 3, axis=-1)
    elif arr.ndim == 3 and arr.shape[2] == 4:
        arr = arr[:, :, :3]
    if arr.dtype != np.uint8:
        arr = np.clip(arr, 0, 255).astype(np.uint8)
    return arr


def _safe_gen_image(pipe, prompt: str, *,
                    height: int, width: int,
                    seed: int, num_inference_steps: int,
                    promptEnhance: bool = False,
                    negative_prompt: str = ""):
    """Call gen_ImageZ_image with an automatic CPU-fallback on cuDNN/CUDA errors.

    If a cuDNN version-mismatch or other CUDA error fires, the pipeline is
    temporarily moved to CPU, the image is regenerated, then restored to GPU.
    All other exceptions are re-raised unchanged.

    Parameters
    ----------
    negative_prompt : str
        Extra negative-prompt terms forwarded to gen_ImageZ_image as
        ``extra_negative``.  The base anatomical / text-suppression negatives
        are always present inside gen_ImageZ_image; this parameter adds
        caller-specific terms on top of them.
    """
    try:
        return gen_ImageZ_image(
            pipe, prompt,
            height=height, width=width,
            seed=seed, num_inference_steps=num_inference_steps,
            promptEnhance=promptEnhance,
            extra_negative=negative_prompt,
        )
    except Exception as e:
        err_str = str(e)
        if not any(phrase in err_str for phrase in _CUDNN_ERROR_PHRASES):
            raise  # not a cuDNN/CUDA issue — propagate normally

        logger.warning(
            f"  cuDNN/CUDA error — retrying on CPU for this variant. "
            f"({err_str[:120]})"
        )
        # Pipelines loaded with enable_model_cpu_offload() install accelerate
        # hooks that FORBID a manual .to('cpu')/.to('cuda') move — calling it
        # raises "you have activated model offloading ... cannot be moved". For
        # those pipes (LENS, CHROMA) the offload system already manages device
        # placement, so a manual CPU move is both impossible and unnecessary.
        # Detect that and re-raise the ORIGINAL error rather than crashing the
        # fallback with a confusing secondary exception.
        _is_offloaded = (
            getattr(pipe, '_all_hooks', None)
            or getattr(pipe, 'hf_device_map', None)
            or hasattr(pipe, '_offload_gpu_id')
        )
        if _is_offloaded:
            logger.warning(
                "  Pipe uses model CPU offload (LENS/CHROMA); cannot move it "
                "manually. Re-raising original error for this variant."
            )
            raise
        original_device = None
        try:
            
            if hasattr(pipe, 'unet'):
                original_device = next(pipe.unet.parameters()).device
            elif hasattr(pipe, 'device'):
                original_device = pipe.device
            pipe.to('cpu')
            image = gen_ImageZ_image(
                pipe, prompt,
                height=height, width=width,
                seed=seed, num_inference_steps=num_inference_steps,
                promptEnhance=promptEnhance,
                extra_negative=negative_prompt,
            )
            if original_device is not None:
                pipe.to(original_device)
            logger.info("  CPU fallback succeeded — pipe restored to original device.")
            return image
        except Exception as cpu_err:
            try:
                if original_device is not None:
                    pipe.to(original_device)
            except Exception:
                pass
            raise RuntimeError(
                f"GPU: {err_str[:120]} | CPU fallback: {cpu_err}"
            ) from cpu_err


