# ---------------------------------------------------------------------------
# Comic-format trigger-word suppression
# ---------------------------------------------------------------------------
# The terms below cause diffusion models to render speech bubbles, caption
# boxes, panel borders, and lettering in the generated image.  We strip them
# from every string that enters the image-generation prompt and replace them
# with neutral illustration vocabulary.
#
# IMPORTANT: these replacements are ONLY for image prompts.  The script/story
# generation side still uses "comic book" / "graphic novel" freely — only the
# final prompt fed to the diffusion model is sanitized.
import re as _comic_re
_COMIC_TRIGGER_REPLACEMENTS = [
    # -----------------------------------------------------------------------
    # Comic / graphic-novel format terms (longest / most specific first)
    # -----------------------------------------------------------------------
    
    # 1. Matches "inked graphic novel" or "inked graphic novel illustration"
    (_comic_re.compile(r'\binked\s+graphic\s+novel(?:\s+illustration)?\b', _comic_re.IGNORECASE), 
     'premium graphic novel artwork with expressive ink rendering and painterly color gradients'),
     
    # 2. Matches "graphic novel" or "graphic novel illustration" (but avoids re-matching what Rule 1 just generated!)
    (_comic_re.compile(r'(?<!inked\s)\bgraphic\s+novel(?:\s+illustration)?\b', _comic_re.IGNORECASE), 
     'premium graphic novel artwork with expressive ink rendering and painterly color gradients'),
     
    (_comic_re.compile(r'\bcomic[\s-]book\s+illustration\b',   _comic_re.IGNORECASE), 'premium graphic novel artwork with expressive ink rendering and painterly color gradients'),
    (_comic_re.compile(r'\bcomic[\s-]book\s+artwork\b',        _comic_re.IGNORECASE), 'premium graphic novel artwork with expressive ink rendering and painterly color gradients'),
    (_comic_re.compile(r'\bcomic[\s-]book\b',                  _comic_re.IGNORECASE), 'premium graphic novel artwork with expressive ink rendering and painterly color gradients'),
    (_comic_re.compile(r'\bcomic\s+panel\b',                   _comic_re.IGNORECASE), 'premium graphic novel artwork with expressive ink rendering and painterly color gradients'),
    (_comic_re.compile(r'\bcomic\s+strip\b',                   _comic_re.IGNORECASE), 'premium graphic novel artwork with expressive ink rendering and painterly color gradients'),
    (_comic_re.compile(r'\bsequential\s+art\b',                _comic_re.IGNORECASE), 'premium graphic novel artwork with expressive ink rendering and painterly color gradients'),
    (_comic_re.compile(r'\bmanga\b',                           _comic_re.IGNORECASE), 'anime style inked graphic novel illustration with airbrush gradients of light and color'),
    
    # 3. Catch-all "comic" — Added negative lookbehind so it ignores the "comic" inside your own replacement string
    (_comic_re.compile(r'(?<!light\sand\s)\bcomic\b', _comic_re.IGNORECASE), 'premium graphic novel artwork with expressive ink rendering and painterly color gradients'),
    
    # -----------------------------------------------------------------------
    # Dialog / text-bubble terms
    # -----------------------------------------------------------------------
    (_comic_re.compile(r'\bspeech\s+bubble[s]?\b',             _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\bthought\s+bubble[s]?\b',            _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\bword\s+balloon[s]?\b',              _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\bspeech\s+balloon[s]?\b',            _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\bdialog(?:ue)?\s+box(?:es)?\b',      _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\bcaption\s+box(?:es)?\b',            _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\bcaption\s+text\b',                  _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\btext\s+bubble[s]?\b',               _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\bnarrat(?:or|ion)\s+box(?:es)?\b',   _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\binner\s+monologue\b',               _comic_re.IGNORECASE), ''),
    
    # Standalone tokens
    (_comic_re.compile(r'\bcaption[s]?\b',                     _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\bdialogue\b',                        _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\bdialog\b',                          _comic_re.IGNORECASE), ''),
    (_comic_re.compile(r'\bstoryboard\b',                      _comic_re.IGNORECASE), ''), # Fixed missing \b at start here too
]

# ---------------------------------------------------------------------------
# SINGLE-IMAGE DESCRIPTION RULE
# ---------------------------------------------------------------------------
# Injected into every LLM prompt that writes a panel image description.
# Diffusion models generate ONE image per call. Any language that describes
# a page layout, a grid of panels, or multiple simultaneous scenes causes the
# model to try to render a collage or triptych instead of a single illustration.
# ---------------------------------------------------------------------------
_SINGLE_IMAGE_RULE = (
    "CRITICAL — SINGLE IMAGE RULE: You are writing the brief for ONE image "
    "generated by an AI image model. That model draws exactly one picture per "
    "call. Do NOT write a description that describes the page layout or image "
    "layout. Never use phrases like: 'arranged in a grid', 'five windows in a "
    "row', 'three panels showing', 'each showing a different room', 'across "
    "the page', 'split into sections', 'divided into quadrants', or any other "
    "multi-image / collage framing. If the story beat covers multiple locations "
    "or characters, CHOOSE THE SINGLE MOST DRAMATIC MOMENT and describe only "
    "that one image. The page compositor handles layout — your job is to "
    "describe what is inside one panel frame."
)



def _strip_meta_tags_from_prompt(text: str) -> str:
    """Safety-net: remove any editor/meta-tag labels from a final image prompt.

    The clause builders now emit clean descriptive prose, but this pass is a
    defensive backstop that strips any ALL-CAPS meta-label prefix that might
    still slip in (now or from future additions), e.g.:
        "SCENE LOCK — location: ..."   becomes  "location: ..."
        "COSTUME LOCK — ..."           becomes  "..."
        "TECHNOLOGY VFX — ..."         becomes  "..."

    Diffusion models render the words they're given. These labels carry no
    visual meaning and can be drawn into the image as literal text, so they are
    stripped here. The descriptive CONTENT after the label is preserved.

    Strategy: find a run of 2+ ALL-CAPS words (optionally with a parenthetical
    or slashed qualifier) immediately followed by a separator (em dash, hyphen,
    or colon), and delete the label-plus-separator, keeping the content. Also
    removes a few imperative meta-sentences that instruct rather than describe.
    """
    if not text:
        return text

    # 1) Remove "LABEL — " / "LABEL: " / "LABEL - " prefixes wherever they occur.
    #    A label is 2-5 ALL-CAPS tokens (letters, &, /, -) possibly followed by a
    #    short lowercase qualifier in parens or after a slash. We match the label
    #    only when it is followed by a dash/colon separator, so ordinary
    #    capitalised words in prose are never touched.
    label = (
        r'\b'
        r'[A-Z][A-Z&/]{1,}(?:\s+[A-Z][A-Z&/\-]+){1,4}'   # 2-5 all-caps words
        r'(?:\s*\([^)]{0,40}\))?'                          # optional (qualifier)
        r'(?:\s*[-–/][a-z][a-z/ ]{0,40})?'                 # optional /sub-label
        r'\s*[—–:-]\s+'                                    # required separator
    )
    cleaned = _comic_re.sub(label, '', text)

    # 2) Remove standalone imperative meta-sentences that tell the model what
    #    NOT to do (these add no visual content and waste prompt weight).
    #    Also strips "Continuity is critical: …" directives — these are pipeline
    #    instructions, not visual descriptions, and image models may render them
    #    as literal text in the output image.
    meta_sentences = [
        r'Do not change or reinterpret the location\.?',
        r'Do NOT alter clothing colour, style, or garments,? and do NOT '
        r"change any character'?s gender\.?",
        r'keep EXACTLY this, do not revert to an earlier outfit or change gender\:?',
        r'unchanged from the previous panel\:?',
        r'carried forward from earlier panels\b[^.]*\:?',
        # Continuity-lock directive sentences generated by the art director.
        # These communicate intent within the pipeline but must never reach
        # the image model — they are instructions, not visual content.
        r'Continuity is critical:[^.]+\.',
        r'\bdo not omit, drop, swap, clean up, heal, or otherwise revert these\b[^.]*\.',
        r'\bexactly as established in the preceding panels of this scene\b[^.]*\.',
        r'\bunless this very panel shows the change\b[^.]*\.',
    ]
    for pat in meta_sentences:
        cleaned = _comic_re.sub(pat, '', cleaned, flags=_comic_re.IGNORECASE)

    # 3) Tidy whitespace and stray punctuation left by the removals.
    cleaned = _comic_re.sub(r'\s{2,}', ' ', cleaned)
    cleaned = _comic_re.sub(r'\s+([.,;])', r'\1', cleaned)
    cleaned = _comic_re.sub(r'([.;,])\1+', r'\1', cleaned)   # collapse ".." ",,"
    cleaned = _comic_re.sub(r'^\s*[—–:;,.\-]\s*', '', cleaned)
    return cleaned.strip()


def _strip_comic_terms_from_image_prompt(text: str) -> str:
    """Replace comic/graphic-novel/manga references with neutral illustration
    vocabulary, and remove all dialog/bubble/caption terms before the string
    reaches the diffusion model.

    Background
    ----------
    Image generation models learn from large corpora of tagged images.  Images
    tagged "comic book" or "graphic novel" in those datasets almost always
    include speech bubbles, caption boxes, panel gutters, and lettering.  The
    model therefore treats those terms as implicit instructions to render text
    elements — even when the positive prompt also says "no speech bubbles".

    Mentioning "speech bubble" in a positive prompt (even as "no speech bubble")
    still activates the concept — diffusion models do not parse negation the way
    language models do.  The fix is to never use those trigger words in the image
    prompt at all: no comic-format nouns, no bubble/caption/dialog terms.

    This function is called on every fragment that enters compose_panel_prompt
    — art_style_clean, panel_clause, page_clause, story_clause, grammar_clause
    — so no trigger word can sneak through via any code path.
    """
    if not text:
        return text
    for pattern, replacement in _COMIC_TRIGGER_REPLACEMENTS:
        text = pattern.sub(replacement, text)
    # Clean up double-spaces and orphaned punctuation left by empty replacements.
    text = _comic_re.sub(r'[ \t]{2,}', ' ', text)
    text = _comic_re.sub(r'\s*,\s*,', ',', text)
    text = _comic_re.sub(r'^[\s,;.]+|[\s,;.]+$', '', text)
    return text.strip()


def _strip_meta_annotations(text: str) -> str:
    """Remove 'Label: value (parenthetical)' patterns from injection clauses.

    Diffusion models treat 'word: value (note)' as caption/annotation text
    and render it inside speech bubbles or as image overlays.  This function
    converts label-prefixed fragments to pure descriptive phrases.

    Examples converted:
      'Emotional register: subdued (setup, intensity 0.35)' → 'subdued mood'
      'Palette here: warm amber'  → 'warm amber color palette'
      'Lighting: soft diffused'   → 'soft diffused lighting'
      'Stage: climax'             → '' (pure metadata, not visual)
    """
    if not text:
        return text
    import re as _re

    # Remove parentheticals containing numbers (intensity scores, stage names,
    # metadata) — these are never useful to a diffusion model.
    text = _re.sub(r'\([^)]*\d[^)]*\)', '', text)

    # Strip known label prefixes that look like annotations.
    _LABEL_PREFIXES = [
        r'Emotional\s+register\s*:\s*',
        r'Palette\s+here\s*:\s*',
        r'Page\s+mood\s*:\s*',
        r'Stage\s*:\s*',
        r'Intensity\s*:\s*',
        r'Mood\s+shift\s*:\s*',
        r'Visual\s+grammar\s*:\s*',
        r'Arc\s+state\s*:\s*',
    ]
    for prefix in _LABEL_PREFIXES:
        text = _re.sub(prefix, '', text, flags=_re.IGNORECASE)

    # Clean up residual punctuation.
    text = _re.sub(r'\s{2,}', ' ', text)
    text = _re.sub(r'^[\s,;.]+|[\s,;.]+$', '', text)
    return text.strip()

# ---------------------------------------------------------------------------
# FEW-SHOT PROMPT ENRICHMENT
# ---------------------------------------------------------------------------
# The reference examples below are distilled from high-quality AI image
# prompts that consistently produce striking, well-composed results. They are
# NOT injected verbatim — that would eat the token budget and dilute the
# panel's actual content. Instead, _enrich_prompt_with_few_shot_patterns()
# analyses the assembled prompt, identifies which structural layers are absent,
# and appends concise targeted phrases to fill the gaps.
#
# The six structural layers every strong prompt should have:
#   1. Subject + posture + action (first sentence — already in description)
#   2. Material / texture specificity ("liquid mercury", "individual fur strands")
#   3. Explicit lighting (direction, quality, contrast ratio, colour temperature)
#   4. Named colour palette (concrete words like "electric blue", "warm amber")
#   5. Camera / lens language ("macro lens", "shallow depth of field", "dutch angle")
