# Reuse the emotion synonym map defined for colour grading so the same free-text
# moods resolve consistently to a lighting design.
def _dramatic_lighting_for(emotion_text: str) -> str:
    """Resolve a free-text emotion/mood to a dramatic lighting prescription, or
    '' if nothing matches (caller then uses composition-based defaults)."""
    text = (emotion_text or '').lower()
    if not text:
        return ''
    words = set(re.findall(r"[a-z]+", text))
    # Canonical emotion words win over weaker synonyms (same policy as grading).
    for w in sorted((w for w in words if w in _DRAMATIC_LIGHTING), key=len, reverse=True):
        return _DRAMATIC_LIGHTING[w]
    syn = globals().get('_EMOTION_SYNONYMS', {})
    for w in sorted((w for w in words if w in syn), key=len, reverse=True):
        key = syn[w]
        if key in _DRAMATIC_LIGHTING:
            return _DRAMATIC_LIGHTING[key]
    return ''


# ===========================================================================
# COMPOSITIONAL DESIGN
# ---------------------------------------------------------------------------
# How elements are ARRANGED in the frame is a distinct artistic tool from
# lighting, colour, and shot size. Illustrators stage a panel to guide the
# reader's eye and reinforce meaning: depth layering (foreground/midground/
# background), leading lines, framing devices, figure scale, symmetry vs.
# dynamic imbalance, and negative space used expressively. The same subject at
# the same shot size reads completely differently when staged for compression
# (anxiety) vs. vast deep space (awe) vs. a tiny figure lost in emptiness
# (isolation). This maps the panel's emotion to an intentional compositional
# staging, injected at the generation level alongside lighting and colour.
# ===========================================================================
