# ---------------------------------------------------------------------------
# Sensual atmosphere visual vocabulary
# ---------------------------------------------------------------------------
# Pattern-matched, zero LLM cost. Detects intimate/sensual scene signals and
# returns cinematic image-direction language: lighting quality, camera framing,
# and atmosphere — the same vocabulary used in prestige film and literary
# illustration to evoke intimacy without explicit depiction.
# Fires alongside the existing emotion physicality and spiritual atmosphere
# clauses. Calibrated to three levels so the intensity matches the story beat.
# ---------------------------------------------------------------------------

_SENSUAL_PRESCREEN_RE = _emo_re.compile(
    r'\b(intimate|intimacy|sensual|desire|desir|seduc|allur|erotic|'
    r'undress|disrob|bare skin|bare shoulder|bare back|bare chest|'
    r'naked|nude|nudity|exposed|skin against|bodies close|'
    r'kiss(?:es|ed|ing)|caress|embrace|entangle|entwine|'
    r'heat of|charged moment|electric touch|whisper close|breath (?:warm|hot)|'
    r'lover|lovers|bedroom|bed together|night together|after (?:they|she|he)|'
    r'passion|passionate|lustful|hungry touch|tender touch|'
    r'romance|romantic moment|make love|making love|'
    r'morning after|tangled (?:in|together)|sheets|pillow|'
    r'pulls? (?:her|him|them) close|pulls? (?:her|him|them) in)\b',
    _emo_re.IGNORECASE,
)

# (regex, level, camera_framing, lighting_note, atmosphere_note)
# level: 'charged' | 'intimate' | 'sensual'
_SENSUAL_ATMOSPHERE_PATTERNS = [

    # ── Most intense: undress / bare skin / explicit physical union ─────────
    (
        _emo_re.compile(
            r'\b(undress|disrob|bare skin|bare chest|bare back|bare shoulder|'
            r'naked|nude|nudity|exposed (?:skin|body)|'
            r'make love|making love|after (?:they|she|he)|morning after|'
            r'tangled (?:in|together)|sheets|skin against skin|'
            r'bodies close|bodies entwined|bodies tangled)\b',
            _emo_re.IGNORECASE,
        ),
        'sensual',
        # Camera: suggest rather than show — strategic framing keeps the image
        # artful. Close crops on face/hands/detail; sheets and shadow do the work.
        "close crop on faces or hands, bodies implied by shape and shadow rather than fully depicted; selective focus on a single intimate detail — a shoulder, intertwined fingers, the curve of a back; camera held at a reverential distance or angled to frame suggestion rather than exposition",
        # Lighting: warm, low, intimate
        "warm low candlelight or a single bedside lamp casting long soft shadows; rich chiaroscuro with deep warm darks; subtle rim light tracing edges of skin or fabric; the scene bathed in amber intimacy",
        # Atmosphere
        "the air close and warm, the world narrowed to two people and the space between them; quiet, charged, private",
    ),

    # ── Moderate: kisses / caresses / close physical intimacy ───────────────
    (
        _emo_re.compile(
            r'\b(kiss(?:es|ed|ing)|caress(?:es|ed|ing)|embrace(?:s|d|ing)|'
            r'pulls? (?:her|him|them) (?:close|in|toward)|'
            r'nuzzl|lips (?:meet|touch|press|brush)|breath (?:warm|hot) against|'
            r'fingers trail(?:ing)? (?:along|over|across)|'
            r'bodies (?:press|lean|close)|lean(?:s|ed|ing) in|'
            r'tender touch|hungry touch|warm skin)\b',
            _emo_re.IGNORECASE,
        ),
        'intimate',
        # Camera: close two-shot, emphasis on connection
        "tight two-shot or close-up on the point of contact — lips, hands, faces; the frame closing around the figures to create a private world; soft shallow depth of field blurring everything beyond the connection",
        # Lighting: warm directional, intimate
        "soft warm directional light from one side, the opposite cheek falling into gentle shadow; a flattering quality that evokes a lit candle or a bedside lamp; no harsh edges, all warmth and gradients",
        # Atmosphere
        "the moment contracted to just the two of them; sound implied to fall away; the image holding its breath",
    ),

    # ── Light: charged looks / tension / desire building ─────────────────────
    (
        _emo_re.compile(
            r'\b(desire|desir|attract|seduc|allur|sensual|'
            r'electric touch|charged moment|charged look|'
            r'can\'t look away|magnetis|irresistible|'
            r'longing look|eyes meet|gaze (?:meets|holds|locks)|'
            r'lover|romantic moment|passion|passionate|'
            r'intimate moment|closeness|electricity between)\b',
            _emo_re.IGNORECASE,
        ),
        'charged',
        # Camera: space between them alive with tension
        "the negative space between two figures made electric — eye-line tension crossing the frame; faces held at near-touching distance; or an extreme close-up on eyes and the emotional weight in the gaze",
        # Lighting: warm but not yet intimate — the anticipatory moment
        "warm ambient light with a slight directional quality; soft diffuse fill, the scene lit as if at golden hour or by a single warm source off-screen; no overhead clinical light",
        # Atmosphere
        "the charged, breathless quality of a moment on the edge of something — held rather than released",
    ),
]


def _detect_sensual_level(description: str, mood: str = '', setting: str = '') -> str:
    """Classify the sensual intensity of a panel from its description/mood/setting.

    Returns one of 'sensual' | 'intimate' | 'charged' | '' (not intimate).
    Uses the most-intense matching pattern first so the level always reflects
    the strongest signal in the text — a panel with both a kiss and bare skin
    returns 'sensual', not 'intimate'.

    Zero LLM cost — pure regex.
    """
    blob = f"{description} {mood} {setting}"
    if not _SENSUAL_PRESCREEN_RE.search(blob):
        return ''
    for pattern, level, _cam, _light, _atm in _SENSUAL_ATMOSPHERE_PATTERNS:
        if pattern.search(blob):
            return level
    return ''


def _build_sensual_atmosphere_clause(
    description: str,
    mood: str = '',
    setting: str = '',
    exposure: str = '',
) -> str:
    """Build a cinematic atmosphere clause for intimate/sensual panels.

    Returns a dict with 'camera', 'lighting', 'atmosphere' keys containing
    image-direction language drawn from the matched intensity level, or an
    empty dict when the panel is not intimate. The caller decides which fields
    to inject and where in the structured prompt.

    ``exposure`` is the scene's exposure tier from ``classify_setting_exposure``
    (public / semi_public / private / intimate / unknown). Sensual atmosphere
    is only generated for private/intimate settings — a charged look across a
    crowded bar stays 'charged' but doesn't get the full intimate lighting
    prescription because it is a public setting. Explicit undress language in a
    public setting is already suppressed by the continuity tracker; this guard
    prevents the atmosphere clause from amplifying it.
    """
    blob = f"{description} {mood} {setting}"
    if not _SENSUAL_PRESCREEN_RE.search(blob):
        return {}

    # Public/semi-public settings: allow 'charged' level only (a look, a moment)
    # but suppress 'intimate'/'sensual' atmosphere amplification — the plausibility
    # rule applied to the visual atmosphere, not just the clothing state.
    _public_tiers = {'public', 'semi_public'}
    _cap_level = 'charged' if (exposure or '').lower() in _public_tiers else None

    for pattern, level, cam, light, atm in _SENSUAL_ATMOSPHERE_PATTERNS:
        if pattern.search(blob):
            # Apply public-setting cap
            if _cap_level and level in ('intimate', 'sensual'):
                level = _cap_level
                # Find the charged-level entry and use its framing instead
                for _p2, _l2, _c2, _li2, _a2 in _SENSUAL_ATMOSPHERE_PATTERNS:
                    if _l2 == 'charged':
                        cam, light, atm = _c2, _li2, _a2
                        break
            return {'level': level, 'camera': cam, 'lighting': light, 'atmosphere': atm}
    return {}
