# Signals that determine which aura colour applies
# Each: (emotion_regex, aura_key)
_AURA_SIGNAL_MAP = [
    (_emo_re.compile(r'\b(love|compassion|tender|ador|devot|cherish|beloved|warmth toward|heart open)\b', _emo_re.IGNORECASE), 'love'),
    (_emo_re.compile(r'\b(rage|fury|furious|wrath|enraged|seething|livid|anger|incensed)\b', _emo_re.IGNORECASE), 'anger'),
    (_emo_re.compile(r'\b(grief|mourn|bereav|heartbreak|devastating loss|lost forever|can never return)\b', _emo_re.IGNORECASE), 'grief'),
    (_emo_re.compile(r'\b(sad|lonely|isolated|alone|desolat|despair|hopeless|hollow|numb|abandon)\b', _emo_re.IGNORECASE), 'sadness'),
    (_emo_re.compile(r'\b(cosmic|divine purpose|universal|connected to everything|infinite|transcendent|universal truth|chosen|awakening|enlighten)\b', _emo_re.IGNORECASE), 'cosmic'),
    (_emo_re.compile(r'\b(joy|triumph|jubil|elation|victorious|radiant|celebrate|overcome with joy|glory)\b', _emo_re.IGNORECASE), 'joy'),
    (_emo_re.compile(r'\b(transcend|enlighten|one with|truth revealed|pure light|beyond self|nirvana|liberation|ascend)\b', _emo_re.IGNORECASE), 'transcendence'),
    (_emo_re.compile(r'\b(terrified|terror|dread|panic|primal fear|survival|cornered|hunted|no escape)\b', _emo_re.IGNORECASE), 'fear'),
    (_emo_re.compile(r'\b(power surges|power within|inner strength|will|resolve|force of will|limitless|becoming)\b', _emo_re.IGNORECASE), 'power'),
    (_emo_re.compile(r'\b(heal|healing|restore|restoration|mend|made whole|recover|renewal|rebirth)\b', _emo_re.IGNORECASE), 'healing'),
]

# Levels of spiritual intensity — used to gate aura application
# 'none'   = no aura regardless of emotion
# 'subtle' = faint aura, mostly colour wash, no visible glow ring
# 'strong' = full aura with visible luminous corona
# 'peak'   = overwhelming, fills the scene, almost abstract
_SPIRITUAL_INTENSITY_LEVELS = {'none', 'subtle', 'strong', 'peak'}


def _build_spiritual_aura_clause(
    description: str,
    mood: str,
    spiritual_intensity: str,
    manifestation_style: str = '',
) -> str:
    """Build a spiritual aura + scene colour composition clause when a panel
    is flagged as a spiritually heightened moment.

    Only fires when `spiritual_intensity` is 'subtle', 'strong', or 'peak'.
    Returns empty string for 'none' or unrecognised values.

    The aura is selected by matching the panel's emotion signals against
    the _AURA_SIGNAL_MAP, then modulated by intensity level.
    """
    intensity = (spiritual_intensity or 'none').lower().strip()
    if intensity not in ('subtle', 'strong', 'peak'):
        return ''

    blob = f"{description} {mood} {manifestation_style}"

    # Find the matching aura colour
    aura_key = None
    for pattern, key in _AURA_SIGNAL_MAP:
        if pattern.search(blob):
            aura_key = key
            break

    if not aura_key:
        # Default for spiritually-marked panels without a specific emotion signal
        aura_key = 'transcendence'

    aura_text = _SPIRITUAL_AURA_COLOURS[aura_key]

    # Modulate by intensity
    if intensity == 'subtle':
        aura_text = (
            "A subtle, understated spiritual aura — barely visible, a whisper of "
            "colour the reader senses rather than sees directly. " + aura_text
        )
    elif intensity == 'peak':
        aura_text += (
            " At peak intensity the aura is overwhelming, filling the entire frame; "
            "the scene's normal colours are secondary to the spiritual light; "
            "this is a moment of transformation, not just emotion."
        )

    return aura_text


