# Pre-screen for any technology content
_TECH_VFX_PRESCREEN_RE = _emo_re.compile(
    r'\b(robot|android|mech|cyborg|laser|plasma|hologram|neon|electric|'
    r'lightsaber|energy\s+(?:blade|shield|weapon|field)|thruster|rocket|'
    r'circuit|digital|interface|HUD|augmented|exoskeleton|drone|'
    r'powered\s+(?:armour|suit)|arc\s+discharge|tesla|electrokinesis|'
    r'sparks?\s+(?:fly|shower|spray)|force\s+field|scanner|'
    r'cyberpunk|neon\s+(?:light|sign|glow))\b',
    _emo_re.IGNORECASE,
)


def _build_technology_vfx_clause(description: str, setting: str = '') -> str:
    """Detect technology content and return CGI-specific prompt vocabulary.

    Returns empty string when no technology VFX signals are found.
    Zero LLM cost.
    """
    blob = f"{description} {setting}"
    if not _TECH_VFX_PRESCREEN_RE.search(blob):
        return ''
    hits = []
    seen: set = set()
    for pattern, tokens in _TECHNOLOGY_VFX_PATTERNS:
        if pattern.search(blob):
            key = tokens[:40]
            if key not in seen:
                hits.append(tokens)
                seen.add(key)
        if len(hits) >= 2:
            break
    if not hits:
        return ''
    return 'Rendered with CGI-quality illustrated precision: ' + '; '.join(hits) + '.'


