def _build_technique_visual_clause(panel_script: Dict) -> Dict[str, str]:
    """Translate the beat's master technique label into concrete visual directives.

    Reads panel_script['technique'] (e.g. 'Gaiman:planted-mystery', written by
    _storyboard_act_beats), resolves it against _TECHNIQUE_VISUAL_MAP, and
    returns a dict with keys camera/lighting/composition/atmosphere/detail that
    can be merged into the relevant sections of compose_panel_prompt().

    When no technique is explicitly set, falls back to inferring the most
    appropriate master technique from the panel's emotional arc and mood so
    every panel always carries a concrete visual-grammar directive — never
    an empty dict that leaves the image model without storytelling guidance.
    """
    raw = str(panel_script.get('technique', '') or '').strip()

    if raw:
        # Normalise: lower-case, collapse whitespace, strip surrounding brackets.
        key = raw.lower().strip('[]() ').replace(' ', '-')

        # Direct lookup first.
        entry = _TECHNIQUE_VISUAL_MAP.get(key)
        if entry:
            return dict(entry)

        # Alias lookup.
        canonical = _TECHNIQUE_ALIASES.get(key)
        if canonical:
            entry = _TECHNIQUE_VISUAL_MAP.get(canonical)
            if entry:
                return dict(entry)

        # Partial prefix match — e.g. "Gaiman:planted-mystery-variant" → gaiman.
        for alias_key, canonical_key in _TECHNIQUE_ALIASES.items():
            if key.startswith(alias_key):
                entry = _TECHNIQUE_VISUAL_MAP.get(canonical_key)
                if entry:
                    return dict(entry)
        for map_key, map_entry in _TECHNIQUE_VISUAL_MAP.items():
            if key.startswith(map_key.split(':')[0]):
                return dict(map_entry)

    # ── No explicit technique: infer from emotional arc and mood ─────────────
    # Every panel should carry a master-technique visual grammar so the image
    # model has concrete lighting / camera / atmosphere direction beyond the
    # generic style clause. We pick the best match from the signal available.
    arc_emotion = str(panel_script.get('_arc_emotion', '') or '').lower()
    arc_stage   = str(panel_script.get('_arc_stage', '') or '').lower()
    mood        = str(panel_script.get('mood', '') or '').lower()
    importance  = str(panel_script.get('importance', '') or '').lower()
    description = str(panel_script.get('description', '') or '').lower()
    intensity   = float(panel_script.get('_arc_intensity', 0.5) or 0.5)
    panel_type  = str(panel_script.get('panel_type', 'character')).lower()

    blob = f"{arc_emotion} {mood} {description}"

    # Cosmic / wonder panels → Asimov scale
    if panel_type == 'cosmic' or any(kw in blob for kw in (
            'universe', 'cosmos', 'galaxy', 'void', 'vast', 'infinite', 'star field')):
        return dict(_TECHNIQUE_VISUAL_MAP['asimov:wonder-of-scale'])

    # Dread / horror / ominous → King cascade-of-dread
    if any(kw in blob for kw in (
            'dread', 'horror', 'terror', 'ominous', 'threatening', 'fear', 'danger',
            'sinister', 'shadow')):
        return dict(_TECHNIQUE_VISUAL_MAP['king:cascade-of-dread'])

    # Intimate / emotional cost / love → Yarros earned emotional truth
    if any(kw in blob for kw in (
            'love', 'tender', 'grief', 'loss', 'intimate', 'comfort', 'vulnerable',
            'confession', 'sorrow', 'tears', 'forgiveness')) or importance == 'climactic':
        return dict(_TECHNIQUE_VISUAL_MAP['yarros:earned-emotional-truth'])

    # Magical / liminal / threshold → de Lint liminal-threshold
    if any(kw in blob for kw in (
            'magic', 'magical', 'threshold', 'liminal', 'mystical', 'otherworldly',
            'portal')):
        return dict(_TECHNIQUE_VISUAL_MAP['de-lint:liminal-threshold'])

    # Beautiful and terrible / violence-with-beauty → Barker
    if any(kw in blob for kw in (
            'beautiful and terrible', 'breathtaking', 'radiant', 'overwhelming',
            'splendour', 'magnificent')):
        return dict(_TECHNIQUE_VISUAL_MAP['barker:beautiful-and-terrible'])

    # Payoff / climax / resolution → Spielberg earned payoff
    if arc_stage in ('peak', 'climax', 'resolution', 'payoff') or importance in (
            'splash', 'hero', 'climactic'):
        return dict(_TECHNIQUE_VISUAL_MAP['spielberg:earned-payoff'])

    # Mysterious / planted detail → Gaiman planted mystery
    if any(kw in blob for kw in (
            'mystery', 'mysterious', 'strange', 'unexplained', 'unknown',
            'secret', 'hidden', 'curious')):
        return dict(_TECHNIQUE_VISUAL_MAP['gaiman:planted-mystery'])

    # High intensity action / conflict → King dread (tension serves action too)
    if intensity >= 0.7:
        return dict(_TECHNIQUE_VISUAL_MAP['king:cascade-of-dread'])

    # Quiet / environmental / world-building → Clarke secondary world texture
    if any(kw in blob for kw in (
            'quiet', 'peaceful', 'solitude', 'environment', 'landscape',
            'world', 'place', 'still', 'atmosphere')):
        return dict(_TECHNIQUE_VISUAL_MAP['clarke:secondary-world-texture'])

    # Subtext / power dynamics / conversation scenes → Leonard
    if any(kw in blob for kw in (
            'negotiation', 'confrontation', 'interrogation', 'unspoken',
            'power', 'tension between', 'conversation', 'subtext',
            'what is not said', 'political')):
        return dict(_TECHNIQUE_VISUAL_MAP['leonard:subtext-conversation'])

    # Aftermath / consequence / irreversible loss → McCarthy
    if any(kw in blob for kw in (
            'aftermath', 'consequence', 'irreversible', 'ruin', 'devastation',
            'cannot be undone', 'weight', 'silence after', 'emptiness')):
        return dict(_TECHNIQUE_VISUAL_MAP['mccarthy:weight-of-consequence'])

    # Cultural ritual / world texture / anthropological → Le Guin
    if any(kw in blob for kw in (
            'ritual', 'ceremony', 'cultural', 'society', 'custom', 'tradition',
            'world-building', 'anthropolog', 'civilisation', 'unfamiliar practice')):
        return dict(_TECHNIQUE_VISUAL_MAP['le-guin:anthropological-eye'])

    # Atmospheric / setting-driven / noir → Chandler
    if any(kw in blob for kw in (
            'noir', 'rain', 'city', 'corrupt', 'atmospheric', 'moral ambiguity',
            'street', 'crime scene', 'setting reveals', 'environment as character')):
        return dict(_TECHNIQUE_VISUAL_MAP['chandler:atmospheric-reveal'])

    # Suppressed trauma / wound / cannot be spoken → Morrison
    if any(kw in blob for kw in (
            'trauma', 'suppressed', 'averted', 'cannot look', 'wound',
            'cannot name', 'unspoken pain', 'flinch', 'historical pain')):
        return dict(_TECHNIQUE_VISUAL_MAP['morrison:wound-unnamed'])

    # The held moment before an event → McCloud
    if any(kw in blob for kw in (
            'before the moment', 'threshold', 'about to', 'held breath',
            'gutter', 'between panels', 'reader imagines', 'anticipation')):
        return dict(_TECHNIQUE_VISUAL_MAP['mccloud:eloquent-gutter'])

    # Silent / wordless / pure image storytelling → Eisner
    if any(kw in blob for kw in (
            'silent', 'wordless', 'no dialogue', 'image alone',
            'body language only', 'purely visual', 'without words')):
        return dict(_TECHNIQUE_VISUAL_MAP['eisner:silent-page'])

    # Slow burn romance / unspoken desire / charged proximity → Austen
    if any(kw in blob for kw in (
            'romance', 'desire', 'longing', 'slow burn', 'almost', 'almost said',
            'proximity', 'glance', 'unspoken attraction', 'charged', 'yearning')):
        return dict(_TECHNIQUE_VISUAL_MAP['austen:slow-burn'])

    # Clue / mystery / revelation setup → Christie
    if any(kw in blob for kw in (
            'clue', 'mystery', 'hidden in plain sight', 'detective', 'investigation',
            'red herring', 'who done it', 'evidence', 'suspect', 'reveal')):
        return dict(_TECHNIQUE_VISUAL_MAP['christie:fair-witness'])

    # High-contrast / shadow-dominated / moral darkness → Miller
    if any(kw in blob for kw in (
            'silhouette', 'shadow dominant', 'darkness', 'morally dark',
            'stark', 'high contrast', 'monochromatic', 'graphic noir', 'black and white')):
        return dict(_TECHNIQUE_VISUAL_MAP['miller:economy-of-darkness'])

    # Quiet / ordinary moment / slice of life / breathing room → Miyazaki
    if any(kw in blob for kw in (
            'ordinary moment', 'slice of life', 'quiet', 'breathing',
            'everyday', 'mundane beauty', 'unhurried', 'world at rest')):
        return dict(_TECHNIQUE_VISUAL_MAP['miyazaki:unhurried-world'])

    # Structural / thematic echo / formal experimentation → Moore
    if any(kw in blob for kw in (
            'structural echo', 'formal', 'mirror', 'parallel', 'thematic',
            'callbacks', 'rhymes with', 'architectural metaphor')):
        return dict(_TECHNIQUE_VISUAL_MAP['moore:formal-mirror'])

    # Default: Yarros for character panels, Clarke for scenic/environmental
    if panel_type in ('scenic', 'establishing'):
        return dict(_TECHNIQUE_VISUAL_MAP['clarke:secondary-world-texture'])
    return dict(_TECHNIQUE_VISUAL_MAP['yarros:earned-emotional-truth'])


def _estimate_story_driven_act_beat_counts(
    act_pages: int,
    act_summary: str = '',
    story_idea_str: str = '',
    characters: List = None,
) -> Tuple[int, int]:
    """Return (minimum_beats, suggested_beats) for one act, without a cap.

    The old storyboard prompt used ``min(18, act_pages // 2)`` and then asked
    the LLM for exactly that many beats. For a ~28-page act that repeatedly
    produced 14 beats, regardless of whether the act contained backstory,
    side arcs, parallel plots, or dense world-building.

    This estimator is deliberately a FLOOR + BASELINE, not a maximum. The LLM
    is told to exceed the baseline whenever the story needs more scenes. The
    allocator downstream already grows the page span so extra beats are not
    collapsed onto the same pages.
    """
    try:
        act_pages = max(1, int(act_pages))
    except Exception:
        act_pages = 1

    text = (act_summary or story_idea_str or '')
    # Concrete story markers usually imply separate drawable moments.
    marker_hits = len(re.findall(
        r"(?i)\b(then|meanwhile|flashback|backstory|origin|memory|side\s*arc|"
        r"subplot|reveals?|twists?|betrays?|discovers?|confronts?|battle|"
        r"ritual|ceremony|world[- ]building|mystery|clue|payoff|afterward|"
        r"years? earlier|before|secret|threshold|setpiece|chase|escape)\b",
        text,
    ))
    bullet_hits = len(re.findall(r"(?m)^\s*(?:[-*•]|\d+[.)])\s+", text))
    sentence_hits = len([s for s in re.split(r"[.!?]+", act_summary or '') if len(s.strip()) > 35])
    cast_bonus = min(8, max(0, len(characters or []) // 2))

    # Graphic-novel rhythm: roughly one beat every 1-2 pages is normal for a
    # richly staged act. Dense concepts can ask for more; pages can grow later.
    page_floor = max(6, int(round(act_pages * 0.55)))
    page_baseline = max(page_floor, int(round(act_pages * 0.80)))
    complexity_baseline = 6 + marker_hits + bullet_hits + sentence_hits + cast_bonus

    minimum = max(6, page_floor, min(complexity_baseline, page_baseline))
    suggested = max(minimum, page_baseline, complexity_baseline)
    return minimum, suggested


def _dynamic_backstory_limit(target_pages: int, characters: List = None) -> int:
    """Practical upper bound for the separate backstory enrichment pass."""
    major_with_past = [
        c for c in (characters or [])
        if (getattr(c, 'backstory', '') or getattr(c, 'arc', ''))
        and getattr(c, 'role', '').lower() not in ('background', 'extra', 'minor')
    ]
    if not major_with_past:
        return 0
    return max(3, min(14, len(major_with_past) * 2, int(target_pages) // 25 + 3))


def _dynamic_showcase_limit(target_pages: int, characters: List = None) -> int:
    """Practical upper bound for character showcase / side-story beats."""
    major = [
        c for c in (characters or [])
        if getattr(c, 'role', '').lower() not in ('background', 'extra', 'minor')
    ]
    if not major:
        return 0
    return max(2, min(14, len(major) * 2, int(target_pages) // 28 + 3))


def _dynamic_worldbuilding_limit(target_pages: int, story_idea=None) -> int:
    """Practical upper bound for world/culture/environment spread beats."""
    genre = (getattr(story_idea, 'genre', '') or '').lower()
    premise = (getattr(story_idea, 'premise', '') or '').lower()
    world_heavy = any(k in f"{genre} {premise}" for k in (
        'fantasy', 'science fiction', 'sci-fi', 'space opera', 'cyberpunk',
        'steampunk', 'supernatural', 'cosmic', 'epic', 'alternate history',
        'dystopia', 'post-apocalyptic', 'myth', 'spirit', 'alien', 'future',
    ))
    base = int(target_pages) // (35 if world_heavy else 55)
    return max(1, min(10, base + (2 if world_heavy else 1)))


def _dynamic_emotional_journey_limit(target_pages: int) -> int:
    """Practical upper bound for emotional-journey enrichment beats."""
    try:
        tp = int(target_pages)
    except Exception:
        tp = 24
    if tp < 20:
        return 0
    # Roughly one journey beat per ~18 pages, capped, so long books can earn a
    # richer emotional scaffold without runaway growth.
    return max(3, min(20, tp // 18 + 2))


def generate_emotional_journey_beats(
    story_idea, characters: List, story_idea_str: str,
    required_beats: List[Dict], target_pages: int,
    dynamics_profile: Dict, get_llm_response, parse_json,
    llm_model: str = None, use_grok: bool = False,
    max_beats: int = None,
) -> List[Dict]:
    """Author enrichment beats that specifically STRENGTHEN the emotional journey.

    The other enrichment passes add backstory, showcases, and world-building from
    the cast and setting. This one is different: it reads the DESIRED shape of the
    emotional journey (the dynamics profile — roller coaster, smooth slide,
    descending spiral, rising tide, escalating waves) and the current act/beat
    spine, then proposes the beats the journey is MISSING to land:

      • emotional_setup — a quiet character/backstory beat placed BEFORE a peak so
        the reader cares before the blow (empathy is earned, not assumed);
      • contrast_relief — a valley of levity or calm before a high point, so the
        peak has something to rise from (essential for a roller coaster);
      • stakes — a beat that raises what's at risk just before the climax;
      • side_story — a B-plot beat that mirrors or counterpoints the main
        emotional thread, deepening theme and giving the A-plot room to breathe;
      • payoff — a reflective beat that lets an earned emotion land, or earns the
        ending;
      • interlude — when the journey needs a whole gear change, a short block that
        forms a NEW ACT (a breather act before the finale, an origin act, a
        parallel-thread act).

    Beats attach to existing acts by anchor (growing those acts), except
    ``interlude`` beats, which are marked to form a new act. Returns a list of
    beat dicts to merge with required_beats; best-effort, returns [] on failure.
    """
    if not required_beats or target_pages < 20:
        return []
    if max_beats is None:
        max_beats = _dynamic_emotional_journey_limit(target_pages)
    if max_beats <= 0:
        return []

    dynamics_profile = dynamics_profile or {}
    dyn_label = dynamics_profile.get('label', 'gentle wave')
    dyn_directive = dynamics_profile.get('directive', '')

    # Group the spine by act so the model can add to acts — or slot a new one.
    acts: Dict[str, List[Dict]] = {}
    for b in required_beats:
        acts.setdefault(str(b.get('act', '1')), []).append(b)
    act_block_lines = []
    for ak in sorted(acts, key=lambda a: (_parse_pr(acts[a][0].get('page_range', ''))[0] or 0)):
        bs = acts[ak]
        s = _parse_pr(bs[0].get('page_range', ''))[0] or 0
        e = _parse_pr(bs[-1].get('page_range', ''))[1] or 0
        act_block_lines.append(f"  ACT {ak} (pp.{s}-{e}, {len(bs)} beats):")
        for b in bs[:6]:
            act_block_lines.append(
                f"    {b.get('beat_id','?')} (pp.{b.get('page_range','?')}): "
                f"{str(b.get('description',''))[:90]}")
        if len(bs) > 6:
            act_block_lines.append(f"    …(+{len(bs)-6} more beats)")
    act_block = "\n".join(act_block_lines)

    # Empathy hooks — who has past/arc material a setup beat could draw on.
    char_hooks = "\n".join(
        f"  {c.name}: {(getattr(c,'backstory','') or getattr(c,'arc','') or '')[:110]}"
        for c in (characters or [])
        if getattr(c, 'role', '').lower() not in ('background', 'extra', 'minor')
    )[:1200]

    climax_page = int(target_pages * 0.8)

    prompt = (
        f"{_SINGLE_IMAGE_RULE}\n\n"
        "You are a graphic-novel story editor STRENGTHENING the reader's "
        "emotional journey by adding the beats it is missing. You do not touch "
        "the existing beats; you propose NEW ones that make the intended journey "
        "land harder.\n\n"
        f"GENRE: {getattr(story_idea,'genre','')} | MOOD: {getattr(story_idea,'mood','')}\n"
        f"PREMISE: {str(getattr(story_idea,'premise','') or story_idea_str)[:220]}\n\n"
        f"INTENDED EMOTIONAL JOURNEY — a {dyn_label.upper()}:\n{dyn_directive}\n\n"
        f"The emotional climax lands near page {climax_page}.\n\n"
        f"CURRENT ACT / BEAT STRUCTURE:\n{act_block}\n\n"
        + (f"CHARACTER MATERIAL FOR EMPATHY SETUPS:\n{char_hooks}\n\n" if char_hooks else "")
        + "Propose beats that serve the journey above. Use these types:\n"
        "  - emotional_setup: a quiet character or backstory beat placed BEFORE a "
        "peak so the reader CARES before the blow (earn the emotion).\n"
        "  - contrast_relief: a valley of levity, tenderness, or calm before a "
        "high point, so the peak rises out of something (vital for a roller "
        "coaster; gentler swells for a smooth slide).\n"
        "  - reaction_turn: a small, intimate MOMENT where a feeling TURNS on a "
        "character's face — a kind or harsh word landing, an opportunity sparking "
        "excitement, a small mishap souring the mood, a quiet moment of wonder at "
        "something beautiful. These are close-up soul-moments that let the reader "
        "connect eye-to-eye with a character; place them where the journey needs "
        "the reader pulled INTO a character rather than moved through plot.\n"
        "  - stakes: a beat just before the climax that raises what is at risk.\n"
        "  - side_story: a B-plot beat that mirrors or counterpoints the main "
        "emotional thread and gives the A-plot room to breathe.\n"
        "  - payoff: a reflective beat that lets an earned feeling land, or earns "
        "the ending.\n"
        "  - interlude: ONLY when the journey needs a whole gear change — a short "
        "run that forms a NEW ACT (a breather before the finale, an origin act, a "
        "parallel-thread act). Mark these new_act=true and give them a shared "
        "'act' label like 'interlude'.\n\n"
        f"Add up to {max_beats} beats — fewer if more would pad. Each must EARN "
        "its pages by deepening emotion, empathy, contrast, or stakes; never add "
        "filler. Return a JSON array; each item:\n"
        "{\n"
        '  "beat_id": "journey_01",\n'
        '  "description": "2-3 sentences of what we SEE — a drawable scene, not exposition",\n'
        '  "beat_type": "emotional_setup|contrast_relief|reaction_turn|stakes|side_story|payoff|interlude",\n'
        '  "emotional_purpose": "how this strengthens the intended journey (one sentence)",\n'
        '  "target_emotion": "the precise feeling (e.g. saudade, dread, tender relief)",\n'
        '  "anchor_beat_id": "the existing beat_id this should sit near",\n'
        '  "page_range": "34-35",\n'
        '  "act": "2",\n'
        '  "new_act": false,\n'
        '  "temporal_marker": "" ,\n'
        '  "must_include": true\n'
        "}\n"
        "JSON array only. Return [] if the journey is already well served."
    )

    try:
        kwargs = {"temperature": 0.7,
                  "max_completion_tokens": max(3000, 600 * max_beats)}
        if llm_model:
            kwargs["openai_model"] = llm_model
        kwargs["use_grok"] = use_grok
        parsed = parse_json(get_llm_response(prompt, **kwargs)) or []
    except Exception as e:
        logger.warning(f"  [JourneyBeats] Generation failed ({e}).")
        return []
    if not isinstance(parsed, list):
        return []

    valid_types = {'emotional_setup', 'contrast_relief', 'reaction_turn', 'stakes',
                   'side_story', 'payoff', 'interlude'}
    beats = []
    for b in parsed:
        if not isinstance(b, dict) or not b.get('description'):
            continue
        bt = str(b.get('beat_type', '') or '').strip().lower()
        if bt not in valid_types:
            bt = 'emotional_setup'
        b['beat_type'] = bt
        # Surface the beat's designed feeling as a standard emotional_tone field
        # so the outline generator and the emotional-arc author honour the intent
        # (a contrast_relief scored as relief, an emotional_setup as tender, a
        # stakes beat as dread). This is what makes the added beat actually
        # strengthen the journey rather than read as neutral plot.
        _te = str(b.get('target_emotion', '') or '').strip()
        if _te and not b.get('emotional_tone'):
            b['emotional_tone'] = _te
        # interlude beats form a NEW act → give them a distinct act label so the
        # act-normalizer (which renumbers by first-appearance page) turns them
        # into their own act rather than folding them into a neighbour.
        if bt == 'interlude' or b.get('new_act'):
            b['beat_type'] = 'interlude'
            if not str(b.get('act', '')).strip() or not b.get('new_act'):
                b['act'] = b.get('act') or 'interlude'
            b['new_act'] = True
        beats.append(b)
    beats = beats[:max_beats]

    if beats:
        by_type: Dict[str, int] = {}
        for b in beats:
            by_type[b['beat_type']] = by_type.get(b['beat_type'], 0) + 1
        new_acts = sum(1 for b in beats if b.get('new_act'))
        logger.info(
            "  [JourneyBeats] Added %d beat(s) to strengthen the %s journey: %s%s",
            len(beats), dyn_label,
            ", ".join(f"{v}× {k}" for k, v in sorted(by_type.items())),
            f" (incl. {new_acts} new-act beat(s))" if new_acts else "",
        )
    return beats


def generate_story_enrichment_beats(
    story_idea,
    characters: List,
    story_idea_str: str,
    required_beats: List[Dict],
    target_pages: int,
    get_llm_response,
    parse_json,
    sanitize=None,
    llm_model: str = None,
    use_grok: bool = False,
    enable_backstory: bool = True,
    enable_showcases: bool = True,
    enable_worldbuilding: bool = True,
    enable_emotional_journey: bool = True,
    panels_per_page_avg: int = 4,
) -> Tuple[List[Dict], Dict[str, Any]]:
    """Create enrichment beats BEFORE script generation and merge them.

    This is the key pipeline fix: side arcs, flashbacks, character showcases,
    and world-building spreads must be in ``required_beats`` before
    ``generate_comic_script()`` expands pages into panels. If they are generated
    after the script exists, they become metadata only and cannot add story pages.
    """
    if sanitize is None:
        sanitize = lambda x: x  # noqa: E731

    data: Dict[str, Any] = {
        'backstory_beats': [],
        'showcase_beats': [],
        'worldbuilding_beats': [],
        'journey_beats': [],
        'pre_enrichment_count': len(required_beats or []),
    }

    backstory_beats: List[Dict] = []
    if enable_backstory:
        limit = _dynamic_backstory_limit(target_pages, characters)
        if limit > 0:
            backstory_beats = generate_character_backstory_beats(
                characters, story_idea, required_beats, target_pages,
                get_llm_response, parse_json, llm_model, use_grok,
                max_backstory_beats=limit,
            )
            data['backstory_beats'] = backstory_beats
            data['backstory_limit'] = limit

    showcase_beats: List[Dict] = []
    if enable_showcases:
        limit = _dynamic_showcase_limit(target_pages, characters)
        if limit > 0:
            showcase_beats = generate_character_showcase_beats(
                characters, story_idea, required_beats, target_pages,
                get_llm_response, parse_json, llm_model, use_grok,
                max_showcase_beats=limit,
            )
            data['showcase_beats'] = showcase_beats
            data['showcase_limit'] = limit

    worldbuilding_beats: List[Dict] = []
    if enable_worldbuilding:
        limit = _dynamic_worldbuilding_limit(target_pages, story_idea)
        if limit > 0:
            worldbuilding_beats = generate_worldbuilding_spread_beats(
                story_idea, story_idea_str, required_beats, target_pages,
                get_llm_response, parse_json, sanitize, llm_model, use_grok,
                max_worldbuilding_spreads=limit,
            )
            data['worldbuilding_beats'] = worldbuilding_beats
            data['worldbuilding_limit'] = limit

    # Emotional-journey enrichment: the beats the DESIRED journey is missing —
    # empathy setups before peaks, relief valleys, stakes raisers, mirroring
    # side-stories, earned payoffs, and (when the journey needs a gear change) a
    # new interlude act. Driven by the book's emotional-dynamics profile.
    journey_beats: List[Dict] = []
    if enable_emotional_journey:
        try:
            dyn = emotional_dynamics_for(story_idea)
            journey_beats = generate_emotional_journey_beats(
                story_idea, characters, story_idea_str, required_beats,
                target_pages, dyn, get_llm_response, parse_json,
                llm_model, use_grok,
            )
            data['journey_beats'] = journey_beats
            data['journey_dynamics'] = dyn.get('_key', '')
        except Exception as _jb_e:
            logger.warning(f"  [JourneyBeats] Skipped ({_jb_e}).")

    merged = merge_enrichment_beats(
        required_beats, backstory_beats, showcase_beats, worldbuilding_beats,
        target_pages, journey_beats=journey_beats,
    )
    added_n = len(merged) - len(required_beats or [])
    if added_n > 0:
        # ── GROW THE BOOK TO FIT THE NEW BEATS ───────────────────────────────
        # Each enrichment beat (a backstory, a side event, a character showcase)
        # is there to deepen the emotional journey — so it must earn its own
        # pages, not be crammed into gaps in the existing budget. We expand the
        # target by the page cost of the beats we just added, at the same
        # average density the required beats already enjoy (with a hard floor so
        # an added beat is never reduced to a single throwaway page), then
        # re-tile EVERY beat across the expanded range. The act that received
        # the new beats naturally widens, because its beats now span more pages;
        # the realised length flows back to the caller so the storyboard and the
        # downstream script are generated against the grown page count.
        floor = _min_pages_per_beat_for_density(panels_per_page_avg)
        req_n = max(1, len(required_beats or []))
        # Respect the book's EXISTING beat granularity. A story whose required
        # beats already run ~1 page each is using fine-grained, panel-level
        # beats; forcing the 2-3 pages/beat "breathe" floor onto every one of
        # (now) hundreds of beats would roughly DOUBLE the book. So we only
        # impose that floor when the existing beats are genuinely coarse
        # (>= ~1.8 pages each, i.e. one beat ≈ one scene); otherwise we match
        # the book's own pacing with a floor of 1.
        existing_ppb = int(target_pages) / req_n
        if existing_ppb < 1.8:
            floor = 1
        # Grow by the added beats at the book's existing pacing (never less than
        # the floor), so the page count rises proportionally to HOW MANY beats
        # were added — not to the size of a major plot beat (which over-inflates
        # when required beats are few and large).
        per_added = max(floor, int(round(existing_ppb)))
        grown_target = int(target_pages) + added_n * per_added

        merged = normalize_beats_to_pages(
            merged, grown_target,
            panels_per_page_avg=panels_per_page_avg,
            min_pages_per_beat=floor,
        )
        realised = _max_beat_end(merged)
        data['target_pages'] = realised
        data['pages_added'] = max(0, realised - int(target_pages))
        logger.info(
            "  [PageGrowth] %d enrichment beat(s) added → growing book %d -> %d "
            "pages (>=%d pages/beat) so backstories and side events get room to "
            "breathe.",
            added_n, int(target_pages), realised, floor,
        )
    else:
        data['target_pages'] = int(target_pages)
        data['pages_added'] = 0

    data['post_enrichment_count'] = len(merged or [])
    data['added_count'] = data['post_enrichment_count'] - data['pre_enrichment_count']
    return merged, data


def _storyboard_act_beats(
    act_number,
    act_title,
    act_summary,
    story_idea,
    characters,
    total_acts,
    act_page_start,
    act_page_end,
    story_idea_str='',
    preceding_acts_context='',
    has_explicit=False,
):
    """Generate a rich, fully-expanded beat list for ONE act.

    Invents new beats -- side plots, backstory/origin flashbacks, world-texture
    moments, planted mysteries, earned payoffs -- that transform a concept
    outline into a master-class script. Returns a story-driven number of beats
    spanning the assigned page range; there is no hard per-act maximum.
    """
    act_pages = act_page_end - act_page_start + 1
    char_block = "\n".join(
        "  {} ({}): {}".format(
            c.name,
            getattr(c, 'role', ''),
            ', '.join(getattr(c, 'traits', [])[:3])
        )
        for c in (characters or [])[:12]
    )
    _min_beats, _suggested_beats = _estimate_story_driven_act_beat_counts(
        act_pages, act_summary=act_summary, story_idea_str=story_idea_str,
        characters=characters,
    )

    end_note = (
        "  7. The final beat must end on a hook or threshold that makes the "
        "reader desperate to turn into Act {}.".format(act_number + 1)
        if act_number < total_acts else
        "  7. The final beat must provide emotional resolution and a lasting image."
    )
    explict_note = ""
    if has_explicit:
        explict_note = "Encourage NSFW content with beats that highlight the beatiful, naked female body with scenes that highlight their body, seduction, foreplay, sensuality, sexuality, eroticism, etc."
        

    beat_example = (
        '{{\n'
        '  "beat_id": "a{}b01",\n'
        '  "description": "2-3 sentences -- specific, visual, sensory",\n'
        '  "act": "{}",\n'
        '  "page_range": "{}-{}",\n'
        '  "visual_keywords": ["keyword1", "keyword2", "keyword3"],\n'
        '  "panel_type": "character",\n'
        '  "technique": "Gaiman:planted-mystery",\n'
        '  "beat_type": "main",\n'
        '  "adult_content": false,\n'
        '  "must_include": true\n'
        '}}'
    ).format(
        act_number, act_number,
        act_page_start, min(act_page_start + 2, act_page_end)
    )

    # Generic (act-independent) schema for the STABLE prefix so the cached
    # portion is not broken by the concrete example's act number / page range.
    generic_schema = (
        '{\n'
        '  "beat_id": "<aNbNN, sequential within the act, e.g. a2b01>",\n'
        '  "description": "2-3 sentences -- specific, visual, sensory",\n'
        '  "act": "<act number>",\n'
        '  "page_range": "<a range within this act\'s assigned pages>",\n'
        '  "visual_keywords": ["keyword1", "keyword2", "keyword3"],\n'
        '  "panel_type": "character",\n'
        '  "technique": "Gaiman:planted-mystery",\n'
        '  "beat_type": "main",\n'
        '  "adult_content": false,\n'
        '  "must_include": true\n'
        '}'
    )

    prompt = (
        # ══ STABLE PREFIX ══════════════════════════════════════════════════
        # Identical for every act of this book (same story context, cast,
        # technique vocabulary, enrichment rules, requirements, schema), so it
        # is cached after the first act instead of re-billed once per act. Only
        # this act's assignment varies, and it trails in the tail below.
        "You are a master graphic-novel story editor expanding the acts of a "
        "{total}-act {genre} story into rich, fully-realised beat lists. For "
        "each act you are assigned you invent side plots, backstory/origin "
        "flashbacks, world-texture moments, planted mysteries, and earned "
        "payoffs that turn a concept outline into a master-class script.  {explict_note}\n\n"
        "FULL STORY CONTEXT:\n{ctx}\n\n"
        "CAST:\n{cast}\n\n"
        "GENRE: {genre} | MOOD: {mood} | THEMES: {themes}\n\n"
        "{techniques}\n\n"
        "{enrichment}\n\n"
        "HOW TO BUILD AN ACT'S BEATS: create as many SPECIFIC, VIVID, CONCRETE "
        "story beats as the act needs. Each beat must be a scene the artist can "
        "draw -- an EVENT with sensory detail (light quality, sound, texture, "
        "temperature). You will be given a per-act beat FLOOR and BASELINE, but "
        "never treat the baseline as a cap: if the act contains side arcs, "
        "backstory, parallel action, world history, planted mysteries, "
        "reversals, or emotional aftermath that need their own drawable scene, "
        "add more beats.\n\n"
        "Requirements:\n"
        "  1. COVER all events the author specified for the act faithfully.\n"
        "  2. INVENT new beats where they improve the story: side arcs, "
        "character showcases, origin/backstory flashbacks, world-texture "
        "reveals, planted mysteries, moral reversals, quiet aftermaths, earned "
        "payoffs.\n"
        "  3. Label each beat with the master technique it employs.\n"
        "  4. Vary beat TYPE. Use precise beat_type values such as main, "
        "side_arc, backstory, origin, character_showcase, world_building, "
        "mystery_seed, payoff, reveal, action, confrontation, quiet, bridge, "
        "climax.\n"
        "  5. Beat descriptions: 2-3 sentences, visually concrete, sensory.\n"
        "  6. Keep page ranges in narrative order within the act's assigned "
        "window. The allocator may grow the book later if the act needs more "
        "beats than the original page window can honestly hold.\n\n"
        "Return a JSON array of beat objects shaped like this:\n{schema}\n\n"
        "JSON array only.\n"
        # ══ VARIABLE TAIL (this act only) ══════════════════════════════════
        "\n========================================================\n"
        "YOUR ASSIGNMENT: ACT {act} OF {total}\n"
        "========================================================\n"
        "ACT: {title}\n"
        "PAGES: {ps}-{pe} ({pages} pages)\n\n"
        "THE AUTHOR'S CONCEPT FOR THIS ACT:\n{summary}\n\n"
        "PRECEDING ACTS SUMMARY:\n{preceding}\n\n"
        "For this {pages}-page act, use {minb} beats as the minimum floor and "
        "about {sugg} beats as a starting baseline -- not a cap; add more if the "
        "act earns them. Page ranges should begin within {ps}-{pe}.\n"
        "{end_note}\n\n"
        "Example beat object for THIS act (match this beat_id / page_range "
        "style):\n{example}\n\n"
        "Create the beats for Act {act} now. JSON array only."
    ).format(
        total=total_acts, genre=story_idea.genre,
        explict_note=explict_note,
        ctx=sanitize_text_for_prompt(story_idea_str),
        cast=char_block,
        mood=story_idea.mood, themes=', '.join(story_idea.themes),
        techniques=_MASTER_TECHNIQUES,
        enrichment=(ENRICHMENT_BEAT_INSTRUCTIONS + '\n\n' + CHARACTER_DEVELOPMENT_CONTEXT_TEMPLATE),
        schema=generic_schema, example=beat_example,
        act=act_number, title=act_title,
        ps=act_page_start, pe=act_page_end, pages=act_pages,
        summary=act_summary[:3000],
        preceding=preceding_acts_context or '(This is the opening act.)',
        minb=_min_beats, sugg=_suggested_beats,
        end_note=end_note,
    )

    try:
        response = get_openai_prompt_response(
            prompt, temperature=0.78, max_completion_tokens=75000,
            openai_model=openai_model_large, use_grok=USE_GROK,
        )
        parsed = parse_json_response(response)
        if isinstance(parsed, list):
            beats = [b for b in parsed if isinstance(b, dict) and b.get('description')]
            # Content-aware tiling: ignore the LLM's (often overflowing or
            # overlapping) page_range guesses and lay the beats down end-to-end
            # so they exactly cover [act_page_start, act_page_end], sized by each
            # beat's content. Merges the slightest beats if the LLM returned more
            # beats than the act has pages.
            beats = tile_beats_across_pages(
                beats, act_page_start, act_page_end,
                panels_per_page_avg=4, min_pages_per_beat=1,
            )
            for b in beats:
                b['act'] = str(act_number)
                b['must_include'] = True
            if beats:
                logger.info(
                    "[Act {}] Storyboarded {} beats (pp.{}-{})".format(
                        act_number, len(beats), act_page_start, act_page_end
                    )
                )
                return beats
    except Exception as e:
        logger.warning("[Act {}] Storyboard LLM failed ({}); using fallback.".format(act_number, e))

    # Fallback: extract sentences from the act summary
    import re as _re2
    sentences = [s.strip() for s in _re2.split(r'[.!?]+', act_summary) if len(s.strip()) > 30]
    fallback = []
    for i, sent in enumerate(sentences):
        fallback.append({
            'beat_id': "a{}b{:02d}".format(act_number, i + 1),
            'description': sent[:300],
            'act': str(act_number),
            'page_range': "{}-{}".format(act_page_start, act_page_end),
            'visual_keywords': [],
            'panel_type': 'character',
            'technique': '',
            'beat_type': 'main',
            'adult_content': False,
            'must_include': True,
        })
    if fallback:
        # Tile the fallback beats across the act range by content weight.
        fallback = tile_beats_across_pages(
            fallback, act_page_start, act_page_end,
            panels_per_page_avg=4, min_pages_per_beat=1,
        )
    else:
        fallback.append({
            'beat_id': "a{}b01".format(act_number),
            'description': act_summary[:300],
            'act': str(act_number),
            'page_range': "{}-{}".format(act_page_start, act_page_end),
            'visual_keywords': [],
            'panel_type': 'character',
            'technique': '',
            'beat_type': 'main',
            'adult_content': False,
            'must_include': True,
        })
    return fallback


def _recommend_target_pages(
    story_idea,
    story_idea_str,
    characters=None,
    panels_per_page_avg=4,
    act_structure=None,
):
    """Storyboard the concept and recommend the best total page count.

    When target_pages == 'auto':
      - Explicit multi-act stories: sizes each act independently, ensuring every
        act has enough pages to breathe. A 5-act epic gets enough pages for each
        act, never squeezed into a 24-page default.
      - Otherwise: original beat-counting single-pass approach.

    Page count clamped to [8, 400].
    """
    _MIN_PAGES, _MAX_PAGES = 8, 400
    _MIN_PAGES_PER_ACT = 12
    _IDEAL_PAGES_PER_ACT = 20

    def _heuristic_from_scope():
        concept_len = len((story_idea_str or '') + ' ' + (story_idea.premise or ''))
        cast_n = len(characters or [])
        n_acts = (act_structure or {}).get('num_acts', 0) or 1
        base = (16 + min(60, concept_len // 120) + max(0, cast_n - 4)) * n_acts
        if panels_per_page_avg >= 6:
            base = int(base * 0.85)
        elif panels_per_page_avg <= 2:
            base = int(base * 1.25)
        return max(_MIN_PAGES, min(_MAX_PAGES, base))

    _acts = act_structure or {}
    if _acts.get('has_explicit_acts') and _acts.get('num_acts', 0) >= 2:
        num_acts = _acts['num_acts']
        summaries = _acts.get('act_summaries', [])
        titles = _acts.get('act_titles', [])
        logger.info(
            "  Auto target-pages: {}-act structure -- storyboarding each act...".format(num_acts)
        )
        act_totals = []
        for i, summary in enumerate(summaries):
            act_label = titles[i] if i < len(titles) else "Act {}".format(i + 1)
            try:
                prompt = (
                    "You are a graphic-novel story editor sizing Act {} of {} "
                    "in a {} graphic novel.\n\n"
                    "ACT: {}\n\nACT CONTENT:\n{}\n\n"
                    "PANELS PER PAGE: {}\n\n"
                    "Decompose into beats/scenes. Minimum {} pages; ideally {}+. "
                    "Include pages for side-character moments, world-texture, "
                    "wonder, and quiet scenes.\n\n"
                    "Return ONLY JSON: {{\"beats\":[{{\"beat\":\"<label>\",\"pages\":<int>}},...], "
                    "\"total_pages\":<int>, \"rationale\":\"<one sentence>\"}}"
                ).format(
                    i + 1, num_acts, story_idea.genre,
                    act_label, summary[:3000],
                    panels_per_page_avg,
                    _MIN_PAGES_PER_ACT, _IDEAL_PAGES_PER_ACT,
                )
                resp = get_openai_prompt_response(
                    prompt, temperature=0.65, max_completion_tokens=4000,
                    openai_model=openai_model_large, use_grok=USE_GROK,
                )
                parsed = parse_json_response(resp) or {}
                total = int(parsed.get('total_pages', 0) or 0)
                beats = parsed.get('beats') or []
                beat_sum = sum(
                    int((b or {}).get('pages', 0) or 0)
                    for b in beats if isinstance(b, dict)
                )
                if beat_sum > 0 and (total <= 0 or abs(total - beat_sum) > max(8, total * 0.5)):
                    total = beat_sum
                total = max(_MIN_PAGES_PER_ACT, total)
                act_totals.append(total)
                logger.info("    {}: {} pages -- {}".format(
                    act_label, total, str(parsed.get('rationale', ''))[:60]
                ))
            except Exception as e:
                logger.warning("    {}: sizing failed ({}); using {}".format(
                    act_label, e, _IDEAL_PAGES_PER_ACT
                ))
                act_totals.append(_IDEAL_PAGES_PER_ACT)

        if act_totals:
            raw = sum(act_totals)
            if panels_per_page_avg >= 6:
                raw = int(raw * 0.85)
            elif panels_per_page_avg <= 2:
                raw = int(raw * 1.25)
            total = max(_MIN_PAGES, min(_MAX_PAGES, raw))
            logger.info("  Auto target-pages -> {} pages ({} acts: {})".format(
                total, num_acts, act_totals
            ))
            return total

    # Single-concept path
    try:
        themes = ", ".join(story_idea.themes or [])
        cast_desc = ""
        if characters:
            _names = [getattr(c, 'name', '') for c in characters if getattr(c, 'name', '')]
            cast_desc = (
                "CAST: {} named characters".format(len(characters))
                + (" ({}{})".format(
                    ', '.join(_names[:12]),
                    '...' if len(_names) > 12 else ''
                ) if _names else "")
                + "\n"
            )
        prompt = (
            "You are a graphic-novel story editor storyboarding a book. "
            "Decompose into beats/scenes including side-character moments, "
            "world-texture reveals, and wonder spreads.\n"
            "Typical scene: 2-5 pages; climax: 4-8.\n\n"
            "GENRE: {}\nTHEMES: {}\nMOOD: {}\nPREMISE: {}\n{}"
            "PANELS/PAGE: {}\n\n"
            "CONCEPT:\n{}\n\n"
            "Return ONLY JSON: {{\"beats\":[{{\"beat\":\"<label>\",\"pages\":<int>}},...], "
            "\"total_pages\":<int>, \"rationale\":\"<one sentence>\"}}"
        ).format(
            story_idea.genre, themes, story_idea.mood,
            story_idea.premise, cast_desc,
            panels_per_page_avg,
            sanitize_text_for_prompt(story_idea_str),
        )
        resp = get_openai_prompt_response(prompt, temperature=0.65)
        parsed = parse_json_response(resp) or {}
        total = int(parsed.get('total_pages', 0) or 0)
        beats = parsed.get('beats') or []
        beat_sum = sum(
            int((b or {}).get('pages', 0) or 0)
            for b in beats if isinstance(b, dict)
        )
        if beat_sum > 0 and (total <= 0 or abs(total - beat_sum) > max(8, total * 0.5)):
            total = beat_sum
        if total <= 0:
            raise ValueError("no usable total")
        total = max(_MIN_PAGES, min(_MAX_PAGES, total))
        logger.info("  Auto target-pages -> {} pages ({} beats)".format(
            total, len(beats) if isinstance(beats, list) else 0
        ))
        return total
    except Exception as e:
        fallback = _heuristic_from_scope()
        logger.warning("  Auto target-pages failed ({}); heuristic -> {} pages.".format(e, fallback))
        return fallback


def _reconcile_target_pages_to_beats(
    beats: List[Dict],
    estimated_pages: int,
    panels_per_page_avg: int = 4,
) -> int:
    """Snap target_pages to the actual story coverage revealed by the beat list.

    Problem: ``_recommend_target_pages`` runs BEFORE beats exist, so it sizes
    the book from the concept alone. ``extract_required_story_beats`` then tells
    the LLM "fit beats into N pages" but the LLM may only find enough story for
    60 pages and spread it thinly across 86 — producing 24 empty filler pages.

    This function is called AFTER beat extraction. It reads the actual page
    ranges the beats occupy, computes true story coverage, and returns a revised
    page count that is grounded in what the story actually needs.

    Adjustment rules
    ----------------
    Let ``beat_max``  = highest end-page across all beats.
    Let ``beat_span`` = beat_max  (beats start at page 1).

    1. If beat_span < estimated × 0.85   → story is shorter than estimated.
       Reduce target_pages to beat_span + small breathing room.

    2. If beat_span > estimated × 1.05   → beats overflowed the estimate.
       Increase target_pages to beat_span.

    3. If the beats are very sparse (avg pages-per-beat < 3 after density
       adjustment) the book would feel rushed — apply a minimum of
       ``len(beats) * min_pages_per_beat``.

    4. Always clamp to [max(8, len(beats)*2), 400].

    The breathing-room padding (``tail_pad``) gives the script LLM space for a
    proper ending scene after the last required beat — typically 2-4 pages.

    Returns the reconciled integer page count and logs the change.
    """
    if not beats:
        return estimated_pages

    # --- Parse page ranges from all beats -----------------------------------
    import re as _re
    beat_max = 0
    for b in beats:
        pr = str(b.get('page_range', '') or '').strip()
        if not pr or pr.lower() in ('tbd', ''):
            continue
        # Handle "N-end", "N-M", "N"
        pr_clean = pr.lower().replace('end', str(estimated_pages))
        parts = _re.findall(r'\d+', pr_clean)
        if parts:
            beat_max = max(beat_max, max(int(p) for p in parts))

    if beat_max <= 0:
        # No parseable ranges — fall back to estimated
        logger.warning(
            "  [Reconcile] No parseable beat page ranges; keeping estimated "
            "{} pages.".format(estimated_pages)
        )
        return estimated_pages

    # --- Breathing room: space for a proper ending after the last beat -------
    # Scale with book size: small book → 2 pages; large book → 4 pages.
    tail_pad = 2 if estimated_pages <= 40 else (3 if estimated_pages <= 80 else 4)

    # --- Minimum density: apply a floor ONLY when the LLM's own beat pacing
    # is dangerously shallow (beats crammed into too few pages).
    #
    # CRITICAL DESIGN RULE: do NOT apply a fixed beats*N floor blindly.
    # If the LLM storyboarded 44 beats at 2 pages each to fill a 90-page book,
    # the beats ARE the correct pacing signal. Overriding with beats*3=132
    # produces 42 anchor-free pages that the script LLM fills with pure filler.
    # Instead, use the LLM's actual pacing and only apply a floor if that pacing
    # falls below a minimum that would make individual beats unreadable
    # (less than ~1.8 pages/beat for standard panels; less than 1.5 for
    # high-density layouts where each page carries more panels and story).
    actual_pacing = beat_max / len(beats) if beats else 3.0

    if panels_per_page_avg >= 6:
        min_acceptable_pacing = 1.5   # dense pages carry more story per page
    elif panels_per_page_avg <= 2:
        min_acceptable_pacing = 3.0   # very sparse pages need more room per beat
    else:
        min_acceptable_pacing = 1.8   # standard 3-5 panels/page

    raw = beat_max + tail_pad

    if actual_pacing < min_acceptable_pacing:
        # Beats are genuinely too compressed — apply a density floor so each
        # beat has enough pages to breathe.  This is the unusual case.
        density_min = round(len(beats) * min_acceptable_pacing)
        reconciled  = max(raw, density_min)
        _density_floor_applied = True
    else:
        # LLM's own pacing is acceptable. Trust it: use beat_max + tail padding
        # only. Adding extra pages beyond beat coverage produces anchor-free
        # filler that weakens the story.
        reconciled = raw
        density_min = 0
        _density_floor_applied = False

    reconciled = max(8, min(400, reconciled))

    _lo = estimated_pages * 0.85
    _hi = estimated_pages * 1.05

    if abs(reconciled - estimated_pages) <= 2:
        # Negligible change — keep original and skip noise log
        return estimated_pages

    if reconciled < _lo:
        _floor_note = (
            " [density floor: {} beats x {:.1f} min-pages/beat]".format(
                len(beats), min_acceptable_pacing)
            if _density_floor_applied else ""
        )
        logger.info(
            "  [Reconcile] Beats cover pp.1-{} (estimated {}). "
            "Reducing target_pages: {} -> {}{}.".format(
                beat_max, estimated_pages, estimated_pages, reconciled, _floor_note
            )
        )
    elif reconciled > _hi:
        if _density_floor_applied:
            logger.info(
                "  [Reconcile] Beats cover pp.1-{} but pacing is tight "
                "({:.1f} pp/beat < min {:.1f}). "
                "Expanding target_pages: {} -> {} [density floor].".format(
                    beat_max, actual_pacing, min_acceptable_pacing,
                    estimated_pages, reconciled
                )
            )
        else:
            logger.info(
                "  [Reconcile] Beats overflow estimate (pp.1-{} > {}). "
                "Increasing target_pages: {} -> {}.".format(
                    beat_max, estimated_pages, estimated_pages, reconciled
                )
            )
    else:
        logger.info(
            "  [Reconcile] Beat coverage pp.1-{} within tolerance of {}; "
            "target_pages stays {}.".format(beat_max, estimated_pages, estimated_pages)
        )
        return estimated_pages

    return reconciled


def synthesize_comic_story(story_idea_str: str, creative_seeds: Dict = None,
                            cast_size = "medium") -> Tuple[StoryIdea, List[Character], CharacterGraph, CharacterAppearanceRegistry]:
    """Generate story + cast + EI graph for the comic.
    
    Reuses the novel generator's pipeline but tunes cast size for comics
    (comics are visual, dense; smaller named cast keeps art coherent).
    
    Args:
        story_idea_str: free-text story concept
        creative_seeds: optional dict matching CREATIVE_SEEDS structure
        cast_size: 'small'       → 2 main + 4 support + 2 minor  (~8  chars)
                   'medium'      → 8 main + 6 support + 4 minor  (~18 chars)
                   'large'       → 12 main + 15 support + 8 minor (~35 chars)
                   'extra_large' → 16 main + 20 support + 12 minor (~48 chars)
                   (tier1, tier2, tier3) → exact counts, e.g. (2, 22, 8) for a
                       small human cast with many supporting entities/angels

    Returns:
        (story_idea, characters, graph, registry)
    """
    creative_seeds = creative_seeds or {}

    # ── Parse cast_size ───────────────────────────────────────────────────
    
    logger.info("[1/8] Generating story concept...")
    if any(creative_seeds.values()):
        seed_story = synthesize_seeds_to_story(creative_seeds, story_idea_str)
        if seed_story:
            story_idea = StoryIdea(
                genre=seed_story.get('genre', 'Graphic Novel'),
                themes=seed_story.get('themes', ['adventure']),
                mood=seed_story.get('mood', 'cinematic'),
                premise=seed_story.get('premise', story_idea_str),
            )
        else:
            story_idea = generate_story_idea(story_idea_str)
    else:
        story_idea = generate_story_idea(story_idea_str)
    
    logger.info(f"  Genre: {story_idea.genre}")
    logger.info(f"  Themes: {', '.join(story_idea.themes)}")
    
    # ── Auto cast-size: let the AI recommend the cast composition ─────────────
    # When cast_size == 'auto', ask the model to size the named cast to the
    # story itself (scope, genre, page count) and resolve it to concrete tier
    # targets before the casting step below. Falls back to 'medium' on any
    # failure so synthesis never breaks on a bad/empty LLM response.
    if isinstance(cast_size, str) and cast_size.strip().lower() == "auto":
        cast_size = _recommend_cast_size(story_idea, story_idea_str)

    logger.info("[2/8] Casting...")
    # Tune cast tier sizes for comics
    if isinstance(cast_size, (tuple, list)) and len(cast_size) >= 3:
        tier1_target, tier2_target, tier3_target = (
            int(cast_size[0]), int(cast_size[1]), int(cast_size[2])
        )
    elif cast_size == "small":
        tier1_target, tier2_target, tier3_target = 2, 4, 2
    elif cast_size == "large":
        tier1_target, tier2_target, tier3_target = 12, 15, 8
    elif cast_size == "extra_large":
        tier1_target, tier2_target, tier3_target = 16, 20, 12
    else:  # medium (default)
        tier1_target, tier2_target, tier3_target = 8, 6, 4

    # Always generate the storyboard surrogate — it's needed for the character
    # graph regardless of which casting path was taken.
    storyboard_surrogate = _generate_comic_storyboard_surrogate(story_idea)

    # When cast_size is a tuple the caller is making a deliberate choice about
    # cast composition. Rather than asking a generic casting LLM (which always
    # defaults to human social roles), we:
    #   1. Pre-seed tier 2 with every named non-human entity explicitly
    #      mentioned in the story text — angels, archangels, cosmic forces,
    #      divine beings, etc. — extracted directly from the story.
    #   2. Fill any remaining slots with story-aware LLM casting that is
    #      strictly forbidden from inventing human characters for tier 2.
    #   3. Tier 1 and tier 3 use normal LLM casting.
    if isinstance(cast_size, (tuple, list)) and len(cast_size) >= 3:

        # ── Step 1: Extract named entities — use FULL story text ─────────────
        # Extraction is strictly story-driven: we pull ONLY the non-human
        # entities that are actually named in (or directly implied by) THIS
        # story's text. The prompt deliberately contains NO example entity
        # names — embedding sample names (angels, cosmic forces, etc.) caused
        # the model to import those names into unrelated stories. If the story
        # has no such entities, the correct result is an empty list.
        entity_extract_prompt = (
            f"Read this story carefully and extract every NON-HUMAN entity that "
            f"is explicitly named in it or clearly, directly implied by it — for "
            f"example a creature, animal, spirit, deity, A.I., machine "
            f"intelligence, monster, supernatural presence, or named natural/"
            f"cosmic force, IF and only IF the story actually contains it.\n\n"
            f"STORY:\n{story_idea_str}\n\n"
            f"Strict rules:\n"
            f"- Extract ONLY entities that appear in, or are unmistakably implied "
            f"by, the story text above. Do NOT add any entity, name, mythology, "
            f"or being that is not grounded in this specific story.\n"
            f"- If names are not fully given, imagine them as they are part of the story.  Native American characters should have names associated with their tribal ancestry, etc.\n"
            f"- Do NOT include human characters or unnamed abstract concepts.\n"
            f"- If the story contains NO non-human entities, return an empty "
            f"JSON array [].\n"
            f"- For each entity, write: 'NAME — brief description of its nature "
            f"and role in THIS story'.\n"
            f"- List in narrative importance order. Return at most {tier2_target} "
            f"entries (fewer is correct if the story has fewer).\n\n"
            f"Return a JSON array of role strings (possibly empty). JSON only, no markdown."
        )
        entity_resp = get_openai_prompt_response(
            entity_extract_prompt, temperature=0.2,
            openai_model=openai_model_large, use_grok=USE_GROK,
        )
        entity_roles_raw = parse_json_response(entity_resp)
        if isinstance(entity_roles_raw, list):
            entity_roles = [str(r) for r in entity_roles_raw if r][:tier2_target]
        else:
            entity_roles = []
        logger.info(f"  Extracted {len(entity_roles)} named entities from story")

        # ── Step 2: Fill remaining tier 2 slots if needed ─────────────────────
        # Only fill when the story can plausibly support MORE non-human entities
        # than were explicitly named (e.g. a populous mythic/sci-fi world). This
        # is opt-in via the requested cast size, but it must still stay grounded
        # in the story — never invent entities to hit a target count for a story
        # that simply doesn't have them. If extraction found nothing, we do not
        # fabricate a tier-2 cast.
        remaining = tier2_target - len(entity_roles)
        if remaining > 0 and entity_roles:
            existing = '; '.join(entity_roles[:8])
            fill_prompt = (
                f"STORY:\n{story_idea_str}\n\n"
                f"Already identified non-human entities: {existing}\n\n"
                f"If — and ONLY if — this story clearly contains or directly "
                f"implies additional non-human entities beyond those listed, name "
                f"up to {remaining} more, grounded strictly in the story text.\n"
                f"- Do NOT invent entities, mythologies, or names not supported "
                f"by the story. Do NOT include human characters.\n"
                f"- If there are no further entities, return an empty array [].\n"
                f"Return a JSON array of role strings (possibly empty). JSON only."
            )
            fill_resp = get_openai_prompt_response(
                fill_prompt, temperature=0.3,
                openai_model=openai_model_large, use_grok=USE_GROK,
            )
            fill_raw = parse_json_response(fill_resp)
            if isinstance(fill_raw, list):
                entity_roles += [str(r) for r in fill_raw if r][:remaining]

        entity_roles = entity_roles[:tier2_target]

        # ── Step 3: Named-entity pre-scan ─────────────────────────────────────
        # For stories that explicitly name their cast (like ensemble erotic or
        # ensemble drama stories), extract EVERY named human character from the
        # FULL story text before the casting LLM runs. This guarantees that names
        # the author spelled out — even deep in a long story seed — actually appear
        # in the tier roles rather than being lost to [:2000] truncation or LLM
        # creative substitution.
        _story_full = story_idea_str  # never truncated for name extraction
        _prescan_prompt = (
            "Extract every NAMED human character from this story. "
            "Return ONLY characters who are given explicit names in the text. "
            "Do NOT invent or infer unnamed characters.\n\n"
            f"STORY:\n{sanitize_text_for_prompt(_story_full[:8000])}\n\n"
            "For each named character return: 'NAME — one-sentence role description'\n"
            "Group into: main protagonist(s), recurring supporting characters, "
            "and brief-appearance characters.\n"
            'Return JSON: {"main": [...], "supporting": [...], "brief": [...]}\n'
            "JSON only. If a tier has no characters, return an empty list."
        )
        _prescan_resp = get_openai_prompt_response(
            _prescan_prompt, temperature=0.2,
            openai_model=openai_model_large, use_grok=USE_GROK,
        )
        _prescan = parse_json_response(_prescan_resp) or {}
        _named_main      = [str(r) for r in (_prescan.get('main') or []) if r]
        _named_supporting = [str(r) for r in (_prescan.get('supporting') or []) if r]
        _named_brief      = [str(r) for r in (_prescan.get('brief') or []) if r]

        # Log what was found so the user can see the full scanned cast
        _named_total = len(_named_main) + len(_named_supporting) + len(_named_brief)
        if _named_total:
            logger.info(
                f"  [NameScan] Found {_named_total} explicitly named character(s) in story: "
                f"{_named_main[:2] + _named_supporting[:2] + _named_brief[:2]} ..."
            )

        # Dynamically raise tier targets so ALL explicitly named characters fit.
        # Named main chars → tier 1. Named supporting → tier 2. Named brief → tier 3.
        # We never reduce a tier below what was already requested.
        tier1_target = max(tier1_target, len(_named_main))
        tier2_target = max(tier2_target, len(entity_roles) + len(_named_supporting))
        tier3_target = max(tier3_target, len(_named_brief))

        # ── Step 3b: Tier 1 and tier 2 human roles via story-aware casting ────
        # Seed roles from the name-scan; let the LLM fill remaining slots.
        tier2_human_slots = max(0, tier2_target - len(entity_roles))

        # Build seed role lists from the prescan (already in 'NAME — role' format)
        _seed_t1 = _named_main[:tier1_target]
        _seed_t2 = _named_supporting[:tier2_human_slots]

        # Only call the LLM for slots the prescan didn't fill
        _t1_remaining = max(0, tier1_target - len(_seed_t1))
        _t2_remaining = max(0, tier2_human_slots - len(_seed_t2))

        if _t1_remaining > 0 or _t2_remaining > 0:
            t1t2_prompt = (
                f"You are a casting director for a graphic novel.\n\n"
                f"STORY:\n{sanitize_text_for_prompt(story_idea_str)}\n\n"
                f"The following characters are ALREADY CAST — do NOT repeat them:\n"
                f"  Already in Tier 1: {_seed_t1 or '(none)'}\n"
                f"  Already in Tier 2: {_seed_t2 or '(none)'}\n\n"
                f"Identify any ADDITIONAL main and supporting characters the story "
                f"implies but which are not in the already-cast list above.\n\n"
                f"  Tier 1 (MAIN protagonists, additional):     up to {_t1_remaining} more\n"
                f"  Tier 2 (SUPPORTING, recurring, additional): up to {_t2_remaining} more\n\n"
                f"Return fewer if the story genuinely has fewer unlisted characters.\n"
                f"Return JSON: {{\"tier1\": [...], \"tier2_humans\": [...]}}\n"
                f"Each entry: 'NAME — brief role description'. JSON only."
            )
            t1t2_resp = get_openai_prompt_response(
                t1t2_prompt, temperature=0.4,
                openai_model=openai_model_large, use_grok=USE_GROK,
            )
            t1t2_parsed = parse_json_response(t1t2_resp) or {}
            _extra_t1 = [str(r) for r in (t1t2_parsed.get('tier1') or [])][:_t1_remaining]
            _extra_t2 = [str(r) for r in (t1t2_parsed.get('tier2_humans') or [])][:_t2_remaining]
        else:
            _extra_t1 = []
            _extra_t2 = []

        tier2_humans = (_seed_t2 + _extra_t2)[:tier2_human_slots]
        tiers = {
            'tier1': (_seed_t1 + _extra_t1)[:tier1_target],
            'tier2': (entity_roles + tier2_humans)[:tier2_target],
            'tier3': [],    # populated below
        }
        if not tiers['tier1']:
            tiers['tier1'] = [f"The human protagonist — {story_idea.premise[:80]}"]

        # ── Step 4: Tier 3 — minor characters with story-creative latitude ────
        if tier3_target > 0:
            existing_cast = (
                "; ".join(
                    f"{r.split(' — ')[0].strip()}" for r in
                    tiers['tier1'] + tiers['tier2'] if r
                ) or "(none yet)"
            )
            # Seed tier 3 from the prescan's 'brief' names, then ask the LLM
            # to fill any remaining slots creatively. Use the full story text
            # (up to 6000 chars) so late-appearing names aren't lost.
            _seed_t3 = _named_brief[:tier3_target]
            _t3_remaining = max(0, tier3_target - len(_seed_t3))

            if _t3_remaining > 0:
                t3_prompt = (
                    f"You are a casting director for a graphic novel. Your job is to "
                    f"create {_t3_remaining} ADDITIONAL MINOR characters — named, "
                    f"memorable, and distinct — who populate the world of this story.\n\n"
                    f"STORY:\n{sanitize_text_for_prompt(story_idea_str)}\n\n"
                    f"EXISTING MAIN/SUPPORTING CAST (do NOT duplicate these):\n"
                    f"  {existing_cast}\n\n"
                    f"ALREADY ASSIGNED TO TIER 3 (do NOT duplicate these):\n"
                    f"  {_seed_t3 or '(none)'}\n\n"
                    f"Minor characters are NOT the leads. They appear in 1-3 scenes, "
                    f"each serving a specific narrative function:\n"
                    f"  • A catalyst: triggers a plot event or emotional shift\n"
                    f"  • A mirror: reflects the protagonist's arc back at them\n"
                    f"  • A texture character: makes the world feel lived-in and real\n"
                    f"  • A foil: contrasts with the lead in a revealing way\n\n"
                    f"INSTRUCTIONS:\n"
                    f"  1. Create up to {_t3_remaining} minor characters that fit this "
                    f"story's genre and world.\n"
                    f"  2. You MAY invent characters not named in the story — minor "
                    f"characters who BELONG in this world. For example, if the story "
                    f"involves ten intimate encounters, name ten partners. If it is an "
                    f"urban crime thriller, name bartenders, informants, detectives. "
                    f"If it is a fantasy epic, name inn-keepers, soldiers, and seers.\n"
                    f"  3. Each character must have a clear narrative function.\n"
                    f"  4. Give each a distinctive name that fits the story's setting.\n"
                    f"  5. Return fewer than {_t3_remaining} only if the story's world "
                    f"genuinely cannot support that many minor characters.\n\n"
                    f"Return JSON array of role strings:\n"
                    f"['NAME — function/role description (1 line)', ...]\n"
                    f"JSON only."
                )
                t3_resp = get_openai_prompt_response(
                    t3_prompt, temperature=0.6,
                    openai_model=openai_model_large, use_grok=USE_GROK,
                )
                t3_parsed = parse_json_response(t3_resp)
                _extra_t3: List[str] = []
                if isinstance(t3_parsed, list):
                    _extra_t3 = [str(r) for r in t3_parsed if r][:_t3_remaining]
                elif isinstance(t3_parsed, dict):
                    for key in ('tier3', 'minor', 'characters', 'roles'):
                        v = t3_parsed.get(key)
                        if isinstance(v, list):
                            _extra_t3 = [str(r) for r in v if r][:_t3_remaining]
                            break
            else:
                _extra_t3 = []

            tiers['tier3'] = (_seed_t3 + _extra_t3)[:tier3_target]

    else:
        # Standard path: generic casting director
        tiers = identify_required_characters(storyboard_surrogate, "")
        tiers['tier1'] = (tiers.get('tier1') or [])[:tier1_target]
        tiers['tier2'] = (tiers.get('tier2') or [])[:tier2_target]
        tiers['tier3'] = (tiers.get('tier3') or [])[:tier3_target]

    logger.info(f"  Tier 1: {len(tiers['tier1'])} role(s)")
    logger.info(f"  Tier 2: {len(tiers['tier2'])} role(s)")
    logger.info(f"  Tier 3: {len(tiers['tier3'])} role(s)")
    if tier3_target > 0 and len(tiers['tier3']) == 0:
        logger.warning(
            f"  Tier 3: 0 minor characters returned despite target={tier3_target}. "
            f"Check t3_prompt response. Minor characters will be absent from the cast."
        )
    elif tiers['tier3']:
        for r in tiers['tier3'][:5]:
            logger.info(f"    Minor: {str(r)[:80]}")

    characters = generate_characters(tiers)
    logger.info(f"  Cast: {len(characters)} characters")



    # ── Non-human presence detection ─────────────────────────────────────────
    # Always run nonhuman detection to catch any entities the extraction step
    # missed. When cast_size is a tuple the tier-2 entities are already cast,
    # so we deduplicate strictly — only truly absent entities are appended.
    logger.info("  Detecting non-human presences...")
    current_cast_names = [c.name for c in characters]
    nonhuman_presences = _detect_nonhuman_presences(
        story_idea_str, story_idea, existing_names=current_cast_names
    )
    nonhuman_chars: List[Character] = []
    if nonhuman_presences:
        existing_names_lower = {c.name.lower() for c in characters}
        existing_fragments = set()
        for n in existing_names_lower:
            for word in n.split():
                if len(word) > 3:
                    existing_fragments.add(word)

        for p in nonhuman_presences:
            char = _nonhuman_to_character(p)
            name_low = char.name.lower()
            already_present = (
                name_low in existing_names_lower
                or any(word in existing_fragments
                       for word in name_low.split() if len(word) > 3)
            )
            if already_present:
                continue
            tier = str(p.get('tier', '2'))
            if tier == '1':
                characters.insert(0, char)
            else:
                characters.append(char)
            nonhuman_chars.append(char)
            existing_names_lower.add(name_low)
            for word in name_low.split():
                if len(word) > 3:
                    existing_fragments.add(word)
            logger.info(f"  + Non-human (detected): {char.name} "
                        f"({getattr(char,'character_type','entity')} — {char.role})")
    if nonhuman_chars:
        logger.info(f"  Added {len(nonhuman_chars)} additional non-human entity(ies) "
                    f"not captured by extraction.")
    else:
        logger.info("  No additional non-human presences detected.")

    # ── Deduplication ─────────────────────────────────────────────────────────
    # The extraction step and the detection step can produce Character objects
    # for the same entity under slightly different names (e.g. a bare name vs
    # the same name with an appended title/epithet, or "Captain Reyes" vs
    # "Reyes"). Consolidate by keeping the first (richest) entry for each
    # canonical name cluster.
    def _name_key(name: str) -> str:
        """Normalise a character name to a dedup key.

        Strips common prefixes/suffixes and reduces to the longest meaningful
        word so 'Archangel Michael', 'Michael — Prince of Archangels', and
        'Michael' all collapse to the same key ('michael').
        """
        low = name.lower()
        # Strip common title prefixes
        for prefix in ('archangel ', 'angel ', 'prince of ', 'the ', 'master '):
            if low.startswith(prefix):
                low = low[len(prefix):]
        # Take only the part before ' — ' (role description separator)
        low = low.split(' — ')[0].split(' (')[0].strip()
        # Return the longest word as the canonical key (most distinctive)
        words = [w for w in low.split() if len(w) > 2]
        return max(words, key=len) if words else low

    seen_keys: dict = {}   # key → index of first occurrence in characters
    deduped: List[Character] = []
    duplicates_removed = 0
    for char in characters:
        key = _name_key(char.name)
        if key not in seen_keys:
            seen_keys[key] = len(deduped)
            deduped.append(char)
        else:
            # Merge: if the duplicate has a richer appearance/role, update the
            # keeper's fields rather than discarding the information entirely.
            keeper = deduped[seen_keys[key]]
            if len(char.appearance) > len(keeper.appearance):
                keeper.appearance = char.appearance
            if len(char.role) > len(keeper.role):
                keeper.role = char.role
            if char.traits and not keeper.traits:
                keeper.traits = char.traits
            duplicates_removed += 1

    if duplicates_removed:
        logger.info(f"  Deduplication: removed {duplicates_removed} duplicate(s), "
                    f"{len(deduped)} unique characters remain.")
    characters = deduped

    # Ensure no two characters look alike before the registry locks their
    # appearances — a reader must be able to tell the cast apart at a glance.
    try:
        ensure_distinct_appearances(characters, story_idea)
    except Exception as _e:
        logger.warning(f"  Distinctiveness pass skipped ({_e}).")

    logger.info("[3/8] Building visual registry...")
    registry = CharacterAppearanceRegistry(characters)
    # Store character list for lookups elsewhere
    registry._characters = characters

    # Rebuild registry with visual drawing directives — and use non-human-aware
    # guidance: an eagle's entry should describe plumage, wingspread, talons,
    # and bearing; NOT personality or speech patterns.
    try:
        char_descs = []
        for c in characters:
            ctype = getattr(c, 'character_type', 'human')
            if ctype != 'human':
                species = getattr(c, 'species', c.age)
                char_descs.append(
                    f"Name: {c.name} | Type: {ctype} ({species}) | "
                    f"Appearance: {c.appearance} | "
                    f"Behavioral traits: {', '.join(c.traits[:3])}"
                )
            else:
                char_descs.append(
                    f"Name: {c.name} | Role: {c.role} | Age: {c.age} | "
                    f"Appearance: {c.appearance}"
                )
        regen_prompt = (
            "You are an art director briefing an illustrator on characters to draw.\n\n"
            "For each character below write a SHORT (≤50 words) visual drawing directive "
            "that describes ONLY what the illustrator draws:\n"
            "  • For HUMANS: physical features, build, hair, eyes, skin, age, clothing, posture\n"
            "  • For ANIMALS/SPIRITS/ENTITIES: species markings, size, distinctive features,\n"
            "    bearing, how they hold themselves, what makes them visually striking\n"
            "DO NOT include personality traits, job titles, backstory, emotional states,\n"
            "or any text that reads like a character-sheet label.\n"
            "Return JSON: {\"CharacterName\": \"visual directive...\"}\n\n"
            "Characters:\n" + "\n".join(char_descs)
        )
        regen_resp = get_openai_prompt_response(
            regen_prompt, temperature=0.3,
            openai_model=openai_model_large, use_grok=USE_GROK,
        )
        regen_parsed = parse_json_response(regen_resp)
        if isinstance(regen_parsed, dict):
            updated = 0
            for name, visual in regen_parsed.items():
                if isinstance(visual, str) and visual.strip():
                    registry.registry[name] = visual.strip()
                    updated += 1
            logger.info(f"  Visual registry rebuilt with drawing directives ({updated} entries).")
        else:
            logger.warning("  Visual registry rebuild parse failed; using base registry.")
    except Exception as e:
        logger.warning(f"  Visual registry rebuild failed ({e}); using base registry.")
    
    logger.info("[4/8] Building character graph (EI engine)...")
    # Convert storyboard surrogate to graph-compatible format
    graph_storyboard = {}
    for i, sb in enumerate(storyboard_surrogate, 1):
        graph_storyboard[str(i)] = {
            'chapter': i,
            'setting': sb.get('setting', ''),
            'events': sb.get('events', []),
            'twist': sb.get('twist', ''),
            'intensity': sb.get('intensity', 'medium'),
        }
    
    graph = build_character_graph(characters, story_idea, graph_storyboard)
    logger.info(f"  Graph: {len(graph.nodes)} nodes, {len(graph.edges)} edges")

    # Override EI nodes for non-human characters with behavior/symbol profiling.
    # build_character_graph calls ai_build_character_node which applies a human
    # "psychological profiler" prompt — wrong for an eagle or a spirit. We
    # replace those nodes with non-human-aware profiles.
    if nonhuman_chars:
        logger.info(f"  Building non-human EI profiles for "
                    f"{len(nonhuman_chars)} presence(s)...")
        for nh_char in nonhuman_chars:
            nh_node = _build_nonhuman_ei_node(nh_char, story_idea, characters)
            # Replace the node in the graph (build_character_graph will have
            # added a human-profiled version; we overwrite it)
            if hasattr(graph, 'nodes') and isinstance(graph.nodes, dict):
                graph.nodes[nh_char.name] = nh_node
            logger.info(f"    {nh_char.name}: archetype='{nh_node.archetype}', "
                        f"function='{nh_node.core_longing[:60]}'")

    # Cast spread — deliberately balance the ensemble between larger-than-life
    # and relatable/ordinary so the book has emotional contrast and a diverse
    # cast. Annotates each node with a register the beat + dialogue passes honour.
    try:
        from novel_generator import assign_cast_spread
        assign_cast_spread(graph, characters, story_idea, use_grok=USE_GROK)
    except Exception as _cs_e:
        logger.warning(f"  [CastSpread] Skipped ({_cs_e}).")

    # Build the Series Visual Bible — canonical descriptions for every recurring
    # prop, costume, and equipment piece so the Art Director can catch and fix
    # "mask → medical mask" class of image-generation errors.
    logger.info("[AD] Building Series Visual Bible from story concept...")
    visual_bible = build_series_visual_bible(story_idea_str, characters, story_idea)

    return story_idea, characters, graph, registry, visual_bible


# =============================================================================
# BEAT CRITIC — evaluate and amplify the storyboarded beats before page-locking
# =============================================================================
# Beats are generated one-shot from a masterful technique catalog, but nothing
# ever EVALUATES whether they're actually amazing, whether they cohere, whether
# the payoffs land, or whether the emotional targets are hit. This pass adds the
# missing evaluation loop: it scores the whole beat sequence on the dimensions
# that make a story unputdownable, then rewrites the weakest beats and shores up
# any setup that never pays off. It only ever STRENGTHENS the set — never drops
# or shrinks beats — and degrades to a clean no-op on any failure.
# =============================================================================

# The rubric the critic scores against. Each maps to a reader-experience goal:
# imaginative spectacle, escalating stakes, emotional connection, payoff
# discipline, and cast contrast (the larger-than-life vs the relatable).
_BEAT_RUBRIC = (
    "IMAGINATION: is this beat surprising, inventive, over-the-top in the best "
    "way — something a reader hasn't seen a hundred times? Flat/generic = low.\n"
    "STAKES & ESCALATION: does it raise tension or cost relative to the beats "
    "around it, so the sequence tightens rather than plateaus?\n"
    "EMOTION & CONNECTION: does it make the reader FEEL something and bond with "
    "a character (awe, dread, longing, delight, heartbreak)? A beat that only "
    "moves plot with no feeling = low. Score this HARSHLY: competent-but-cold "
    "is a 4, not a 6. Ask — would a reader's chest tighten, eyes sting, pulse "
    "lift? Is there a PERSON to ache for, not just an event to watch?\n"
    "PAYOFF DISCIPLINE: is it either planting something or paying something off? "
    "Setups that never pay and payoffs with no setup are flaws.\n"
    "COHERENCE: does it follow believably from the previous beat and set up the "
    "next, or does it feel arbitrary / out of sequence?"
)

# The named emotional registers the critic checks the WHOLE sequence for. A
# bestseller moves a reader through a RANGE — not one note held flat. The critic
# reports which of these the sequence delivers and which are missing, so the
# amplifier can inject the absent ones where they'd land.
_EMOTIONAL_SPECTRUM = (
    "awe/wonder", "dread/fear", "longing/yearning", "heartbreak/grief",
    "joy/delight", "passion/desire", "righteous anger", "tenderness/warmth",
    "catharsis/release", "hope",
)

_BEAT_CRITIC_BATCH = 12   # beats scored per LLM call (keeps prompts bounded)

# Concrete craft levers the amplifier uses to raise emotion, passion, and drama
# — so "deepen emotion" becomes actionable technique, not a vague instruction.
_EMOTIONAL_CRAFT_TOOLKIT = (
    "EMOTIONAL CRAFT — raise the feeling with SPECIFIC technique, not adjectives:\n"
    "  - GIVE IT A BODY: attach the emotion to one person the reader is bonded "
    "to, in one concrete physical detail (a hand that won't stop shaking, a "
    "laugh that breaks). Abstract stakes don't move anyone; a face does.\n"
    "  - RAISE THE PERSONAL COST: make what's at risk something the character "
    "loves, not just something they need. Drama is desire meeting an obstacle "
    "that costs them.\n"
    "  - CONTRAST FOR AMPLITUDE: a moment of tenderness or humour right before "
    "a blow makes the blow land harder; stillness before the storm. The range "
    "is the feeling.\n"
    "  - PASSION & DESIRE: where two characters want each other or a dream, let "
    "the yearning be physical and specific — the charge of proximity, the thing "
    "left unsaid, the reach that isn't completed.\n"
    "  - EARN THE CATHARSIS: if a beat is a release (a reunion, a confession, a "
    "sacrifice), make sure the ache it resolves was planted earlier so the "
    "reader breaks open, not just nods.\n"
    "  - THE PRIVATE TRUTH: reveal what the character feels UNDER what they show "
    "— the gap between the brave face and the fear is where a reader aches.\n"
)


def _beats_digest_for_critic(beats: List[Dict], max_chars: int = 90) -> str:
    """Compact, numbered digest of the beat sequence for the critic prompt."""
    lines = []
    for i, b in enumerate(beats):
        tech = b.get('technique', '')
        btype = b.get('beat_type', 'main')
        desc = str(b.get('description', ''))[:220]
        lines.append(
            f"[{i}] (act {b.get('act', '?')}, {btype}"
            + (f", {tech}" if tech else "") + f") {desc}"
        )
    return "\n".join(lines)


def critique_and_amplify_beats(
    beats: List[Dict],
    story_idea: 'StoryIdea',
    story_idea_str: str,
    characters: List = None,
    use_grok: bool = False,
    amplify_fraction: float = 0.34,
    min_score_floor: float = 6.0,
    emotion_floor: float = 6.5,
    graph=None,
) -> List[Dict]:
    """Evaluate the storyboarded beats and rewrite the weakest into amazing ones.

    Two phases, both LLM-driven, both degrading to no-op on failure:

      Phase 1 — CRITIQUE. Score every beat 1-10 on the rubric (imagination,
        stakes, emotion, payoff discipline, coherence) and collect sequence-level
        notes: unpaid setups, payoffs with no setup, emotional flat stretches,
        and where the cast's larger-than-life vs relatable contrast is missing.

      Phase 2 — AMPLIFY. Take the lowest-scoring beats (the weakest
        ``amplify_fraction`` of the book, or anything below ``min_score_floor``)
        and rewrite ONLY those — pushing imagination and emotion harder, wiring
        in the flagged setups/payoffs, keeping each beat's act, page_range, and
        role intact. Never changes the beat COUNT (page allocation downstream
        depends on it); only the descriptions/keywords/technique get richer.

    Returns the amplified beat list (same length, same order).
    """
    if not beats or len(beats) < 3:
        return beats

    # Cast description, enriched with each lead's register (mythic / aspirational
    # / relatable / grounded) so the amplifier honours the extraordinariness ↔
    # relatability spread when it rewrites beats.
    def _register_for(name):
        if graph is None or not getattr(graph, 'nodes', None):
            return ""
        key = str(name).lower()
        for gk, gn in graph.nodes.items():
            if key == gk.lower() or key in gk.lower() or gk.lower() in key:
                return str(getattr(gn, 'cast_register', '') or '')
        return ""
    _cast_bits = []
    for c in (characters or [])[:10]:
        nm = getattr(c, 'name', '')
        reg = _register_for(nm)
        _cast_bits.append(f"{nm} ({getattr(c, 'role', '')}"
                          + (f", {reg}" if reg else "") + ")")
    cast = ", ".join(_cast_bits) or "(cast not specified)"

    # ── Phase 1: critique ──────────────────────────────────────────────────
    scores: Dict[int, float] = {}
    emo_scores: Dict[int, float] = {}
    sequence_notes = ""
    digest = _beats_digest_for_critic(beats)
    critique_prompt = (
        "You are a ruthless, brilliant graphic-novel story editor. Score a beat "
        "sequence for a bestseller that must be creative, imaginative, "
        "over-the-top, emotionally gripping, and impossible to put down.\n\n"
        f"GENRE: {story_idea.genre}   MOOD: {story_idea.mood}\n"
        f"THEMES: {', '.join(story_idea.themes or [])}\n"
        f"CAST: {cast}\n\n"
        "RUBRIC (score each beat 1-10; 10 = unforgettable, 5 = competent but "
        f"forgettable, 1 = flat filler):\n{_BEAT_RUBRIC}\n\n"
        "For EACH beat give TWO scores: 'score' (overall, per the full rubric) "
        "and 'emotion' (JUST the EMOTION & CONNECTION dimension — how hard it "
        "makes the reader FEEL and bond with a person). Judge emotion strictly: "
        "a beat can be clever and coherent yet emotionally cold — that is a LOW "
        "emotion score even if the overall is decent.\n\n"
        "Also diagnose the WHOLE sequence's emotional RANGE. A bestseller moves "
        "the reader through many registers; a flat one hits the same note. From "
        "this spectrum — " + ", ".join(_EMOTIONAL_SPECTRUM) + " — report which "
        "the sequence delivers well and which are MISSING or underused.\n\n"
        "THE BEAT SEQUENCE:\n" + digest + "\n\n"
        "Return ONLY JSON:\n"
        '{"scores": [{"i": 0, "score": 7.5, "emotion": 6.0, "why": "<8 words>"}, ...],\n'
        ' "unpaid_setups": ["<beat idx or short desc>", ...],\n'
        ' "unset_payoffs": ["..."],\n'
        ' "flat_stretches": ["beats N-M feel emotionally flat because ..."],\n'
        ' "missing_emotions": ["longing/yearning — no beat lets the reader ache for anyone", ...],\n'
        ' "peak_opportunities": ["beat N could be the emotional high point if ...", ...],\n'
        ' "cast_contrast_gap": "<one line: is the larger-than-life vs relatable '
        'contrast landing across the cast? what is missing?>"}\n'
        "Score EVERY beat by index (both score and emotion). JSON only."
    )
    try:
        resp = get_openai_prompt_response(
            critique_prompt, temperature=0.35, max_completion_tokens=9000,
            use_grok=use_grok,
        )
        crit = parse_json_response(resp)
    except Exception as e:
        logger.warning(f"  [BeatCritic] Critique call failed ({e}); beats unchanged.")
        return beats

    if not isinstance(crit, dict):
        return beats
    for s in (crit.get('scores') or []):
        try:
            idx = int(s.get('i'))
            scores[idx] = float(s.get('score'))
        except (TypeError, ValueError):
            continue
        # Emotion sub-score is optional; fall back to the overall when absent.
        try:
            emo_scores[idx] = float(s.get('emotion'))
        except (TypeError, ValueError):
            emo_scores[idx] = scores[idx]
    if not scores:
        return beats

    # Persist both scores onto each beat (useful for downstream logging / debug).
    for i, b in enumerate(beats):
        if i in scores:
            b['_beat_score'] = round(scores[i], 1)
        if i in emo_scores:
            b['_beat_emotion'] = round(emo_scores[i], 1)

    notes_bits = []
    for key, label in (('unpaid_setups', 'UNPAID SETUPS'),
                       ('unset_payoffs', 'PAYOFFS MISSING SETUP'),
                       ('flat_stretches', 'FLAT STRETCHES'),
                       ('missing_emotions', 'MISSING EMOTIONAL REGISTERS'),
                       ('peak_opportunities', 'PEAK OPPORTUNITIES'),
                       ('cast_contrast_gap', 'CAST CONTRAST GAP')):
        val = crit.get(key)
        if isinstance(val, list) and val:
            notes_bits.append(f"{label}: " + " | ".join(str(x)[:120] for x in val[:5]))
        elif isinstance(val, str) and val.strip():
            notes_bits.append(f"{label}: {val.strip()[:200]}")
    sequence_notes = "\n".join(notes_bits)

    avg = sum(scores.values()) / len(scores)
    emo_avg = sum(emo_scores.values()) / len(emo_scores) if emo_scores else avg
    logger.info(
        "  [BeatCritic] Scored %d beats (avg %.1f/10, emotion %.1f/10). %s",
        len(scores), avg, emo_avg,
        "Sequence notes found." if sequence_notes else "No sequence-level flaws flagged.",
    )

    # ── Choose which beats to amplify ───────────────────────────────────────
    # TWO independent triggers, so emotion is never lost inside the overall score:
    #   (a) the weakest beats overall (the original behaviour), and
    #   (b) emotionally FLAT beats — low emotion sub-score — even when their
    #       overall score is respectable. A clever, coherent, cold beat is
    #       exactly what drains a book's passion, and it would otherwise sail
    #       through. This is the core of "amplify emotion".
    n_amplify = max(1, int(round(len(beats) * amplify_fraction)))
    ranked = sorted(scores.items(), key=lambda kv: kv[1])
    target_idxs = {i for i, sc in ranked[:n_amplify]}
    target_idxs |= {i for i, sc in scores.items() if sc < min_score_floor}
    # (b) Emotion trigger: any beat whose emotion sub-score is below the floor,
    # OR that sits in the bottom third of the book on emotion specifically.
    if emo_scores:
        emo_ranked = sorted(emo_scores.items(), key=lambda kv: kv[1])
        n_emo = max(1, len(emo_scores) // 3)
        flat_emo = {i for i, sc in emo_ranked[:n_emo]}
        flat_emo |= {i for i, sc in emo_scores.items() if sc < emotion_floor}
        target_idxs |= flat_emo
    # Cap so we never rewrite more than half the book in one pass. When over the
    # cap, prioritise the beats that are worst on the COMBINED signal (overall +
    # emotion), so emotionally-flat beats aren't dropped in favour of ones that
    # are merely a little below average overall.
    if len(target_idxs) > len(beats) // 2:
        def _combined(i):
            return scores.get(i, 10) + emo_scores.get(i, scores.get(i, 10))
        target_idxs = set(sorted(target_idxs, key=_combined)[:len(beats)//2])
    if not target_idxs:
        logger.info("  [BeatCritic] No beats below the amplification threshold — sequence is strong.")
        return beats

    # ── Phase 2: amplify the weak beats ─────────────────────────────────────
    # Mark WHY each beat was selected so the writer knows where to pour feeling:
    # a beat pulled in only for a low emotion sub-score gets an explicit
    # [EMOTION] tag so the rewrite prioritises passion/connection over plot.
    _emo_flagged = {
        i for i in target_idxs
        if emo_scores.get(i, 10) < emotion_floor
        or (emo_scores and i in {j for j, _ in sorted(
            emo_scores.items(), key=lambda kv: kv[1])[:max(1, len(emo_scores)//3)]})
    }
    weak_list = "\n".join(
        f"[{i}]{' [EMOTION — this beat is cold; make the reader FEEL]' if i in _emo_flagged else ''} "
        f"(act {beats[i].get('act','?')}, keep this page_range: "
        f"{beats[i].get('page_range','?')}) {str(beats[i].get('description',''))[:260]}"
        for i in sorted(target_idxs)
    )
    amplify_prompt = (
        "You are a master graphic-novel writer. Rewrite ONLY the listed weak "
        "beats into unforgettable ones — more imaginative, higher stakes, more "
        "emotionally charged — WITHOUT changing their place in the sequence.\n\n"
        f"GENRE: {story_idea.genre}   MOOD: {story_idea.mood}\n"
        f"THEMES: {', '.join(story_idea.themes or [])}\n"
        f"CAST: {cast}\n\n"
        + _EMOTIONAL_CRAFT_TOOLKIT + "\n"
        "GOALS FOR THE REWRITE:\n"
        "- Push imagination: make each beat something a reader would tell a "
        "friend about. Over-the-top is welcome when it serves feeling.\n"
        "- Deepen emotion and human connection: the reader must FEEL it and bond "
        "with a character. Beats tagged [EMOTION] are cold — their FIRST job is "
        "to make a reader ache, thrill, or swoon; use the craft toolkit above.\n"
        "- Balance the cast: some beats should showcase a larger-than-life "
        "character doing the unbelievable; others should ground us in a "
        "relatable, ordinary, desirable, or enviable character we root for.\n"
        + (f"\nFIX THESE SEQUENCE ISSUES where the relevant beats are below:\n{sequence_notes}\n"
           if sequence_notes else "")
        + "\nCONSTRAINTS: keep each beat's act and page_range EXACTLY. Do not add "
        "or remove beats. Return each rewritten beat by its original index.\n\n"
        "WEAK BEATS TO REWRITE:\n" + weak_list + "\n\n"
        "Return ONLY JSON:\n"
        '{"rewrites": [{"i": 3, "description": "<richer beat>", '
        '"visual_keywords": ["..."], "technique": "<optional master technique>"}, ...]}\n'
        "JSON only."
    )
    try:
        resp2 = get_openai_prompt_response(
            amplify_prompt, temperature=0.85, max_completion_tokens=12000,
            use_grok=use_grok,
        )
        amp = parse_json_response(resp2)
    except Exception as e:
        logger.warning(f"  [BeatCritic] Amplify call failed ({e}); scored but not rewritten.")
        return beats

    rewritten = 0
    if isinstance(amp, dict):
        for r in (amp.get('rewrites') or []):
            try:
                i = int(r.get('i'))
            except (TypeError, ValueError):
                continue
            if i not in target_idxs or i >= len(beats):
                continue
            new_desc = str(r.get('description', '') or '').strip()
            if len(new_desc) < 20:
                continue
            beats[i]['description'] = new_desc
            beats[i]['_amplified'] = True
            if i in _emo_flagged:
                beats[i]['_emotion_amplified'] = True
            kw = r.get('visual_keywords')
            if isinstance(kw, list) and kw:
                beats[i]['visual_keywords'] = [str(k) for k in kw][:8]
            tech = str(r.get('technique', '') or '').strip()
            if tech:
                beats[i]['technique'] = tech
            rewritten += 1

    _emo_rewritten = sum(1 for i in target_idxs
                         if i in _emo_flagged and beats[i].get('_amplified'))
    logger.info(
        "  [BeatCritic] Amplified %d/%d weak beat(s) into stronger ones "
        "(%d specifically for emotion/passion/connection).",
        rewritten, len(target_idxs), _emo_rewritten,
    )
    return beats


def extract_required_story_beats(story_idea: 'StoryIdea',
                                  story_idea_str: str,
                                  target_pages: int = 50,
                                  act_structure: Dict = None,
                                  characters: List = None,
                                  graph=None) -> 'List[Dict]':
    """Extract AND richly expand the required story beats for each act.

    This function does two things:
      1. Extracts the concrete plot points the author specified (as before).
      2. For each act, calls _storyboard_act_beats to INVENT additional beats
         using master storytelling techniques — side plots, world-texture moments,
         planted mysteries, earned payoffs — so each act is rich enough to fill
         its page budget without repetition or padding.

    The act count respects the explicit structure in the story concept (if it says
    "Act I ... Act V", that's 5 acts), rather than being inferred from page count.

    Page ranges are scaled to target_pages so beats are spread correctly
    across any book length.

    Returns a list of beat dicts:
        [
          {'beat_id': 'a1b01', 'description': '...', 'page_range': '1-4',
           'must_include': True, 'act': '1',
           'visual_keywords': [...], 'technique': 'Gaiman:planted-mystery',
           'beat_type': 'main'},
          ...
        ]
    """
    # ── Resolve act structure ──────────────────────────────────────────────────
    _acts = act_structure or _detect_act_structure(story_idea_str)
    has_explicit = _acts.get('has_explicit_acts', False)

    if has_explicit and _acts.get('num_acts', 0) >= 2:
        num_acts = _acts['num_acts']
        logger.info(
            f"  [Beats] {num_acts} explicit acts detected; "
            f"storyboarding each act for maximum richness..."
        )
    else:
        # Fall back to page-count-derived act count (existing behaviour)
        if target_pages <= 20:
            num_acts = 1
        elif target_pages <= 50:
            num_acts = 2
        elif target_pages <= 100:
            num_acts = 3
        else:
            num_acts = 4

    # ── Build act page boundaries ─────────────────────────────────────────────
    act_boundaries = [
        round(target_pages * (i / num_acts))
        for i in range(1, num_acts + 1)
    ]
    act_starts = [1] + [act_boundaries[i] + 1 for i in range(num_acts - 1)]
    act_ends = act_boundaries

    # ── Per-act storyboarding ─────────────────────────────────────────────────
    if has_explicit and num_acts >= 2:
        all_beats: List[Dict] = []
        preceding_ctx = ""
        summaries = _acts.get('act_summaries', [])
        titles = _acts.get('act_titles', [])

        for act_idx in range(num_acts):
            act_num = act_idx + 1
            act_title = titles[act_idx] if act_idx < len(titles) else f"Act {act_num}"
            act_summary = summaries[act_idx] if act_idx < len(summaries) else story_idea.premise
            act_page_start = act_starts[act_idx]
            act_page_end = act_ends[act_idx]

            act_beats = _storyboard_act_beats(
                act_number=act_num,
                act_title=act_title,
                act_summary=act_summary,
                story_idea=story_idea,
                characters=characters or [],
                total_acts=num_acts,
                act_page_start=act_page_start,
                act_page_end=act_page_end,
                story_idea_str=story_idea_str,
                preceding_acts_context=preceding_ctx,
                has_explicit=has_explicit,
            )
            all_beats.extend(act_beats)

            # Build a brief context summary for subsequent acts so they don't
            # repeat earlier story points
            if act_beats:
                preceding_ctx += (
                    f"\nAct {act_num} ({act_title}): "
                    + " | ".join(b.get('description', '')[:80] for b in act_beats[:4])
                )

        if all_beats:
            # BEAT CRITIC — before locking beats to pages, evaluate the whole
            # act sequence for quality and coherence, then amplify the weakest
            # beats and shore up unpaid setups. This is the single evaluation
            # loop over the one-shot-generated beats: it never shrinks the set,
            # only strengthens it. Degrades to a no-op on any failure.
            try:
                all_beats = critique_and_amplify_beats(
                    all_beats, story_idea, story_idea_str,
                    characters=characters or [],
                    use_grok=USE_GROK,
                    graph=graph,
                )
            except Exception as _bc_e:
                logger.warning(f"  [BeatCritic] Skipped ({_bc_e}).")

            # Global content-aware allocation. Every beat is sized by its own
            # content and the book GROWS so each beat gets its own pages; acts
            # naturally span the sum of their beats' pages (a dense middle act
            # ends up longer than a short epilogue). No beat is merged or
            # starved.
            all_beats = normalize_beats_to_pages(
                all_beats, target_pages,
                panels_per_page_avg=4, min_pages_per_beat=1,
            )
            _span = _max_beat_end(all_beats)
            logger.info(
                f"  [Beats] {len(all_beats)} total beats across "
                f"{num_acts} acts (pp.1-{_span})"
            )
            for b in all_beats:
                act_label = f" [Act {b.get('act', '?')}]"
                tech = f" [{b.get('technique', '')}]" if b.get('technique') else ""
                adult_marker = " [adult]" if b.get('adult_content') else ""
                logger.info(
                    f"    {b.get('beat_id', '??')} "
                    f"(pp.{b.get('page_range', '?')})"
                    f"{act_label}: "
                    f"{b.get('description', '')[:70]}"
                    f"{tech}"
                    f"{adult_marker}"
                )
            return all_beats

    # ── Single-pass extraction (no explicit acts or single-act story) ─────────
    # This is the original extraction path for concept-outline stories.

    if num_acts == 1:
        act_hint_boundaries = (
            f"  This is a {target_pages}-page short-form comic -- treat it as "
            f"a single continuous act. Assign act=\"1\" to every beat."
        )
        act_field_spec = '"act": "1"'
    else:
        boundary_lines = '\n'.join(
            f"  Act {i} ends around page {act_boundaries[i-1]}"
            for i in range(1, num_acts + 1)
        )
        act_hint_boundaries = (
            f"  {num_acts}-act structure for this {target_pages}-page book:\n"
            + boundary_lines
        )
        valid_acts = ' | '.join(f'"{i}"' for i in range(1, num_acts + 1))
        act_field_spec = f'"act": "1"   // {valid_acts}'

    has_acts = any(kw in story_idea_str for kw in
                   ['Act 1', 'Act 2', 'Act 3', 'Volume', 'Chapter', 'Part 1'])

    act_hint = (
        "The concept contains explicit act/volume/chapter labels. "
        "Honour them: the page_range for each beat must fall within the "
        "act it belongs to, scaled to the total page count below."
        if has_acts else
        "The concept has no explicit act labels. Distribute beats "
        "chronologically across the full page range."
    )

    # Story-driven beat request for non-explicit-act concepts. This is a
    # minimum + baseline, not a cap; the allocator can grow pages afterward.
    min_beats = max(8, int(round(target_pages / 8)))
    ideal_beats = max(min_beats, int(round(target_pages / 3)))

    prompt = (
        f"You are a story analyst extracting REQUIRED PLOT POINTS from a comic, graphic novel "
        f"book concept. Beats are the concrete events that MUST appear in the "
        f"final graphic novel -- not generic structure, but the specific moments the "
        f"author asked for.\n\n"
        f"USER'S CONCEPT (preserve every element faithfully):\n"
        f"{story_idea_str}\n\n"
        f"STORY METADATA:\n"
        f"  Genre:  {story_idea.genre}\n"
        f"  Mood:   {story_idea.mood}\n"
        f"  Themes: {', '.join(story_idea.themes)}\n\n"
        f"COMIC LENGTH: {target_pages} pages total\n"
        f"{act_hint_boundaries}\n\n"
        f"ACT STRUCTURE NOTE: {act_hint}\n\n"
        f"INSTRUCTIONS:\n"
        f"  1. Extract as many required beats as the story genuinely needs. Use {min_beats} as a floor "
        f"and about {ideal_beats} as a starting baseline, but DO NOT treat that as a cap.\n"
        f"  2. Each beat must be a SPECIFIC EVENT, not a generic phase.\n"
        f"  3. Cover every named character introduction, world-building reveal, "
        f"and climactic confrontation the author specified.\n"
        f"  4. Do NOT skip sensitive beats -- mark them adult_content=true.\n"
        f"  5. page_range MUST use pages within 1-{target_pages}.\n"
        f"  6. Beats must be in chronological order.\n"
        f"  7. No two beats should share an identical page_range.\n"
        f"  8. COSMIC BEATS: if the concept describes zoom-out sequences, each "
        f"zoom level is a SEPARATE beat with panel_type='cosmic' and empty "
        f"characters_in_frame.\n"
        f"  9. MASTER TECHNIQUE: assign each beat the storytelling technique "
        f"that best serves its emotional purpose. These techniques directly drive "
        f"the lighting, camera, composition, and atmosphere of every panel image "
        f"generated for that beat — they are the visual grammar of the emotional journey.\n\n"
        f"{_MASTER_TECHNIQUES}\n\n"
        f"Also use enrichment beat types when they improve the story: side_arc, backstory, origin, "
        f"character_showcase, world_building, mystery_seed, payoff, reveal, quiet, bridge, climax.\n\n"
        f"{ENRICHMENT_BEAT_INSTRUCTIONS}\n\n"
        f"Return a JSON ARRAY. Each item:\n"
        f"{{\n"
        f"  \"beat_id\": \"b01\",\n"
        f"  \"description\": \"1-2 sentences -- the specific event, visually concrete\",\n"
        f"  {act_field_spec},\n"
        f"  \"page_range\": \"1-4\",\n"
        f"  \"visual_keywords\": [\"keyword1\", \"keyword2\", \"keyword3\"],\n"
        f"  \"panel_type\": \"character\",\n"
        f"  \"technique\": \"Gaiman:planted-mystery\",\n"
        f"  \"beat_type\": \"main\",\n"
        f"  \"adult_content\": false,\n"
        f"  \"must_include\": true\n"
        f"}}\n\n"
        f"JSON array only. Every beat MUST have a non-empty technique field."
    )

    response = get_openai_prompt_response(
        prompt, temperature=0.4, max_completion_tokens=75000,
        openai_model=openai_model_large, use_grok=USE_GROK,
    )
    parsed = parse_json_response(response)
    if parsed and isinstance(parsed, list):
        beats = [b for b in parsed if isinstance(b, dict) and b.get('description')]
        if beats:
            # BEAT CRITIC — evaluate + amplify the weakest beats before locking to
            # pages (same pass the multi-act path runs). Degrades to no-op.
            try:
                beats = critique_and_amplify_beats(
                    beats, story_idea, story_idea_str,
                    characters=characters or [], use_grok=USE_GROK, graph=graph,
                )
            except Exception as _bc_e:
                logger.warning(f"  [BeatCritic] Skipped ({_bc_e}).")
            # Content-aware normalization: re-tile beats so they cover
            # pp.1-target_pages contiguously, sized by content. For multi-act
            # concepts this also re-weights the per-act page spans.
            beats = normalize_beats_to_pages(
                beats, target_pages,
                panels_per_page_avg=4, min_pages_per_beat=1, min_pages_per_act=6,
            )

            logger.info(f"  Extracted {len(beats)} required beats:")
            for b in beats:
                act_label = f" [Act {b.get('act', '?')}]" if b.get('act') else ""
                marker    = " [adult]" if b.get('adult_content') else ""
                tech_tag  = f" [{b.get('technique')}]" if b.get('technique') else " [no-technique]"
                logger.info(
                    f"    {b.get('beat_id', '??')}"
                    f" (pp.{b.get('page_range', '?')})"
                    f"{act_label}: "
                    f"{b.get('description', '')[:75]}{marker}{tech_tag}"
                )
            return beats

    logger.warning("  Beat extraction failed; building beats from concept structure")

    # Structured fallback
    fallback_beats = []
    bid = 1
    import re as _re
    act_chunks = _re.split(r'(?im)^\s*(act|volume|chapter|part)\s*\d', story_idea_str)
    if len(act_chunks) > 1:
        for chunk_idx, chunk in enumerate(act_chunks[1:], 1):
            sentences = [s.strip() for s in chunk.replace('\n', ' ').split('.') if len(s.strip()) > 20]
            for sent in sentences[:4]:
                fallback_beats.append({
                    'beat_id':        f"b{bid:02d}",
                    'description':    sent[:200],
                    'act':            str(chunk_idx),
                    'page_range':     f"1-{target_pages}",
                    'visual_keywords':[],
                    'technique':      '',
                    'beat_type':      'main',
                    'adult_content':  False,
                    'must_include':   True,
                })
                bid += 1

    if not fallback_beats:
        fallback_beats.append({
            'beat_id':        'b01',
            'description':    story_idea_str,
            'act':            '1',
            'page_range':     f"1-{target_pages}",
            'visual_keywords':[],
            'technique':      '',
            'beat_type':      'main',
            'adult_content':  False,
            'must_include':   True,
        })

    # Content-aware tiling for the fallback path too.
    fallback_beats = normalize_beats_to_pages(
        fallback_beats, target_pages,
        panels_per_page_avg=4, min_pages_per_beat=1, min_pages_per_act=6,
    )
    return fallback_beats


def _detect_nonhuman_presences(story_idea_str: str, story_idea: 'StoryIdea',
                                existing_names: List[str] = None) -> List[Dict]:
    """Detect significant non-human characters (animals, spirits, entities, forces)
    from the story concept and return structured presence dicts.

    The standard casting pipeline only looks for human social roles (protagonists,
    antagonists, shopkeepers). Animals like the eagle in "a man bonds with an eagle
    at his jail window" would be silently omitted or miscast as a human extra.

    Args:
        existing_names: list of character names already in the cast. When
            provided, the detection prompt explicitly instructs the LLM to
            skip any entity whose name (or a key word within it) matches one
            of these — preventing duplicates at the source rather than having
            to deduplicate after the fact.

    Returns a list of dicts:
        [{'name': 'The Eagle', 'species': 'golden eagle', ...}, ...]
    """
    combined = (
        f"GENRE: {story_idea.genre}\n"
        f"THEMES: {', '.join(story_idea.themes)}\n"
        f"PREMISE: {story_idea.premise}\n\n"
        f"FULL CONCEPT:\n{story_idea_str}"
    )

    # Build an exclusion block so the LLM never re-suggests already-cast entities.
    exclusion_block = ""
    if existing_names:
        names_str = "\n".join(f"  - {n}" for n in existing_names)
        exclusion_block = (
            f"\nALREADY IN THE CAST — do NOT suggest any of these or any alias "
            f"/ alternative name for them:\n{names_str}\n"
            f"If an entity you would suggest is the same being as one of the above "
            f"under a different label (e.g. a title or epithet for a character "
            f"already listed), skip it entirely.\n"
        )

    prompt = (
        "You are a story analyst identifying NON-HUMAN significant presences in a "
        "comic book, graphic novel concept. These include: animals, birds, mythic creatures, spirits, "
        "nature forces, AI entities, supernatural beings, or any non-human that has "
        "narrative agency or emotional significance.\n\n"
        f"{combined}\n"
        f"{exclusion_block}\n"
        "List ONLY non-human presences that: (a) appear in more than one scene, "
        "or (b) have a named relationship with a human character, "
        "or (c) carry symbolic or thematic weight in the story.\n"
        "Ignore background animals (herd of cows in a field, birds on a wire).\n"
        "Return ONLY entities NOT already listed in the exclusion list above.\n\n"
        "For each presence, return JSON:\n"
        "[\n"
        "  {\n"
        '    "name": "distinctive name or title (e.g. \'The Eagle\', \'Spirit Wolf\')",\n'
        '    "species": "biological or mythic type",\n'
        '    "character_type": "animal | spirit | entity | force | mythic",\n'
        '    "role": "1-sentence narrative role",\n'
        '    "narrative_function": "catalytic | antagonistic | guardian | mirror | messenger | companion",\n'
        '    "symbolic_meaning": "what this being represents thematically",\n'
        '    "behavioral_traits": ["3-5 observable behaviors"],\n'
        '    "appearance": "concrete visual description for illustration",\n'
        '    "arc": "how their presence evolves across the story",\n'
        '    "tier": "1 | 2 | 3"  // 1=central, 2=recurring, 3=cameo\n'
        "  }\n"
        "]\n\n"
        "Return empty array [] if no significant non-human presences exist "
        "beyond those already in the cast.\n"
        "JSON only."
    )
    try:
        response = get_openai_prompt_response(
            prompt, temperature=0.4, max_completion_tokens=75000,
            openai_model=openai_model_large, use_grok=USE_GROK,
        )
        parsed = parse_json_response(response)
        if isinstance(parsed, list):
            return [p for p in parsed if isinstance(p, dict) and p.get('name')]
    except Exception as e:
        logger.warning(f"  Non-human detection failed ({e}); proceeding without.")
    return []


def _nonhuman_to_character(presence: Dict) -> 'Character':
    """Convert a non-human presence dict into a Character object.

    Non-human characters need a different profile than human ones:
    - No romantic_energy, humor_style, or dialect
    - behavioral_traits replaces personality traits
    - symbolic_meaning replaces backstory
    - narrative_function maps to role
    - character_type stored in personality_type (reuse existing field)
    """
    name  = presence.get('name', 'Unknown')
    ctype = presence.get('character_type', 'animal')
    traits = presence.get('behavioral_traits', [])
    if isinstance(traits, str):
        traits = [t.strip() for t in traits.split(',') if t.strip()]

    char = Character(
        name        = name,
        age         = presence.get('species', 'unknown species'),  # reuse age for species
        role        = presence.get('role', f'{ctype} character'),
        traits      = traits,
        backstory   = presence.get('symbolic_meaning', ''),
        appearance  = presence.get('appearance', ''),
        speech_pattern = '',        # non-humans don't have speech patterns
        arc         = presence.get('arc', ''),
        personality_type = ctype,   # 'animal' | 'spirit' | 'entity' etc.
        cognitive_style  = presence.get('narrative_function', ''),
        inner_world      = presence.get('symbolic_meaning', ''),
    )
    # Tag with character_type for downstream use
    char.character_type = ctype
    char.narrative_function = presence.get('narrative_function', '')
    char.symbolic_meaning   = presence.get('symbolic_meaning', '')
    char.species            = presence.get('species', '')
    return char


def _build_nonhuman_ei_node(char: 'Character', story_idea: 'StoryIdea',
                             all_characters: List['Character']) -> 'CharacterNode':
    """Build an EI CharacterNode for a non-human presence.

    Human psychological profiling (core_wound, defense_mechanism, lexical_habits)
    is meaningless for an eagle or a spirit. Instead we profile:
    - Behavioral traits (observable actions that create meaning)
    - Symbolic/archetypal register (what the being represents)
    - Narrative function (how it catalyses human characters)
    - Relationship dynamics with each human it touches
    - Its arc: how its presence evolves and what it leaves behind

    The EI graph then models the human's emotional response to the non-human
    rather than imputing human psychology onto the animal.
    """
    ctype   = getattr(char, 'character_type', 'animal')
    species = getattr(char, 'species', char.age)   # we stored species in age field
    sym     = getattr(char, 'symbolic_meaning', char.backstory)
    fn      = getattr(char, 'narrative_function', char.cognitive_style)

    human_chars = [c for c in all_characters
                   if getattr(c, 'character_type', 'human') == 'human']
    cast_ctx = '\n'.join(
        f"- {c.name} ({c.role}): {c.personality_type or ''}"
        for c in human_chars[:10]
    )

    # Trim cast context to 5 characters max — the full list inflates the
    # response size without adding meaningful relational signal for a
    # non-human entity.
    cast_ctx_trimmed = '\n'.join(
        f"- {c.name} ({c.role})"
        for c in human_chars[:5]
    )

    # ── Call A: scalar fields (archetype, wounds, voice, rhythm, arc) ──────────
    # Decomposed into two smaller calls so neither hits Grok's hard output ceiling.
    # Call A returns the 6 narrative descriptors + voice/rhythm/arc metadata.
    # Call B returns the two arrays (traits, self_components) + motif lists.
    prompt_a = (
        f"You are a narrative analyst profiling a NON-HUMAN character for an "
        f"emotional intelligence graph. Write rich, specific descriptions. "
        f"Target ~80 words total.\n\n"
        f"STORY: {story_idea.genre} | {story_idea.mood}\n"
        f"PREMISE: {story_idea.premise[:200]}\n\n"
        f"KEY HUMAN CAST:\n{cast_ctx_trimmed}\n\n"
        f"NON-HUMAN BEING:\n"
        f"  Name: {char.name} | Type: {ctype} ({species})\n"
        f"  Role: {char.role}\n"
        f"  Behavioral traits: {', '.join(char.traits[:4])}\n"
        f"  Symbolic meaning: {str(sym)[:120]}\n"
        f"  Narrative function: {fn}\n"
        f"  Arc: {str(char.arc)[:120]}\n\n"
        f"Return ONLY this JSON (no markdown). Each string value: 1 vivid sentence.\n\n"
        f"{{\n"
        f'  "archetype": "mythic/symbolic archetype",\n'
        f'  "core_wound": "what rupture or absence this being embodies",\n'
        f'  "core_longing": "the story need or force this being serves",\n'
        f'  "defense_mechanism": "how this being maintains its nature",\n'
        f'  "shadow": "what humans project onto or deny about this being",\n'
        f'  "growth_edge": "what this being makes possible in those it touches",\n'
        f'  "voice_signature": "how it communicates without words",\n'
        f'  "rhythm": "sudden | gradual | cyclical | crescendo",\n'
        f'  "arc_stage": "act1_setup",\n'
        f'  "arc_pressure": 0.0\n'
        f"}}"
    )

    # ── Call B: array fields (traits, self_components, motif lists) ──────────
    prompt_b = (
        f"You are a narrative analyst profiling a NON-HUMAN character for an "
        f"emotional intelligence graph. Target ~120 words total.\n\n"
        f"NON-HUMAN BEING:\n"
        f"  Name: {char.name} | Type: {ctype} ({species})\n"
        f"  Role: {char.role}\n"
        f"  Behavioral traits: {', '.join(char.traits[:4])}\n"
        f"  Symbolic meaning: {str(sym)[:120]}\n"
        f"  Narrative function: {fn}\n\n"
        f"Return ONLY this JSON (no markdown). 4-6 traits, 3-5 self_components.\n\n"
        f"{{\n"
        f'  "traits": [\n'
        f'    {{"name": "observable_behavior", "baseline": -1.0, "volatility": 0.3,\n'
        f'      "evidence": "how it shows in scenes (1 sentence)"}},\n'
        f'    ... 4-6 behavioral traits\n'
        f'  ],\n'
        f'  "self_components": [\n'
        f'    {{"name": "what this being represents", "category": "identity|goal|relational|ideological",\n'
        f'      "importance": 1-10, "state": "intact|threatened|lost|strengthened",\n'
        f'      "attached_to": "character name or null"}},\n'
        f'    ... 3-5 entries\n'
        f'  ],\n'
        f'  "lexical_habits": ["3-4 recurring visual or behavioral motifs"],\n'
        f'  "metaphor_pool": ["3-4 thematic domains this being embodies"]\n'
        f"}}"
    )

    def _array_fields_well_formed(d: dict) -> bool:
        """Call B's 'traits' / 'self_components' must be lists of objects.
        The model occasionally flattens them to lists of bare strings; treat
        that as a parse failure so we retry instead of silently dropping
        entries later."""
        for key in ('traits', 'self_components'):
            val = d.get(key)
            if val is not None and not (
                isinstance(val, list) and all(isinstance(item, dict) for item in val)
            ):
                return False
        return True

    MAX_RETRIES = 3
    parsed: Dict = {}

    for attempt in range(1, MAX_RETRIES + 1):
        try:
            raw_a = get_openai_prompt_response(
                prompt_a, temperature=0.6, max_completion_tokens=2000,
                openai_model=openai_model_large, use_grok=USE_GROK,
            )
            part_a = parse_json_response(raw_a)
            if part_a and isinstance(part_a, dict):
                parsed.update(part_a)
                break
            else:
                raise ValueError("Call A parse failed")
        except Exception as e:
            logger.warning(
                f"  Non-human EI node (Call A) for {char.name} "
                f"attempt {attempt}/{MAX_RETRIES} failed ({e})."
            )
            if attempt == MAX_RETRIES:
                logger.warning(
                    f"  Non-human EI node (Call A) for {char.name} "
                    f"failed after {MAX_RETRIES} attempts; using fallback."
                )

    for attempt in range(1, MAX_RETRIES + 1):
        try:
            raw_b = get_openai_prompt_response(
                prompt_b, temperature=0.6, max_completion_tokens=3000,
                openai_model=openai_model_large, use_grok=USE_GROK,
            )
            part_b = parse_json_response(raw_b)
            if part_b and isinstance(part_b, dict) and _array_fields_well_formed(part_b):
                parsed.update(part_b)
                break
            else:
                raise ValueError("Call B parse failed or returned malformed traits/self_components")
        except Exception as e:
            logger.warning(
                f"  Non-human EI node (Call B) for {char.name} "
                f"attempt {attempt}/{MAX_RETRIES} failed ({e})."
            )
            if attempt == MAX_RETRIES:
                logger.warning(
                    f"  Non-human EI node (Call B) for {char.name} "
                    f"failed after {MAX_RETRIES} attempts; using fallback."
                )

    # Build the node from the assembled parsed dict (both Call A + Call B merged)
    node = CharacterNode(
        name             = char.name,
        role             = char.role,
        archetype        = parsed.get('archetype', f'{ctype} — {fn}'),
        core_wound       = parsed.get('core_wound', sym),
        core_longing     = parsed.get('core_longing', fn),
        defense_mechanism= parsed.get('defense_mechanism', ''),
        shadow           = parsed.get('shadow', ''),
        growth_edge      = parsed.get('growth_edge', char.arc),
        voice_signature  = parsed.get('voice_signature',
                                      'Communicates through presence and behavior, not words.'),
        lexical_habits   = parsed.get('lexical_habits', char.traits[:3]),
        rhythm           = parsed.get('rhythm', 'cyclical'),
        metaphor_pool    = parsed.get('metaphor_pool', [sym]),
        arc_stage        = parsed.get('arc_stage', 'act1_setup'),
        arc_pressure     = float(parsed.get('arc_pressure', 0.0) or 0.0),
    )

    for t in (parsed.get('traits') or []):
        # The model occasionally returns a bare string (e.g. just the trait
        # name) instead of an object here; skip anything that isn't a dict
        # rather than letting .get() blow up with AttributeError.
        if not isinstance(t, dict):
            continue
        try:
            tname = t.get('name', '').strip()
            if not tname:
                continue
            baseline = max(-1.0, min(1.0, float(t.get('baseline', 0.0))))
            volatility = max(0.0, min(1.0, float(t.get('volatility', 0.3))))
            node.traits[tname] = DynamicTrait(
                name=tname, baseline=baseline, current=baseline,
                volatility=volatility,
            )
        except (TypeError, ValueError, AttributeError):
            continue

    for sc in (parsed.get('self_components') or []):
        # Same defensive check: the model sometimes flattens self_components
        # to a list of plain strings instead of objects.
        if not isinstance(sc, dict):
            continue
        try:
            scname = sc.get('name', '').strip()
            if not scname:
                continue
            node.self_components.append(SelfComponent(
                name       = scname,
                category   = sc.get('category', 'identity'),
                importance = int(sc.get('importance', 5)),
                state      = sc.get('state', 'intact'),
                attached_to= sc.get('attached_to') or None,
            ))
        except (TypeError, ValueError, AttributeError):
            continue

    return node


def _generate_comic_storyboard_surrogate(story_idea: 'StoryIdea', num_beats: int = 8) -> List[Dict]:
    """Quick storyboard for casting/graph init — not the comic script itself."""
    prompt = (
        f"Create {num_beats} major story beats for a comic book, graphic novel.\n\n"
        f"GENRE: {story_idea.genre}\nMOOD: {story_idea.mood}\n"
        f"THEMES: {', '.join(story_idea.themes)}\n"
        f"PREMISE: {story_idea.premise}\n\n"
        f"Each beat: 'chapter' (int 1-{num_beats}), 'setting', 'events' (array 1-2 items), "
        f"'twist' (or empty), 'intensity' ('low'|'medium'|'high'|'explosive').\n\n"
        f"Return JSON array. No markdown."
    )
    response = get_openai_prompt_response(
        prompt, temperature=0.6, openai_model=openai_model_large, use_grok=USE_GROK, max_completion_tokens=75000,
    )
    parsed = parse_json_response(response)
    if parsed and isinstance(parsed, list):
        return [b for b in parsed if isinstance(b, dict)]
    # Fallback: build something minimal
    return [
        {'chapter': i, 'setting': 'unspecified',
         'events': [f'Story beat {i}'], 'twist': '', 'intensity': 'medium'}
        for i in range(1, num_beats + 1)
    ]


# =============================================================================
# PHASE 2: COMIC SCRIPT GENERATION
# =============================================================================
# Generates the panel-by-panel script for the entire comic. Each panel gets:
#   - Visual description (what's depicted)
#   - Composition (close-up / medium / wide / etc.)
#   - Mood, sensory anchor, characters in frame
#   - Dialogue lines (per character, with bubble type)
#   - SFX (optional)
#   - Importance tier (splash, hero, standard, beat, reaction)
# =============================================================================

def generate_comic_script(story_idea: 'StoryIdea', characters: 'List[Character]',
                          graph: 'CharacterGraph', target_pages: int = 24,
                          panels_per_page_avg: int = 4,
                          required_beats: 'List[Dict]' = None,
                          story_idea_str: str = '',
                          visual_bible=None,
                          voice_profiles=None) -> 'List[Dict]':
    """Generate the full panel-by-panel script with beat-coverage validation."""
    # Guard: target_pages must be an int by this point. 'auto' should have been
    # resolved by the caller (synthesize_comic_book or from_story_idea); any
    # other string is a caller bug. Coerce with a clear message rather than
    # letting the arithmetic fail silently inside _generate_outline_span.
    if isinstance(target_pages, str):
        raise TypeError(
            f"generate_comic_script() received target_pages={target_pages!r} (str). "
            "Resolve 'auto' to an int before calling this function — "
            "see synthesize_comic_book() or StoryAnimator.from_story_idea() for the "
            "full pipeline (act detection → beat extraction → reconciliation → "
            "enrichment → growth guarantee)."
        )
    target_pages = int(target_pages)
    logger.info(f"[5/8] Generating comic script ({target_pages} pages target)...")
    
    # Generate outline with up to 2 retries if beat coverage is insufficient.
    # On a coverage miss we do NOT rebuild the whole book — we regenerate only
    # the section(s) that contain the missing beat(s) and keep every other
    # already-good section, so recovering one stray beat costs one LLM call
    # instead of the entire 15-section outline again.
    outline = None
    prior_outline = None
    repair_ids = None
    for attempt in range(3):
        if attempt == 0 or prior_outline is None or not repair_ids:
            outline = _generate_page_outline(
                story_idea, characters, graph, target_pages,
                required_beats=required_beats, story_idea_str=story_idea_str,
            )
        else:
            logger.info(
                "  [Outline] Targeted repair: regenerating only the section(s) "
                "containing %d missing beat(s), reusing the rest.",
                len(repair_ids),
            )
            outline = _generate_page_outline(
                story_idea, characters, graph, target_pages,
                required_beats=required_beats, story_idea_str=story_idea_str,
                prior_outline=prior_outline, repair_beat_ids=repair_ids,
            )
        if not outline:
            continue

        if required_beats:
            is_valid, missing = _validate_outline_coverage(outline, required_beats)
            if is_valid:
                logger.info(f"  Outline: {len(outline)} pages, all required beats covered")
                break
            else:
                logger.warning(
                    f"  Outline attempt {attempt+1}: {len(missing)} required "
                    f"beats missing"
                )
                for m in missing[:5]:
                    logger.warning(f"    Missing: {m}")
                # Remember the good outline + which beats to repair next attempt.
                prior_outline = outline
                repair_ids = {m.split(':', 1)[0].strip().lower()
                              for m in missing if m.split(':', 1)[0].strip()}
                if attempt == 2:
                    logger.warning(
                        "  Proceeding with partial coverage after 3 attempts"
                    )
        else:
            logger.info(f"  Outline: {len(outline)} pages planned")
            break
    
    if not outline:
        raise RuntimeError("Failed to generate page outline after 3 attempts")
    
    # Expand each page into panel-level detail in batches
    full_script = []
    batch_size = 4

    # Scene dramatic-engine pass — author each dialogue scene's objective,
    # opposition, turn, and tactics ON THE OUTLINE so the FIRST draft of every
    # line is written as characters pursuing a want against resistance, not
    # relaying plot. Stamped onto the outline pages, so it flows into both the
    # panel-expansion dialogue and (later) the dialogue review. Best-effort.
    try:
        annotate_scene_dramatic_engine(outline, story_idea, graph)
    except Exception as _se_e:
        logger.warning(f"  [SceneEngine] Skipped ({_se_e}).")

    for batch_start in range(0, len(outline), batch_size):
        batch = outline[batch_start:batch_start + batch_size]
        batch_pages = _expand_pages_to_panels(
            batch, story_idea, characters, graph,
            panels_per_page_avg, full_script,
            voice_profiles=voice_profiles,
        )
        # Re-attach beat_id (and act, if already set) from the outline into
        # the panel-expanded pages. The panel-expansion LLM prompt does not ask
        # for beat_id, so returned page objects never carry it — causing
        # _propagate_act_numbers to find no matches and forward-fill everything
        # as act '1', which means insert_act_breaks detects no transitions and
        # silently skips all act-break pages.
        outline_by_page = {op.get('page'): op for op in batch}
        for p in batch_pages:
            pnum = p.get('page')
            if pnum in outline_by_page:
                op = outline_by_page[pnum]
                if not p.get('beat_id'):
                    p['beat_id'] = op.get('beat_id', '')
                if not p.get('act') and op.get('act'):
                    p['act'] = op['act']
        full_script.extend(batch_pages)
        # Report actual page numbers from the returned objects, not array indices.
        returned_nums = sorted(p.get('page', '?') for p in batch_pages)
        requested_nums = sorted(p.get('page', '?') for p in batch)
        if returned_nums != requested_nums:
            logger.warning(
                f"  Batch pages {requested_nums} → got {returned_nums} "
                f"(fallback entries built for any gaps)"
            )
        else:
            nums = returned_nums
            logger.info(f"  Pages {nums[0]}-{nums[-1]} scripted")
    
    # Validate and repair any empty/malformed panels
    full_script = _validate_and_repair_panels(
        full_script, story_idea, characters, graph,
    )

    # Emotional physicality enrichment pass — rewrites panel descriptions with
    # specific, illustrator-grade physical/sensory detail for emotional beats,
    # and injects magic/spiritual VFX vocabulary where appropriate.
    # Runs AFTER repair (so repaired panels are also enriched) and BEFORE the
    # Art Director pass (which handles prop/costume disambiguation separately).
    full_script = _enrich_descriptions_with_physicality(
        full_script, story_idea,
    )

    # Art Director pass — fix "mask → medical mask" class of image-gen errors.
    # Runs AFTER _validate_and_repair_panels so repaired panels are also reviewed,
    # and BEFORE _enforce_shot_variety (which only touches composition, not descriptions).
    if visual_bible is not None:
        # Coverage audit + backfill FIRST: guarantee the bible isn't missing a
        # main character's costume, a signature prop, or a named location before
        # the review pass expands aliases against it. A missing costume means a
        # character's clothing drifts panel-to-panel even though their face is
        # locked by the appearance registry.
        try:
            from comic_book_art_director import audit_and_backfill_visual_bible
            _n_added = audit_and_backfill_visual_bible(
                visual_bible=visual_bible,
                characters=characters,
                script=full_script,
                story_idea=story_idea,
                story_idea_str=story_idea_str,
            )
            if _n_added:
                logger.info(
                    f"  Visual Bible: backfilled {_n_added} missing "
                    f"costume/prop/location entry(ies)."
                )
        except Exception as _vb_e:
            logger.warning(f"  Visual Bible coverage audit skipped ({_vb_e}).")

        full_script, ad_log = art_director_review_panels(
            full_script, visual_bible, story_idea, characters
        )
        if ad_log:
            logger.info(
                f"  Art Director: {len(ad_log)} description(s) corrected "
                f"for visual specificity."
            )

    # Enforce shot variety so pages don't read as flat repetition
    full_script = _enforce_shot_variety(full_script)

    # Enforce scene/character diversity: cap any single character/entity's panel
    # presence and vary a dominant non-human entity's manifestation, so the book
    # doesn't render the same presence (e.g. a leviathan) in every frame.
    full_script = _enforce_scene_diversity(full_script, characters)

    # NOTE: dramatic-hook shaping + page-turn reveal marking run later, in
    # synthesize_comic_book, AFTER the emotional arc is shaped — so hooks can
    # escalate toward the real climax and land on physical right-hand pages.

    return full_script


# ---------------------------------------------------------------------------
# PAGE-TURN REVEAL PASS
# ---------------------------------------------------------------------------
# In a printed book the reader cannot see the next page until they physically
# turn it, so the LAST panel of a right-hand (recto) page is the strongest place
# in the whole medium for a hook, reveal, or cliffhanger — the held breath
# before the turn. This pass identifies those panels and flags them so the
# layout reserves a big final slot AND the prompt pushes the image toward a
# compelling, curiosity-provoking beat.
#
# Recto/verso parity depends on the front matter that precedes the story pages
# (cover + title + credits, etc.), which shifts which physical side story page 1
# lands on. We account for that offset so "page turn" is physically correct.
# ---------------------------------------------------------------------------

# Front matter placed before the story body in the assembled book: cover,
# title page, credits/indicia. With this many leading leaves, story page 1's
# physical side = (front_matter + 1) parity. Kept as a constant so it tracks the
# assembler; if the assembler's front matter changes, update this in one place.
_FRONT_MATTER_LEAVES = 3   # cover, title, credits


def _shape_dramatic_hooks(script: 'List[Dict]',
                          emotional_arc: 'Dict' = None) -> 'List[Dict]':
    """Make the book a page-turner by shaping WHERE narrative hooks land.

    The script LLM sets a per-page `cliffhanger` flag with no craft guidance, so
    hooks end up arbitrary — often on left-hand (verso) pages where there is no
    physical page-turn to exploit, or absent for long stretches that let tension
    sag. This deterministic pass (run after the emotional arc is shaped, before
    the page-turn reveal pass reads the flags) enforces page-turner dramaturgy:

      1. OPENING HOOK — the first page carries a hook so the reader is gripped
         immediately (a graphic novel must earn the second page).
      2. RECTO PLACEMENT — hooks are biased onto right-hand pages, the only
         place a page-turn reveal can actually pay off. A hook the LLM put on a
         verso page is nudged to the adjacent recto page.
      3. CADENCE — a hook lands at least every few pages so momentum never
         stalls; long hookless runs get one added on their best recto page.
      4. ESCALATION — pages in the run-up to the climax (the tense back third)
         are made hook-dense so tension ratchets toward the peak.
      5. RESOLVE THE ENDING — the final page never cliffhangs; the book lands.

    Sets/clears each page's `cliffhanger` flag and marks `_opening_hook` on the
    first page. Idempotent and safe on any page count.
    """
    arc = emotional_arc or {}
    story_pages = [p for p in script if not p.get('_act_break')]
    n = len(story_pages)
    if n == 0:
        return script

    def _is_recto(page_idx0: int, page) -> bool:
        story_no = page.get('page', page_idx0 + 1)
        return ((_FRONT_MATTER_LEAVES + story_no) % 2 == 1)

    # Climax position (from the shaped arc) — escalate hooks toward it.
    climax_idx = None
    if arc:
        best = None
        for i, page in enumerate(story_pages):
            st = arc.get(page.get('page'), {})
            if st.get('is_climax'):
                climax_idx = i
                break
            inten = float(st.get('intensity', 0.0) or 0.0)
            if best is None or inten > best[1]:
                best = (i, inten)
        if climax_idx is None and best is not None:
            climax_idx = best[0]
    if climax_idx is None:
        climax_idx = int(round(0.78 * (n - 1)))

    # 1. Opening hook — grab the reader on page one. This is a CONTENT hook
    #    (a compelling first image/beat), tracked separately from `cliffhanger`
    #    which specifically means a page-TURN beat. If page one happens to be a
    #    recto page, it can also carry a true cliffhanger; otherwise we only set
    #    the content-hook marker so we don't flag a page-turn that can't happen.
    story_pages[0]['_opening_hook'] = True
    # Propagate to the page's panels so compose_panel_prompt (which sees panels,
    # not pages) can emphasise the opening image.
    for _p in (story_pages[0].get('panels') or []):
        _p['_opening_hook'] = True
    if n > 1 and _is_recto(0, story_pages[0]):
        story_pages[0]['cliffhanger'] = True

    # 2. Recto placement — move verso hooks to the neighbouring recto page.
    for i, page in enumerate(story_pages):
        if page.get('cliffhanger') and not _is_recto(i, page):
            # Prefer the next page if it's recto (the turn still follows the
            # beat); else the previous recto.
            moved = False
            if i + 1 < n and _is_recto(i + 1, story_pages[i + 1]):
                story_pages[i + 1]['cliffhanger'] = True
                moved = True
            elif i - 1 >= 0 and _is_recto(i - 1, story_pages[i - 1]):
                story_pages[i - 1]['cliffhanger'] = True
                moved = True
            if moved and not page.get('_opening_hook'):
                page['cliffhanger'] = False

    # 3 + 4. Cadence and escalation. Walk recto pages; ensure no long gap and
    # ramp density in the pre-climax stretch.
    last_hook = -99
    for i, page in enumerate(story_pages):
        if i == n - 1:
            continue  # ending handled below
        recto = _is_recto(i, page)
        if page.get('cliffhanger'):
            last_hook = i
            continue
        gap = i - last_hook
        in_runup = (climax_idx - 4) <= i < climax_idx     # tense pre-climax pages
        # Add a hook if we've gone too long without one, or we're ramping to the
        # climax — but only on recto pages so it can pay off at the turn.
        if recto and (gap >= 3 or (in_runup and gap >= 2)):
            page['cliffhanger'] = True
            last_hook = i

    # 5. The final page resolves — never end the book on a cliffhanger.
    story_pages[-1]['cliffhanger'] = False

    hooks = sum(1 for p in story_pages if p.get('cliffhanger'))
    logger.info(
        f"  Dramatic hooks: {hooks} page-turn hook(s) shaped across {n} pages "
        f"(opening hook set, ending resolved, climax≈p{story_pages[climax_idx].get('page')})"
    )
    return script


def _mark_page_turn_reveals(script: 'List[Dict]') -> 'List[Dict]':
    """Flag the final panel of each recto (right-hand) page that ends a beat as
    a page-turn reveal, so it gets a hero slot + a hook-forward prompt.

    A panel is marked when its page is a right-hand page AND either the page is
    a declared cliffhanger or it ends a scene (the next page moves elsewhere) or
    it is a high-importance page. We never override a 'splash' page (already a
    full reveal) and we set a lightweight sidecar the layout chooser and
    compose_panel_prompt read — no structural change to the script.
    """
    story_pages = [p for p in script if not p.get('_act_break')]
    n = len(story_pages)
    marked = 0

    for idx, page in enumerate(story_pages):
        panels = page.get('panels') or []
        if not panels:
            continue

        # Physical side: account for the leading front-matter leaves so parity
        # reflects the actual bound book, not just the story page number.
        story_page_no = page.get('page', idx + 1)
        physical_leaf = _FRONT_MATTER_LEAVES + story_page_no
        is_recto = (physical_leaf % 2 == 1)   # odd leaf = right-hand page

        # Does this page end a beat? cliffhanger flag, last story page, an
        # importance hook, or a scene change on the NEXT page.
        next_setting = ''
        if idx + 1 < n:
            nxt = story_pages[idx + 1]
            next_setting = (nxt.get('setting') or
                            (nxt.get('panels') or [{}])[0].get('setting', '') or '')
        this_setting = (page.get('setting') or panels[0].get('setting') or '')
        scene_ends = bool(this_setting) and _settings_differ_for_scene(this_setting, next_setting)

        ends_beat = (
            bool(page.get('cliffhanger', False))
            or scene_ends
            or page.get('importance', 'standard') in ('hero', 'climactic')
            or idx == n - 1   # final story page always lands its closing image
        )

        if is_recto and ends_beat and page.get('importance') != 'splash':
            last = panels[-1]
            # A deliberate quiet closer (e.g. resolution beat on the last page)
            # still benefits from emphasis, but we don't force a hook tone on a
            # gentle ending — only flag the hook intent for genuine cliffhangers.
            last['_page_turn_reveal'] = True
            last['_page_turn_hook'] = bool(page.get('cliffhanger', False)) or scene_ends
            # Nudge the page to end on its strongest slot so the reveal is big.
            page.setdefault('_hero_panel_pos', 'last')
            marked += 1

    if marked:
        logger.info(f"  Page-turn reveals: flagged {marked} pre-turn hook panel(s)")
    return script


# Shot grammar: a deliberate rhythm for varying camera within a scene. Real
# sequential art breathes — wide to establish, medium for action/dialogue,
# close for the emotional hit. Three identical shots in a row is the single
# most common thing that makes comic pages monotonous.
_SHOT_CYCLE = ['wide_shot', 'medium_shot', 'close_up', 'medium_shot']
_VALID_COMPOSITIONS = {
    'splash', 'extreme_close', 'close_up', 'medium_shot', 'wide_shot',
    'over_shoulder', 'dutch_angle', 'bird_eye', 'worm_eye', 'establishing',
}

def _settings_differ_for_scene(a: str, b: str) -> bool:
    """True when two setting strings denote different scenes/locations.

    Conservative token-overlap heuristic (mirrors the continuity tracker): a
    new scene is declared only when the settings share little vocabulary, so we
    don't re-establish every page of a long conversation in one room, but we DO
    open a wide grounding shot whenever the story actually moves.
    """
    a = (a or '').strip().lower()
    b = (b or '').strip().lower()
    if not a or not b:
        return bool(a) != bool(b)   # known→unknown counts as a move; unknown→unknown doesn't
    if a == b:
        return False
    _stop = {'the','a','an','in','on','at','of','and','with','to','into','near',
             'by','inside','outside','over','under','is','are','as','scene','shot',
             'view','interior','exterior','int','ext'}
    def toks(s):
        return {w for w in re.findall(r'[a-z0-9]+', s) if w not in _stop and len(w) > 2}
    ta, tb = toks(a), toks(b)
    if not ta or not tb:
        return False
    return (len(ta & tb) / max(1, len(ta | tb))) < 0.30


def _enforce_shot_variety(script: 'List[Dict]') -> 'List[Dict]':
    """Break up monotonous runs of identical shot types, and open every new
    scene with an establishing shot so the reader is always spatially grounded.

    Two distinct jobs:
      1. ESTABLISHING CADENCE: the first panel of a genuinely new scene (a
         location/time the story just moved to) is set to a wide establishing
         shot — the classic "where are we now" grounding beat — UNLESS the
         script deliberately wants a tight reveal there. We track the running
         setting across the whole book, so continuing in the same room does NOT
         trigger a redundant re-establish, and a one-panel detour back to a
         familiar place still re-grounds the reader.
      2. SHOT VARIETY: within a page, 3+ identical compositions in a row get the
         third retargeted from a cycle, so the eye always feels movement.

    We never override a panel explicitly marked 'splash', nor a deliberate
    close-up/reveal ('reaction'/'hero' importance, or an extreme-close intent).
    """
    adjusted = 0
    established = 0
    current_setting = ''

    for page in script:
        if page.get('_act_break'):
            continue
        panels = page.get('panels', []) or []
        if not panels:
            continue

        # Normalise missing/invalid compositions to medium_shot first.
        for p in panels:
            comp = str(p.get('composition', '')).strip()
            if comp not in _VALID_COMPOSITIONS:
                p['composition'] = 'medium_shot'

        # ── 1. Establishing cadence on scene change ──────────────────────────
        # Use the page setting (falling back to the first panel's setting) to
        # decide whether the story has moved to a new scene.
        page_setting = (page.get('setting') or panels[0].get('setting') or '').strip()
        scene_changed = _settings_differ_for_scene(page_setting, current_setting)
        if scene_changed and page_setting:
            first = panels[0]
            # Don't override a deliberate tight opener: a reveal/reaction/hero
            # beat or an extreme close-up is an intentional choice.
            deliberate_tight = (
                first.get('importance', 'standard') in ('reaction', 'hero', 'splash')
                or first.get('composition') in ('extreme_close', 'close_up')
                or bool(first.get('_no_establish'))
            )
            if not deliberate_tight and first.get('composition') != 'establishing':
                first['composition'] = 'establishing'
                first['_scene_establishing'] = True   # downstream prompt hint
                established += 1
                adjusted += 1
            current_setting = page_setting
        elif page_setting and not current_setting:
            current_setting = page_setting

        if len(panels) < 2:
            continue

        # ── 2. Shot variety within the page ──────────────────────────────────
        cycle_i = 0
        for i in range(2, len(panels)):
            a = panels[i - 2].get('composition')
            b = panels[i - 1].get('composition')
            c = panels[i].get('composition')
            if a == b == c and panels[i].get('importance', 'standard') != 'splash':
                for _ in range(len(_SHOT_CYCLE)):
                    cand = _SHOT_CYCLE[cycle_i % len(_SHOT_CYCLE)]
                    cycle_i += 1
                    if cand != c:
                        panels[i]['composition'] = cand
                        adjusted += 1
                        break

    if adjusted:
        logger.info(
            f"  Shot variety: adjusted {adjusted} panel(s) for visual rhythm "
            f"({established} new-scene establishing shot(s))"
        )
    return script


# ---------------------------------------------------------------------------
# SCENE / CHARACTER DIVERSITY PASS
# ---------------------------------------------------------------------------
# The rest of the pipeline is tuned hard for CONSISTENCY (locked appearances,
# scene anchors, page anchors) and even camera VARIETY (_enforce_shot_variety),
# but nothing measures or limits how often a single character/entity appears.
# A dominant presence — e.g. a leviathan, a cosmic force, an ever-present
# spirit — therefore tends to end up rendered in *every* panel, which makes the
# images monotonous. This deterministic pass is the safety-net that the prompt
# nudges cannot guarantee: it measures per-character panel presence and caps it,
# freeing panels for breathing room and (for non-human entities) varying the
# manifestation so even legitimate appearances never render the same way twice.

# Non-human character_type / personality_type tokens (set by _nonhuman_to_character).
_NONHUMAN_TYPES = {
    'animal', 'spirit', 'entity', 'force', 'deity', 'god', 'goddess', 'monster',
    'creature', 'machine', 'ai', 'cosmic', 'phenomenon', 'ghost', 'demon',
    'angel', 'elemental', 'leviathan', 'presence',
}
# Marker words that flag a name itself as a non-human presence even without a
# Character object. Self-contained (mirrors _NONCORPOREAL_MARKERS defined later
# in the file) plus corporeal monsters, so this works at import time.
_NONHUMAN_NAME_MARKERS = (
    'mythic', 'cosmic', 'celestial', 'divine', 'deity', 'deities', 'god',
    'goddess', 'pantheon', 'chorus', 'observer', 'spirit', 'eternal',
    'primordial', 'incorporeal', 'ethereal', 'phantom', 'apparition',
    'presence', 'angel', 'demon', 'ghost', 'entity', 'abstract', 'force',
    'leviathan', 'beast', 'monster', 'creature', 'dragon', 'kraken', 'titan',
    'serpent', 'behemoth', 'wyrm', 'colossus', 'null', 'void', 'swarm',
)

# Scale/form variations for a recurring non-human entity, ordered subtle →
# dominant. The pass rotates through these so the entity looms differently each
# time; the dominant forms are reserved for important/climactic panels.
_ENTITY_MANIFESTATION_VARIANTS = (
    "barely perceptible at the very edge of the frame, easily missed",
    "a faint, distant presence low on the horizon, small against the scene",
    "glimpsed only as a shadow or reflection — in water, glass, or a "
        "character's eyes — never shown directly",
    "a subtle disturbance of light, air, and shadow, its form barely coherent",
    "present at a middle distance, unmistakable but not dominating the frame",
    "a vast silhouette rising behind the scene, dwarfing the figures",
    "colossal and overwhelming, filling the sky as the undeniable focal subject",
)
_ENTITY_DOMINANT_VARIANTS = (5, 6)   # reserve these indices for important panels


SCENE_DIVERSITY_DEFAULTS = {
    'enabled':            True,
    'max_share':          0.60,   # no single character/entity in >60% of content panels
    'min_breathing_frac': 0.15,   # >=15% of content panels free of the dominant entity
    'vary_manifestation': True,   # rotate a non-human entity's scale/form
    'strategy':           'vary', # 'vary' (keep central, vary it) | 'thin' | float share
}
# Live config for the current run; set by synthesize_comic_book via
# set_scene_diversity(). Reads fall back to the defaults.
_SCENE_DIVERSITY = dict(SCENE_DIVERSITY_DEFAULTS)


def _resolve_scene_diversity_config(scene_diversity) -> Dict:
    """Map a public ``scene_diversity`` argument to a full config dict.

    Accepts:
      • None / 'auto' / True  → sensible defaults
      • False / 'off'         → disabled (pass is a no-op)
      • float in (0,1]        → that value becomes max_share
      • dict                  → overrides merged onto the defaults
    """
    cfg = dict(SCENE_DIVERSITY_DEFAULTS)
    if scene_diversity in (None, 'auto', True):
        return cfg
    if scene_diversity is False or scene_diversity == 'off':
        cfg['enabled'] = False
        return cfg
    if isinstance(scene_diversity, bool):
        return cfg
    if isinstance(scene_diversity, (int, float)):
        cfg['max_share'] = max(0.05, min(1.0, float(scene_diversity)))
        return cfg
    if isinstance(scene_diversity, dict):
        for k in cfg:
            if k in scene_diversity and scene_diversity[k] is not None:
                cfg[k] = scene_diversity[k]
        # allow a numeric 'strategy' to mean an explicit max share
        if isinstance(cfg.get('strategy'), (int, float)) and not isinstance(cfg['strategy'], bool):
            cfg['max_share'] = max(0.05, min(1.0, float(cfg['strategy'])))
        return cfg
    return cfg


def set_scene_diversity(scene_diversity) -> Dict:
    """Set the module-level scene-diversity config for the current run."""
    global _SCENE_DIVERSITY
    _SCENE_DIVERSITY = _resolve_scene_diversity_config(scene_diversity)
    return _SCENE_DIVERSITY


def _diversity_name_key(entry) -> str:
    """Normalise a characters_in_frame entry (str or {'name':..}) to a lower key."""
    if isinstance(entry, dict):
        entry = entry.get('name') or entry.get('character') or entry.get('character_name') or ''
    return str(entry or '').strip().lower()


def _looks_nonhuman_name(name: str) -> bool:
    low = (name or '').lower()
    return any(mk in low for mk in _NONHUMAN_NAME_MARKERS)


def _enforce_scene_diversity(script: 'List[Dict]',
                             characters: 'List[Character]' = None,
                             cfg: Dict = None) -> 'List[Dict]':
    """Cap how often any one character/entity appears, and vary a dominant
    non-human entity's manifestation so panels stop looking repetitive.

    Strategy (default 'vary', the recommended setting for a thematically central
    presence): the entity stays central — allowed in up to ``max_share`` of the
    story's content panels — but is removed from the panels where it is *least*
    essential (not named in the beat/description, not speaking), which both
    creates entity-free "breathing" panels and lets the focus land elsewhere.
    Wherever the entity remains, its ``manifestation_style`` is rotated through a
    scale/form palette (a far silhouette here, a faint shimmer there, a colossal
    presence at the climax) so no two appearances render alike.

    'thin' is the same but with a tighter cap (≈⅓ of panels); a float strategy
    sets an explicit max share. The pass never empties a *human* character panel
    — if removing a name would leave no subject, the panel is re-typed 'scenic'
    so it renders as an environment beat rather than a blank.

    Deterministic and side-effect-local: it only edits characters_in_frame,
    manifestation_style, and panel_type on the script dicts.
    """
    cfg = cfg or _SCENE_DIVERSITY
    if not cfg.get('enabled', True):
        return script

    max_share          = float(cfg.get('max_share', 0.60))
    min_breathing_frac = float(cfg.get('min_breathing_frac', 0.15))
    vary_manifestation = bool(cfg.get('vary_manifestation', True))
    strategy           = cfg.get('strategy', 'vary')

    # ── classify non-human names from the cast ────────────────────────────────
    nonhuman_names: set = set()
    for c in (characters or []):
        nm = (getattr(c, 'name', '') or '').strip().lower()
        if not nm:
            continue
        ct    = str(getattr(c, 'character_type', '') or '').lower()
        ptype = str(getattr(c, 'personality_type', '') or '').lower()
        if ct in _NONHUMAN_TYPES or ptype in _NONHUMAN_TYPES or _looks_nonhuman_name(nm):
            nonhuman_names.add(nm)

    def _is_nonhuman(name_key: str) -> bool:
        return name_key in nonhuman_names or _looks_nonhuman_name(name_key)

    # ── collect content panels (skip act-breaks and intentionally empty cosmic)
    content: List[Dict] = []
    for page in script:
        if page.get('_act_break'):
            continue
        page_beat = (str(page.get('beat', '')) + ' ' + str(page.get('title', ''))).lower()
        for panel in page.get('panels', []) or []:
            if str(panel.get('panel_type', 'character')).lower() == 'cosmic':
                continue
            names = {_diversity_name_key(n) for n in (panel.get('characters_in_frame', []) or [])}
            names.discard('')
            content.append({'panel': panel, 'names': names, 'page_beat': page_beat})

    total = len(content)
    if total < 4:
        return script   # too short for repetition to matter

    # ── frequency of each name across content panels ──────────────────────────
    from collections import Counter
    freq: Counter = Counter()
    for it in content:
        for n in it['names']:
            freq[n] += 1

    over = [(n, c) for n, c in freq.items() if c > max_share * total]
    over.sort(key=lambda x: -x[1])
    if not over:
        # Even with nothing over the cap, still vary manifestation for any
        # recurring non-human entity so repeated appearances differ.
        if vary_manifestation:
            _vary_entity_manifestations(content, [n for n in freq if _is_nonhuman(n)])
        return script

    def _essential_score(item: Dict, name_key: str) -> int:
        """Higher ⇒ more essential to keep the name in this panel."""
        panel = item['panel']
        score = 0
        # named in the beat/description ⇒ essential
        desc = str(panel.get('description', '')).lower()
        first_token = name_key.split()[0] if name_key.split() else name_key
        if first_token and (first_token in desc or first_token in item['page_beat']):
            score += 3
        # speaks in this panel ⇒ essential
        for d in (panel.get('dialogue', []) or []):
            spk = (d.get('speaker', '') if isinstance(d, dict) else '') or ''
            if spk and (spk.lower() == name_key or spk.lower().split()[:1] == name_key.split()[:1]):
                score += 2
                break
        # important panels keep their cast
        if str(panel.get('importance', 'standard')).lower() in ('splash', 'climactic', 'hero'):
            score += 2
        return score

    changed = 0
    # Effective cap also honours the breathing-room floor (whichever is tighter).
    breathing_cap = (1.0 - max(0.0, min(0.9, min_breathing_frac)))
    for name, cnt in over:
        nonhuman = _is_nonhuman(name)
        if strategy == 'thin':
            base_share = min(max_share, 0.34)
        elif isinstance(strategy, (int, float)) and not isinstance(strategy, bool):
            base_share = max(0.05, min(1.0, float(strategy)))
        else:                       # 'vary' (default)
            base_share = max_share
        target = int(min(base_share, breathing_cap) * total)
        target = max(0, min(cnt, target))
        to_remove = cnt - target
        if to_remove <= 0:
            continue

        holding = [it for it in content if name in it['names']]
        # least essential first; tie-break to break up consecutive runs
        holding.sort(key=lambda it: _essential_score(it, name))
        removed = 0
        for it in holding:
            if removed >= to_remove:
                break
            panel, names = it['panel'], it['names']
            others = [m for m in names if m != name]
            # never strip the last subject from a HUMAN character panel
            if not others and not nonhuman \
               and str(panel.get('panel_type', 'character')).lower() == 'character':
                continue
            # remove the name from characters_in_frame (case-insensitive)
            panel['characters_in_frame'] = [
                c for c in (panel.get('characters_in_frame', []) or [])
                if _diversity_name_key(c) != name
            ]
            it['names'] = set(others)
            panel.pop('manifestation_style', None)   # no longer in frame
            if not it['names'] and str(panel.get('panel_type', 'character')).lower() == 'character':
                panel['panel_type'] = 'scenic'        # becomes an environment beat
                panel['_diversity_scenic'] = True
            removed += 1
            changed += 1

    # ── vary manifestation for the entities that remain ───────────────────────
    if vary_manifestation:
        _vary_entity_manifestations(content, [n for n, _ in over if _is_nonhuman(n)])

    if changed:
        logger.info(
            f"  Scene diversity: thinned {changed} over-present appearance(s) "
            f"across {total} content panel(s) "
            f"[strategy={strategy}, max_share={max_share:.0%}]."
        )
    return script


def _vary_entity_manifestations(content: List[Dict], entity_keys: List[str]) -> None:
    """Rotate a non-human entity's manifestation_style across its appearances so
    no two consecutive panels render it the same way. Fills empties and breaks
    identical repeats; reserves the 'dominant' forms for important panels."""
    for name in entity_keys:
        appearances = [it for it in content if name in it['names']]
        if len(appearances) < 2:
            continue
        vi = 0
        prev_style = None
        for it in appearances:
            panel = it['panel']
            important = str(panel.get('importance', 'standard')).lower() in ('splash', 'climactic', 'hero')
            # pick the next variant; skip dominant forms unless the panel earns one
            for _ in range(len(_ENTITY_MANIFESTATION_VARIANTS)):
                idx = vi % len(_ENTITY_MANIFESTATION_VARIANTS)
                vi += 1
                if (idx in _ENTITY_DOMINANT_VARIANTS) and not important:
                    continue
                candidate = _ENTITY_MANIFESTATION_VARIANTS[idx]
                break
            else:
                candidate = _ENTITY_MANIFESTATION_VARIANTS[vi % len(_ENTITY_MANIFESTATION_VARIANTS)]
            existing = str(panel.get('manifestation_style', '') or '').strip()
            # Fill when empty, or rewrite when it would repeat the previous panel.
            if not existing or existing == prev_style:
                panel['manifestation_style'] = candidate
                prev_style = candidate
            else:
                prev_style = existing


# ---------------------------------------------------------------------------
# EMOTIONAL PHYSICALITY ENRICHMENT PASS
# ---------------------------------------------------------------------------

_PHYSICALITY_BATCH_SIZE = 14   # panels per LLM call (ID-keyed output; safe to batch)

def _enrich_descriptions_with_physicality(
    script: 'List[Dict]',
    story_idea: 'StoryIdea',
) -> 'List[Dict]':
    """Rewrite panel descriptions with specific, illustrator-grade physical and
    sensory language for emotional beats and magic/spiritual content.

    This pass runs after _validate_and_repair_panels. It identifies panels where
    the LLM used emotional labels ("she is devastated", "he looks afraid") or
    generic action verbs ("she cries", "he fights the darkness") and rewrites
    them with concrete visual language that a diffusion model can render:
      - Grief → shoulders drawn in, hollow gaze, swollen eyelids, tear tracks
      - Terror → pupils blown, grey skin, white-knuckled grip, body frozen
      - Magic → plasma arcs, volumetric light, crystalline refractions
      - Spiritual → god-rays, particle dissolve, inner luminescence

    Uses two strategies:
      1. Fast pattern-match (no LLM): detects strong emotion/magic signals and
         annotates the panel with an `_emotion_detail` sidecar field that
         compose_panel_prompt picks up.
      2. LLM batch rewrite: for panels where the description itself is weak
         (short, labels emotion instead of showing it), calls the LLM to rewrite
         the description in place. Batched to minimise API calls.
    """
    logger.info("  [Physicality] Enriching panel descriptions with emotional/visual detail...")

    panels_to_rewrite: list = []   # (page, panel) tuples needing LLM rewrite
    annotated = 0

    for page in script:
        if page.get('_act_break'):
            continue
        for panel in (page.get('panels') or []):
            desc = (panel.get('description') or '').strip()
            mood = (panel.get('mood') or '').strip()
            setting = (panel.get('setting') or '').strip()
            manifestation = (panel.get('manifestation_style') or '').strip()
            spiritual_intensity = str(panel.get('spiritual_intensity', '') or '').lower().strip()

            # Layer 1: fast annotation — store pre-computed clauses as sidecar
            # fields so compose_panel_prompt can inject them without LLM cost.
            emotion_clause = _build_emotion_physicality_clause(desc, mood)
            magic_clause   = _build_magic_vfx_clause(desc, setting, manifestation)
            tech_clause    = _build_technology_vfx_clause(desc, setting)
            atmo_clause    = _build_scene_atmosphere_clause(desc, mood)
            aura_clause    = _build_spiritual_aura_clause(desc, mood, spiritual_intensity, manifestation)
            if emotion_clause:
                panel['_emotion_physicality'] = emotion_clause
                annotated += 1
            if magic_clause:
                panel['_magic_vfx'] = magic_clause
                annotated += 1
            if tech_clause:
                panel['_technology_vfx'] = tech_clause
                annotated += 1
            if atmo_clause:
                panel['_scene_atmosphere'] = atmo_clause
                annotated += 1
            if aura_clause:
                panel['_spiritual_aura'] = aura_clause
                annotated += 1

            # Layer 2: flag for LLM rewrite if description is emotionally thin.
            # Criteria: description names emotions rather than showing them,
            # OR is short (< 60 chars), OR contains explicit label phrases.
            if _description_needs_enrichment(desc):
                panels_to_rewrite.append((page, panel))

    if annotated:
        logger.info(f"  [Physicality] Fast-annotated {annotated} panel(s) with emotion/VFX tokens.")

    if panels_to_rewrite:
        logger.info(
            f"  [Physicality] LLM-rewriting {len(panels_to_rewrite)} "
            f"emotionally thin panel description(s)..."
        )
        _physicality_llm_rewrite_batches(panels_to_rewrite, story_idea)

    return script


# ---------------------------------------------------------------------------
# EXPRESSION AMPLIFICATION PASS
# ---------------------------------------------------------------------------
# The writing often nails an emotion (a punchline, a moment of dread) that the
# art under-delivers, because diffusion models default to neutral, naturalistic
# faces. Comics — especially comedy — convey emotion through EXAGGERATION: the
# bigger the feeling, the broader the physical expression. This pass asks, per
# emotional beat, "what specific, exaggerated character attributes would make
# this feeling unmistakable in THIS story's register?" and injects them into
# the prompt. It adapts to genre: a comedy amplifies toward broad cartooning;
# a drama amplifies toward intense but grounded physicality.
# ---------------------------------------------------------------------------

_AMPLIFY_BATCH_SIZE = 16   # index-keyed one-sentence output; safe to batch larger

# Story tones that license broad, exaggerated, cartoon-style expression.
_COMEDIC_GENRE_SIGNALS = (
    'comedy', 'comedic', 'humor', 'humour', 'humorous', 'satire', 'satirical',
    'parody', 'farce', 'sitcom', 'slapstick', 'rom-com', 'romantic comedy',
    'spoof', 'lighthearted', 'light-hearted', 'whimsical', 'absurdist',
    'screwball', 'gag', 'caper', 'feel-good',
)


def _story_expression_register(story_idea: 'StoryIdea') -> str:
    """Classify how broadly expressions should be amplified for this story.

    Returns 'comedic' (broad, exaggerated cartooning), 'dramatic' (intense but
    grounded), or 'neutral'. Driven by genre + tone/mood so the amplification
    matches the book — a farce gets rubber-faced mugging, a thriller gets taut
    realism.
    """
    blob = ' '.join(str(getattr(story_idea, f, '') or '') for f in
                    ('genre', 'tone', 'mood')).lower()
    themes = getattr(story_idea, 'themes', None) or []
    blob += ' ' + ' '.join(str(t).lower() for t in themes)
    if any(sig in blob for sig in _COMEDIC_GENRE_SIGNALS):
        return 'comedic'
    if any(sig in blob for sig in (
            'drama', 'tragedy', 'tragic', 'thriller', 'horror', 'noir',
            'tense', 'grim', 'dark', 'serious', 'epic', 'war')):
        return 'dramatic'
    return 'neutral'


# Lightweight signal that a panel carries an emotional beat worth amplifying.
_EMOTION_BEAT_RE = _emo_re.compile(
    # Word-boundary anchored so emotion STEMS only match at a word start and are
    # never triggered by an incidental substring (the old un-anchored form fired
    # on "gloved" (love), "pilgrim" (grim), "saddle" (sad), "smith" (smit),
    # "sobriety" (sob), etc., which falsely flagged panels and bloated prompts).
    # Prefix stems allow a trailing word-continuation (\w*); short whole-word
    # emotions that are dangerous as prefixes are matched as whole words only.
    r'\b(?:laugh|funny|joke|hilar|smug|smirk|awkward|cringe|embarrass|mischiev|'
    r'panic|exasperat|deadpan|eye-roll|double[- ]take|grin|gasp|shock|stunned|'
    r'furious|raging|enraged|angry|anger|terrif|afraid|dread|grief|griev|weep|'
    r'cries|crying|despair|joyful|triumph|elat|ecstat|euphor|lov(?:e|ed|es|ing|er|ely)|'
    r'fear|tender|guilt|asham|betray|disgust|horror|delight|gleeful|shout|'
    r'scream|beaming|fuming|sulk|wince|flinch|recoil|swoon|giddy|smitten|'
    r'jubil|devastat|heartbroken|mortified|flustered|gloat|sadden|sadness|sorrow|'
    r'melancholy|melancholic|wistful|anguish|bitter|grimac|tense|tension|'
    r'anxious|anxiety|nervous|hopeful|hopeless|serene|peaceful|relief|'
    r'relieved|nostalg|longing|yearn|wonder|tenderness|happy|content|'
    r'frighten|menac|sinister|eerie|warmth|affection|excited|thrill)\w*'
    r'|\bsob(?:s|bed|bing)?\b'
    r'|\b(?:sad|grim|rage|hope|peace|awe|glee|joy|calm|pout|weep|cry|grin)\b',
    _emo_re.IGNORECASE)


_EMOTION_BUCKETS = [
    ('anger',    _emo_re.compile(r'\b(anger|angry|furious|rage|raging|fuming|seeth|irate|livid|wrath|incens|hostile|contempt|scowl)\w*', _emo_re.IGNORECASE)),
    ('frustration', _emo_re.compile(r'\b(frustrat|exasperat|aggravat|annoy|irritat|vexed|fed up|had enough|last straw|grumbl|huff|through gritted|clench\w* jaw|pinch\w* the bridge)\w*', _emo_re.IGNORECASE)),
    ('fear',     _emo_re.compile(r'\b(fear|afraid|terrif|scared|dread|panic|horror|frighten|petrified|alarm|trembl)\w*', _emo_re.IGNORECASE)),
    ('sadness',  _emo_re.compile(r'\b(sad|sorrow|grief|griev|weep|cry|cries|crying|sob|despair|anguish|heartbroke|devastat|melanchol|mourn|wistful|forlorn|tears?)\w*', _emo_re.IGNORECASE)),
    ('excitement', _emo_re.compile(r'\b(excit|thrill|exhilar|eager|elated by|can.?t wait|buzzing|electrifi|pumped|fired up|anticipat|giddy with|breathless with|lights? up|leaps? up|opportunit)\w*', _emo_re.IGNORECASE)),
    ('joy',      _emo_re.compile(r'\b(joy|joyful|happy|happi|delight|glee|gleeful|elat|ecstat|euphor|triumph|jubil|beaming|grin|laugh|radiant)\w*', _emo_re.IGNORECASE)),
    ('tender',   _emo_re.compile(r'\b(tender|love|loving|affection|warmth|warm|gentle|intimate|fond|caring|adoring|soft)\w*', _emo_re.IGNORECASE)),
    ('disgust',  _emo_re.compile(r'\b(disgust|revuls|repuls|nause|contempt|sneer|loath)\w*', _emo_re.IGNORECASE)),
    ('surprise', _emo_re.compile(r'\b(shock|stunned|surpris|astonish|gasp|startl|dumbfound|aghast|amazed)\w*', _emo_re.IGNORECASE)),
    ('wonder',   _emo_re.compile(r'\b(wonder|awe|awestruck|marvel|breathtaking|spellbound|reverent|transfixed|beauty of|beautiful vista|majest|sublime|transcend)\w*', _emo_re.IGNORECASE)),
    ('tension',  _emo_re.compile(r'\b(tense|tension|anxious|anxiety|nervous|unease|apprehens|wary|on edge|suspicious|guarded)\w*', _emo_re.IGNORECASE)),
    ('calm',     _emo_re.compile(r'\b(calm|serene|peace|peaceful|content|relaxed|relief|relieved|composed|tranquil|settled)\w*', _emo_re.IGNORECASE)),
]

# Description verbs that already SHOW an emotional transition — when present we
# don't need to inject a continuity note (the shift is already staged).
_TRANSITION_CUE_RE = _emo_re.compile(
    r'\b(wipe[sd]?|compos|steady|steadie|calm(?:s|ing|ed)?|collect|regain|'
    r'soften[s]?|softening|harden[s]?|hardening|shift[s]?|shifting|turn[s]?\s|'
    r'break[s]?\s+down|breaking\s+down|crumbl|melt[s]?|brighten|darken|'
    r'stiffen|slump|straighten|recover|swallow[s]?|steel[s]?|masks?\b|'
    r'forcing\s+a|forces\s+a|fights?\s+back|blink[s]?\s+away)',
    _emo_re.IGNORECASE)


def _classify_emotion_bucket(text: str) -> str:
    """Map an emotion phrase to a coarse bucket, or '' if none matches.

    Coarse buckets let the continuity tracker fire only on GENUINE emotional
    shifts (anger → grief) and stay silent on synonyms (sad → sorrow), so it
    adds signal, not noise.
    """
    if not text:
        return ''
    for bucket, rx in _EMOTION_BUCKETS:
        if rx.search(text):
            return bucket
    return ''


def _panel_char_emotion(panel: Dict, char: str) -> str:
    """Best-effort dominant emotion phrase for one character in one panel.

    Priority: a dialogue line spoken by this character that carries an
    emotion/delivery field, then the panel's own mood/emotional_tone, then the
    arc's authored emotion for the page. Returns '' when nothing is detectable.
    """
    ckey = str(char or '').strip().lower()
    for d in (panel.get('dialogue') or []):
        if not isinstance(d, dict):
            continue
        if str(d.get('speaker', '') or '').strip().lower() == ckey:
            for fld in ('emotion', 'delivery'):
                v = str(d.get(fld, '') or '').strip()
                if v:
                    return v
            bt = str(d.get('bubble_type', '') or '').strip().lower()
            if bt in ('shout', 'angry', 'excited', 'sarcastic', 'scared',
                      'tender', 'cold', 'whisper'):
                return bt
    for fld in ('mood', 'emotional_tone'):
        v = str(panel.get(fld, '') or '').strip()
        if v:
            return v
    return str(panel.get('_arc_emotion', '') or '').strip()


# =============================================================================
# EMOTION-DRIVEN CLOSE-UP SELECTION
# -----------------------------------------------------------------------------
# The eyes are the gateway to the soul: a reader connects to a character most
# strongly when the art frames tight on a face at the moment a feeling TURNS —
# a kind or harsh word lands, an opportunity sparks excitement, a spilled drink
# curdles ease into frustration, or a character is stopped by a moment of beauty.
# The pipeline already renders eye-focus when a panel's composition is a
# close-up (the lens clause becomes "razor-sharp focus on the subject's eyes"),
# and _COMPOSITION_DESIGN already stages wonder/awe/intimacy — but nothing was
# CHOOSING a close-up because the story reached an emotional turn. This pass
# does exactly that, deterministically, using the authored emotional arc as its
# intensity signal and the per-scene emotion buckets as its turn detector.
#
# Rules honoured:
#   • At most ONE forced close-up per page (kept special, never mechanical).
#   • Never on a scene's establishing panel (the first panel of a new setting),
#     which must show the space.
#   • A carve-out for VAST/WIDE feelings — awe at a landscape, isolation,
#     grief-as-emptiness — where the emotion lives in scale, not a single face;
#     these stay wide. (Wonder AT NATURE is special-cased: the vista stays wide
#     and the character's wide-eyed reaction earns the close-up on an adjacent
#     panel.)
#   • At peak arc intensity the close-up is promoted to a FULL-PAGE SPLASH on
#     its own page (page count grows for that beat) so the moment lands with a
#     reader's full attention — handled downstream by promote_emotional_splash_pages.
# =============================================================================

# Emotions whose power is SCALE, not a single face — these must NOT be forced
# into a close-up; they read best wide, the figure small against the immense.
_VAST_EMOTION_BUCKETS = frozenset({'wonder'})   # bucket-level guard (see also phrase guard)
_VAST_EMOTION_PHRASE_RE = _emo_re.compile(
    r'\b(awe|awestruck|vast|vastness|immense|immensity|infinite|infinity|'
    r'insignifican|dwarfed|tiny against|small against|overwhelm\w* scale|'
    r'sublime|majest|cosmic|the void|endless|boundless|sweeping vista|'
    r'isolation|isolated|utterly alone|profound\w* alone|empty\w* around|'
    r'lost in the|grand scale|towering above)\b', _emo_re.IGNORECASE)

# Wonder specifically AT NATURE'S BEAUTY — a character stopped by a beautiful
# view. The vista is wide; the FACE taking it in earns the close-up cutaway.
_WONDER_AT_NATURE_RE = _emo_re.compile(
    r'\b(gaz\w*|star\w*|look\w*|watch\w*|behold\w*|takes? in|drink\w* in|'
    r'transfixed|spellbound|breath\w* catch\w*|stops? to)\b.{0,40}\b('
    r'sunset|sunrise|dawn|dusk|horizon|vista|landscape|mountains?|ocean|sea|'
    r'valley|forest|stars?|sky|aurora|waterfall|meadow|blossom\w*|'
    r'nature|beauty|view|panorama|shoreline|wildflowers?)\b',
    _emo_re.IGNORECASE)

# Compositions that already show a wide/environmental frame — a forced close-up
# would fight the story's deliberate choice, so we leave these alone.
_WIDE_COMPOSITIONS = frozenset({
    'wide_shot', 'establishing', 'bird_eye', 'worm_eye', 'extreme_wide',
})
_WIDE_PANEL_TYPES = frozenset({'scenic', 'cosmic'})


def _closeup_intensity_for_page(page_num: int, emotional_arc: Dict) -> Tuple[float, str, str]:
    """Return (intensity, key_emotion, stage) for a page from the arc, safely."""
    if not isinstance(emotional_arc, dict):
        return 0.5, '', ''
    st = emotional_arc.get(page_num) or {}
    try:
        inten = float(st.get('intensity', 0.5) or 0.5)
    except (TypeError, ValueError):
        inten = 0.5
    return inten, str(st.get('key_emotion', '') or ''), str(st.get('stage', '') or '')


def _panel_is_wide_by_design(panel: Dict) -> bool:
    """True when a panel is deliberately a wide/environmental frame that a
    forced close-up should not override."""
    comp = str(panel.get('composition', '') or '').lower()
    ptype = str(panel.get('panel_type', '') or '').lower()
    if comp in _WIDE_COMPOSITIONS:
        return True
    if ptype in _WIDE_PANEL_TYPES:
        return True
    return False


def _emotion_is_vast(phrase: str, bucket: str, desc: str) -> bool:
    """True when the feeling in play lives in SCALE (awe at a landscape,
    isolation, grief-as-emptiness) and should stay WIDE, not close.

    Wonder AT NATURE is deliberately NOT treated as vast here — it earns a
    face cutaway — so it is excluded before the vast test.
    """
    blob = f"{phrase} {desc}"
    if _WONDER_AT_NATURE_RE.search(blob):
        return False
    if bucket in _VAST_EMOTION_BUCKETS:
        return True
    if _VAST_EMOTION_PHRASE_RE.search(blob):
        return True
    return False


def track_emotional_continuity(script: 'List[Dict]',
                               emotional_arc: Dict = None) -> int:
    """Prevent emotional whiplash AND select emotion-driven close-ups.

    Two deterministic jobs in one scene-aware walk:

    1. EMOTIONAL CONTINUITY (original): flag panels where a character's feeling
       jumps between adjacent panels of the same scene with no transition shown,
       so the art renders the CHANGE rather than snapping to an unrelated
       expression. Memory resets on a scene change or act change.

    2. EMOTION-DRIVEN CLOSE-UP (new): on each page, find the single strongest
       emotional TURN — a bucket change (ease -> frustration, tension -> relief),
       weighted by the authored arc intensity for that page — and, when it is
       appropriate, frame that panel as a close-up so the eyes carry the moment.
       At most one per page; never the establishing panel; and vast/wide
       feelings (awe at scale, isolation, emptiness) are left wide. At peak
       intensity the chosen panel is flagged for full-page-splash promotion.
       The per-page arc emotion/intensity/stage is stamped onto every panel so
       the signal survives any later page renumbering (splash promotion inserts
       pages).

    Returns the number of transition notes added. Pure/deterministic, no LLM.
    """
    if not script:
        return 0
    arc = emotional_arc or {}
    last_bucket: Dict[str, str] = {}
    last_phrase: Dict[str, str] = {}
    prev_scene_key = None
    added = 0
    closeups_selected = 0

    for page in script:
        if page.get('_act_break') or page.get('_prologue'):
            continue
        scene_key = (str(page.get('setting', '') or '').strip().lower()
                     + '|' + str(page.get('act', '1')))
        is_new_scene = scene_key != prev_scene_key
        if is_new_scene:
            last_bucket.clear()
            last_phrase.clear()
            prev_scene_key = scene_key

        pnum = page.get('page', 0)
        page_intensity, page_key_emotion, page_stage = _closeup_intensity_for_page(pnum, arc)

        panels = [p for p in (page.get('panels') or []) if isinstance(p, dict)]

        # Candidate close-up targets on THIS page: (score, panel, panel_pos).
        closeup_candidates: List[Tuple[float, Dict, int]] = []

        for _pos, panel in enumerate(panels):
            desc = str(panel.get('description', '') or '')
            has_cue = bool(_TRANSITION_CUE_RE.search(desc))
            chars = panel.get('characters_in_frame') or []

            # Track the strongest per-character turn on this panel for close-up scoring.
            panel_turn_strength = 0.0
            panel_turn_phrase = ''
            panel_turn_bucket = ''

            for char in chars:
                name = str(char or '').strip()
                if not name or name.upper() == 'NARRATOR':
                    continue
                # Emotion from the panel's OWN signals only. We intentionally do
                # NOT stamp _arc_emotion before this point: _panel_char_emotion
                # falls back to _arc_emotion, and the page-level arc emotion is a
                # single value for every panel — stamping it first would make
                # every panel read the same bucket and manufacture phantom turns.
                phrase = _panel_char_emotion(panel, name)
                bucket = _classify_emotion_bucket(f"{phrase} {desc}")
                if not bucket:
                    continue
                prev = last_bucket.get(name)
                if prev and prev != bucket:
                    # A genuine turn. Continuity note (unless already staged).
                    if not has_cue:
                        note = (
                            f"Emotional continuity: {name} read as "
                            f"{last_phrase.get(name, prev)} a beat ago and is "
                            f"{phrase or bucket} now — render the visible shift on "
                            f"{name}'s face and posture (a person mid-change, not a "
                            f"neutral reset)."
                        )
                        existing = str(panel.get('_emotion_transition', '') or '')
                        panel['_emotion_transition'] = (
                            (existing + ' ' + note).strip() if existing else note
                        )
                        added += 1
                    # Turn strength for close-up scoring: a bucket change is the
                    # strongest signal; scale it by the page's arc intensity so a
                    # turn on a loud page beats an incidental one on a quiet page.
                    strength = 1.0 + page_intensity
                    if strength > panel_turn_strength:
                        panel_turn_strength = strength
                        panel_turn_phrase = phrase or bucket
                        panel_turn_bucket = bucket
                elif not prev and bucket and _pos > 0:
                    # First clear emotion for this character mid-scene (not the
                    # establishing panel) is a mild close-up candidate, scaled
                    # down — a turn is preferred, but a strong first feeling on a
                    # high-intensity page can still earn the frame.
                    strength = 0.4 * (1.0 + page_intensity)
                    if strength > panel_turn_strength:
                        panel_turn_strength = strength
                        panel_turn_phrase = phrase or bucket
                        panel_turn_bucket = bucket
                last_bucket[name] = bucket
                last_phrase[name] = phrase or bucket

            # Register this panel as a close-up candidate if it carries a turn,
            # isn't the establishing panel, isn't already wide by design, and the
            # feeling isn't one that should stay wide.
            if (panel_turn_strength > 0.0
                    and _pos > 0
                    and chars
                    and not _panel_is_wide_by_design(panel)
                    and not _emotion_is_vast(panel_turn_phrase, panel_turn_bucket, desc)):
                # A wonder-at-nature beat gets a boost — it's exactly the kind of
                # soul-moment the reader should share from the character's face.
                if _WONDER_AT_NATURE_RE.search(f"{panel_turn_phrase} {desc}"):
                    panel_turn_strength += 0.5
                    panel['_wonder_at_nature'] = True
                closeup_candidates.append((panel_turn_strength, panel, _pos))

            # NOW stamp arc data onto the panel (after emotion detection, so the
            # page-level arc emotion never pollutes per-panel turn detection).
            # This travels with the panel through any later page renumbering
            # (splash promotion inserts a page), keeping emotion/intensity/stage
            # aligned even when page indices shift.
            if page_key_emotion:
                panel.setdefault('_arc_emotion', page_key_emotion)
            panel.setdefault('_arc_intensity', page_intensity)
            if page_stage:
                panel.setdefault('_arc_stage', page_stage)
            # Carry the beat critic's emotional-peak marker down to the panel so
            # the expression amplifier knows to push passion/drama hardest here.
            _pst = arc.get(pnum) if isinstance(arc, dict) else None
            if isinstance(_pst, dict) and _pst.get('_beat_peak'):
                panel.setdefault('_arc_beat_peak', True)

        # Select at most ONE close-up per page: the strongest candidate.
        if closeup_candidates:
            closeup_candidates.sort(key=lambda t: t[0], reverse=True)
            best_strength, best_panel, best_pos = closeup_candidates[0]
            _apply_emotion_closeup(best_panel, page, page_intensity, page_stage)
            closeups_selected += 1

    if added:
        logger.info(
            "  [EmotionContinuity] Flagged %d panel(s) with an emotional shift "
            "so the art renders the transition instead of snapping.", added,
        )
    if closeups_selected:
        logger.info(
            "  [EmotionCloseup] Selected %d emotion-driven close-up(s) — one per "
            "page at the strongest turn — to frame the eyes at the moment feeling "
            "lands.", closeups_selected,
        )
    return added


def _apply_emotion_closeup(panel: Dict, page: Dict,
                           intensity: float, stage: str) -> None:
    """Frame a chosen panel as an emotion-driven close-up.

    Sets composition to close_up (or extreme_close at high intensity), marks the
    panel as a reaction beat, and records `_emotion_closeup`. At peak intensity
    the panel is flagged `_emotion_closeup_splash` so promote_emotional_splash_pages
    lifts it onto its own full page (growing the beat's page count) — the moment
    then commands the reader's full attention with nowhere else for the eye to go.
    """
    peak = (intensity >= 0.8) or (str(stage or '').lower() in ('peak', 'climax'))
    panel['composition'] = 'extreme_close' if peak else 'close_up'
    # Only elevate importance toward 'reaction' when it isn't already a stronger
    # structural role (splash/hero/climactic keep their weight).
    if str(panel.get('importance', 'standard')).lower() in ('standard', 'beat', ''):
        panel['importance'] = 'reaction'
    panel['_emotion_closeup'] = True
    # A short, explicit art direction so the eyes lead even before the lens
    # clause and physicality table add their detail.
    eye_note = (
        "Frame this as an intimate close-up on the character's face, the eyes as "
        "the focal point — pupils, gaze, and the fine muscles around the eyes "
        "carrying the emotion; the feeling lands in the look before anything else."
    )
    existing = str(panel.get('_emotion_closeup_note', '') or '')
    panel['_emotion_closeup_note'] = (
        (existing + ' ' + eye_note).strip() if existing else eye_note
    )
    if peak:
        panel['_emotion_closeup_splash'] = True
        page['_wants_emotion_splash'] = True


_SEDUCTION_RE = _emo_re.compile(
    r'\b(seduc|desire|arous|lust|sensual|intimate|erotic|passion|attract|'
    r'longing|yearn|flirt|tender|caress|embrace|kiss|breathless|heat|'
    r'romance|romantic|sultry|allure)\w*', _emo_re.IGNORECASE,
)
_COMEDY_RE = _emo_re.compile(
    r'\b(comic|comedy|funny|hilarious|absurd|ridiculous|slapstick|joke|'
    r'silly|goofy|banter|witty|farce|prank|mischief|deadpan|awkward)\w*',
    _emo_re.IGNORECASE,
)
_DRAMA_RE = _emo_re.compile(
    r'\b(furious|rage|wrath|grief|anguish|despair|terror|betray|heartbreak|'
    r'devastat|desperate|vengeance|agony|dread|climax|confront|reckon)\w*',
    _emo_re.IGNORECASE,
)


def _passion_register_note(blob: str, intensity) -> str:
    """Return a register-specific craft cue for panels whose feeling lives in
    seduction, comedy, or high drama — the three registers where a generic
    'show the emotion' note under-delivers the specific physical language each
    demands. Empty when none applies.
    """
    try:
        hot = float(intensity or 0.5) >= 0.55
    except (TypeError, ValueError):
        hot = True
    if _SEDUCTION_RE.search(blob):
        return (" [SEDUCTION — render desire in the body: a lowered gaze that "
                "lifts, parted lips, the charged inches of proximity, a hand "
                "that hovers before it touches, weight shifted toward the other; "
                "heat through tension and restraint, tasteful but unmistakable]")
    if _COMEDY_RE.search(blob):
        return (" [COMEDY — push the physical comedy: oversized reaction, "
                "rubber-faced mugging, a double-take, wide eyes and dropped jaw, "
                "comic timing frozen at its funniest instant; land the joke on "
                "the face and body]")
    if hot and _DRAMA_RE.search(blob):
        return (" [HIGH DRAMA — the whole body commits: taut muscles, a face "
                "cracked open by the feeling, white-knuckled hands, the posture "
                "of someone at their breaking point; no restraint, this is the "
                "storm]")
    return ""


def amplify_panel_expressions(
    script: 'List[Dict]',
    story_idea: 'StoryIdea',
    register: str = '',
    emotional_arc: 'Dict' = None,
) -> 'List[Dict]':
    """Inject exaggerated, register-appropriate character-expression attributes
    into emotionally-charged panels so the ART conveys the feeling as strongly
    as the WRITING does.

    For each panel that carries an emotional beat, the LLM is asked what
    specific, exaggerated physical attributes (face, eyes, brows, mouth,
    posture, hands, comic devices like sweat-drops or motion) would make that
    emotion unmistakable in this story's register. The answer is stored as a
    sidecar `_expression_amplify` clause that compose_panel_prompt injects — it
    never overwrites the description, so continuity and other passes are intact.

    When an ``emotional_arc`` is supplied, amplification becomes intensity-aware:
    the per-page intensity is passed to the model so loud/climactic beats get
    pushed harder than quiet ones, and the arc's coherent ``key_emotion`` is
    offered as a hint alongside the panel's own mood. This is what lets the
    amplification track the book's emotional journey rather than treating every
    beat at one volume.

    Batched to keep API cost low; only panels with a detectable emotional beat
    are sent. Degrades gracefully: any failure simply leaves panels unamplified.
    """
    register = register or _story_expression_register(story_idea)
    arc = emotional_arc or {}

    # Collect emotional-beat panels, tagging each with its page's arc data so
    # the prompt can scale exaggeration by intensity and borrow the arc emotion.
    targets: list = []           # (panel, page_intensity, arc_emotion)
    _skipped_enriched = 0
    for page in script:
        if page.get('_act_break'):
            continue
        page_no = page.get('page')
        arc_state = arc.get(page_no, {}) if isinstance(arc, dict) else {}
        page_intensity = arc_state.get('intensity')
        arc_emotion = str(arc_state.get('key_emotion', '') or '')
        for panel in (page.get('panels') or []):
            desc = (panel.get('description') or '')
            mood = (panel.get('mood') or '')
            # A panel's OWN text showing an emotional beat always qualifies —
            # that's a genuine beat the art should push.
            own_beat = bool(_EMOTION_BEAT_RE.search(f"{desc} {mood}"))
            # A panel qualifies if its own text shows a beat OR (when we have an
            # arc) the page is emotionally loud enough to warrant amplification.
            loud = (page_intensity is not None and float(page_intensity) >= 0.6)
            if not (own_beat or loud):
                continue
            # SKIP CONDITION (cost saver, quality-neutral): when a panel qualifies
            # ONLY because its page is loud — not from its own text — and it has
            # already been enriched with concrete physical expression detail by
            # the physicality pass (a substantial `_emotion_physicality` sidecar)
            # AND its description is already visually detailed (long, no bare
            # emotion label), amplifying again is redundant: the art already has
            # specific, intensity-appropriate direction. Panels with their own
            # emotional beat are never skipped.
            if loud and not own_beat:
                already = str(panel.get('_emotion_physicality', '') or '')
                rich_desc = (len(desc) >= 140
                             and not _EMOTION_LABEL_RE.search(desc)
                             and not _description_needs_enrichment(desc))
                if len(already) >= 60 and rich_desc:
                    _skipped_enriched += 1
                    continue
            targets.append((panel, page_intensity, arc_emotion))

    if _skipped_enriched:
        logger.info(
            f"  [Expression] Skipped {_skipped_enriched} already-enriched "
            f"panel(s) on loud pages (no re-amplification needed)."
        )

    if not targets:
        return script

    style_directive = {
        'comedic': (
            "This is a COMEDY. Push expressions BROAD and EXAGGERATED — "
            "rubber-faced cartooning, oversized reactions, visual comic devices "
            "(bulging eyes, dropped jaws, sweat-drops, motion lines, comic "
            "recoils). The funnier the beat, the bigger the physical expression. "
            "Land the joke visually."
        ),
        'dramatic': (
            "This is a DRAMATIC story. Amplify expressions to be intense and "
            "vivid but still grounded and believable — heightened real human "
            "physicality, not cartoon mugging."
        ),
        'neutral': (
            "Amplify expressions to be clear and readable — a little larger "
            "than life so the emotion reads at a glance, without tipping into "
            "cartoon unless the beat is clearly comedic."
        ),
    }[register]

    logger.info(
        f"  [Expression] Amplifying {len(targets)} emotional-beat panel(s) "
        f"(register: {register}{', arc-aware' if arc else ''})..."
    )

    def _intensity_word(v) -> str:
        if v is None:
            return ''
        try:
            v = float(v)
        except (TypeError, ValueError):
            return ''
        if v >= 0.85:
            return ' [PEAK intensity — push the expression to its absolute maximum]'
        if v >= 0.6:
            return ' [high intensity — push the expression large]'
        if v <= 0.32:
            return ' [quiet beat — keep the expression restrained and subtle]'
        return ''

    for start in range(0, len(targets), _AMPLIFY_BATCH_SIZE):
        batch = targets[start:start + _AMPLIFY_BATCH_SIZE]
        items = []
        for i, (panel, intensity, arc_emotion) in enumerate(batch):
            desc = (panel.get('description') or '')[:300]
            mood = (panel.get('mood') or '') or arc_emotion
            # Flag emotion-driven close-ups so the coach leads with the eyes.
            _cu = ' [CLOSE-UP — the eyes must carry this: specify pupil size, ' \
                  'gaze direction, and the muscles around the eyes]' \
                  if panel.get('_emotion_closeup') else ''
            # PEAK BEAT — this panel sits on a page the beat critic crowned an
            # emotional peak (or amplified for emotion). Tell the coach to push
            # the expression to its dramatic maximum here regardless of the
            # generic intensity word, so the art delivers the passion the story
            # earned.
            _peak = ' [PEAK EMOTIONAL BEAT — the story is working hardest here; ' \
                    'push the expression to its most intense, unforgettable form]' \
                    if panel.get('_beat_peak') or panel.get('_arc_beat_peak') else ''
            # Register-specific passion: seduction, comedy, and high drama each
            # need a DIFFERENT physical vocabulary. Detect from mood/emotion/desc.
            _passion = _passion_register_note(f"{mood} {arc_emotion} {desc}", intensity)
            items.append(
                f"{i}. mood='{mood}'{_intensity_word(intensity)}{_peak}{_cu}"
                f"{_passion} | {desc}"
            )
        listing = "\n".join(items)
        prompt = (
            "You are a comics art director coaching an illustrator on how to "
            "draw EMOTION so it reads instantly. " + style_directive + "\n\n"
            "For each panel below, name the SPECIFIC, concrete physical "
            "attributes that would convey its emotion at a glance. LEAD WITH THE "
            "EYES — the eyes are the gateway to the soul: pupil size (dilated with "
            "excitement or fear, contracted with anger), how wide or narrow the "
            "eyes are, gaze direction, the fine muscles around them, whether they "
            "glisten or go flat — then brows, mouth, head/posture, hands/gesture, "
            "and any comic or dramatic device. For panels marked [CLOSE-UP] the "
            "eyes are the SUBJECT and must be described first and most specifically. "
            "Scale the size of the expression to the intensity note; at PEAK "
            "intensity push the eyes hardest. Be visual and concrete, never name "
            "the emotion as a label. One vivid sentence per panel.\n\n"
            f"PANELS:\n{listing}\n\n"
            "Return a JSON object mapping each index (as a string) to its "
            "one-sentence visual attribute description. JSON only, e.g. "
            '{\"0\": \"...\", \"1\": \"...\"}.'
        )
        try:
            resp = get_openai_prompt_response(
                prompt, temperature=0.6,
                openai_model=openai_model, use_grok=USE_GROK,
            )
            parsed = parse_json_response(resp) or {}
        except Exception as e:
            logger.warning(f"  [Expression] batch failed ({e}); skipping.")
            continue
        if not isinstance(parsed, dict):
            continue
        for i, (panel, _intensity, _arc_emotion) in enumerate(batch):
            clause = parsed.get(str(i)) or parsed.get(i)
            if clause and isinstance(clause, str) and clause.strip():
                panel['_expression_amplify'] = clause.strip()

    return script


_EMOTION_LABEL_RE = _emo_re.compile(
    r'\b(looks? (sad|afraid|angry|happy|scared|confused|surprised|devastated|'
    r'heartbroken|furious|terrified|shocked|guilty|ashamed|hopeless|empty)|'
    r'she (is|was|seems|appears|feels) (sad|afraid|angry|happy|devastated|hopeless|broken)|'
    r'he (is|was|seems|appears|feels) (sad|afraid|angry|happy|devastated|hopeless|broken)|'
    r'they (are|were) (sad|afraid|angry|devastated|hopeless)|'
    r'expression of (grief|fear|anger|sadness|terror|despair|joy)|'
    r'her face shows?|his face shows?|clearly (sad|devastated|afraid|angry))\b',
    _emo_re.IGNORECASE,
)


def _description_needs_enrichment(desc: str) -> bool:
    """Return True if the panel description is emotionally thin and could benefit
    from LLM rewriting into more specific visual language."""
    if not desc or len(desc) < 20:
        return False   # too short to rewrite meaningfully
    # Named-emotion labels without physical specificity
    if _EMOTION_LABEL_RE.search(desc):
        return True
    # Very short descriptions are usually incomplete
    if len(desc) < 60:
        return True
    return False


def _physicality_llm_rewrite_batches(
    panels: list, story_idea: 'StoryIdea',
) -> None:
    """Send batches of emotionally-thin panel descriptions to the LLM for
    illustrator-grade rewriting. Modifies panel dicts in place."""
    for i in range(0, len(panels), _PHYSICALITY_BATCH_SIZE):
        batch = panels[i: i + _PHYSICALITY_BATCH_SIZE]
        _physicality_llm_rewrite_batch(batch, story_idea)


def _physicality_llm_rewrite_batch(batch: list, story_idea: 'StoryIdea') -> None:
    """One LLM call: rewrite up to _PHYSICALITY_BATCH_SIZE panel descriptions."""
    items = []
    for page, panel in batch:
        page_num  = page.get('page', '?')
        panel_num = panel.get('panel_index', '?')
        desc      = (panel.get('description') or '').strip()
        mood      = (panel.get('mood') or '').strip()
        comp      = (panel.get('composition') or 'medium_shot').strip()
        chars     = ', '.join(str(c) for c in (panel.get('characters_in_frame') or []))
        items.append(
            f'{{"id": "p{page_num}_pan{panel_num}", '
            f'"desc": {json.dumps(desc)}, '
            f'"mood": {json.dumps(mood)}, '
            f'"composition": {json.dumps(comp)}, '
            f'"chars": {json.dumps(chars)}}}'
        )

    prompt = (
        f"{_SINGLE_IMAGE_RULE}\n\n"
        f"You are an experienced comic book illustrator briefing an artist "
        f"on how to DRAW specific panels.\n\n"
        f"STORY: {story_idea.genre} | {story_idea.mood}\n"
        f"PREMISE: {story_idea.premise[:200]}\n\n"
        f"YOUR TASK: Rewrite each panel description so it tells the artist "
        f"EXACTLY what to draw — not what to feel. Replace all emotional labels "
        f"with specific, observable physical and visual details.\n\n"
        f"RULES:\n"
        f"1. SHOW, DON'T LABEL. Never use 'looks sad', 'appears afraid', 'seems angry', "
        f"   'expression of grief', 'clearly devastated'. Instead, describe the exact "
        f"   physical reality:\n"
        f"   BAD:  'She looks devastated'\n"
        f"   GOOD: 'Her shoulders collapse inward, arms hanging at her sides; "
        f"          she stares at a fixed point on the floor, eyes red-rimmed "
        f"          and unfocused, jaw working silently'\n\n"
        f"2. EMOTIONAL STATES HAVE PHYSICAL SIGNATURES — use them:\n"
        f"   GRIEF/DEVASTATION: shoulders drawn in and down, spine curved, "
        f"     arms limp or self-hugging, hollow distant gaze, swollen eyelids, "
        f"     pallor, jaw tight\n"
        f"   GRIEF TEARS: red-rimmed eyes, bloodshot sclera with fine capillary lines, "
        f"     glistening lower lids, tear tracing the cheek, jaw clenched against trembling\n"
        f"   FEAR/TERROR: pupils dilated to black, whites above the iris, "
        f"     grey-white pallor, shoulders raised toward ears, "
        f"     white-knuckled grip, chest expanded but not breathing\n"
        f"   RAGE/FURY: jaw muscle knotted at the temple, brow deeply furrowed, "
        f"     neck tendons taut, hands balled white-knuckled, weight forward\n"
        f"   DESPAIR/NUMBNESS: head drooped, limbs too heavy to lift, "
        f"     thousand-yard stare, body of someone whose strings were cut\n"
        f"   SHOCK/DISBELIEF: mouth open, jaw dropped, brows arched, "
        f"     one hand raised to the mouth or chest, half-step backward\n"
        f"   DETERMINATION: feet planted wide, chin level or raised, "
        f"     gaze direct and unwavering, the stillness of a decision made\n\n"
        f"3. MAGICAL/SPIRITUAL CONTENT — use specific VFX vocabulary:\n"
        f"   DIVINE LIGHT: volumetric god-rays, chromatic aberration at edges, "
        f"     gold dust particles, lens bloom\n"
        f"   GHOST/SPIRIT: translucent layered light, cool blue-white, "
        f"     background visible through the form, edges dissolving to luminous mist\n"
        f"   SPELL/MAGIC: luminous plasma core, electric arc tendrils, "
        f"     helical particle vortex, heat-shimmer distortion\n"
        f"   FIRE MAGIC: white-hot core transitioning to deep orange turbulent edges, "
        f"     individual twisting flame wisps, subsurface glow in nearby skin\n"
        f"   SPIRITUAL AWAKENING: mandala light patterns, inner luminescence "
        f"     from chest and crown, figure/background boundary softly dissolving\n\n"
        f"4. TECHNOLOGY CONTENT — use CGI-precision vocabulary:\n"
        f"   ENERGY WEAPON (lightsaber/plasma): brilliant white-cyan core cylinder, "
        f"     saturated coloured plasma sleeve, hard geometric edges, "
        f"     casts coloured light on all nearby surfaces\n"
        f"   ELECTRICITY/SPARKS: branching fractal lightning in blue-white, "
        f"     jagged random sub-arcs, blue-white strobe illumination, "
        f"     ionisation at contact point — hard edges not soft glow\n"
        f"   ROBOT/MECH: brushed titanium panel surfaces with hex-bolt detail, "
        f"     internal gears and hydraulic pistons visible at joints, "
        f"     LED indicators at articulation points, motion as geometric "
        f"     afterimage trails not organic smear\n"
        f"   HOLOGRAM/HUD: translucent blue-cyan panels floating in air, "
        f"     scan-line texture, crisp monospaced data, cool cyan light "
        f"     cast on nearby faces, vector-clean geometric UI elements\n"
        f"   ENERGY SHIELD: iridescent translucent membrane, "
        f"     hexagonal tessellation ripples from impact points, "
        f"     glows brighter at its boundary edge\n"
        f"   NEON/CYBERPUNK: hot magenta, electric cyan, acid yellow light sources "
        f"     casting saturated pools on rain-wet reflective surfaces; "
        f"     hard-edged colour blocks on faces\n\n"
        f"5. SPIRITUAL AURA (only when the panel is explicitly spiritually heightened):\n"
        f"   If the panel's emotional beat reaches a spiritual or transcendent level, "
        f"   describe the scene's colour field and any aura around the figure:\n"
        f"   LOVE (spiritual): warm golden-amber luminescence from the chest, "
        f"     honey-warm tint in the air, rose-gold at the periphery\n"
        f"   GRIEF (spiritual): scene colour drains to near-monochrome ash-blue, "
        f"     barely-visible dark violet outline at the figure's edge\n"
        f"   COSMIC CONNECTION: deep royal-purple crown light, tiny star-points "
        f"     orbiting in slow arcs, sacred geometry overlays dissolving in the air\n"
        f"   RAGE (mythic): fierce crimson-red corona pulsing at the figure's edge, "
        f"     shadows in the scene bleed red, heat-distortion lines radiating outward\n"
        f"   TRANSCENDENCE: omnidirectional white-blue light as if the figure IS "
        f"     the source; boundary with background dissolving into soft luminous white\n\n"
        f"6. Keep descriptions 2-4 sentences. Stay within what the camera can see. "
        f"   No dialogue, no quoted thoughts, no character names as text.\n"
        f"7. PRESERVE the composition ({{}}) and characters in frame — only improve "
        f"   the visual language.\n\n"
        f"PANELS TO REWRITE:\n" + "\n".join(items) + "\n\n"
        f"Return ONLY a JSON array:\n"
        f'[{{"id": "p1_pan2", "description": "rewritten description here"}}, ...]\n'
        f"One entry per panel. IDs must match exactly. "
        f"Omit a panel if its description is already specific and strong."
    )

    try:
        raw = get_openai_prompt_response(
            prompt, temperature=0.65, max_completion_tokens=4000,
            openai_model=openai_model_large, use_grok=USE_GROK,
        )
        parsed = parse_json_response(raw)
        if not isinstance(parsed, list):
            logger.warning("  [Physicality] LLM batch returned non-list; skipping.")
            return

        # Index by id
        rewrites = {}
        for item in parsed:
            if isinstance(item, dict) and item.get('id') and item.get('description'):
                rewrites[item['id']] = item['description'].strip()

        # Apply back
        applied = 0
        for page, panel in batch:
            page_num  = page.get('page', '?')
            panel_num = panel.get('panel_index', '?')
            key = f"p{page_num}_pan{panel_num}"
            if key in rewrites and len(rewrites[key]) > 20:
                old_preview = (panel.get('description') or '')[:50]
                panel['description'] = rewrites[key]
                logger.debug(
                    f"  [Physicality] p{page_num} panel {panel_num}: "
                    f"'{old_preview}…' → rewritten"
                )
                applied += 1
        if applied:
            logger.info(f"  [Physicality] Batch: {applied} description(s) rewritten.")
    except Exception as e:
        logger.warning(f"  [Physicality] LLM batch failed: {e}; skipping.")


def _validate_and_repair_panels(script: 'List[Dict]', story_idea: 'StoryIdea',
                                  characters: 'List[Character]',
                                  graph: 'CharacterGraph') -> 'List[Dict]':
    """Scan every panel for empty/short descriptions; regenerate or fall back.
    
    A panel is invalid if its description is missing, empty, or shorter than
    15 characters. For each invalid panel, we ask the LLM to write a
    description using the page's beat as the anchor. If that also fails, we
    fill in a generic description derived from the page beat.
    """
    invalid_panels = []
    for page_idx, page in enumerate(script):
        for panel_idx, panel in enumerate(page.get('panels', [])):
            desc = (panel.get('description') or '').strip()
            if len(desc) < 15:
                invalid_panels.append((page_idx, panel_idx, page, panel))
    
    if not invalid_panels:
        logger.info(f"  Panel validation: all panels have descriptions")
        return script
    
    logger.warning(
        f"  Panel validation: {len(invalid_panels)} empty/short panel(s) found; "
        f"repairing..."
    )
    
    for page_idx, panel_idx, page, panel in invalid_panels:
        page_num = page.get('page', page_idx + 1)
        page_beat = page.get('beat', '') or page.get('emotional_tone', '')
        page_setting = page.get('setting', '')
        chars = panel.get('characters_in_frame', []) or page.get(
            'characters_present', []
        )
        
        # Try to regenerate via LLM
        repair_prompt = (
            f"{_SINGLE_IMAGE_RULE}\n\n"
            f"You are a comic book, graphic novel artist sketching a single panel. Write a "
            f"vivid 1-2 sentence visual description for this panel.\n\n"
            f"Page {page_num} beat: {page_beat}\n"
            f"Setting: {page_setting}\n"
            f"Characters present: {', '.join(chars) if chars else 'see page beat'}\n"
            f"Panel position: {panel_idx + 1} of "
            f"{len(page.get('panels', []))} on this page\n\n"
            f"Return ONLY the visual description, no preamble or quotes. "
            f"Be specific and concrete. Describe what is in frame."
        )
        try:
            repaired = get_openai_prompt_response(
                repair_prompt, temperature=0.7,
                max_completion_tokens=4000,
                openai_model=openai_model, use_grok=USE_GROK,
            )
            repaired = (repaired or '').strip().strip('"').strip("'").strip()
            if len(repaired) >= 15:
                panel['description'] = repaired
                # Do NOT force-fill characters_in_frame for cosmic panels —
                # their empty character list is intentional.
                if not panel.get('characters_in_frame') and panel.get('panel_type', 'character') != 'cosmic':
                    panel['characters_in_frame'] = chars[:3]
                logger.info(
                    f"    Repaired page {page_num} panel "
                    f"{panel.get('panel_index', panel_idx + 1)}"
                )
                continue
        except Exception as e:
            logger.warning(f"    LLM repair failed: {e}")
        
        # Fallback: synthesize from page beat
        fallback = (
            f"{page_beat[:120] if page_beat else 'Story moment'}. "
            f"{page_setting[:80] if page_setting else ''}"
        ).strip()
        panel['description'] = fallback or f"Story beat from page {page_num}"
        if not panel.get('characters_in_frame') and panel.get('panel_type', 'character') != 'cosmic':
            panel['characters_in_frame'] = chars[:3]
        logger.info(
            f"    Used fallback for page {page_num} panel "
            f"{panel.get('panel_index', panel_idx + 1)}"
        )
    
    return script

# ===========================================================================
# PAGE OUTLINE — generated per ACT (ralph-loop), never the whole book at once
# ===========================================================================
# A single LLM call cannot emit a 900-page outline: the RESPONSE blows past the
# model's output-token ceiling and gets truncated mid-JSON, which forces the
# generic "distribute beats safely" fallback and throws away the creative
# outline entirely. So we generate the outline in bounded sections — one Act at
# a time (sub-windowed when an Act is itself very long) — giving each call only
# its own required beats plus a COMPACT summary of the previous and next Act for
# continuity, then aggregate the sections into the complete outline. Each call
# emits at most a few dozen pages, so nothing is ever truncated, and the
# narrative still connects across section boundaries because every section sees
# where it came from and where it is heading.
_OUTLINE_MAX_PAGES_PER_CALL = 40    # hard cap on pages requested in one call
_OUTLINE_SINGLE_CALL_MAX = 60       # books this size or smaller: one call, as before


def _parse_pr(pr_raw, fallback_end=10**9):
    """Parse a beat page_range like '12-18' / '12' / '12-end' -> (start, end)."""
    import re as _re
    pr = str(pr_raw or '').lower().replace('end', str(fallback_end)).strip()
    parts = _re.findall(r'\d+', pr)
    if not parts:
        return (0, 0)
    if len(parts) == 1:
        v = int(parts[0])
        return (v, v)
    return (int(parts[0]), int(parts[1]))


def _outline_act_of_page(target_pages, required_beats):
    """Map every page 1..target_pages to an act number (str), from beat ranges.

    Pages not covered by any beat inherit the nearest preceding act (forward
    fill), so act runs are always contiguous and cover the whole book.
    """
    page_to_act = {}
    for b in (required_beats or []):
        s, e = _parse_pr(b.get('page_range', ''), fallback_end=target_pages)
        act = str(b.get('act', '') or '').strip() or '1'
        for p in range(max(1, s), min(target_pages, e) + 1):
            # First beat to claim a page wins; later overlapping beats don't
            # flip an already-assigned page's act.
            page_to_act.setdefault(p, act)
    # Forward-fill any gaps.
    last = '1'
    out = {}
    for p in range(1, target_pages + 1):
        if p in page_to_act:
            last = page_to_act[p]
        out[p] = last
    return out


def _compute_outline_spans(target_pages, act_of_page, max_window):
    """Break pages 1..target_pages into per-act spans, sub-windowed by max_window.

    Returns a list of {'start', 'end', 'act'} dicts in page order. Each span is
    contiguous, belongs to exactly one act, and is at most ``max_window`` pages.
    """
    spans = []
    p = 1
    while p <= target_pages:
        act = act_of_page.get(p, '1')
        run_end = p
        while run_end + 1 <= target_pages and act_of_page.get(run_end + 1, '1') == act:
            run_end += 1
        # Sub-window this act-run so no single call exceeds max_window pages.
        s = p
        while s <= run_end:
            e = min(s + max_window - 1, run_end)
            spans.append({'start': s, 'end': e, 'act': act})
            s = e + 1
        p = run_end + 1
    return spans


def _summarize_act_beats(act, beats, limit=10, per_beat_chars=90):
    """One compact line per beat for a neighbouring act (continuity context)."""
    if not beats:
        return ''
    lines = []
    for b in beats[:limit]:
        desc = str(b.get('description', '') or '').strip().replace('\n', ' ')
        lines.append(
            "  {} (pp.{}): {}".format(
                b.get('beat_id', '?'), b.get('page_range', '?'),
                desc[:per_beat_chars]
            )
        )
    more = "" if len(beats) <= limit else "\n  …(+{} more)".format(len(beats) - limit)
    text = "ACT {}:\n".format(act) + "\n".join(lines) + more
    if _tb is not None:
        text = _tb.clamp_text(text, 600, where="outline.act_summary")
    return text


def _summarize_tail_pages(pages, k=3, per_page_chars=80):
    """Compact summary of the last k generated pages, for cross-section flow."""
    if not pages:
        return ''
    tail = pages[-k:]
    lines = []
    for p in tail:
        beat = str(p.get('beat', '') or p.get('title', '') or '').strip().replace('\n', ' ')
        lines.append("  p{}: {}".format(p.get('page', '?'), beat[:per_page_chars]))
    text = "\n".join(lines)
    if _tb is not None:
        text = _tb.clamp_text(text, 400, where="outline.tail_summary")
    return text


def _build_storyboard_summary(beats_by_act, current_act=None,
                              max_beats_per_act=4, per_beat_chars=70,
                              budget_tokens=10000):
    """A compact WHOLE-BOOK overview: one block per act, a few key beats each.

    This is global context every section receives, so a section can deliberately
    set up a payoff that lands in a LATER act, or call back to an EARLIER one —
    cases the immediate previous/next-act window can't cover. It is kept short
    (act-level, a handful of representative beats per act, hard token budget) so
    it never reintroduces prompt bloat, even for a book with hundreds of beats.

    ``current_act`` (when given) is marked so the model can locate the section
    it is writing within the whole arc.
    """
    if not beats_by_act:
        return ''

    def _act_sort_key(a):
        try:
            return (0, int(a))
        except (TypeError, ValueError):
            return (1, str(a))

    lines = []
    for act in sorted(beats_by_act.keys(), key=_act_sort_key):
        beats = beats_by_act.get(act) or []
        if not beats:
            continue
        # Act page span across its beats.
        starts, ends = [], []
        for b in beats:
            s, e = _parse_pr(b.get('page_range', ''))
            if s:
                starts.append(s)
            if e:
                ends.append(e)
        span = "pp.{}-{}".format(min(starts), max(ends)) if starts and ends else "pp.?"
        # A few representative beats: first, last, and any adult/climactic ones.
        picks = []
        seen = set()
        priority = [b for b in beats if b.get('adult_content')
                    or str(b.get('importance', '')).lower() in ('climactic', 'splash')]
        for b in (priority + [beats[0], beats[-1]] + beats):
            bid = b.get('beat_id', '')
            if bid in seen:
                continue
            seen.add(bid)
            desc = str(b.get('description', '') or '').strip().replace('\n', ' ')
            picks.append("    {}: {}".format(bid or '?', desc[:per_beat_chars]))
            if len(picks) >= max_beats_per_act:
                break
        marker = "  ◀ current section" if str(act) == str(current_act) else ""
        more = "" if len(beats) <= max_beats_per_act else \
            "    …(+{} more beats)".format(len(beats) - max_beats_per_act)
        block = "ACT {} ({}, {} beats):{}\n{}".format(
            act, span, len(beats), marker, "\n".join(picks))
        if more:
            block += "\n" + more
        lines.append(block)

    text = "\n".join(lines)
    if _tb is not None:
        text = _tb.clamp_text(text, budget_tokens, where="outline.storyboard_summary")
    return text


def _outline_span_fallback(span_start, span_end, span_beats, characters,
                           story_idea):
    """Local recovery for ONE span: distribute its beats across its pages.

    Used only when a span's LLM call fails or truncates — keeps the failure
    contained to a few dozen pages instead of the whole book.
    """
    pages = []
    n = span_end - span_start + 1
    for i in range(n):
        page_no = span_start + i
        assigned_bid, assigned_beat = "", "Story beat {}".format(page_no)
        if span_beats:
            idx = min(int(i / max(1, n) * len(span_beats)), len(span_beats) - 1)
            tb_ = span_beats[idx]
            assigned_bid = tb_.get('beat_id', '')
            assigned_beat = tb_.get('description', assigned_beat)
        pages.append({
            'page': page_no,
            'title': 'Page {}'.format(page_no),
            'setting': 'Houston',
            'characters_present': [c.name for c in characters[:3]] if characters else ["Gonzo"],
            'beat': assigned_beat,
            'beat_id': assigned_bid,
            'emotional_tone': story_idea.mood if story_idea else 'dynamic',
            'visual_hook': 'establishing shot',
            'cliffhanger': (page_no % 4 == 0),
            'importance': 'standard',
        })
    return pages


def _build_outline_span_prompt(story_idea, story_idea_str, char_summary,
                               tensions_str, target_pages, span_start, span_end,
                               span_beats, prev_ctx, next_ctx, tail_ctx,
                               storyboard_ctx=''):
    """Prompt for ONE contiguous page span. Same schema/voice as the original
    whole-book prompt, but scoped to span_start..span_end with neighbour-act
    context so it connects to the rest of the book."""
    n_pages = span_end - span_start + 1

    beats_section = ""
    has_adult = False
    if span_beats:
        beats_section = (
            "\n========== REQUIRED STORY BEATS FOR THIS SECTION (NON-NEGOTIABLE) ==========\n"
            "Every beat below MUST appear in your outline at the assigned page "
            "range. Do not omit, soften, or replace any beat. If a beat involves "
            "fantastical elements (alien planets, portals, augmentation, "
            "telepathy), depict them DIRECTLY — do not replace them with "
            "metaphorical or 'safer' alternatives. Mature/intimate beats must "
            "appear, in full, across every page of their assigned range.\n\n"
        )
        for b in span_beats:
            tag = (
                " [ADULT/EXPLICIT — this beat earned a wider page range "
                "specifically so the encounter can be paced out scene by scene: "
                "build-up, escalation, the act itself, aftermath. Use ALL of "
                "the assigned pages for it. Depict it directly and explicitly "
                "— sexual, sensual, anatomically frank — do not cut away, "
                "fade to black, time-skip, or compress it onto fewer pages "
                "than assigned.]"
                if b.get('adult_content') else ""
            )
            # Surface the beat's designed emotional intent so the outline honours
            # it when scoring each page's emotional_tone — this is how an added
            # enrichment beat (a relief valley, an empathy setup, a stakes spike)
            # actually shapes the emotional journey instead of reading as plot.
            _feeling = str(b.get('emotional_tone', '') or b.get('target_emotion', '') or '').strip()
            _purpose = str(b.get('emotional_purpose', '') or '').strip()
            _intent = ''
            if _feeling:
                _intent += f" | feeling: {_feeling[:60]}"
            if _purpose:
                _intent += f" | purpose: {_purpose[:90]}"
            beats_section += (
                "  {} (pages {}): {}{}{}\n".format(
                    b.get('beat_id', '?'), b.get('page_range', '?'),
                    b.get('description', ''), _intent, tag,
                )
            )
            if b.get('adult_content'):
                has_adult = True
        beats_section += "===============================================\n\n"

    adult_pacing_note = (
        "ADULT CONTENT PACING: beats marked [ADULT/EXPLICIT] above were given "
        "MORE pages than a typical beat precisely because explicit scenes need "
        "room — do not compress one into a single page or rush past it. Spread "
        "it across its full assigned range: a page of escalating tension/"
        "undressing, a page (or more) of the explicit act itself shown directly, "
        "a page of aftermath/afterglow. Each of those pages should still be a "
        "distinct beat with its own visual_hook — don't repeat the same moment "
        "across pages just to fill space. Confident, explicit, unhurried.\n\n"
        if has_adult else ""
    )

    continuity_section = ""
    if storyboard_ctx:
        continuity_section += (
            "========== FULL STORYBOARD (whole-book overview — for orientation "
            "and DELIBERATE cross-act craft only) ==========\n"
            "This is the shape of the entire book. Use it ONLY to (a) plant "
            "setups/foreshadowing for beats that pay off in a LATER act, and "
            "(b) honour callbacks to an EARLIER act. Do NOT write any pages "
            "outside your assigned range, and do not restate other acts' "
            "scenes — just let this section quietly serve the larger arc.\n"
            + storyboard_ctx + "\n\n"
        )
    if tail_ctx:
        continuity_section += (
            "========== STORY SO FAR (immediately preceding pages — continue "
            "seamlessly from here) ==========\n" + tail_ctx + "\n\n"
        )
    if prev_ctx:
        continuity_section += (
            "========== PREVIOUS ACT (context only — already written, do NOT "
            "re-write these pages) ==========\n" + prev_ctx + "\n\n"
        )
    if next_ctx:
        continuity_section += (
            "========== NEXT ACT (what comes after this section — lead toward "
            "it, but do NOT write these pages) ==========\n" + next_ctx + "\n\n"
        )

    prompt = (
        # ══ STABLE PREFIX ══════════════════════════════════════════════════
        # Identical for every section of this book, so xAI serves it from the
        # prompt cache after the first section instead of re-billing it 15×.
        # Everything that varies per section is deferred to the tail below.
        "You are a comic book / graphic novel writer breaking a {total}-page "
        "story into a page-by-page outline. Think Alan Moore, Brian K. Vaughan, "
        "Saladin Ahmed. Every page must MOVE the story.\n\n"
        "========== ORIGINAL USER CONCEPT (preserve faithfully) ==========\n"
        "{concept}\n"
        "=================================================================\n\n"
        "STORY METADATA:\n  Genre: {genre}\n  Mood: {mood}\n  Themes: {themes}\n\n"
        "{genre_structure}"
        "CAST:\n  {cast}\n\n"
        "KEY TENSIONS:\n{tensions}\n\n"
        "Depict fantastical/sci-fi elements (alien planets, portals, "
        "augmentation, telepathy) DIRECTLY — never replace them with "
        "metaphorical or 'safer' alternatives.\n\n"
        "You will be assigned a contiguous range of pages. For each page in "
        "your assigned range, produce a JSON object:\n"
        "  - page (int, within your assigned range)\n"
        "  - title: short evocative title (3-7 words)\n"
        "  - setting: where it happens, vivid\n"
        "  - characters_present: array of character names. EMPTY [] for "
        "cosmic/environment-only pages.\n"
        "  - panel_type: 'character' | 'scenic' | 'cosmic'\n"
        "  - beat: one sentence — the SINGLE story beat this page delivers. If "
        "this page corresponds to a required beat, START with the beat_id, e.g. "
        "'[b03] Diego steps through the portal and...'\n"
        "  - beat_id: the required beat_id if this page maps to one, else ''\n"
        "  - emotional_tone: one phrase\n"
        "  - visual_hook: the moment a reader would scan to first\n"
        "  - cliffhanger: bool\n"
        "  - importance: 'splash' | 'climactic' | 'standard' | 'transition'\n\n"
        "PAGE-TURN PULL (comics craft): a page's LAST beat is what makes the "
        "reader turn it. End every page's beat on an unresolved note — a "
        "question raised, a door opening, a line half-spoken, a look "
        "misread — and save the answer for the next page. Pages marked "
        "cliffhanger:true should end on the hardest pulls; even quiet pages "
        "should close leaning forward, not settled.\n"
        # ══ VARIABLE TAIL (this section only) ══════════════════════════════
        "\n========================================================\n"
        "YOUR ASSIGNMENT FOR THIS SECTION\n"
        "========================================================\n"
        "Write ONLY pages {ps}-{pe} of the book right now (this is one section "
        "of a longer work). Produce EXACTLY these {n} pages — no more, no "
        "fewer — numbered from {ps} to {pe}.\n\n"
        "{continuity}"
        "{beats}"
        "{adult}"
        "CRITICAL CHECKS before returning:\n"
        "  1. Did you include EVERY required beat listed for THIS section?\n"
        "  2. Are fantastical/sci-fi elements depicted directly, not replaced?\n"
        "  3. Are your page numbers exactly {ps}..{pe}?\n\n"
        "Return a JSON array of EXACTLY {n} entries. JSON only, no markdown."
    ).format(
        total=target_pages, ps=span_start, pe=span_end, n=n_pages,
        concept=(story_idea_str or story_idea.premise),
        continuity=continuity_section, beats=beats_section,
        genre=story_idea.genre, mood=story_idea.mood,
        themes=', '.join(story_idea.themes), cast=char_summary,
        tensions=tensions_str, adult=adult_pacing_note,
        genre_structure=_genre_structure_clause(story_idea),
    )
    return prompt


def _generate_outline_span(story_idea, story_idea_str, char_summary,
                           tensions_str, target_pages, span_start, span_end,
                           span_beats, characters, prev_ctx='', next_ctx='',
                           tail_ctx='', storyboard_ctx=''):
    """Generate the outline for ONE page span. Falls back locally on failure."""
    span_start, span_end = int(span_start), int(span_end)  # guard against str callers
    n_pages = span_end - span_start + 1
    prompt = _build_outline_span_prompt(
        story_idea, story_idea_str, char_summary, tensions_str, target_pages,
        span_start, span_end, span_beats, prev_ctx, next_ctx, tail_ctx,
        storyboard_ctx=storyboard_ctx,
    )
    # Size the output budget to the span (≈400 tokens/page) but stay modest so a
    # section can never itself approach the truncation ceiling.
    out_budget = max(4000, min(60000, n_pages * 400))
    response = get_openai_prompt_response(
        prompt, temperature=0.7, max_completion_tokens=out_budget,
        openai_model=openai_model_large, use_grok=USE_GROK,
    )
    parsed = parse_json_response(response)
    if parsed and isinstance(parsed, list):
        valid = [p for p in parsed if isinstance(p, dict) and p.get('page')]
        # Keep only pages that fall in this span; renumber defensively if the
        # model drifted but produced the right count.
        in_span = [p for p in valid if span_start <= int(p.get('page', 0) or 0) <= span_end]
        if len(in_span) >= int(n_pages * 0.8):
            return in_span
        if len(valid) >= int(n_pages * 0.8):
            # Right count, wrong numbers — renumber sequentially across the span.
            for i, p in enumerate(valid[:n_pages]):
                p['page'] = span_start + i
            return valid[:n_pages]
    logger.warning(
        "  [Outline] Section pp.%d-%d did not parse cleanly; using local "
        "beat distribution for this section only.", span_start, span_end,
    )
    return _outline_span_fallback(span_start, span_end, span_beats, characters,
                                  story_idea)


def _generate_page_outline(story_idea: 'StoryIdea', characters: 'List[Character]',
                            graph: 'CharacterGraph', target_pages: int,
                            required_beats: 'List[Dict]' = None,
                            story_idea_str: str = '',
                            prior_outline: 'List[Dict]' = None,
                            repair_beat_ids: set = None) -> 'List[Dict]':
    """Generate a page-by-page outline that HONORS the user's required beats.

    For small books this is a single LLM call. For large books the outline is
    generated ACT BY ACT (sub-windowed for very long acts) so no single response
    is ever truncated; each section is given the previous/next act as context
    and the sections are aggregated into the full outline. The required_beats
    checklist is mandatory: every beat must appear at its assigned page range.

    Targeted repair: when ``repair_beat_ids`` is provided (with ``prior_outline``
    the last attempt's pages), only the section(s) whose beats include a missing
    beat are regenerated with a fresh LLM call; every other section's pages are
    reused verbatim from the prior outline. This turns a one-beat coverage miss
    into a single-section retry instead of a full rebuild of the whole book.
    """
    char_summary = "; ".join([
        "{} ({}): {}".format(
            c.name, c.role, ', '.join(c.traits[:3]) if c.traits else 'complex')
        for c in characters[:12]
    ])

    tensions = []
    for edge in graph.significant_edges(threshold=5.0)[:8]:
        tensions.append("  {} → {}: {}".format(edge.source, edge.target, edge.label()))
    tensions_str = "\n".join(tensions) if tensions else "  (none charged yet)"

    # --- Small book OR no beats: single call (original fast path) ------------
    if not required_beats or target_pages <= _OUTLINE_SINGLE_CALL_MAX:
        return _generate_outline_span(
            story_idea, story_idea_str, char_summary, tensions_str,
            target_pages, 1, target_pages, list(required_beats or []),
            characters,
        )

    # --- Large book: generate per-act, sub-windowed, with neighbour context --
    act_of_page = _outline_act_of_page(target_pages, required_beats)
    spans = _compute_outline_spans(target_pages, act_of_page,
                                   _OUTLINE_MAX_PAGES_PER_CALL)

    # Group beats by act for neighbour-context summaries.
    beats_by_act = {}
    for b in required_beats:
        act = str(b.get('act', '') or '').strip() or '1'
        beats_by_act.setdefault(act, []).append(b)

    logger.info(
        "  [Outline] %d-page book → generating in %d section(s) across %d act(s) "
        "(ralph-loop, ≤%d pages/call) to avoid response truncation.",
        target_pages, len(spans), len(beats_by_act), _OUTLINE_MAX_PAGES_PER_CALL,
    )

    full_outline = []
    for si, span in enumerate(spans):
        s, e, act = span['start'], span['end'], span['act']
        # Beats whose range intersects this span.
        span_beats = []
        for b in required_beats:
            bs, be = _parse_pr(b.get('page_range', ''), fallback_end=target_pages)
            if bs <= e and be >= s:
                span_beats.append(b)

        # ── Targeted repair: skip (reuse) sections with no missing beat ───────
        # In repair mode we only spend an LLM call on the section(s) that
        # actually contain a beat the last attempt failed to cover; every other
        # section's pages are carried over from the prior outline unchanged.
        if repair_beat_ids is not None and prior_outline is not None:
            span_has_missing = any(
                (b.get('beat_id') or '').strip().lower() in repair_beat_ids
                for b in span_beats
            )
            if not span_has_missing:
                reused = [p for p in prior_outline
                          if s <= int(p.get('page', 0) or 0) <= e]
                full_outline.extend(reused)
                logger.info(
                    "  [Outline] Section %d/%d (act %s, pp.%d-%d): reused %d "
                    "page(s) (no missing beat here).",
                    si + 1, len(spans), act, s, e, len(reused),
                )
                continue

        # Neighbour-act context: previous act (if any precedes this act) and
        # next act (if any follows). Skipped for the first/last act naturally.
        try:
            act_n = int(act)
        except (TypeError, ValueError):
            act_n = None
        prev_ctx = next_ctx = ''
        if act_n is not None:
            prev_ctx = _summarize_act_beats(act_n - 1, beats_by_act.get(str(act_n - 1), []))
            next_ctx = _summarize_act_beats(act_n + 1, beats_by_act.get(str(act_n + 1), []))

        # Whole-book storyboard overview, with THIS section's act marked, so the
        # section can set up payoffs that land in a later act (or honour
        # callbacks to an earlier one) — not just the immediate neighbours.
        storyboard_ctx = _build_storyboard_summary(beats_by_act, current_act=act)

        # Running continuity: the tail of what we just generated.
        tail_ctx = _summarize_tail_pages(full_outline, k=3)

        section = _generate_outline_span(
            story_idea, story_idea_str, char_summary, tensions_str,
            target_pages, s, e, span_beats, characters,
            prev_ctx=prev_ctx, next_ctx=next_ctx, tail_ctx=tail_ctx,
            storyboard_ctx=storyboard_ctx,
        )
        full_outline.extend(section)
        logger.info(
            "  [Outline] Section %d/%d (act %s, pp.%d-%d): %d page(s) written.",
            si + 1, len(spans), act, s, e, len(section),
        )

    # --- Stitch: sort, dedupe by page, and fill any missing page numbers -----
    by_page = {}
    for p in full_outline:
        try:
            pn = int(p.get('page', 0) or 0)
        except (TypeError, ValueError):
            continue
        if 1 <= pn <= target_pages:
            by_page.setdefault(pn, p)
    stitched = []
    for pn in range(1, target_pages + 1):
        if pn in by_page:
            stitched.append(by_page[pn])
        else:
            # Gap: fill from the beat covering this page so coverage holds.
            covering = [b for b in required_beats
                        if _parse_pr(b.get('page_range', ''), target_pages)[0] <= pn
                        <= _parse_pr(b.get('page_range', ''), target_pages)[1]]
            stitched.extend(
                _outline_span_fallback(pn, pn, covering, characters, story_idea)
            )
    return stitched

 
def _validate_outline_coverage(outline: 'List[Dict]',
                                 required_beats: 'List[Dict]') -> 'Tuple[bool, List[str]]':
    """Check whether every required beat appears in the outline.
    
    Returns (is_valid, list_of_missing_beat_descriptions).
    
    A beat is considered "covered" if any page's beat_id matches the beat's
    beat_id, OR if the page's beat text contains keywords from the beat's
    description.
    """
    if not required_beats:
        return True, []
    
    covered_beat_ids = set()
    all_page_beats_text = ' '.join(
        f"{p.get('beat', '')} {p.get('setting', '')} {p.get('title', '')}".lower()
        for p in outline
    )
    
    for p in outline:
        bid = (p.get('beat_id') or '').strip().lower()
        if bid:
            covered_beat_ids.add(bid)
    
    missing = []
    for b in required_beats:
        if not b.get('must_include', True):
            continue
        bid = (b.get('beat_id') or '').lower()
        if bid in covered_beat_ids:
            continue
        # Fallback: check if visual keywords appear in any page beat text
        keywords = b.get('visual_keywords', []) or []
        # Be a little lenient: require at least one strong keyword to appear
        keyword_hit = False
        for kw in keywords:
            kw_lower = str(kw).lower().strip()
            if len(kw_lower) > 3 and kw_lower in all_page_beats_text:
                keyword_hit = True
                break
        if not keyword_hit:
            missing.append(
                f"{b.get('beat_id', '?')}: {b.get('description', '')[:100]}"
            )
    
    return (len(missing) == 0), missing

def _group_outline_into_scenes(outline: List[Dict]) -> List[List[Dict]]:
    """Group consecutive outline pages into scenes by setting change."""
    scenes: List[List[Dict]] = []
    cur: List[Dict] = []
    cur_setting = None
    for p in outline:
        s = str(p.get('setting', '') or '').strip()
        if cur and cur_setting is not None and _settings_differ_for_scene(s, cur_setting):
            scenes.append(cur)
            cur = []
        cur.append(p)
        if s:
            cur_setting = s
    if cur:
        scenes.append(cur)
    return scenes


def annotate_scene_dramatic_engine(outline: List[Dict], story_idea,
                                   graph=None, scenes_per_call: int = 10) -> int:
    """Author the DRAMATIC ENGINE of each dialogue scene and stamp it on pages.

    Storyboarding tells us WHAT happens on a page; it does not tell the dialogue
    WHY anyone is talking. Alive dialogue is characters pursuing an objective
    against resistance while a scene's value quietly flips. This pass supplies
    exactly that, before a single line is written: it groups the outline into
    scenes, and for each scene with real conversation (two or more present
    characters) it authors —

      • objective   — what the focal character is trying to GET here (a want),
      • opposition  — the person/force/counter-want resisting it,
      • turn        — the value shift across the scene ('from X to Y'),
      • tactics     — a few verbs the characters use to pursue the want.

    Each page in the scene is stamped with `_scene_engine`, which then charges
    BOTH the first-draft dialogue and the review pass. Bounded (windowed by
    `scenes_per_call`), deterministic in structure, and degrades to a no-op on
    any failure so generation never blocks. Returns the number of scenes
    annotated.
    """
    if not outline:
        return 0
    scenes = _group_outline_into_scenes(outline)

    # Only author engines for scenes that actually have a conversation.
    def _scene_chars(scene):
        names = []
        for p in scene:
            for c in (p.get('characters_present') or []):
                c = str(c).strip()
                if c and c not in names:
                    names.append(c)
        return names

    indexed = []
    for si, scene in enumerate(scenes):
        chars = _scene_chars(scene)
        if len(chars) >= 2:
            indexed.append((si, scene, chars))
    if not indexed:
        return 0

    annotated = 0
    for i in range(0, len(indexed), scenes_per_call):
        batch = indexed[i:i + scenes_per_call]
        blocks = []
        for si, scene, chars in batch:
            p0 = scene[0].get('page', '?')
            p1 = scene[-1].get('page', '?')
            beats = ' → '.join(
                str(p.get('beat', '') or p.get('title', ''))[:80] for p in scene
            )[:400]
            blocks.append(
                f"SCENE {si}: pages {p0}-{p1} | setting: "
                f"{scene[0].get('setting', '')[:60]} | characters: "
                f"{', '.join(chars[:5])}\n  beats: {beats}"
            )
        prompt = (
            "You are a dramatist mapping the ENGINE of each scene so its dialogue "
            "can be charged with want and resistance instead of just relaying "
            "plot. A scene lives when someone wants something, something resists, "
            "and a value flips across the scene.\n\n"
            f"STORY: {getattr(story_idea, 'genre', '')} | "
            f"{getattr(story_idea, 'mood', '')}\n"
            f"PREMISE: {str(getattr(story_idea, 'premise', ''))[:200]}\n\n"
            "For EACH scene below, return the dramatic engine:\n"
            "  - objective: what the focal character is trying to GET in this "
            "scene, as an active want (≤12 words, e.g. 'make her admit she "
            "lied')\n"
            "  - opposition: the person, force, or counter-want resisting it "
            "(≤12 words)\n"
            "  - turn: the value shift across the scene as 'from X to Y' "
            "(e.g. 'from trust to suspicion', 'from safe to hunted')\n"
            "  - tactics: 2-3 verbs the characters use to pursue their wants "
            "(e.g. ['charm','provoke','deflect'])\n\n"
            "SCENES:\n" + "\n\n".join(blocks) + "\n\n"
            "Return ONLY a JSON array, one object per scene, each with fields "
            "{scene_id (int), objective, opposition, turn, tactics (array)}. "
            "No markdown."
        )
        try:
            resp = get_openai_prompt_response(
                prompt, temperature=0.6,
                max_completion_tokens=max(1500, min(30000, len(batch) * 260)),
                openai_model=openai_model_large, use_grok=USE_GROK,
            )
            parsed = parse_json_response(resp)
        except Exception as e:
            logger.warning(f"  [SceneEngine] Batch failed ({e}); scenes left unannotated.")
            continue
        if not isinstance(parsed, list):
            continue

        by_id = {}
        for e in parsed:
            if isinstance(e, dict) and 'scene_id' in e:
                try:
                    by_id[int(e['scene_id'])] = e
                except (TypeError, ValueError):
                    pass

        for si, scene, chars in batch:
            e = by_id.get(si)
            if not e:
                continue
            objective = str(e.get('objective', '') or '').strip()
            opposition = str(e.get('opposition', '') or '').strip()
            turn = str(e.get('turn', '') or '').strip()
            tactics = e.get('tactics', []) or []
            if isinstance(tactics, str):
                tactics = [tactics]
            tactics = [str(t).strip() for t in tactics if str(t).strip()][:3]
            if not (objective or turn):
                continue
            engine = (
                "SCENE ENGINE (drive the dialogue with this — never state it "
                "outright): "
                + (f"the focal character wants to {objective}; " if objective else "")
                + (f"resisted by {opposition}; " if opposition else "")
                + (f"across the scene the value turns {turn}; " if turn else "")
                + (f"tactics in play: {', '.join(tactics)}." if tactics else "")
            ).strip()
            for p in scene:
                p['_scene_engine'] = engine
            annotated += 1

    if annotated:
        logger.info(
            "  [SceneEngine] Authored the objective/opposition/turn for %d "
            "dialogue scene(s) to charge the writing.", annotated,
        )
    return annotated


def _expand_pages_to_panels(outline_batch: List[Dict], story_idea: StoryIdea,
                              characters: List[Character], graph: CharacterGraph,
                              panels_per_page_avg: int,
                              prior_script: List[Dict],
                              voice_profiles=None) -> List[Dict]:
    """Expand a batch of outline pages into full panel scripts."""
    
    # Build context from prior pages
    prior_context = ""
    if prior_script:
        recent = prior_script[-3:]
        prior_context = "\nPRIOR PAGES (for continuity):\n"
        for p in recent:
            beat = p.get('beat', '')
            ending = ''
            if p.get('panels') and len(p['panels']) > 0:
                last_panel = p['panels'][-1]
                # Defensive type checking prevents crashes if a panel isn't a dict
                if isinstance(last_panel, dict):
                    ending = last_panel.get('description', '') or ''
                elif isinstance(last_panel, list):
                    strings = [str(item) for item in last_panel if item is not None]
                    ending = " ".join(strings)
                else:
                    ending = str(last_panel)
                ending = ending[:100]
            prior_context += f"  Page {p.get('page')}: {beat} | ended: {ending}...\n"
    
    # Relationship subtext for pairs present in this batch — gives the script
    # LLM the unspoken-truths material that turns flat exchanges into charged
    # ones. Without this, the prompt asks for subtext but supplies none.
    _batch_pages_as_panels = [
        {'panels': [{'characters_in_frame': op.get('characters_present', [])}]}
        for op in outline_batch
    ]
    subtext_block = _build_relationship_subtext_block(graph, _batch_pages_as_panels)

    # Compact character info — human characters get voice/personality;
    # non-human characters get behavioral/symbolic description instead.
    char_voices = []
    for c in characters[:10]:
        ctype = getattr(c, 'character_type', 'human')
        if ctype != 'human':
            # Non-human: show species, role, behavioral traits, symbolic meaning
            species  = getattr(c, 'species', c.age)
            sym      = getattr(c, 'symbolic_meaning', c.backstory)[:100]
            fn       = getattr(c, 'narrative_function', c.cognitive_style)
            trait_str = ', '.join(c.traits[:3])
            char_voices.append(
                f"  {c.name} [{ctype} — {species}]: "
                f"role={c.role} | behaviors={trait_str} | "
                f"function={fn} | symbolises={sym}"
            )
        else:
            # Recommendation A: when an enriched voice profile exists for this
            # character, use its full guide block (origin, accent, heritage-
            # informed idiom, signature lexicon, register, cadence, tics,
            # catchphrases, synthesized speech signature) so the FIRST draft is
            # already written in that voice. Fall back to the raw Character
            # fields only when no profile was built.
            _prof = None
            if voice_profiles:
                _prof = (voice_profiles.get(c.name)
                         or voice_profiles.get(str(c.name).strip()))
            if _prof is not None and hasattr(_prof, 'guide_block'):
                char_voices.append(_prof.guide_block())
                continue
            voice_bits = []
            if getattr(c, 'dialect', ''):
                voice_bits.append(f"dialect: {c.dialect[:80]}")
            if getattr(c, 'cadence', ''):
                voice_bits.append(f"cadence: {c.cadence[:80]}")
            if getattr(c, 'vocabulary_level', ''):
                voice_bits.append(f"vocab: {c.vocabulary_level[:60]}")
            if c.speech_pattern:
                voice_bits.append(f"speech: {c.speech_pattern[:80]}")
            if getattr(c, 'verbal_tics', None):
                voice_bits.append(f"tics: {', '.join(c.verbal_tics[:3])}")
            if getattr(c, 'catchphrases', None):
                voice_bits.append(f"catchphrases: {'; '.join(c.catchphrases[:2])}")
            if c.personality_type:
                voice_bits.append(f"personality: {c.personality_type}")
            if c.humor_style:
                voice_bits.append(f"humor: {c.humor_style}")
            char_voices.append(f"  {c.name}: {' | '.join(voice_bits)}")
    
    pages_brief = []
    for p in outline_batch:
        _tech = str(p.get('_beat_technique', '') or p.get('technique', '')).strip()
        _tech_directives = _build_technique_visual_clause(p) if _tech else {}
        _tech_line = (
            f"  Master Technique: {_tech}\n"
            f"    → Camera: {_tech_directives.get('camera', '')}\n"
            f"    → Lighting: {_tech_directives.get('lighting', '')}\n"
            f"    → Atmosphere: {_tech_directives.get('atmosphere', '')}\n"
            if _tech_directives else ""
        )
        pages_brief.append(
            f"PAGE {p.get('page')}: {p.get('title', '')}\n"
            f"  Setting: {p.get('setting', '')}\n"
            f"  Characters: {', '.join(p.get('characters_present', []) or [])}\n"
            f"  Beat: {p.get('beat', '')}\n"
            f"  Tone: {p.get('emotional_tone', '')}\n"
            + (f"  {p.get('_scene_engine')}\n" if p.get('_scene_engine') else "")
            + f"  Visual hook: {p.get('visual_hook', '')}\n"
            f"  Importance: {p.get('importance', 'standard')}\n"
            f"  Cliffhanger: {p.get('cliffhanger', False)}\n"
            f"{_tech_line}"
        )
    
    prompt = (
        f"{_SINGLE_IMAGE_RULE}\n\n"
        f"You are scripting comic book, graphic novel pages with panel-level detail. Each page "
        f"gets {panels_per_page_avg-1}-{panels_per_page_avg+2} panels (more for action, "
        f"fewer for emotional beats; splash pages = 1 panel only).\n"
        f"  PANEL COUNT FOLLOWS THE WRITING:\n"
        f"  - DIALOGUE-HEAVY beats (negotiations, confrontations, confessions): "
        f"MORE panels — {panels_per_page_avg+1}-{panels_per_page_avg+3}. Every panel holds AT MOST 2-3 "
        f"dialogue lines. Break conversation across shot / reverse-shot / "
        f"reaction panels the way film coverage does; never bury one drawing "
        f"under five bubbles.\n"
        f"  - STRONG-EMOTION beats (loss, awe, terror, love declared, a vow): "
        f"FEWER, LARGER panels — 1-2 — with minimal dialogue (0-2 lines). The "
        f"image IS the beat; give it the page area to land. Mark the page "
        f"importance 'climactic' when one image should own the whole page.\n\n"
        f"STORY CONTEXT:\n"
        f"  {story_idea.genre} | {story_idea.mood}\n"
        f"  Premise: {story_idea.premise[:200]}\n\n"
        f"CHARACTER VOICES:\n" + "\n".join(char_voices) + "\n"
        + (f"\n{trait_voice_amplifier_block(characters)}\n"
           if trait_voice_amplifier_block(characters) else "")
        + (f"\n{subtext_block}\n" if subtext_block else "")
        + f"{prior_context}\n\n"
        f"PAGES TO SCRIPT IN THIS BATCH:\n\n" + "\n\n".join(pages_brief) + "\n\n"
        f"For each page, produce panels with:\n"
        f"  - panel_index (int, starting from 1)\n"
        f"  - description: WHAT IS VISUALLY IN FRAME, written as a vivid 2-3 sentence\n"
        f"      shot the way a graphic novel artist would brief an artist.\n"
        f"      MASTER TECHNIQUE — each page lists its technique and concrete visual\n"
        f"      directives (camera, lighting, atmosphere). Apply these to EVERY panel\n"
        f"      on that page: the camera angle, lighting quality, and visual atmosphere\n"
        f"      stated in the technique directives must be directly reflected in the\n"
        f"      description. This is how the book creates a planned emotional journey —\n"
        f"      not just what happens, but HOW IT LOOKS determines how the reader feels.\n"
        f"      Always cover:\n"
        f"        • EXPRESSION & BODY LANGUAGE: each character's facial expression and\n"
        f"          posture, chosen to convey the panel's emotion. CRITICAL RULE:\n"
        f"          NEVER name an emotion as a label. Show its physical reality instead.\n"
        f"          BAD:  'she looks devastated' / 'he appears afraid' / 'clearly angry'\n"
        f"          GOOD: 'her shoulders collapse inward as if the air left the room;\n"
        f"                 she stares past the camera, eyes red-rimmed and unfocused'\n"
        f"          GOOD: 'his pupils have blown wide, whites visible above the iris;\n"
        f"                 every muscle in his body has frozen, chest expanded mid-breath'\n"
        f"          GOOD: 'jaw muscle knotted at the temple, neck tendons taut,\n"
        f"                 hands balled white-knuckled at his sides'\n"
        f"          Physical signatures to use:\n"
        f"            GRIEF: shoulders drawn in/down, hollow gaze, swollen eyelids,\n"
        f"              tear tracks catching light, jaw tight against trembling\n"
        f"            TERROR: dilated pupils, grey-white pallor, shoulders raised\n"
        f"              to ears, white-knuckled grip, body frozen mid-motion\n"
        f"            DESPAIR: head drooped, limbs too heavy to lift, blank stare,\n"
        f"              body language of someone whose strings were cut\n"
        f"            RAGE: jaw clenched, brow deeply furrowed, tendons in neck,\n"
        f"              hands balled, weight forward on the balls of the feet\n"
        f"            LONGING: gaze at something just outside frame, one hand\n"
        f"              unconsciously reaching, weight shifted toward the absent thing\n"
        f"            SHAME: gaze dropped, shoulders hunched making the body smaller,\n"
        f"              flush of heat visible on cheekbones and neck\n"
        f"        • MAGICAL/SPIRITUAL VFX: when the panel contains supernatural\n"
        f"          elements, describe the VISUAL EFFECT with technical specificity:\n"
        f"            DIVINE LIGHT: volumetric god-rays, chromatic aberration at edges,\n"
        f"              gold dust particles drifting through beams, lens bloom\n"
        f"            GHOST/SPIRIT: translucent layered cool blue-white light, background\n"
        f"              visible through the form, edges dissolving to luminous mist\n"
        f"            SPELL/MAGIC: luminous plasma core with electric arc tendrils,\n"
        f"              helical particle vortex, heat-shimmer distortion in surrounding air\n"
        f"            FIRE MAGIC: white-hot core transitioning to turbulent orange edges,\n"
        f"              individual twisting wisps, subsurface glow on nearby skin\n"
        f"            SPIRITUAL: mandala light patterns forming and dissolving, inner\n"
        f"              luminescence from chest/crown, figure edges softly diffusing to light\n"
        f"        • ACTION & GESTURE: what hands and bodies are physically doing.\n"
        f"        • SPATIAL STAGING: where characters are relative to each other and\n"
        f"          the camera (foreground/background, who faces whom, eyelines).\n"
        f"        • ENVIRONMENT & LIGHT: the concrete setting details and how light\n"
        f"          falls (direction, warmth, shadow), so the space feels real and\n"
        f"          consistent with neighbouring panels.\n"
        f"      Describe ONLY what the camera sees in THIS SINGLE PANEL IMAGE. Do NOT include:\n"
        f"        • Quoted speech or thoughts (e.g. NOT: she says 'I can do this')\n"
        f"        • Caption text (e.g. NOT: caption reads 'Day 312')\n"
        f"        • Character names rendered as on-screen labels, or any word that\n"
        f"          should appear as text in the image\n"
        f"        • Page-layout or multi-panel language — NEVER write phrases like:\n"
        f"            'arranged in a grid across the page'\n"
        f"            'three panels showing...'\n"
        f"            'five windows in a row'\n"
        f"            'each showing a different room'\n"
        f"          A panel description is the brief for ONE image drawn by ONE artist.\n"
        f"          It describes what is INSIDE the frame, not how panels are laid out.\n"
        f"          If a beat covers multiple locations, PICK THE SINGLE MOST DRAMATIC\n"
        f"          LOCATION and describe that one image clearly. The page layout is\n"
        f"          the compositor's job — not the panel description's job.\n"
        f"      Dialogue lives in the 'dialogue' array, not the description.\n"
        f"      The FIRST panel of each new location must be an ESTABLISHING shot that\n"
        f"      fully describes the space (architecture, key props, time of day, weather,\n"
        f"      light source) — later panels in that location inherit and reuse those\n"
        f"      details so the scene stays visually coherent.\n"
        f"      SIMULTANEITY RULE — A CHARACTER CANNOT BE IN TWO PLACES AT ONCE: if a\n"
        f"      page cuts to a SIMULTANEOUS scene (a caption like 'Meanwhile, across\n"
        f"      town…', 'At the same moment…', 'Elsewhere…'), that scene happens AT\n"
        f"      THE SAME TIME as the one you just left, in a DIFFERENT place. Any\n"
        f"      character shown in the scene you just cut away from CANNOT appear in\n"
        f"      the simultaneous scene — populate it ONLY with characters who are\n"
        f"      genuinely elsewhere. (A plain 'Later…' or 'That evening…' cut is\n"
        f"      SEQUENTIAL, not simultaneous — there a character may have travelled and\n"
        f"      can legitimately appear.)\n"
        f"  - composition: close_up | medium_shot | wide_shot | extreme_close | "
        f"over_shoulder | dutch_angle | bird_eye | worm_eye | establishing\n"
        f"      EMOTIONAL FRAMING RULE: when a panel is the MOMENT A FEELING TURNS\n"
        f"      — a kind or harsh word landing, an opportunity sparking excitement,\n"
        f"      a small mishap curdling ease into frustration, a realization, a\n"
        f"      character moved by something — choose close_up or extreme_close and\n"
        f"      make the EYES the focal point (the eyes are the gateway to the soul:\n"
        f"      pupil size, gaze direction, and the fine muscles around the eyes\n"
        f"      carry the emotion). BUT keep VAST feelings WIDE: awe at a landscape,\n"
        f"      a character dwarfed by scale, profound isolation or emptiness live in\n"
        f"      the wide frame, the figure small against the immense — do NOT close in\n"
        f"      on those. For wonder AT NATURE specifically, show the beautiful view\n"
        f"      WIDE, then let a SEPARATE adjacent panel close in on the character's\n"
        f"      wide-eyed face taking it in.\n"
        f"  - camera_angle: eye_level | low_angle | high_angle | dutch\n"
        f"  - mood: one evocative phrase\n"
        f"  - panel_type: character | scenic | cosmic\n"
        f"      character = humans/figures are the primary subject (most panels)\n"
        f"      scenic    = wide environment panel; character may appear small/absent\n"
        f"                  (establishing shots, reaction landscapes, visual breathing room)\n"
        f"      cosmic    = pure cosmic/astronomical subject — Earth from orbit, solar\n"
        f"                  system, galaxy, universe, multiverse, abstract dimensionality.\n"
        f"                  For cosmic panels: characters_in_frame MUST be [] (empty).\n"
        f"                  The image IS the cosmos — no figures, no humanoid shapes.\n"
        f"                  Use dialogue_density: light with EXACTLY one NARRATOR caption (no character speech).\n"
        f"                  This story REQUIRES cosmic panels for its zoom-out sequence.\n"
        f"  - characters_in_frame: array of names (EMPTY [] for cosmic panels)\n"
        f"      HARD LIMIT: at most TWO human characters may appear in any single\n"
        f"      panel. Images render cleanly with one or two figures but garble\n"
        f"      with three or more (blended faces, duplicated limbs). When a beat\n"
        f"      involves three or more people, STAGE IT as the artist would:\n"
        f"        • split the moment across panels (a two-shot, then a reaction),\n"
        f"        • use a close-up or over-the-shoulder on the two who matter most,\n"
        f"        • keep the others off-panel, implied by dialogue or a hand/edge.\n"
        f"      Never list more than two names in characters_in_frame, and never\n"
        f"      describe three or more people together in one description.\n"
        f"      SCENE & SUBJECT VARIETY (critical — avoid monotony): do NOT put\n"
        f"      the same character or entity in every panel. Vary the focal\n"
        f"      subject panel to panel — a reaction on one character, an\n"
        f"      environment/scenic beat, an object or detail, a different\n"
        f"      character pairing. A recurring or ever-present entity (a\n"
        f"      monster, god, cosmic force, spirit) should appear DELIBERATELY\n"
        f"      for the beats that need it, NOT in every frame: leave it out of\n"
        f"      panels where the story focus is elsewhere, and let scenes\n"
        f"      breathe with entity-free panels. When such an entity does\n"
        f"      appear repeatedly, change HOW it appears each time (see\n"
        f"      manifestation_style) so no two panels render it the same way.\n"
        f"  - manifestation_style: OPTIONAL — for non-human entities (spirits,\n"
        f"      angels, gods, cosmic beings) only. Describe HOW the entity appears\n"
        f"      in THIS panel, chosen to serve the emotional beat:\n"
        f"\n"
        f"      This is the most powerful tool for spiritual/cosmic stories.\n"
        f"      A single entity can manifest completely differently panel to panel:\n"
        f"        'a barely visible whisper of golden light at John's shoulder'\n"
        f"        'a vast silhouette filling the entire sky, face unseen'\n"
        f"        'a column of blinding white radiance, abstract and terrifying'\n"
        f"        'a gentle warm glow cupped in John's hands, almost firefly-sized'\n"
        f"        'a colossal geometric form of interlocking sacred symbols'\n"
        f"        'an impression rather than a form — heat, light, and presence'\n"
        f"        'human-sized, translucent, almost recognizable as a face'\n"
        f"        'a fractal spiral of pure light consuming half the panel'\n"
        f"\n"
        f"      Let the emotional purpose drive the choice:\n"
        f"        COMFORT → small, close, warm, intimate\n"
        f"        AWE/REVELATION → vast, overwhelming, filling the frame\n"
        f"        MYSTERY → partial, half-glimpsed, suggested not shown\n"
        f"        INTIMACY → human-adjacent scale, gentle\n"
        f"        COSMIC TRUTH → abstract geometry, pure light, borderless\n"
        f"        GRIEF → dim, receding, at the edge of vision\n"
        f"        POWER → explosive, space-filling, impossible to look at directly\n"
        f"\n"
        f"      Leave empty ('') for human characters and panels where no\n"
        f"      non-human entity appears.\n"
        f"  - sensory_anchor: ONE specific sensory detail anchoring the panel\n"
        f"  - spiritual_intensity: OPTIONAL — use ONLY when this panel is making\n"
        f"      an explicit spiritual, transcendent, or deeply symbolic statement.\n"
        f"      NOT every emotional scene gets this — only when the story is\n"
        f"      reaching beyond the physical into the spiritual dimension.\n"
        f"      Values:\n"
        f"        ''      = no spiritual dimension (most panels — the default)\n"
        f"        'subtle'= a barely-visible spiritual undertone; colour whisper\n"
        f"        'strong'= clear spiritual presence; visible aura or colour field\n"
        f"        'peak'  = overwhelming spiritual moment; aura fills the scene\n"
        f"      When to use 'strong' or 'peak':\n"
        f"        - A character receives divine guidance or a cosmic sign\n"
        f"        - A moment of genuine transcendence or spiritual awakening\n"
        f"        - Love so intense it transcends the personal (universal love)\n"
        f"        - A death that carries spiritual weight (not just physical loss)\n"
        f"        - A revelation that reframes the entire story's meaning\n"
        f"        - Rage or grief at a level that borders on the mythic\n"
        f"      When to use 'subtle':\n"
        f"        - A quiet moment of prayer or meditation\n"
        f"        - A character sensing something beyond the ordinary\n"
        f"        - An emotional undercurrent that the story hints is spiritual\n"
        f"      The pipeline maps this to chakra-inspired aura colours:\n"
        f"        Love → warm golden-amber | Anger → crimson-red | \n"
        f"        Sadness → indigo-violet | Cosmic truth → royal purple |\n"
        f"        Joy → radiant gold-white | Fear → cold yellow-green |\n"
        f"        Transcendence → clear white-blue | Power → electric amber\n"
        f"  - importance: splash | hero | standard | beat | reaction\n"
        f"  - dialogue_density: none | light | moderate | heavy\n"
        f"      none     = purely visual panel, no speech at all (action, environment, reaction)\n"
        f"      light    = 1 short line (≤8 words), panel is mostly image\n"
        f"      moderate = 2-3 lines, balanced image + speech\n"
        f"      heavy    = inner monologue + speech, or extended exchange; panel is dialogue-led\n"
        f"      AIM for HEAVY dialogue coverage: roughly 75-85% of panels should carry\n"
        f"      at least one line of dialogue, thought, or caption. Default to dialogue;\n"
        f"      only omit it when the panel is a deliberate silent beat (pure action,\n"
        f"      a gasp, a wide establishing shot that needs to breathe). A page with\n"
        f"      fewer than 2 dialogue-carrying panels is almost always wrong.\n"
        f"      EXCEPTION: cosmic panels (panel_type: cosmic) SHOULD be none or light\n"
        f"      (narrator caption only) — the cosmos speaks louder without dialogue.\n"
        f"      Preferred page rhythm example: light, moderate, moderate, heavy, light,\n"
        f"      moderate — not none, none, light, none, light, none.\n"
        f"  - dialogue: array of objects, each with:\n"
        f"      speaker: character name, or 'NARRATOR' for caption boxes\n"
        f"      text: the line (\u226415 words \u2014 comics demand brevity)\n"
        f"      bubble_type: speech | thought | shout | whisper | caption\n"
        f"               | excited | angry | scared | tender | cold | sarcastic\n"
        f"\n"
        f"          The bubble TYPE is a visual emotion signal. Choosing the right\n"
        f"          type is as important as the words inside it. Default speech\n"
        f"          bubbles are neutral and boring. Push the reader deeper:\n"
        f"\n"
        f"          speech   = plain rounded bubble (neutral conversation)\n"
        f"          thought  = cloud (inner monologue, no pointer)\n"
        f"          shout    = jagged burst (yelling, sudden impact)\n"
        f"          whisper  = dashed outline (quiet, conspiratorial, secret)\n"
        f"          caption  = yellow narrator box at top of panel\n"
        f"          excited  = TILTED YELLOW rectangle, thick amber border.\n"
        f"                     Joy, elation, triumph, surprise, enthusiasm.\n"
        f"                     The tilt conveys kinetic energy before words are read.\n"
        f"          angry    = red-tinted rectangle with corner spikes, bold border.\n"
        f"                     Rage, defiance, accusation. Colder than 'shout'.\n"
        f"          scared   = wavy pale-blue outline. Trembling edge = physical fear.\n"
        f"                     Dread, panic, shock, horror.\n"
        f"          tender   = soft pink, heavily rounded (near-oval).\n"
        f"                     Love, comfort, vulnerability, gentleness.\n"
        f"          cold     = sharp right-angled rectangle, no rounding, double border.\n"
        f"                     Calculated detachment, cruelty, robotic calm.\n"
        f"          sarcastic= grey, slight clockwise tilt (the 'wrong' direction).\n"
        f"                     Dry wit, irony, disbelief, eye-rolls.\n"
        f"\n"
        f"          USE EMOTIONAL TYPES LIBERALLY:\n"
        f"          joy / triumph \u2192 excited | anger / accusation \u2192 angry\n"
        f"          fear / dread \u2192 scared (as thought) | love / warmth \u2192 tender\n"
        f"          detachment / cold cruelty \u2192 cold | irony / sarcasm \u2192 sarcastic\n"
        f"          secrets / asides \u2192 whisper | raw volume \u2192 shout\n"
        f"          Defaulting to 'speech' for an emotional line is a missed\n"
        f"          opportunity \u2014 visual bubble grammar is one of the medium's\n"
        f"          greatest advantages over prose. Use it.\n"
        f"      speaker_side: left | right | center\n"
        f"          Which HALF of the panel the speaking character occupies.\n"
        f"          The bubble will be placed on that side, adjacent to the character.\n"
        f"          This replaces tails \u2014 proximity communicates attribution.\n"
        f"          Rule: if two characters speak, assign them opposite sides.\n"
        f"      Keep dialogue SHORT \u2014 comics demand brevity. Max ~15 words per bubble.\n"
        f"      INNER MONOLOGUE RULE: if a character is alone or reacting internally,\n"
        f"      give them a thought bubble \u2014 readers want to be inside the character's\n"
        f"      head. Don't leave a reaction panel silent when a thought reveals subtext.\n"
        f"      Use thought/caption for internal moments; speech for conversation;\n"
        f"      shout for action peaks.\n"
        f"  - sfx: array of {{text, position}} objects (e.g. 'BOOM', 'WHUMPH', 'tick tick')\n"
        f"      Most panels have 0 SFX. Use sparingly — only for impact/sound beats.\n\n"
        f"RULES:\n"
        f"  - Splash pages: 1 large panel, minimal dialogue, maximum visual impact\n"
        f"  - Standard pages: vary panel count for rhythm\n"
        f"  - Last panel of a cliffhanger page must hook the reader\n"
        f"  - Dialogue lines should feel natural; characters interrupt, hesitate, lie\n"
        f"  - AVOID pure talking-head sequences (3+ consecutive dialogue panels with\n"
        f"    no action or environment). Interleave wide/action shots to break them up.\n"
        f"  - SCENE-TRANSITION CAPTIONS: whenever the location or time changes from\n"
        f"    the previous page, the FIRST panel of the new scene gets a NARRATOR\n"
        f"    caption orienting the reader — the new place, the time elapsed, or a\n"
        f"    'Meanwhile...' pivot. Readers re-anchor at every cut.\n"
        f"  - NARRATION CADENCE: aim for at least one NARRATOR caption every 3-4\n"
        f"    pages — act openers, scene cuts, time jumps, and thematic beats. A\n"
        f"    graphic novel without narration reads as disconnected stills.\n"
        f"  - FILL PANELS WITH VOICE: every panel where a character is present should\n"
        f"    carry dialogue, thought, or a caption UNLESS it is a deliberate silent beat\n"
        f"    (an explosion, a wide landscape, a wordless reaction close-up that speaks\n"
        f"    for itself). Silent panels are a conscious artistic choice, not a default.\n"
        f"  - Lone characters almost always have inner monologue (thought bubbles).\n"
        f"  - Two characters in frame means they are speaking, reacting, or thinking.\n"
        f"  - If a page has 5+ panels, at most 1-2 may be dialogue_density: none.\n"
        f"  - Match character voices specified above\n"
        f"\n"
        f"  DIALOGUE CRAFT (this is what separates forgettable comics from great ones):\n"
        f"  - RHYTHM: mimic natural speech by alternating short, punchy statements with\n"
        f"    longer, more complex clauses. A page of uniform-length lines reads flat.\n"
        f"    'No. I won't.' next to 'You always do this - you decide, then you call it\n"
        f"    a conversation.' The contrast itself creates energy and feels human.\n"
        f"  - DIALECT ON THE PAGE: render each character's regional/class voice through\n"
        f"    concrete word choice, contractions, and grammar from their voice profile -\n"
        f"    not phonetic spelling gimmicks. Keep it readable but unmistakably theirs.\n"
        f"  - EXACT WORDS, NO FLUFF: choose the precise right word and cut everything\n"
        f"    else. Comics have no room for padding. A learned character may speak with\n"
        f"    Emily-Dickinson-level precision; a blunt one in five-word jabs - but every\n"
        f"    word earns its place.\n"
        f"  - SLANG & EVERYDAY SPEECH: real people use contractions, fragments, filler,\n"
        f"    interruptions, and the slang of their world. Let characters talk like\n"
        f"    people, not like exposition.\n"
        f"  - HUMOR: where a character is witty, let the humor puncture societal\n"
        f"    hypocrisy, human foolishness, or romanticized illusions about the world.\n"
        f"    Wit that observes truth lands harder than wordplay for its own sake.\n"
        f"  - DISTINCT VOICES: a reader should be able to cover the speaker labels and\n"
        f"    still know who is talking. Honour each character's dialect, cadence,\n"
        f"    vocabulary register, verbal tics, and catchphrases from the voice guide.\n"
        f"  - SUBTEXT: people rarely say exactly what they mean. Let characters deflect,\n"
        f"    hint, and talk around the thing - the gap between line and meaning is\n"
        f"    where readers lean in.\n"
        f"  - SCENE ENGINE: where a page carries a SCENE ENGINE line, write the\n"
        f"    dialogue as that character actively PURSUING their objective while the\n"
        f"    opposition pushes back, and let the exchange move the scene's value\n"
        f"    across its turn. Characters chase the want through the listed tactics;\n"
        f"    they never announce the objective. A scene with a want and resistance\n"
        f"    reads alive; one without reads as information.\n"
        f"  - PAGE-TURN PULL: the LAST panel of every page is the page's engine —\n"
        f"    end it on the unresolved thing: a question, a reveal half-shown, a line\n"
        f"    cut off mid-sentence, a reaction to something off-panel. Never let a\n"
        f"    page's final panel merely conclude; make the reader NEED the next page.\n"
        f"    On cliffhanger pages, this final panel should be the strongest image\n"
        f"    and the sharpest line of the page.\n"
        f"  - COSMIC PANELS (panel_type: cosmic):\n"
        f"      * characters_in_frame MUST be [] — no human figures in frame.\n"
        f"      * The image IS the subject: Earth from space, the solar system, the\n"
        f"        Milky Way spiral, the observable universe bubble, the multiverse\n"
        f"        cluster, a dimension-fold, abstract cosmic geometry, etc.\n"
        f"      * Use only caption (NARRATOR) for text — the cosmos does not speak.\n"
        f"      * description must describe ONLY the astronomical/cosmic subject.\n"
        f"        Do NOT mention characters or human figures in the description.\n"
        f"      * Use 'cosmic' or 'establishing' composition.\n"
        f"      * Scale: each zoom-out beat should feel MORE vast than the last.\n"
        f"        Earn the scale through the description (star counts, distances,\n"
        f"        light-year spans, the fetal curve of the multiverse cluster, etc.).\n"
        f"  - SCENIC PANELS (panel_type: scenic): character may be visible but tiny —\n"
        f"    a silhouette against the stars, a figure dwarfed by a cosmic vista.\n"
        f"    These are the bridge panels between dialogue and pure cosmic beats.\n\n"
        f"Return JSON: an array of page objects. Each page object:\n"
        f"  {{ 'page': N, 'title': '...', 'setting': '...', 'emotional_tone': '...',\n"
        f"     'cliffhanger': bool, 'importance': '...', 'panels': [...] }}\n\n"
        f"JSON only. No markdown."
    )
    
    response = get_openai_prompt_response(
        prompt, temperature=0.7, max_completion_tokens=75000,
        openai_model=openai_model_large, use_grok=USE_GROK,
    )
    parsed = parse_json_response(response)
    if parsed and isinstance(parsed, list):
        valid = [p for p in parsed if isinstance(p, dict) and p.get('panels')]
        if valid:
            # Normalize panels to guarantee downstream code always gets dictionaries
            for page in valid:
                clean_panels = []
                raw_panels = page.get('panels', [])
                if not isinstance(raw_panels, list):
                    raw_panels = [raw_panels]
                
                for idx, panel in enumerate(raw_panels, 1):
                    if isinstance(panel, dict):
                        # Normalise the dialogue field — the LLM returns it in
                        # several inconsistent shapes and the downstream renderer
                        # silently drops anything that isn't a list of dicts.
                        raw_dlg = panel.get('dialogue') or []
                        if isinstance(raw_dlg, str):
                            # Bare string: treat as anonymous speech
                            raw_dlg = [{'speaker': '', 'text': raw_dlg,
                                        'bubble_type': 'speech', 'speaker_side': 'left'}]
                        elif isinstance(raw_dlg, list):
                            normed = []
                            for entry in raw_dlg:
                                if isinstance(entry, dict):
                                    # Normalise speaker_side; fall back to position_hint
                                    side = (entry.get('speaker_side')
                                            or entry.get('position_hint', '')
                                            or '').lower()
                                    if 'right' in side:  side = 'right'
                                    elif 'center' in side: side = 'center'
                                    else: side = 'left'
                                    normed.append({
                                        'speaker':      entry.get('speaker', ''),
                                        'text':         entry.get('text', entry.get('line', entry.get('content', ''))),
                                        'bubble_type':  entry.get('bubble_type', entry.get('type', 'speech')),
                                        'speaker_side': side,
                                    })
                                elif isinstance(entry, str) and entry.strip():
                                    normed.append({'speaker': '', 'text': entry.strip(),
                                                   'bubble_type': 'speech', 'speaker_side': 'left'})
                            raw_dlg = normed
                        panel['dialogue'] = [d for d in raw_dlg if d.get('text', '').strip()]
                        # Propagate panel_type from the outline page (or the
                        # required beat) down to each panel so compose_panel_prompt
                        # knows whether this is a cosmic/scenic/character panel.
                        page_panel_type = page.get('panel_type', '')
                        if not panel.get('panel_type') and page_panel_type:
                            panel['panel_type'] = page_panel_type
                        # If the panel has no characters and the page is cosmic,
                        # enforce the cosmic type so no character injection happens.
                        if not panel.get('characters_in_frame') and page_panel_type == 'cosmic':
                            panel['panel_type'] = 'cosmic'

                        # dialogue_density
                        dd = str(panel.get('dialogue_density', '')).lower()
                        # Contradiction guard: the LLM sometimes writes an
                        # explicit 'none' WHILE including a caption in the
                        # dialogue array (the cosmic instruction invited
                        # this). 'none' wipes ALL text at render — including
                        # narration. Content wins over the flag: any panel
                        # with actual dialogue entries is at least 'light'.
                        if dd == 'none' and panel['dialogue']:
                            dd = 'light'
                        if dd not in ('none', 'light', 'moderate', 'heavy'):
                            # Infer from dialogue count when the LLM didn't set it.
                            #
                            # IMPORTANT: do NOT default zero-dialogue character panels
                            # to 'none'.  'none' tells overlay_panel_text to suppress
                            # ALL bubbles — including any NARRATOR captions or thought
                            # bubbles that the dialog-review pass adds afterward.
                            # Character panels with no dialogue yet are a gap to be
                            # filled, so we leave the rendering path open with 'light'.
                            #
                            # Only genuinely visual panel types — cosmic (no figures),
                            # pure-action, or explicitly scenic — default to 'none' when
                            # their dialogue array is empty.
                            n = len(panel['dialogue'])
                            _ptype = str(panel.get('panel_type', '') or '').lower()
                            _chars = panel.get('characters_in_frame') or []
                            _is_visual_panel = (
                                _ptype in ('cosmic', 'scenic')
                                or (not _chars and _ptype not in ('character', 'acting'))
                            )
                            if n == 0:
                                dd = 'none' if _is_visual_panel else 'light'
                            elif n == 1:
                                dd = 'light'
                            elif n <= 3:
                                dd = 'moderate'
                            else:
                                dd = 'heavy'
                        panel['dialogue_density'] = dd

                        # Same normalisation for sfx
                        raw_sfx = panel.get('sfx') or []
                        if isinstance(raw_sfx, str):
                            raw_sfx = [{'text': raw_sfx, 'position': 'top-right'}]
                        elif isinstance(raw_sfx, list):
                            normed_sfx = []
                            for entry in raw_sfx:
                                if isinstance(entry, dict):
                                    normed_sfx.append({
                                        'text':     entry.get('text', entry.get('sfx', '')),
                                        'position': entry.get('position', 'top-right'),
                                    })
                                elif isinstance(entry, str) and entry.strip():
                                    normed_sfx.append({'text': entry.strip(), 'position': 'top-right'})
                            raw_sfx = normed_sfx
                        panel['sfx'] = [s for s in raw_sfx if s.get('text', '').strip()]

                        clean_panels.append(panel)
                    elif isinstance(panel, list):
                        # If the LLM returned a raw list array, extract the text items
                        strings = [str(item) for item in panel if item is not None]
                        desc = " ".join(strings) if strings else "Story moment"
                        clean_panels.append({
                            'panel_index': idx,
                            'description': desc,
                            'composition': 'medium_shot',
                            'camera_angle': 'eye_level',
                            'mood': page.get('emotional_tone', 'standard'),
                            'characters_in_frame': page.get('characters_present', []),
                            'sensory_anchor': '',
                            'importance': 'standard',
                            'dialogue': [],
                            'sfx': []
                        })
                    else:
                        clean_panels.append({
                            'panel_index': idx,
                            'description': str(panel) if panel else "Story moment",
                            'composition': 'medium_shot',
                            'camera_angle': 'eye_level',
                            'mood': page.get('emotional_tone', 'standard'),
                            'characters_in_frame': page.get('characters_present', []),
                            'sensory_anchor': '',
                            'importance': 'standard',
                            'dialogue': [],
                            'sfx': []
                        })
                page['panels'] = clean_panels

            # --- PARTIAL-BATCH RECOVERY ---
            # The LLM sometimes returns only a subset of the requested pages
            # (truncated JSON, token pressure, etc.). Cross-reference every
            # outline page in this batch against what was returned, and build
            # a fallback single-panel entry for any that are missing — so
            # nothing is silently dropped from the final script.
            returned_page_nums = {
                p.get('page') for p in valid if p.get('page') is not None
            }
            dropped = [op for op in outline_batch
                       if op.get('page') not in returned_page_nums]
            if dropped:
                logger.warning(
                    f"  Panel expansion: LLM returned {len(valid)}/{len(outline_batch)} "
                    f"pages. Building fallback for missing pages: "
                    f"{[op.get('page') for op in dropped]}"
                )
                for op in dropped:
                    valid.append({
                        'page': op.get('page'),
                        'title': op.get('title', ''),
                        'setting': op.get('setting', ''),
                        'emotional_tone': op.get('emotional_tone', ''),
                        'cliffhanger': op.get('cliffhanger', False),
                        'importance': op.get('importance', 'standard'),
                        'beat_id': op.get('beat_id', ''),   # preserve for act propagation
                        'panels': [{
                            'panel_index': 1,
                            'description': op.get('beat', '') or op.get('title', 'Story moment'),
                            'composition': 'medium_shot',
                            'camera_angle': 'eye_level',
                            'mood': op.get('emotional_tone', ''),
                            'characters_in_frame': op.get('characters_present', []),
                            'sensory_anchor': op.get('visual_hook', ''),
                            'importance': op.get('importance', 'standard'),
                            'dialogue': [],
                            'sfx': [],
                        }]
                    })
            # Return in original outline order so page numbering stays sequential.
            outline_order = {op.get('page'): i for i, op in enumerate(outline_batch)}
            valid.sort(key=lambda p: outline_order.get(p.get('page'), 9999))
            return valid
    
    logger.warning(f"Panel expansion failed for batch, using outline as-is")
    # Recovery: build minimal single-panel pages
    fallback = []
    for op in outline_batch:
        fallback.append({
            'page': op.get('page'),
            'title': op.get('title', ''),
            'setting': op.get('setting', ''),
            'emotional_tone': op.get('emotional_tone', ''),
            'cliffhanger': op.get('cliffhanger', False),
            'importance': op.get('importance', 'standard'),
            'beat_id': op.get('beat_id', ''),   # preserve for act propagation
            'panels': [{
                'panel_index': 1,
                'description': op.get('beat', 'Story moment'),
                'composition': 'medium_shot',
                'camera_angle': 'eye_level',
                'mood': op.get('emotional_tone', ''),
                'characters_in_frame': op.get('characters_present', []),
                'sensory_anchor': op.get('visual_hook', ''),
                'importance': 'standard',
                'dialogue': [],
                'sfx': [],
            }]
        })
    return fallback


# =============================================================================
# PHASE 3: PAGE LAYOUT PLANNING
# =============================================================================
# Translates panel counts and importance flags into concrete page layouts.
# Each page gets a template assigned, and the template's panel boxes (in
# percentage coordinates) are computed. Layouts vary: splash, half-split,
# thirds, 2x2, 2x3, 3x3, T-layout, L-layout, irregular.
# =============================================================================

# Layout templates. Each: list of (x%, y%, w%, h%) panel boxes within the
