def _pick_layout_template(panel_count: int, importance: str,
                          last_panel_importance: str = '',
                          page_number: int = 0,
                          arc_intensity: float = 0.5,
                          is_cliffhanger: bool = False,
                          stage: str = '',
                          hero_panel_pos: str = '') -> str:
    """Choose a layout template using dramaturgy, not just panel count.

    Layout IS pacing in comics: a large panel makes the reader's eye dwell
    (emotional weight); a dense grid accelerates the read (busy, tense, or
    transitional). We pick to match the page's place on the emotional curve:

      - True peaks / splash beats          -> single splash (held note)
      - High intensity (climbing/climax)   -> hero-dominant layouts (emphasis)
      - Cliffhanger on a right-hand page    -> bottom-dominant payoff panel so
        the hook lands just before the page turn
      - Quiet 'breath' beats                -> cinematic widescreen stacks (slow,
        filmic, lets the moment breathe)
      - Everything else                     -> balanced grids, varied for rhythm

    ``hero_panel_pos`` ('first' | 'last' | '') indicates whether a specific
    panel on the page is marked 'hero'. When set, we choose a template whose
    DOMINANT slot sits at that reading position, so the hero panel actually
    occupies the big box (panels fill boxes in reading order, so the dominant
    slot must align with the hero panel's place in the sequence).
    """
    # Splash always wins — a single full-bleed image is the strongest beat.
    if importance in ('splash', 'climactic') or panel_count == 1:
        return 'splash_1'

    # The shaped emotional climax (stage 'peak') is the book's single loudest
    # moment — give it a splash so it lands with full force, collapsing the
    # page to one held image even if the script planned a multi-panel grid.
    if stage == 'peak':
        return 'splash_1'

    is_right_hand = (page_number % 2 == 1)   # odd = recto = pre-page-turn
    high_intensity = arc_intensity >= 0.7
    quiet = arc_intensity <= 0.32 or stage in ('breath', 'setup', 'resolution')

    # --- Hero-panel position: put the big slot where the hero panel reads. ---
    # This takes precedence over generic intensity layouts because it targets a
    # specific panel the script flagged as the page's focal image.
    if hero_panel_pos == 'first':
        if panel_count == 4:
            return 'hero_top_2_small_below_3'   # dominant slot is box 0 (top)
        if panel_count == 3:
            return 'tall_reveal_left_2'         # dominant slot is box 0 (left, read first)
        if panel_count == 2:
            return 'cinematic_stack_2'          # box 0 is the larger top beat
    elif hero_panel_pos == 'last':
        if panel_count == 4:
            return 'small_top_3_hero_below_4'   # dominant slot is box 3 (bottom)
        if panel_count == 3:
            return 'cinematic_stack_3'          # equal stack; hero reads last & big-feel
        if panel_count == 2:
            return 'cinematic_stack_2'

    # --- Cliffhanger on a right-hand page: end on a big bottom panel so the
    #     hook is the last thing seen before the turn. ---
    if is_cliffhanger and is_right_hand:
        if panel_count >= 4:
            return 'small_top_3_hero_below_4'
        if panel_count == 3:
            return 'cinematic_stack_3'
        if panel_count == 2:
            return 'cinematic_stack_2'

    # --- High intensity: hero-dominant layouts give a clear focal beat. ---
    if high_intensity:
        if panel_count == 2:
            return 'cinematic_stack_2'
        if panel_count == 3:
            return 'tall_reveal_left_2' if page_number % 2 == 0 else 'cinematic_stack_3'
        if panel_count == 4:
            return 'hero_top_2_small_below_3' if page_number % 2 == 0 else 'small_top_3_hero_below_4'
        if panel_count >= 5:
            return 'top_row_2_bottom_3_5'

    # --- Quiet beats: widescreen, slow, filmic. ---
    if quiet:
        if panel_count == 2:
            return 'cinematic_stack_2'
        if panel_count == 3:
            return 'cinematic_stack_3'
        if panel_count == 4:
            return 'splash_top_2_below_3'

    # --- Mid-intensity: balanced grids, rotated for visual variety. ---
    by_count = {
        2: ['split_horizontal_2', 'split_vertical_2'],
        3: ['thirds_horizontal_3', 'cinematic_stack_3'],
        4: ['two_by_two_4', 'tall_left_3_stacked_right_4',
            'tall_right_3_stacked_left_4', 'splash_top_2_below_3'],
        5: ['top_row_2_bottom_3_5'],
        6: ['two_by_three_6'],
        7: ['cinema_wide_top_grid_below_7'],
        8: ['three_by_three_9'],
        9: ['three_by_three_9'],
    }
    options = by_count.get(panel_count, ['two_by_two_4'])
    if not options:
        return 'two_by_two_4'
    return options[page_number % len(options)]


# =============================================================================
# PANEL-STORY RELATIONSHIP PASSES
# -----------------------------------------------------------------------------
# Two deterministic passes that make page structure serve the writing, run
# BEFORE plan_page_layouts so panel scripts and layouts always agree:
#
#   1. promote_emotional_splash_pages — the book's strongest emotional moments
#      collapse to a single full-page image with minimal dialogue. A splash is
#      comics' held note: the reader's eye has nowhere else to go, so the
#      feeling lands at full weight. This also FIXES a real orphaning bug:
#      _pick_layout_template forces 'splash_1' (one box) for stage=='peak'
#      pages, but the page might still carry 4 panel scripts — panels 2-4 and
#      all their dialogue silently fell off the page. Consolidating the panel
#      scripts BEFORE layout planning keeps script, layout, and artwork in
#      agreement.
#
#   2. split_dialogue_heavy_panels — a panel is a beat of time; six dialogue
#      lines in one panel means six moments crammed into one drawing, and the
#      lettering buries the art. Conversation needs PANELS: shot / reverse-shot
#      / reaction. Any panel carrying more than 3 dialogue lines is split into
#      two panels at the dialogue midpoint (respecting MAX_PANELS_PER_PAGE),
#      with the second panel reframed as the conversational counter-angle.
# =============================================================================

def _consolidate_panels_to_splash(page_script: Dict) -> None:
    """Merge all of a page's panels into ONE splash panel, in place.

    Keeps the visual core of the strongest panel and at most two dialogue
    lines (one NARRATOR caption + the page's final spoken line), so the image
    dominates and the words are an accent, not a competition.
    """
    panels = page_script.get('panels') or []
    if len(panels) <= 1:
        return

    # Base panel: an explicitly flagged hero/splash panel wins; otherwise the
    # panel with the richest description (most visual material to draw).
    base = None
    for p in panels:
        if str(p.get('importance', '')).lower() in ('hero', 'splash', 'climactic'):
            base = p
            break
    if base is None:
        base = max(panels, key=lambda p: len(str(p.get('description', '') or '')))

    # Dialogue: gather every line in page order, keep at most 2 —
    # the first NARRATOR caption (orientation) and the LAST non-narrator line
    # (the line the moment lands on). A splash with a wall of bubbles defeats
    # its own purpose.
    all_lines: List[Dict] = []
    for p in panels:
        for d in (p.get('dialogue') or []):
            if isinstance(d, dict) and (d.get('text') or '').strip():
                all_lines.append(d)
    kept: List[Dict] = []
    for d in all_lines:
        if str(d.get('speaker', '')).upper() == 'NARRATOR':
            kept.append(d)
            break
    last_spoken = next(
        (d for d in reversed(all_lines)
         if str(d.get('speaker', '')).upper() != 'NARRATOR'),
        None,
    )
    if last_spoken is not None:
        kept.append(last_spoken)

    # Characters: union across panels in first-appearance order, capped at the
    # two-character limit the rest of the pipeline enforces.
    chars: List[str] = []
    for p in panels:
        for c in (p.get('characters_in_frame') or []):
            c = str(c).strip()
            if c and c not in chars:
                chars.append(c)
    chars = chars[:2]

    # SFX: at most one — the loudest moment's sound.
    sfx = []
    for p in panels:
        for s in (p.get('sfx') or []):
            if isinstance(s, dict) and (s.get('text') or '').strip():
                sfx = [s]
                break
        if sfx:
            break

    merged = dict(base)   # inherit setting, panel_type, technique, annotations
    merged['panel_index'] = 1
    merged['importance'] = 'splash'
    merged['description'] = (
        str(base.get('description', '') or '').rstrip('.') +
        '. A single held full-page moment — the entire emotional weight of '
        'the scene carried in one image, composed for maximum impact.'
    )
    merged['dialogue'] = kept
    merged['dialogue_density'] = 'light' if kept else 'none'
    merged['characters_in_frame'] = chars
    merged['sfx'] = sfx
    # Splash promotion makes the dominant slot moot.
    merged.pop('_page_turn_reveal', None)

    page_script['panels'] = [merged]
    page_script['importance'] = 'climactic'
    page_script['_splash_promoted'] = True


def _build_closeup_splash_page(source_page: Dict, closeup_panel: Dict) -> Dict:
    """Build a NEW full-page splash page carrying only the emotional close-up.

    The close-up panel becomes the sole panel of a fresh page, framed as an
    extreme close-up on the character's face so the emotional beat lands with a
    reader's whole attention. Inherits the source page's setting/act so it slots
    seamlessly into the scene. Carries a light dialogue load (at most the single
    line the moment lands on) so the image dominates.
    """
    # Keep at most one spoken line — the one the moment lands on — plus an
    # optional narrator caption, mirroring _consolidate_panels_to_splash policy.
    lines = [d for d in (closeup_panel.get('dialogue') or [])
             if isinstance(d, dict) and (d.get('text') or '').strip()]
    kept: List[Dict] = []
    for d in lines:
        if str(d.get('speaker', '')).upper() == 'NARRATOR':
            kept.append(d)
            break
    last_spoken = next(
        (d for d in reversed(lines)
         if str(d.get('speaker', '')).upper() != 'NARRATOR'),
        None,
    )
    if last_spoken is not None:
        kept.append(last_spoken)

    splash_panel = dict(closeup_panel)
    splash_panel['panel_index'] = 1
    splash_panel['composition'] = 'extreme_close'
    splash_panel['importance'] = 'splash'
    splash_panel['dialogue'] = kept
    splash_panel['dialogue_density'] = 'light' if kept else 'none'
    splash_panel['_emotion_closeup'] = True
    splash_panel['_emotion_closeup_splash'] = True
    # Strengthen the description toward a held, eye-led full-page moment.
    _base_desc = str(closeup_panel.get('description', '') or '').rstrip('.')
    splash_panel['description'] = (
        _base_desc +
        '. A single held full-page close-up — the character\'s face fills the '
        'frame, the eyes carrying the entire emotional weight of the moment; '
        'pupils, gaze, and the fine muscles around the eyes doing the work, '
        'nothing else competing for the reader\'s attention.'
    )

    new_page = {
        'page': source_page.get('page', 0),   # renumbered by caller
        'setting': source_page.get('setting', ''),
        'act': source_page.get('act', '1'),
        'panels': [splash_panel],
        'importance': 'climactic',
        '_splash_promoted': True,
        '_emotion_splash_page': True,
    }
    # Inherit beat/technique metadata that downstream act/narration passes read.
    for k in ('beat', 'beat_type', 'beat_id', 'title', 'technique',
              '_arc_emotion', '_arc_intensity', '_arc_stage'):
        if k in source_page and k not in new_page:
            new_page[k] = source_page[k]
        elif k in closeup_panel and k not in new_page:
            new_page[k] = closeup_panel[k]
    return new_page


def promote_emotional_splash_pages(script: List[Dict],
                                    emotional_arc: Dict = None) -> Tuple[List[Dict], int]:
    """Collapse the strongest emotional pages to single full-page splashes, and
    lift emotion-driven peak close-ups onto their OWN new full page.

    Two promotion paths:

    A. WHOLE-PAGE PROMOTION (original): a page whose arc marks it a peak — or
       that already declares splash/climactic intent while carrying >1 panel —
       is consolidated to one splash panel in place. This is comics' held note
       and also fixes a real orphaning bug (layout forces splash_1 for peak
       pages, so panels 2..n would otherwise silently fall off).

    B. EMOTION CLOSE-UP EXTRACTION (new): a page containing a peak-intensity
       emotion-driven close-up (flagged `_emotion_closeup_splash` by
       track_emotional_continuity) is SPLIT — the close-up moves onto its own
       new full-page splash placed right after the source page, and the source
       page keeps its remaining panels. This GROWS the book by one page for that
       beat so the emotional moment gets a whole page to itself and nothing else
       is crowded out. If the close-up is already the page's only panel, the
       page is simply promoted in place (no growth needed).

    Because path B inserts pages, this returns a NEW list and the caller must
    renumber pages afterward (the pipeline already re-propagates act numbers and
    renumbers right after this pass). Arc data travels on the panels themselves
    (stamped upstream), so a shifted page index does not desync the emotion.

    Returns (new_script, n_promoted).
    """
    arc = emotional_arc or {}
    promoted = 0
    out: List[Dict] = []

    for pg in script:
        if pg.get('_act_break'):
            out.append(pg)
            continue
        panels = [p for p in (pg.get('panels') or []) if isinstance(p, dict)]

        # ── Path B: peak emotion close-up wants its own splash page ──────────
        closeup_panel = next(
            (p for p in panels if p.get('_emotion_closeup_splash')), None)
        if closeup_panel is not None and len(panels) > 1:
            # Remove the close-up from the source page; it becomes its own page.
            remaining = [p for p in panels if p is not closeup_panel]
            # Re-index the remaining panels so panel_index stays contiguous.
            for _i, _p in enumerate(remaining):
                _p['panel_index'] = _i + 1
            pg['panels'] = remaining
            out.append(pg)
            # The extracted close-up splash page follows immediately.
            splash_page = _build_closeup_splash_page(pg, closeup_panel)
            out.append(splash_page)
            promoted += 1
            logger.info(
                "  [Splash] Emotion close-up extracted to its own full-page "
                "splash after page %s (beat grows by one page).",
                pg.get('page', '?'),
            )
            continue

        # ── Path A: whole-page peak / declared-splash consolidation ──────────
        if len(panels) <= 1:
            # A lone close-up panel flagged for splash still becomes a splash.
            if closeup_panel is not None:
                _consolidate_panels_to_splash(pg)
                promoted += 1
            out.append(pg)
            continue

        pnum = pg.get('page', 0)
        state = arc.get(pnum, {}) if isinstance(arc, dict) else {}
        stage = str(state.get('stage', '') or '')
        try:
            intensity = float(state.get('intensity', 0.5) or 0.5)
        except (TypeError, ValueError):
            intensity = 0.5
        already_splash_intent = str(pg.get('importance', '')).lower() in (
            'splash', 'climactic')
        if stage == 'peak' or intensity >= 0.92 or already_splash_intent:
            _consolidate_panels_to_splash(pg)
            promoted += 1
            logger.info(
                f"  [Splash] Page {pnum} promoted to full-page splash "
                f"(stage={stage or 'n/a'}, intensity={intensity:.2f})"
            )
        out.append(pg)

    # Renumber pages so the inserted splash pages get sequential numbers. Arc
    # data lives on the panels, so this does not desync emotion/intensity.
    for _i, _p in enumerate(out):
        _p['page'] = _i + 1

    if promoted:
        logger.info(f"  [Splash] {promoted} page(s) promoted to emotional splashes.")
    return out, promoted


_REVERSE_ANGLE_REFRAMES = (
    "Reverse angle of the same moment: the camera now behind the listener, "
    "framing the speaker's face over their shoulder as the exchange continues.",
    "The counter-shot: the listening character's reaction fills the frame — "
    "the conversation continuing, the same space from the opposite side.",
    "Same scene a breath later, reframed at a complementary angle; the second "
    "half of the exchange, faces and gestures carrying the reply.",
)


def split_dialogue_heavy_panels(script: List[Dict],
                                 max_lines_per_panel: int = 3,
                                 max_words_per_panel: int = 30) -> Tuple[List[Dict], int]:
    """Split panels carrying too much dialogue into shot/reverse-shot pairs.

    A panel is over-dense — and gets split — when it holds more than
    `max_lines_per_panel` dialogue lines, OR more than `max_words_per_panel`
    total words of dialogue (a two-line, forty-word speech buries the art just
    as badly as four short lines), OR more than two distinct speakers (a reader
    can only track two bubbles' worth of back-and-forth in one drawing). The
    first panel keeps the front half of the lines and the original description;
    the second gets the back half with a reverse-angle reframe. Conversation
    gets the panel real estate it needs instead of burying one drawing under
    lettering.

    When a split is blocked because the page is already at MAX_PANELS_PER_PAGE,
    the panel is flagged `_lettering_over_budget` (non-destructively — no lines
    are dropped) so the layout/rendering stage can give it a larger cell.

    Skips: act breaks, splash-promoted pages, and pages already at
    MAX_PANELS_PER_PAGE. Appearance-continuity annotations are copied onto the
    twin; transition annotations stay on the FIRST twin only.

    Returns (script, n_splits).
    """
    def _over_dense(dlg):
        if len(dlg) > max_lines_per_panel:
            return True
        words = sum(len(str(d.get('text', '') or '').split()) for d in dlg)
        if words > max_words_per_panel:
            return True
        speakers = {str(d.get('speaker', '') or '').strip().lower()
                    for d in dlg if str(d.get('speaker', '') or '').strip()}
        speakers.discard('narrator')
        if len(speakers) > 2:
            return True
        return False

    splits = 0
    over_budget = 0
    for pg in script:
        if pg.get('_act_break') or pg.get('_splash_promoted'):
            continue
        panels = pg.get('panels') or []
        if not panels:
            continue

        new_panels: List[Dict] = []
        page_changed = False
        for _pi, panel in enumerate(panels):
            dlg = [d for d in (panel.get('dialogue') or [])
                   if isinstance(d, dict) and (d.get('text') or '').strip()]
            # Projected page total if we split THIS panel: panels already
            # emitted + this one as two + the untouched remainder.
            projected = len(new_panels) + 2 + (len(panels) - _pi - 1)
            if not _over_dense(dlg):
                new_panels.append(panel)
                continue
            if projected > MAX_PANELS_PER_PAGE:
                # Can't add a panel — flag for a larger cell instead of dropping
                # lines. Readability is preserved by layout, not by deletion.
                panel['_lettering_over_budget'] = True
                over_budget += 1
                new_panels.append(panel)
                continue

            # Split point: dialogue midpoint, front-weighted (3 lines → 2+1).
            mid = (len(dlg) + 1) // 2
            first, second = dict(panel), dict(panel)
            first['dialogue'] = dlg[:mid]
            second['dialogue'] = dlg[mid:]

            # Reframe the twin so the artwork varies: deterministic rotation
            # over the reframe phrasings keyed on page+panel for reproducibility.
            pnum = pg.get('page', 0)
            key = (int(pnum) + len(new_panels)) % len(_REVERSE_ANGLE_REFRAMES)
            base_desc = str(panel.get('description', '') or '').rstrip('.')
            second['description'] = f"{base_desc}. {_REVERSE_ANGLE_REFRAMES[key]}"

            # Density refresh on both twins.
            for twin in (first, second):
                n = len(twin['dialogue'])
                twin['dialogue_density'] = (
                    'light' if n <= 1 else 'moderate' if n <= 3 else 'heavy')

            # SFX belongs to the moment of impact — keep on the first twin only.
            second['sfx'] = []
            # Appearance-continuity: state persists on both twins; the
            # transition (the change event) happens once, on the first.
            second.pop('_appearance_changes', None)
            # Page-turn reveal flag belongs to whichever twin is LAST.
            if panel.get('_page_turn_reveal'):
                first.pop('_page_turn_reveal', None)

            new_panels.extend([first, second])
            splits += 1
            page_changed = True

        if page_changed:
            # Renumber in reading order.
            for i, p in enumerate(new_panels):
                p['panel_index'] = i + 1
            pg['panels'] = new_panels

    if splits:
        logger.info(
            f"  [PanelSplit] {splits} dialogue-heavy panel(s) split into "
            f"shot/reverse-shot pairs."
        )
    if over_budget:
        logger.info(
            f"  [PanelSplit] {over_budget} over-dense panel(s) at the page cap "
            f"flagged for a larger cell (lines preserved, not dropped)."
        )
    return script, splits



def _fill_layout_gaps(boxes: List[Tuple[float, float, float, float]]
                      ) -> List[Tuple[float, float, float, float]]:
    """Expand panel boxes so they tile the full page with no uncovered area.

    Some templates are designed for N panels but can be trimmed to M < N when
    a page has fewer panels than the template's maximum.  The trim leaves white
    space.  This function detects those gaps and grows the surviving boxes to
    fill them, preserving reading order.

    Strategy (correct for any layout):
      1. Compute the total page area not covered by any box.
      2. If coverage >= 98%, the page is already full — return unchanged.
      3. For each column group (boxes sharing an x-range), extend the
         bottommost box DOWN only as far as the next box's top edge, not
         past any other box. This avoids the catastrophic error where a top-row
         panel is extended full-height over a bottom panel that lives in the
         same x column group.
      4. For each row group, extend the rightmost box RIGHT only as far as
         the next box's left edge.

    The original implementation used a simple "extend to 1.0" rule which
    destroyed multi-row layouts: for a 3-top + 1-bottom template, each top-row
    panel was extended to full page height, completely overlapping the bottom
    panel's slot and generating images at the wrong (full-column) aspect ratio.
    """
    if not boxes:
        return boxes

    # Fast path: already full coverage (allow 2% tolerance for rounding)
    total = sum(w * h for _, _, w, h in boxes)
    if total >= 0.98:
        return list(boxes)

    boxes = [list(b) for b in boxes]  # make mutable copies

    # ── Width axis: for each row-group, extend the rightmost box rightward ───
    # Only extend to 1.0 if there is no other box whose x-start falls to the
    # right of this box's right edge in the same y-band.
    rows: Dict[int, List[int]] = {}
    for i, (x, y, w, h) in enumerate(boxes):
        row_key = round(y * 20)  # 5% buckets
        rows.setdefault(row_key, []).append(i)

    for idxs in rows.values():
        # rightmost box in this row
        rightmost = max(idxs, key=lambda i: boxes[i][0] + boxes[i][2])
        x, y, w, h = boxes[rightmost]
        right_edge = x + w
        gap_right = 1.0 - right_edge
        if gap_right > 0.005:
            # Only extend if no OTHER box starts between right_edge and 1.0
            # in an overlapping y-range
            blocked = any(
                bx >= right_edge - 0.005
                and not (by + bh <= y + 0.005 or by >= y + h - 0.005)
                for j, (bx, by, bw, bh) in enumerate(boxes)
                if j != rightmost
            )
            if not blocked:
                boxes[rightmost][2] = w + gap_right

    # ── Height axis: for each col-group, extend the bottommost box downward ──
    # Only extend to 1.0 if there is no other box whose y-start falls below
    # this box's bottom edge in the same x-band.
    cols: Dict[int, List[int]] = {}
    for i, (x, y, w, h) in enumerate(boxes):
        col_key = round(x * 20)  # 5% buckets
        cols.setdefault(col_key, []).append(i)

    for idxs in cols.values():
        bottommost = max(idxs, key=lambda i: boxes[i][1] + boxes[i][3])
        x, y, w, h = boxes[bottommost]
        bottom_edge = y + h
        gap_bottom = 1.0 - bottom_edge
        if gap_bottom > 0.005:
            # Only extend if no OTHER box starts between bottom_edge and 1.0
            # in an overlapping x-range
            blocked = any(
                by >= bottom_edge - 0.005
                and not (bx + bw <= x + 0.005 or bx >= x + w - 0.005)
                for j, (bx, by, bw, bh) in enumerate(boxes)
                if j != bottommost
            )
            if not blocked:
                boxes[bottommost][3] = h + gap_bottom

    return [tuple(b) for b in boxes]


def plan_page_layouts(script: List[Dict],
                      emotional_arc: Optional[Dict] = None) -> List[PageLayout]:
    """Translate the script into concrete page layouts.

    When `emotional_arc` is supplied (keyed by page number), layout selection
    becomes dramaturgical: panel size and arrangement track the emotional curve
    so the page composition itself paces the story.
    """
    logger.info(f"[6/8] Planning page layouts for {len(script)} pages...")
    emotional_arc = emotional_arc or {}
    layouts = []
    for i, page_script in enumerate(script):
        page_number = page_script.get('page', i + 1)
        panels = page_script.get('panels', []) or []
        panel_count = max(1, min(MAX_PANELS_PER_PAGE, len(panels)))
        
        # If we have more panels than max, truncate
        if len(panels) > MAX_PANELS_PER_PAGE:
            panels = panels[:MAX_PANELS_PER_PAGE]
            page_script['panels'] = panels
            panel_count = MAX_PANELS_PER_PAGE
        
        importance = page_script.get('importance', 'standard')
        # Narration splash, act-interstitial AND prologue pages are always laid
        # out as a single full-page panel (the text is the point; one image
        # holds it).
        if (page_script.get('_narration_splash') or importance == 'narration_splash'
                or page_script.get('_act_interstitial') or importance == 'act_interstitial'
                or page_script.get('_prologue') or importance == 'prologue'):
            importance = 'splash'
            panel_count = 1
            if panels:
                panels = panels[:1]
                page_script['panels'] = panels
        last_imp = panels[-1].get('importance', 'standard') if panels else 'standard'

        # Locate a panel flagged as the page's focal image so its layout slot
        # can be the dominant one. We only special-case first/last positions,
        # since those map cleanly to top-dominant / bottom-dominant templates
        # without disturbing reading order.
        hero_panel_pos = ''
        for _pi, _p in enumerate(panels):
            if _p.get('importance', 'standard') in ('hero', 'splash', 'climactic'):
                if _pi == 0:
                    hero_panel_pos = 'first'
                elif _pi == len(panels) - 1:
                    hero_panel_pos = 'last'
                break
        # Page-turn reveal pass may request the final slot be dominant so the
        # pre-turn hook lands big, even without an explicit hero panel.
        if not hero_panel_pos and page_script.get('_hero_panel_pos') == 'last':
            if panels and panels[-1].get('_page_turn_reveal'):
                hero_panel_pos = 'last'

        # Recommendation F↔G synergy: a panel that was too dialogue-dense to
        # split (flagged _lettering_over_budget) needs the biggest cell it can
        # get so its lettering stays readable. If it sits first or last, give it
        # the dominant slot. (Only when no stronger hero claim already exists.)
        if not hero_panel_pos:
            for _pi, _p in enumerate(panels):
                if _p.get('_lettering_over_budget'):
                    if _pi == 0:
                        hero_panel_pos = 'first'
                    elif _pi == len(panels) - 1:
                        hero_panel_pos = 'last'
                    break

        # Pull this page's place on the emotional curve.
        arc_state = emotional_arc.get(page_number, {})
        arc_intensity = float(arc_state.get('intensity', 0.5) or 0.5)
        stage = str(arc_state.get('stage', ''))
        is_cliffhanger = bool(page_script.get('cliffhanger', False))
        
        template_name = _pick_layout_template(
            panel_count, importance, last_imp, page_number,
            arc_intensity=arc_intensity,
            is_cliffhanger=is_cliffhanger,
            stage=stage,
            hero_panel_pos=hero_panel_pos,
        )
        boxes = LAYOUT_TEMPLATES.get(template_name, LAYOUT_TEMPLATES['two_by_two_4'])
        
        # Orphan guard: if the chosen template has FEWER boxes than the page
        # has panels (splash_1 forced for a multi-panel peak page that the
        # promotion pass didn't reach), consolidate the panel scripts so no
        # panel — and no dialogue — silently falls off the page.
        if len(boxes) < panel_count:
            if len(boxes) == 1:
                _consolidate_panels_to_splash(page_script)
                panels = page_script.get('panels', [])
                panel_count = 1
            else:
                # Shouldn't occur with current templates; fall back to a
                # grid that can hold every panel.
                template_name = 'three_by_three_9'
                boxes = LAYOUT_TEMPLATES[template_name]
        
        # Trim boxes to actual panel count, then fill any uncovered page area
        # so panels always tile the full page with no white gaps.
        boxes = boxes[:panel_count]
        boxes = _fill_layout_gaps(boxes)
        
        layouts.append(PageLayout(
            page_number=page_number,
            template_name=template_name,
            panel_count=panel_count,
            panel_boxes=boxes,
            page_title=page_script.get('title', ''),
            page_mood=page_script.get('emotional_tone', ''),
            cliffhanger=is_cliffhanger,
        ))
    
    return layouts


# =============================================================================
# PHASE 4: VISUAL DNA — THREE TIER (Story / Page / Panel)
# =============================================================================
# Story DNA: global look (palette, line style, era, tonal range)
# Page DNA: per-page mood overlay (night scene shifts palette; flashback = sepia)
# Panel DNA: per-panel style emphasis (intimate close-up vs. epic wide shot)
# Emotional Arc: a book-wide curve so palette/light/intensity EVOLVE across pages
#                instead of resetting per page — this is what makes the artwork
#                read as one continuous emotional journey rather than a gallery
#                of strong-but-disconnected stills.
# Visual Grammar: per-beat storytelling techniques drawn from the masters
#                (Schulz/Guarnido acting, Mignola/Miller chiaroscuro, Kirby/Akira
#                 kinetics, Miyazaki environmental "ma").
# All layers are stacked when building the image prompt.
# =============================================================================

# -----------------------------------------------------------------------------
# VISUAL GRAMMAR LIBRARY
# -----------------------------------------------------------------------------
# The named masters, distilled into reusable directive clauses. Each entry is a
# storytelling *method*, not just a look — it shapes how a single image carries
# narrative weight. We pick one per panel based on beat type + emotional
# intensity so the sequence varies its visual language the way a story should.
# -----------------------------------------------------------------------------
VISUAL_GRAMMAR = {
    'acting': {
        # Schulz economy + Guarnido (Blacksad) expressive acting.
        'label': 'character acting',
        'clause': (
            "Economy of storytelling in the spirit of Schulz and Guarnido: lock "
            "the staging and let a single readable facial expression and precise "
            "body language carry the entire beat. Acting over spectacle, subtext "
            "in the posture, restraint in the linework"
        ),
    },
    'chiaroscuro': {
        # Mignola (Hellboy) + Frank Miller (Sin City).
        'label': 'chiaroscuro / silhouette',
        'clause': (
            "Mignola/Miller chiaroscuro: dramatic spot-blacks, bold silhouette, "
            "high-contrast rim light, and generous negative space. Light is the "
            "subject; what is hidden in shadow creates the dread. Graphic, "
            "reductive shapes rather than rendered detail"
        ),
    },
    'kinetic': {
        # Kirby + Akira / Dragon Ball Z.
        'label': 'kinetic action',
        'clause': (
            "Kirby/Akira kinetic energy: dynamic foreshortening, exaggerated "
            "scale and perspective, motion and speed lines, an impact-frame sense "
            "of force exploding out of the panel. Bold diagonals, power posing, "
            "energy crackling at the edges"
        ),
    },
    'environmental': {
        # Miyazaki (Howl's Moving Castle) — the held breath, "ma".
        'label': 'environmental breath (ma)',
        'clause': (
            "Miyazaki environmental storytelling and 'ma' (the held pause): let "
            "the setting, weather, light and sky carry the emotion. A quiet, "
            "atmospheric breath between intensities — character small within a "
            "world that feels alive, wonder and melancholy in the air"
        ),
    },
    'cosmic': {
        # Sagan / Hubble / Moebius — the astronomical sublime.
        'label': 'cosmic sublime',
        'clause': (
            "The astronomical sublime — render the universe itself as the "
            "protagonist. Inspiration: Hubble deep-field photography, Moebius "
            "cosmic space art, Syd Mead, and classic NASA concept art. "
            "Absolute scale: stars are uncountable, galaxies are smudges of "
            "light, the geometry of spacetime bends at the edges. Rich deep "
            "blacks interrupted by bioluminescent nebulae, spiral arms of hot "
            "blue and cool red light, the curve of a gas giant horizon. "
            "Composition: let the void breathe — negative space IS the point. "
            "No human figures, no text, no mechanical objects. Pure cosmos."
        ),
    },
    'reveal': {
        # Stillness that lands a turn — close on the telling detail.
        'label': 'the reveal',
        'clause': (
            "A held, deliberate reveal: isolate the single telling detail, frame "
            "it with intent so the reader's eye lands exactly where the story "
            "turns. Stillness and focus give the moment its weight"
        ),
    },
    'neutral': {
        'label': 'clear staging',
        'clause': (
            "Clear, confident staging that reads instantly: unambiguous focal "
            "point, clean spatial logic, purposeful composition"
        ),
    },
}


def select_visual_grammar(panel_script: Dict, arc_state: Dict) -> Dict[str, str]:
    """Pick the storytelling technique for a panel from beat type + intensity.

    This is deterministic and cheap — no LLM call. The arc's per-page
    `visual_grammar` hint (authored by the art-director pass) wins when present;
    otherwise we infer from composition / mood / importance keywords so the
    sequence still varies its visual language sensibly.
    """
    # 1) Honour an explicit hint from the emotional-arc pass.
    hint = (arc_state or {}).get('visual_grammar', '')
    if hint and hint in VISUAL_GRAMMAR:
        return VISUAL_GRAMMAR[hint]

    # 1b) panel_type=cosmic always uses the cosmic grammar regardless of other
    #     signals — the astronomical sublime has its own visual language.
    panel_type = str(panel_script.get('panel_type', '')).lower()
    if panel_type == 'cosmic':
        return VISUAL_GRAMMAR['cosmic']

    # 1c) Empty characters_in_frame combined with cosmic/space keywords also
    #     suggests a cosmic treatment even when panel_type is unset.
    chars_in_frame = panel_script.get('characters_in_frame', []) or []
    if not chars_in_frame:
        desc_lower = str(panel_script.get('description', '')).lower()
        cosmic_kws = ('galaxy', 'universe', 'cosmos', 'nebula', 'star field',
                      'solar system', 'orbit', 'planet earth', 'milky way',
                      'multiverse', 'dimension', 'void', 'space', 'quasar',
                      'black hole', 'light-year', 'parsec', 'fetus', 'yin-yang')
        if any(kw in desc_lower for kw in cosmic_kws):
            return VISUAL_GRAMMAR['cosmic']

    composition = str(panel_script.get('composition', '')).lower()
    camera = str(panel_script.get('camera_angle', '')).lower()
    importance = str(panel_script.get('importance', 'standard')).lower()
    mood = str(panel_script.get('mood', '')).lower()
    desc = str(panel_script.get('description', '')).lower()
    blob = f"{mood} {desc}"
    intensity = float((arc_state or {}).get('intensity', 0.5) or 0.5)

    action_words = (
        'fight', 'run', 'chase', 'punch', 'explos', 'crash', 'attack', 'leap',
        'smash', 'strike', 'blast', 'battle', 'flee', 'collid', 'slam',
    )
    quiet_words = (
        'whisper', 'alone', 'tear', 'grief', 'memory', 'remember', 'gentle',
        'tender', 'silence', 'still', 'longing', 'embrace', 'reflect', 'mourn',
    )
    dread_words = (
        'fear', 'monster', 'shadow', 'horror', 'nightmare', 'creature', 'dark',
        'lurk', 'dread', 'menace', 'looming', 'threat', 'hollow',
    )

    # 2) Strong cues by content.
    if any(w in blob for w in action_words) or (intensity >= 0.8 and importance in ('splash', 'climactic', 'hero')):
        return VISUAL_GRAMMAR['kinetic']
    if any(w in blob for w in dread_words):
        return VISUAL_GRAMMAR['chiaroscuro']
    if any(w in blob for w in quiet_words) or 'close' in composition:
        return VISUAL_GRAMMAR['acting']

    # 3) Structural cues.
    if composition in ('establishing', 'wide_shot', 'bird_eye') and intensity < 0.55:
        return VISUAL_GRAMMAR['environmental']
    if 'extreme_close' in composition or (importance == 'reaction'):
        return VISUAL_GRAMMAR['reveal']

    # 4) Fall back along the intensity curve.
    if intensity >= 0.75:
        return VISUAL_GRAMMAR['kinetic']
    if intensity <= 0.3:
        return VISUAL_GRAMMAR['environmental']
    return VISUAL_GRAMMAR['acting']


def _fallback_emotional_arc(script: List[Dict], story_dna: Dict) -> Dict[int, Dict[str, Any]]:
    """Deterministic arc if the LLM pass is unavailable.

    Uses each page's own `importance`/`cliffhanger`/`emotional_tone` plus a gentle
    rising-then-resolving curve so the book still has *some* shape rather than a
    flat line.
    """
    arc = {}
    n = max(1, len(script))
    base_palette = story_dna.get('color_palette', 'the established palette')
    for i, page in enumerate(script):
        page_num = page.get('page', i + 1)
        pos = i / max(1, n - 1)            # 0 → 1 across the book
        # Rising action to ~85%, brief peak, then a resolution dip.
        if pos < 0.85:
            intensity = 0.25 + 0.65 * (pos / 0.85)
        else:
            intensity = 0.9 - 0.5 * ((pos - 0.85) / 0.15)
        importance = str(page.get('importance', 'standard')).lower()
        if importance in ('splash', 'climactic'):
            intensity = min(1.0, intensity + 0.15)
        if page.get('cliffhanger'):
            intensity = min(1.0, intensity + 0.08)
        intensity = round(max(0.1, min(1.0, intensity)), 2)

        if intensity >= 0.75:
            grammar, palette, lighting = 'kinetic', 'palette pushed hot and saturated', 'harsh high-contrast light, deep shadows'
        elif intensity <= 0.3:
            grammar, palette, lighting = 'environmental', 'palette cooled and desaturated', 'soft diffuse light, open air'
        else:
            grammar, palette, lighting = 'acting', 'palette holding the established register', 'controlled directional light'

        arc[page_num] = {
            'stage': 'rising' if pos < 0.85 else 'resolution',
            'intensity': intensity,
            'key_emotion': page.get('emotional_tone', '') or story_dna.get('mood_thread', ''),
            'palette_state': f"{palette} (anchored to {base_palette})",
            'lighting_state': lighting,
            'transition_style': 'action-to-action' if intensity >= 0.75 else 'aspect-to-aspect' if intensity <= 0.3 else 'subject-to-subject',
            'visual_grammar': grammar,
        }
    return arc


_ARC_SINGLE_CALL_MAX = 80    # books this size or smaller: one whole-book pass
_ARC_WINDOW = 60             # pages per windowed arc call for larger books


def _arc_prompt_fields(grammar_keys: str, n_expected: int) -> str:
    """The shared per-page JSON field spec for arc-authoring prompts."""
    return (
        f"For EACH page return one JSON object in a top-level array, in page "
        f"order, with fields:\n"
        f"  - page: int (must match the outline)\n"
        f"  - stage: one of 'setup','rising','turn','peak','breath','resolution'\n"
        f"  - intensity: float 0.0-1.0 (the emotional amplitude of this page; "
        f"the values across pages should form a smooth, intentional curve)\n"
        f"  - key_emotion: 1-3 words, the dominant feeling\n"
        f"  - palette_state: how the palette sits HERE relative to the global "
        f"palette (e.g. 'cooled toward sickly cyan', 'bleeding warm amber', "
        f"'drained to near-grey') — phrase as an evolution, not a reset\n"
        f"  - lighting_state: the lighting treatment for this page\n"
        f"  - transition_style: the dominant panel-to-panel transition for this "
        f"page — one of 'moment-to-moment','action-to-action','subject-to-"
        f"subject','scene-to-scene','aspect-to-aspect'\n"
        f"  - visual_grammar: the storytelling technique that best serves this "
        f"page — one of: {grammar_keys}\n\n"
        f"Return ONLY the JSON array of exactly {n_expected} objects. No markdown."
    )


def _parse_arc_entries(parsed, valid_grammar) -> Dict[int, Dict[str, Any]]:
    """Validate/normalise raw LLM arc entries into the arc dict shape."""
    arc: Dict[int, Dict[str, Any]] = {}
    if not isinstance(parsed, list):
        return arc
    for entry in parsed:
        if not isinstance(entry, dict):
            continue
        try:
            pnum = int(entry.get('page'))
        except (TypeError, ValueError):
            continue
        try:
            intensity = float(entry.get('intensity', 0.5))
        except (TypeError, ValueError):
            intensity = 0.5
        intensity = round(max(0.0, min(1.0, intensity)), 2)
        grammar = entry.get('visual_grammar', '')
        if grammar not in valid_grammar:
            grammar = ''   # let select_visual_grammar infer downstream
        arc[pnum] = {
            'stage': entry.get('stage', ''),
            'intensity': intensity,
            'key_emotion': entry.get('key_emotion', ''),
            'palette_state': entry.get('palette_state', ''),
            'lighting_state': entry.get('lighting_state', ''),
            'transition_style': entry.get('transition_style', ''),
            'visual_grammar': grammar,
        }
    return arc


def _designate_climax_page(script: List[Dict]) -> int:
    """Pick ONE page as the book's true climax, deterministically.

    Preference order: the 'climactic'-importance page nearest the 80% mark of
    the book (the classic placement), else any 'splash', else the 80% mark
    itself. Giving every arc window the same designated climax is what stops
    each window from scoring its own local peak at full intensity — which
    would flatten the journey into a plateau of climaxes and rob the real one
    of its headroom.
    """
    pages = [int(p.get('page', i + 1) or (i + 1)) for i, p in enumerate(script)]
    if not pages:
        return 1
    target = pages[min(len(pages) - 1, int(len(pages) * 0.8))]
    best, best_d = None, None
    for p in script:
        if str(p.get('importance', '')).lower() == 'climactic':
            pn = int(p.get('page', 0) or 0)
            d = abs(pn - target)
            if best is None or d < best_d:
                best, best_d = pn, d
    if best:
        return best
    for p in script:
        if str(p.get('importance', '')).lower() == 'splash':
            return int(p.get('page', 0) or 0) or target
    return target


def build_setup_payoff_ledger(script: List[Dict], required_beats: List[Dict],
                              get_llm_response, parse_json,
                              llm_model: str = None, use_grok: bool = False,
                              climax_page: int = None,
                              chunk: int = 60) -> Dict[str, Any]:
    """Track planted story elements and verify they pay off.

    The storyboard-context pass lets a section plant a setup that lands in a
    later act; this closes the loop by checking the setup was actually PAID.
    An LLM extracts planted elements (a named object, a promise, a secret, a
    threat — Chekhov's guns) from the beats, each with the page it is planted
    and a couple of distinctive keywords. A deterministic scan then checks
    whether those keywords reappear later in the script (after the plant, up to
    the end of the element's act or the climax). Elements never touched again
    are 'orphans' — surfaced for repair.

    Returns {'planted': [...], 'orphans': [...], 'paid': int}. Best-effort;
    returns an empty ledger on failure. No changes are made to the script — this
    is a reporting/gate pass so a human (or a later targeted pass) can act.
    """
    empty = {'planted': [], 'orphans': [], 'paid': 0}
    if not required_beats or not script:
        return empty

    # ── Extract planted elements from the beats, in bounded chunks ────────────
    planted: List[Dict] = []
    beats = list(required_beats)
    for i in range(0, len(beats), chunk):
        group = beats[i:i + chunk]
        beat_lines = "\n".join(
            f"  [{b.get('beat_id','?')} act {b.get('act','?')} "
            f"pp.{b.get('page_range','?')}] {str(b.get('description',''))[:160]}"
            for b in group
        )
        prompt = (
            "You are a story editor hunting for SETUPS that must pay off — "
            "Chekhov's guns. From the beats below, list only elements that are "
            "PLANTED and create an expectation of a later payoff: a specific "
            "object introduced with weight, a promise or vow, a secret withheld, "
            "a named threat, a mystery posed, a skill established for later use. "
            "Ignore ordinary scene detail that implies no payoff.\n\n"
            f"BEATS:\n{beat_lines}\n\n"
            "Return ONLY a JSON array. Each item:\n"
            "{\"element\": \"the gun in the drawer\", "
            "\"planted_page\": 12, "
            "\"kind\": \"object|promise|secret|threat|mystery|skill\", "
            "\"keywords\": [\"gun\", \"drawer\"]}\n"
            "keywords: 1-3 distinctive lowercase words that would recur at the "
            "payoff. Return [] if nothing genuinely qualifies."
        )
        try:
            kwargs = {"temperature": 0.3, "max_completion_tokens": 3000,
                      "use_grok": use_grok}
            if llm_model:
                kwargs["openai_model"] = llm_model
            got = parse_json(get_llm_response(prompt, **kwargs)) or []
            if isinstance(got, list):
                for e in got:
                    if isinstance(e, dict) and e.get('element') and e.get('keywords'):
                        planted.append(e)
        except Exception:
            continue

    if not planted:
        return empty

    # ── Build a page-number → searchable-text index of the whole script ───────
    import re as _re2

    def _pr_end(b):
        nums = _re2.findall(r'\d+', str(b.get('page_range', '') or ''))
        return int(nums[-1]) if nums else 0

    # act end page per act (max page_range end among that act's beats)
    act_end: Dict[str, int] = {}
    for b in beats:
        a = str(b.get('act', '1'))
        act_end[a] = max(act_end.get(a, 0), _pr_end(b))

    # planted_page → act lookup (nearest beat covering it)
    page_text: Dict[int, str] = {}
    for page in script:
        if page.get('_act_break') or page.get('_prologue'):
            continue
        pnum = int(page.get('page', 0) or 0)
        parts = [str(page.get('beat', '') or ''), str(page.get('title', '') or '')]
        for panel in (page.get('panels') or []):
            parts.append(str(panel.get('description', '') or ''))
            for d in (panel.get('dialogue') or []):
                parts.append(str((d or {}).get('text', '') or ''))
        page_text[pnum] = ' '.join(parts).lower()

    all_pages_sorted = sorted(page_text)
    max_page = all_pages_sorted[-1] if all_pages_sorted else 0
    climax_page = climax_page or max_page

    orphans: List[Dict] = []
    paid = 0
    for e in planted:
        kws = [str(k).strip().lower() for k in (e.get('keywords') or []) if str(k).strip()]
        if not kws:
            continue
        try:
            pp = int(e.get('planted_page', 0) or 0)
        except (TypeError, ValueError):
            pp = 0
        # Payoff window: after the plant, through the end of its act OR the climax.
        elem_act = None
        for b in beats:
            s, en = 0, _pr_end(b)
            m = _re2.findall(r'\d+', str(b.get('page_range', '') or ''))
            if m:
                s = int(m[0])
            if s <= pp <= en:
                elem_act = str(b.get('act', '1'))
                break
        window_end = max(act_end.get(elem_act, max_page), climax_page)
        found_at = None
        for pnum in all_pages_sorted:
            if pnum <= pp or pnum > window_end:
                continue
            txt = page_text.get(pnum, '')
            if any(k in txt for k in kws):
                found_at = pnum
                break
        if found_at:
            paid += 1
            e['paid_at'] = found_at
        else:
            e['window'] = [pp + 1, window_end]
            orphans.append(e)

    ledger = {'planted': planted, 'orphans': orphans, 'paid': paid}
    if orphans:
        logger.info(
            "  [SetupPayoff] %d/%d planted element(s) pay off; %d orphan(s) "
            "never resolve:", paid, len(planted), len(orphans),
        )
        for o in orphans[:8]:
            logger.info("    orphan: '%s' (planted ~p%s, %s) — no payoff by p%s",
                        str(o.get('element', ''))[:60], o.get('planted_page', '?'),
                        o.get('kind', '?'), o.get('window', ['?', '?'])[1])
    else:
        logger.info("  [SetupPayoff] All %d planted element(s) pay off.", paid)
    return ledger


