def _technique_flourish_for(key_emotion: str, page_number: int) -> str:
    """Pick the art-technique flourish for a page from its arc emotion.

    Deterministic on (emotion family, page_number): the same book re-renders
    identically, while consecutive pages in the same emotional register rotate
    through the family's variants instead of repeating one phrase. Returns ''
    when the emotion doesn't route to a family — the global style stands alone,
    which is the correct behaviour for neutral connective pages.
    """
    emo = str(key_emotion or '').lower().strip()
    if not emo:
        return ''
    family = ''
    for keywords, fam in _FLOURISH_FAMILY_ROUTES:
        if any(k in emo for k in keywords):
            family = fam
            break
    if not family:
        return ''
    variants = _TECHNIQUE_FLOURISHES.get(family) or ()
    if not variants:
        return ''
    return variants[int(page_number) % len(variants)]


# Colour grade is a film's primary emotional instrument — the same scene graded
# cold-and-crushed reads as despair, graded warm-and-golden reads as joy. This
# maps each emotion family to a concrete grade (colour temperature + palette
# psychology), keyed to the SAME families the flourish/drama routers use, so a
# panel's grade is chosen by where it sits on the emotional journey rather than
# by a generic grammar label. Intensity then modulates contrast/saturation.
