def _emotion_prompt_grade_for(emotion_text: str, intensity: float = 0.5) -> str:
    """Resolve an emotion + arc intensity to a concrete colour-grade directive.

    Routes the emotion to its family (same routing as the flourish/drama
    libraries), looks up the family's grade, then modulates contrast/saturation
    by the page's place on the emotional journey — a peak is pushed to the
    sequence's boldest register, a breath is held soft — so the grade both
    colours the feeling AND tracks the arc's rise and fall. Returns '' when the
    emotion doesn't route (neutral pages keep the generic palette logic).
    """
    emo = str(emotion_text or '').lower().strip()
    if not emo:
        return ''
    family = ''
    for keywords, fam in _FLOURISH_FAMILY_ROUTES:
        if any(k in emo for k in keywords):
            family = fam
            break
    base = _EMOTION_PROMPT_GRADE.get(family)
    if not base:
        return ''
    try:
        inten = float(intensity)
    except (TypeError, ValueError):
        inten = 0.5
    if inten >= 0.7:
        mod = ("pushed to the boldest contrast and saturation of the sequence, "
               "the deepest blacks and the most committed colour")
    elif inten <= 0.32:
        mod = ("held soft and low-contrast, shadows lifted and saturation gently "
               "pulled back — a visual exhale")
    else:
        mod = "balanced contrast, colour present but not shouting"
    return f"{base}; {mod}"


# =============================================================================
# DRAMATIC-CRAFT TECHNIQUE LIBRARY  (the writing analogue of the art library)
# -----------------------------------------------------------------------------
# The art-technique library above shifts DRAWING technique with feeling. This is
# its counterpart for the WRITING: it shifts DIALOGUE/SCENE craft with feeling.
# Just as horror pages borrow German-Expressionist shadow geometry, a scene of
# menace should borrow the craft of the stage traditions that mastered menace —
# the loaded pause, the line that says one thing and means another. Each emotion
# family maps to concrete dramatic techniques (subtext, staccato exchange,
# dramatic irony, understatement, the held silence) drawn from theatrical
# TRADITIONS and named CRAFT DEVICES — not from any identifiable living writer,
# so the model reaches for the technique, not a person's style.
#
# Selection is deterministic on (family, seed) so the same act reproduces, while
# neighbouring scenes in the same register rotate through the family's devices
# instead of repeating one. The chosen technique is injected into the dialogue
# reviewer's brief for that act, so the review pass sharpens each scene toward
# the craft that best serves its feeling.
# =============================================================================
