def _dramatic_technique_for(key_emotion: str, seed: int) -> str:
    """Pick the dialogue/scene craft technique for a scene from its emotion.

    Mirrors _technique_flourish_for exactly (same family routing, same
    deterministic rotation), but returns a WRITING directive instead of an art
    one. Returns '' for neutral/unrouted emotions so connective scenes are left
    to the natural voice.
    """
    emo = str(key_emotion or '').lower().strip()
    if not emo:
        return ''
    family = ''
    for keywords, fam in _FLOURISH_FAMILY_ROUTES:
        if any(k in emo for k in keywords):
            family = fam
            break
    variants = _DRAMATIC_TECHNIQUES.get(family) or ()
    if not variants:
        return ''
    return variants[int(seed) % len(variants)]


# =============================================================================
# CHARACTER-TRAIT SPEECH AMPLIFIERS
# -----------------------------------------------------------------------------
# Expression amplification pushes a character's FACE harder toward their
# emotion; this pushes their VOICE harder toward their defining TRAITS. A
# character described as "arrogant" should not merely be labelled arrogant — the
# shape of their sentences should be arrogant. Each trait maps to a concrete,
# exaggeratable speech behaviour, so the dialogue leans into the trait instead
# of only asserting it. Applied on top of the character's base voice profile, in
# both the first-draft brief and the review pass.
# =============================================================================
_TRAIT_SPEECH_AMPLIFIERS: Dict[str, str] = {
    'arrogant': "speaks in verdicts, not opinions; dismisses with a single word; assumes agreement and talks over doubt",
    'proud':    "never asks for help outright; deflects concern; frames need as preference",
    'anxious':  "hedges and qualifies ('maybe', 'I mean', 'sort of'); self-interrupts; trails off; asks permission mid-thought",
    'nervous':  "over-explains, back-tracks, fills silence with apology and caveat",
    'shy':      "under-speaks; answers in fragments; lets others finish for them",
    'sardonic': "answers earnestness with dry irony; understated, deadpan; the joke is in the flatness",
    'sarcastic':"says the opposite of the meaning with a razor edge; mock-agreement as a weapon",
    'witty':    "reaches for the unexpected turn, the pun, the epigram; can't resist the clever line",
    'blunt':    "no cushioning, no preamble; states the hard thing plainly and stops",
    'gentle':   "softens edges; offers rather than demands; asks before asserting",
    'warm':     "reaches toward the other person in the line — uses their name, checks on them",
    'cold':     "clipped, transactional, minimal; withholds warmth like currency",
    'commanding':"imperatives, not requests; short declaratives; expects to be obeyed",
    'timid':    "seeks reassurance; poses statements as questions; apologizes for taking space",
    'boastful': "steers every subject back to themselves; inflates; name-drops their own deeds",
    'cynical':  "assumes the worst motive; punctures sincerity; treats hope as naivety",
    'idealistic':"reaches for the principle, the ought, the larger meaning; earnest to a fault",
    'manipulative':"leads with questions that box the other in; flatters before the ask; never states the real goal",
    'stoic':    "understates pain and cost; short sentences; refuses the emotional word",
    'volatile': "swings register mid-scene — calm to eruption on a single trigger word",
    'playful':  "teases, riffs, refuses to stay serious; turns tension into a game",
    'formal':   "complete sentences, precise diction, no contractions; ceremony as armor",
    'streetwise':"idiom-rich, elliptical, economical; says much in slang and less in full",
    'naive':    "takes things literally; misses the subtext everyone else hears; asks the innocent question",
    'weary':    "spends few words; lets sentences sag; answers as if talking costs something",
    'zealous':  "rhetorical build, repetition, rising cadence; speaks in causes",
    'secretive':"answers narrowly and truthfully-but-incompletely; volunteers nothing",
}

