def trait_speech_directives(character, max_n: int = 2) -> List[str]:
    """Return concrete speech-exaggeration directives for a character's traits.

    Scans the character's traits, personality_type, and humor_style, maps each
    to a canonical amplifier (directly or via synonym), and returns up to
    ``max_n`` distinct directives — enough to shape the voice, few enough to
    keep it coherent. Deterministic in trait order.
    """
    if character is None:
        return []
    pool = []
    for t in (getattr(character, 'traits', None) or []):
        pool.append(str(t))
    for extra in (getattr(character, 'personality_type', ''),
                  getattr(character, 'humor_style', '')):
        if extra:
            pool.append(str(extra))

    seen, out = set(), []
    for raw in pool:
        w = str(raw).strip().lower()
        if not w:
            continue
        key = w if w in _TRAIT_SPEECH_AMPLIFIERS else _TRAIT_SYNONYMS.get(w, '')
        # Also try single-word tokens inside a multi-word trait phrase.
        if not key:
            for tok in _emo_re.split(r'[^a-z\-]+', w):
                if tok in _TRAIT_SPEECH_AMPLIFIERS:
                    key = tok
                    break
                if tok in _TRAIT_SYNONYMS:
                    key = _TRAIT_SYNONYMS[tok]
                    break
        if key and key not in seen:
            seen.add(key)
            out.append(f"{key}: {_TRAIT_SPEECH_AMPLIFIERS[key]}")
            if len(out) >= max_n:
                break
    return out


def trait_voice_amplifier_block(characters: List, max_chars: int = 8) -> str:
    """Build a compact 'lean the voice into the trait' block for a cast.

    Used in the dialogue brief so first-draft AND reviewed lines exaggerate each
    character's defining traits in the SHAPE of their speech, not just assert
    them. Returns '' when no character has a mappable trait.
    """
    lines = []
    for c in (characters or [])[:max_chars]:
        directives = trait_speech_directives(c, max_n=2)
        if directives:
            lines.append(f"  {getattr(c, 'name', '?')} — {'; '.join(directives)}")
    if not lines:
        return ''
    return ("TRAIT-VOICE AMPLIFIERS (make the SHAPE of each character's speech "
            "exaggerate their defining traits, not merely state them):\n"
            + "\n".join(lines))


