    (('gothic', 'haunted', 'haunting'),                              'gothic'),
    (('cosmic horror', 'lovecraft', 'eldritch', 'cosmic dread'),     'cosmic_horror'),
    (('horror', 'slasher', 'terror', 'macabre'),                     'horror'),
    (('fable', 'parable', 'folk tale', 'folktale'),                  'fable'),
    (('fairy tale', 'fairytale'),                                    'fable'),
    (('myth', 'mythic', 'legend', 'epic fantasy', 'saga'),           'myth'),
    (('tragedy', 'tragic'),                                          'tragedy'),
    (('magical realism', 'magic realism', 'magical-realist'),        'magical_realism'),
