def generate_comic_title(project: ComicBookProject, script: List[Dict]) -> str:
    """Generate a title for the comic. Prefers an evocative 2-5 word title."""
    si = project.story_idea
    page_titles = [p.get('title', '') for p in script[:6] if p.get('title')]
    prompt = (
        f"Generate a title for a graphic novel.\n\n"
        f"GENRE: {si.genre}\nMOOD: {si.mood}\n"
        f"PREMISE: {si.premise}\n"
        f"EARLY PAGE TITLES: {'; '.join(page_titles[:4])}\n\n"
        f"Title should be evocative, 2-5 words, memorable, comic-cover ready.\n"
        f"Generate 4 options, pick the best, return ONLY the chosen title in quotes."
    )
    response = get_openai_prompt_response(
        prompt, temperature=0.7, max_completion_tokens=2000,
        openai_model=openai_model_large, use_grok=USE_GROK,
    )
    title = response.strip().strip('"').strip("'")
    quoted = re.findall(r'"([^"]+)"', response)
    if quoted:
        title = quoted[-1]
    return title or f"{si.genre.split()[0]} Tale"


# =============================================================================
# ACT-BREAK PAGES
# =============================================================================
# A full-bleed illustrated act-break card (e.g. "ACT TWO") is inserted at
# each act transition. It works like a chapter title page in a novel — a
# moment of pause and anticipation. Rather than plain text on white (which
# reads as a production artefact), each break card:
#   • generates one AI illustration that captures the tone and colour of the
#     incoming act (using the arc palette state for that page)
#   • overlays a bold, typeset act label at print resolution
#   • occupies exactly one page (single-panel splash) so layouts stay clean
#
# The function is called in synthesize_comic_book() after script + layouts are
# built. It renumbers all subsequent pages to accommodate the inserts.
# =============================================================================

# Beat types produced by the enrichment pass (backstory flashbacks, side-story
# showcases, world-building asides). Their `act` field is written by an LLM and
# is NOT reliable — the model routinely invents act numbers ("act": "6",
# "act": "14") that don't correspond to the real act structure. Left unchecked,
# those phantom acts are what make the act sequence read as 1 → 6 → 14 instead
# of 1 → 2 → 3, so only a handful of act-break cards and interstitials ever fire.
_ENRICHMENT_BEAT_TYPES = {
    'backstory', 'character_showcase', 'showcase', 'side_story',
    'world_building', 'worldbuilding', 'worldbuild',
    # Emotional-journey enrichment that attaches to an EXISTING act (inherits
    # that act by page position). 'interlude' is deliberately NOT here, because
    # it must be allowed to form its own new act.
    'emotional_setup', 'contrast_relief', 'stakes', 'payoff', 'empathy',
}


def _normalize_act_structure(beats: List[Dict],
                             log: bool = True) -> List[Dict]:
    """Make beat act numbers a clean, contiguous 1..K progression.

    Two problems are corrected, in order:

    1. **Phantom acts from enrichment.** An enrichment beat (backstory / side
       event) must not define its own act — it belongs to whatever act its
       *page position* falls in. We overwrite each enrichment beat's `act` with
       the act of the surrounding MAIN spine at that page, so enrichment can
       never introduce a new act value.

    2. **Non-contiguous acts.** Even the main spine can end up with gaps (the
       single-pass extractor trusts the LLM's `act` field). We remap the
       distinct act values — ordered by the page where each first appears — to
       1, 2, 3, … so acts always progress by one. This is what lets
       _forward_act_transitions / _find_act_boundaries fire a break + narration
       page at EVERY act, in order.

    Mutates and returns ``beats``.
    """
    if not beats:
        return beats

    def _act_int(a):
        try:
            return int(str(a).strip())
        except (TypeError, ValueError):
            return 0

    # ── 1. Enrichment beats inherit the main spine's act by page position ──────
    main = [b for b in beats
            if str(b.get('beat_type', '') or '').strip().lower()
            not in _ENRICHMENT_BEAT_TYPES]
    if main:
        page_act = {}
        for b in main:
            s, e = _parse_pr(b.get('page_range', ''))
            act = str(b.get('act', '') or '1').strip() or '1'
            for p in range(max(1, s), max(1, e) + 1):
                page_act.setdefault(p, act)
        if page_act:
            lo, hi = min(page_act), max(page_act)
            filled, last = {}, page_act[lo]
            for p in range(lo, hi + 1):
                last = page_act.get(p, last)
                filled[p] = last
            for b in beats:
                if str(b.get('beat_type', '') or '').strip().lower() in _ENRICHMENT_BEAT_TYPES:
                    s, _ = _parse_pr(b.get('page_range', ''))
                    key = max(lo, min(hi, s or lo))
                    b['act'] = filled.get(key, last)

    # ── 2. Renumber distinct acts contiguously, ordered by first appearance ────
    firsts = {}
    for b in beats:
        act = str(b.get('act', '') or '1').strip() or '1'
        s = _parse_pr(b.get('page_range', ''))[0] or 0
        if act not in firsts or s < firsts[act]:
            firsts[act] = s
    ordered = sorted(firsts, key=lambda a: (firsts[a], _act_int(a)))
    remap = {act: str(i + 1) for i, act in enumerate(ordered)}

    if any(remap[a] != a for a in remap):
        for b in beats:
            act = str(b.get('act', '') or '1').strip() or '1'
            b['act'] = remap.get(act, '1')
        if log:
            logger.info(
                "  [Acts] Normalized act numbers to a contiguous 1..%d "
                "progression (was %s) so every act gets its break + narration "
                "page.", len(ordered), list(ordered),
            )
    return beats


def _propagate_act_numbers(script: List[Dict],
                            required_beats: List[Dict]) -> None:
    """Write act numbers and master-technique labels into every page-script entry.

    `required_beats` has `act`, `beat_id`, and `technique` fields; page scripts
    reference `beat_id`.  We forward-fill act numbers so every page knows its
    act even if it doesn't directly map to a beat.

    Technique propagation strategy (revised):
      - Build a page-number → technique map from required_beats page_ranges.
        Every page that falls inside a beat's page_range gets that beat's
        technique label, not just the single page that matched the beat_id.
      - Bridge pages between beats that still lack a technique are assigned the
        technique of the nearest prior beat so no page ever reaches
        compose_panel_prompt() without a visual grammar directive.
      - This ensures master techniques drive the lighting/camera/atmosphere of
        every generated panel image, creating a deliberate visual journey.
    """
    import re as _re

    # ── Build beat-id lookups ──────────────────────────────────────────────────
    beat_to_act: Dict[str, str] = {}
    beat_to_technique: Dict[str, str] = {}
    # Map page number → technique / act from the beat that covers that page range.
    # The page_range maps are the ROBUST path: act detection must not depend on
    # the outline LLM reliably echoing matching beat_ids onto every page (it
    # often doesn't for bridge pages), or the whole book collapses to one act
    # and the act-interstitial / narration passes find nothing to do.
    page_to_technique: Dict[int, str] = {}
    page_to_act: Dict[int, str] = {}

    def _parse_range(pr_raw: str) -> Tuple[int, int]:
        pr = str(pr_raw or '').replace('end', '9999').strip()
        parts = _re.findall(r'\d+', pr)
        if len(parts) >= 2:
            return int(parts[0]), int(parts[1])
        if len(parts) == 1:
            return int(parts[0]), int(parts[0])
        return -1, -1

    for b in (required_beats or []):
        bid = b.get('beat_id', '')
        act = str(b.get('act', '') or '').strip()
        tech = str(b.get('technique', '') or '').strip()
        if bid:
            if act:
                beat_to_act[bid] = act
            if tech:
                beat_to_technique[bid] = tech

        # Map every page in this beat's range to its act and technique so the
        # forward-fill below has a per-page source even with no beat_id match.
        p_start, p_end = _parse_range(b.get('page_range', ''))
        if p_start >= 0:
            for pn in range(p_start, p_end + 1):
                if act and pn not in page_to_act:
                    page_to_act[pn] = act
                if tech and pn not in page_to_technique:
                    page_to_technique[pn] = tech

    # ── Walk script: assign act numbers and technique to every page ────────────
    current_act = '1'
    last_technique = ''  # forward-fill for bridge pages

    for page in script:
        if page.get('_act_break') or page.get('_prologue'):
            continue

        bid = page.get('beat_id', '')
        page_num = page.get('page', 0)

        # Act resolution priority:
        #   1. beat_id match (most specific)
        #   2. page-number falls inside a beat's page_range
        #   3. an act already set on the page by the outline
        #   4. forward-fill from the previous page's act
        existing_act = str(page.get('act', '') or '').strip()
        if bid and bid in beat_to_act:
            current_act = beat_to_act[bid]
        elif page_num and page_num in page_to_act:
            current_act = page_to_act[page_num]
        elif existing_act and existing_act not in ('', '0'):
            current_act = existing_act
        # else: keep current_act (forward-fill from prior page)
        page['act'] = current_act

        # Technique: try (in priority order):
        #   1. Exact beat_id match on this page
        #   2. Page-number falls within a beat's page_range
        #   3. Forward-fill from the last known technique (bridge pages)
        page_num = page.get('page', 0)
        tech = ''
        if bid and bid in beat_to_technique:
            tech = beat_to_technique[bid]
        elif page_num and page_num in page_to_technique:
            tech = page_to_technique[page_num]
        elif last_technique:
            tech = last_technique  # bridge pages carry the prior beat's grammar

        if tech:
            page['_beat_technique'] = tech
            last_technique = tech

    # ── Structural fallback: ensure multi-act books actually have act spread ───
    # If the beat metadata collapsed every page into a single act (common when
    # the outline LLM omits beat_ids or the extraction didn't label acts), but
    # the book is long enough to warrant acts, synthesize an even act split so
    # the act-break cards, act-interstitial story pages, and act-aware pacing
    # passes have real boundaries to work with. A book with no act structure
    # reads as an undifferentiated wall of scenes — exactly the "sparse, no
    # explanation between acts" problem this guards against.
    story_pages_list = [p for p in script
                        if not p.get('_act_break') and not p.get('_prologue')]
    distinct_acts = {str(p.get('act', '1')) for p in story_pages_list}
    n_story = len(story_pages_list)
    if len(distinct_acts) < 2 and n_story >= 24:
        # Choose act count by length: 24-44 → 3 acts, 45+ → 4 acts.
        n_acts = 4 if n_story >= 45 else 3
        per_act = max(1, n_story // n_acts)
        for i, page in enumerate(story_pages_list):
            act_idx = min(n_acts, (i // per_act) + 1)
            page['act'] = str(act_idx)
        logger.info(
            f"  [Acts] Beat metadata yielded a single act for a {n_story}-page "
            f"book; synthesized a {n_acts}-act structure so act-break, "
            f"interstitial, and pacing passes have boundaries."
        )

    # ── Contiguity backstop: collapse any non-contiguous page acts to 1..K ─────
    # Even after propagation the page acts can be non-contiguous (e.g. 1, 6, 14)
    # if a code path fed in beats that skipped act-structure normalization. The
    # act-break and interstitial passes fire once per FORWARD act opening, so a
    # gap of 1→6 produces one "Act 6" card and no acts 2-5 at all. Remap the
    # distinct page-act values, in order of the page where each first appears, to
    # a clean 1, 2, 3, … progression. Backward-tagged flashback pages keep the
    # act they were assigned (mapping is by value, not by walk position), so this
    # never disturbs non-linear ordering.
    _story_only = [p for p in script
                   if not p.get('_act_break') and not p.get('_prologue')]
    if _story_only:
        _first_seen: Dict[str, int] = {}
        for p in sorted(_story_only, key=lambda x: int(x.get('page', 0) or 0)):
            a = str(p.get('act', '1') or '1')
            if a not in _first_seen:
                _first_seen[a] = int(p.get('page', 0) or 0)

        def _ai(a):
            try:
                return int(a)
            except (TypeError, ValueError):
                return 0
        _ordered = sorted(_first_seen, key=lambda a: (_first_seen[a], _ai(a)))
        _remap = {a: str(i + 1) for i, a in enumerate(_ordered)}
        if any(_remap[a] != a for a in _remap):
            for p in _story_only:
                p['act'] = _remap.get(str(p.get('act', '1') or '1'), '1')
            logger.info(
                "  [Acts] Collapsed non-contiguous page acts %s → 1..%d so every "
                "act gets its break and narration page in order.",
                list(_ordered), len(_ordered),
            )

    # Log technique coverage for visibility
    tech_pages = sum(1 for p in script
                     if not p.get('_act_break') and not p.get('_prologue')
                     and p.get('_beat_technique'))
    total_story_pages = sum(1 for p in script
                            if not p.get('_act_break') and not p.get('_prologue'))
    if tech_pages:
        logger.info(
            f"  [Technique] Master-technique labels propagated to "
            f"{tech_pages}/{total_story_pages} pages."
        )
        # Log the first occurrence of each technique for the run log
        seen: Dict[str, int] = {}
        for page in script:
            t = page.get('_beat_technique', '')
            if t and t not in seen:
                seen[t] = page.get('page', 0)
        for t, pg in sorted(seen.items(), key=lambda x: x[1]):
            logger.info(f"    {t} (first on p.{pg})")


_MATTER_PAGE_FLAGS = ('_act_break', '_prologue', '_narration_splash', '_act_interstitial')


def _is_matter_page(p: Dict) -> bool:
    """True for non-illustrated structural/text pages: act-break cards,
    prologue pages, narration splashes, and act interstitials.

    These pages exist to carry written copy (e.g. ``setting: "Opening Text
    Page"``, ``beat: "Prologue / Opening text page."``) rather than a drawn
    scene. They must never feed into act-break image prompts — including
    one leaks phrases like "Opening Text Page" or "text page" straight into
    the diffusion prompt, causing the model to render literal lettering
    instead of a pure illustration.
    """
    return any(bool(p.get(flag)) for flag in _MATTER_PAGE_FLAGS)


def _llm_write_act_break_image_description(
        act_word: str, act_roman: str, beat_details: List[str],
        art_style: str, palette: str, lighting: str, emotion: str,
        themes: str, genre: str, openai_model: Optional[str] = None) -> str:
    """Ask the LLM to write the act-break image description as a single vivid,
    purely-visual paragraph.

    The model is told explicitly that the ONLY text allowed anywhere in the
    final image is the act number label (e.g. 'ACT III') — that label is
    handled separately by the caller, NOT by this function — and that its
    own output must never mention or imply writing, lettering, captions,
    pages, panels, or any other textual/document concept. This keeps
    page-structure language (e.g. "Opening Text Page") out of the prompt at
    the source, rather than relying solely on post-hoc scrubbing.

    Returns a single paragraph of plain prose (no markdown, no quotes). Falls
    back to an empty string on any failure so the caller can use its
    deterministic assembly instead.
    """
    beats_block = '; '.join(b for b in beat_details if b) or '(no specific beats — use mood/theme only)'
    instructions = (
        "You are writing the image-generation prompt for a single full-bleed "
        "illustrated act-break title card in a graphic novel.\n\n"
        "RULE (read carefully): the ONLY text that will ever appear in the "
        f"final image is the act label '{('ACT ' + act_roman)}' — that label "
        "is added separately by the production pipeline, not by you. Your "
        "job is ONLY the visual scene description. Because of this:\n"
        "  - NEVER mention or imply any writing, lettering, words, text, "
        "captions, titles, signs, labels, subtitles, dialogue, speech "
        "bubbles, or narration boxes in your description.\n"
        "  - NEVER refer to 'pages', 'panels', 'title cards', or any other "
        "document/book-structure concept. Describe only what would be "
        "physically visible in the illustrated scene itself (setting, "
        "characters, action, atmosphere, light, color).\n"
        "  - If any of the story beats below mention a 'text page', "
        "'prologue copy', or similar written-matter content, ignore that "
        "aspect entirely and describe only the surrounding visual scene "
        "(setting/mood), never the fact that text exists.\n\n"
        "STORY CONTEXT\n"
        f"Genre: {genre}\n"
        f"Themes: {themes}\n"
        f"Mood/emotion: {emotion}\n"
        f"Colour palette: {palette}\n"
        f"Lighting: {lighting}\n"
        f"Art style: {art_style}\n"
        f"Act: {act_word}\n\n"
        "OPENING BEATS OF THIS ACT (raw story notes — mine these for setting, "
        "characters, and visual hooks only)\n"
        f"{beats_block}\n\n"
        "TASK\n"
        "Write ONE vivid paragraph (2-4 sentences) describing a single, "
        "dramatic, full-bleed illustrated scene capturing the feeling and "
        "setting of this act's opening. Concrete, sensory, cinematic — "
        "specific setting, lighting, composition. Plain prose only: no "
        "markdown, no quotation marks, no preamble, no explanation. Output "
        "ONLY the paragraph itself."
    )
    try:
        raw = get_openai_prompt_response(
            instructions,
            temperature=0.7,
            max_completion_tokens=400,
            openai_model=openai_model or openai_model_large,
            use_grok=USE_GROK,
        )
        desc = (raw or '').strip().strip('"').strip()
        # Guard against the model violating the no-text rule despite
        # instructions, or returning something degenerate/empty.
        if not desc or len(desc) < 20:
            return ''
        banned_terms = ('caption', 'speech bubble', 'narration box', 'title card',
                         'text page', 'lettering', 'subtitle', 'dialogue box')
        if any(term in desc.lower() for term in banned_terms):
            logger.warning(
                "[ActBreakLLM] Description mentioned forbidden text/page terms — "
                "discarding and using deterministic fallback."
            )
            return ''
        return desc
    except Exception as exc:
        logger.warning(f"[ActBreakLLM] Description generation failed ({exc}) — using fallback.")
        return ''


def _render_act_break_image(act_number: str, story_dna: Dict,
                             arc_state: Dict, story_idea: 'StoryIdea',
                             pipe, panels_dir: str,
                             act_pages: Optional[List[Dict]] = None,
                             num_variants: int = ACT_BREAK_VARIANTS,
                             final_page_num: Optional[int] = None) -> Tuple[List[Dict], str]:
    """Generate full-bleed illustrated act-break page variants (4 by default).

    Each variant is a distinct composition sharing the same prompt but a
    different seed, so the editor can pick the strongest image from the set.

    final_page_num, when given, is folded into the saved filename alongside
    the act number (see the filename note at the call site) so the file's
    identity unambiguously matches the page number a human — or
    ``regenerate_images_with_model``'s ``page_number``/``page_range``
    filters — would expect. Optional only for callers (tests, ad-hoc re-runs)
    that don't have a final page number to hand; in that case the file is
    still named by act number alone, same as before.

    Text rule: the ONLY text rendered in the image is the act number label
    (e.g. 'ACT I', 'ACT II'). The image_description is constructed to never
    mention text, writing, or document-structure concepts in the first
    place, so a single positive instruction naming the act label is
    sufficient — no redundant enumeration of forbidden elements needed.

    Prompt structure:
        {image_description}. The ONLY text in the image is 'ACT {roman}'
        displayed in large bold hand-lettered comic typography, centered
        on the image.

    image_description is built from the act's actual opening page beats
    (setting, visual hook, characters, mood) so each card is specific to
    what follows.  Style, palette, and lighting come from story_dna and
    the arc state.

    Returns a tuple of (variant_records, prompt):
        ([{'index': 1, 'path': '...', 'seed': 12345}, ...], "the actual prompt used")
    variant_records is an empty list on total failure. The returned prompt is
    the exact, story-specific prompt that was used to synthesize the images —
    callers should persist THIS string to the manifest rather than
    reconstructing a generic placeholder.
    """
    act_labels = {'1': 'One', '2': 'Two', '3': 'Three',
                  '4': 'Four', '5': 'Five'}
    act_word  = act_labels.get(str(act_number), str(act_number))
    act_roman = {'1':'I','2':'II','3':'III','4':'IV','5':'V'}.get(
        str(act_number), str(act_number))

    art_style = _strip_comic_terms_from_image_prompt(
        _strip_photoreal_terms(
            story_dna.get('art_style', 'inked graphic novel illustration with airbrush gradients of light and color')))
    palette   = arc_state.get('palette_state', story_dna.get('color_palette', ''))
    lighting  = arc_state.get('lighting_state', story_dna.get('lighting_signature', ''))
    emotion   = arc_state.get('key_emotion',
                               getattr(story_idea, 'mood', '') if story_idea else '')
    genre     = getattr(story_idea, 'genre', 'inked graphic novel illustration with airbrush gradients of light and color') if story_idea else 'inked graphic novel illustration with airbrush gradients of light and color'
    themes    = (', '.join((story_idea.themes or [])[:3])
                 if story_idea and hasattr(story_idea, 'themes') else '')

    # ── Build image_description from the act's opening page beats ─────────────
    # Pull concrete visual details: setting, visual hook, opening beat text, and
    # characters from the first 3 pages of this act.  These are more specific
    # than mood keywords alone and steer the model toward illustrating something
    # that belongs to THIS act rather than generic atmosphere.
    #
    # Matter pages (prologue / narration splash / act interstitial / another
    # act-break) are excluded here: their setting/beat/title fields describe
    # written page copy (e.g. "Opening Text Page", "Prologue / Opening text
    # page.") rather than a drawn scene, and leaking that language into the
    # diffusion prompt causes the model to render literal text in the image.
    act_pages = [p for p in (act_pages or []) if not _is_matter_page(p)]
    beat_details: List[str] = []
    for pg in act_pages[:3]:
        setting = (pg.get('setting') or '').strip()
        beat    = (pg.get('beat')    or pg.get('title') or '').strip()
        hook    = (pg.get('visual_hook') or '').strip()
        chars   = pg.get('characters_present') or []
        if setting and setting not in beat_details:
            beat_details.append(setting)
        if hook and hook not in beat_details:
            beat_details.append(hook)
        if beat and len(beat) < 120 and beat not in beat_details:
            beat_details.append(beat)
        if chars:
            beat_details.append(', '.join(str(c) for c in chars[:3]))

    # ── Image description: LLM-written, with deterministic fallback ──────────
    # The LLM is given the raw beats above plus an explicit rule that the
    # ONLY text in the final image is the act label (added separately, below)
    # and that its description must never mention writing, captions, pages,
    # or panels. This keeps page-structure language out at the source rather
    # than relying solely on after-the-fact string scrubbing.
    image_description = _llm_write_act_break_image_description(
        act_word=act_word, act_roman=act_roman, beat_details=beat_details,
        art_style=art_style, palette=palette, lighting=lighting,
        emotion=emotion, themes=themes, genre=genre,
    )
    if not image_description:
        if beat_details:
            scene_desc = '; '.join(beat_details)
            image_description = (
                f"{art_style} full-page illustrated scene: "
                f"{scene_desc}. "
                f"Mood: {emotion}. "
                f"Colour palette: {palette}. "
                f"{('Lighting: ' + lighting + '.') if lighting else ''} "
                f"Themes: {themes}. "
                f"Full-bleed, no panel borders, single dramatic unified composition"
            )
        else:
            image_description = (
                f"{art_style} full-page illustrated scene, "
                f"Act {act_word} — {emotion} atmosphere, "
                f"palette: {palette}, themes: {themes}, "
                f"full-bleed dramatic composition, no panel borders"
            )

    image_description = _strip_comic_terms_from_image_prompt(
        _strip_photoreal_terms(image_description)
    )

    # ── Final prompt ──────────────────────────────────────────────────────────
    # Text rule: ONLY the act number label may appear in the image. The
    # explicit "no dialog/caption/etc." enumeration was redundant once the
    # description itself is properly constructed (no text-page language,
    # no document-structure concepts) — the single positive instruction
    # below is sufficient.
    prompt = (
        f"{image_description}. "
        f"The ONLY text in the image is 'ACT {act_roman}' displayed in large "
        f"bold hand-lettered comic typography, centered prominently on the image."
    )

    arc_intensity = min(1.0, float(arc_state.get('intensity', 0.7) or 0.7) + 0.15)
    page_w = int(COMIC_PAGE_WIDTH_IN * COMIC_DPI)
    page_h = int(COMIC_PAGE_HEIGHT_IN * COMIC_DPI)

    variant_records: List[Dict] = []
    # Act-break cards are full-page, so size them to the book trim AR at the
    # active model's native resolution (consistent with covers and panels).
    import novel_generator as _ng_ab
    _ab_model = getattr(_ng_ab, 'IMAGE_MODEL', None)
    ab_w, ab_h = _nearest_gen_size(
        int(COMIC_PAGE_WIDTH_IN * 1000), int(COMIC_PAGE_HEIGHT_IN * 1000),
        _ab_model,
    )
    for v in range(num_variants):
        seed        = random.randint(0, MAX_SEED)
        variant_num = v + 1
        # See the filename note in insert_act_breaks: including the final page
        # number (not just the act number) keeps this file's identity
        # unambiguous for page-targeted regeneration. Falls back to the old
        # act-only name when no final page number was supplied.
        if final_page_num is not None:
            fname = (
                f"page_{int(final_page_num):03d}_act_break_{act_number}"
                f"_variant_{variant_num:02d}.jpg"
            )
        else:
            fname = f"act_break_{act_number}_variant_{variant_num:02d}.jpg"
        save_path   = os.path.join(panels_dir, fname)

        try:
            img = _safe_gen_image(
                pipe, prompt,
                height=ab_h, width=ab_w,
                seed=seed,
                num_inference_steps=N_STEPS,
                promptEnhance=False,
                negative_prompt=PANEL_NEGATIVE_PROMPT,
            )
            img_np   = np.array(img)
            enhanced = comic_panel_pipeline(
                img_np,
                grammar_label='kinetic',
                arc_intensity=arc_intensity,
                key_emotion=str(arc_state.get('key_emotion', '') or emotion or ''),
                stage=str(arc_state.get('stage', '') or ''),
            )
            pil = Image.fromarray(enhanced)
            pil = pil.resize((page_w, page_h), Image.LANCZOS)
            pil.save(save_path, format='JPEG',
                     quality=PRINT_PANEL_JPEG_QUALITY, optimize=True)
            variant_records.append({
                'index': variant_num,
                'path':  save_path,
                'seed':  seed,
            })
            logger.info(
                f"  Act {act_roman} break variant {variant_num}/{num_variants} "
                f"saved: {fname}"
            )
        except Exception as e:
            logger.warning(
                f"  Act-break variant {variant_num} failed for Act {act_number}: {e}"
            )

    if variant_records:
        logger.info(
            f"  Act {act_roman} break: {len(variant_records)} variant(s) generated. "
            f"Prompt: {prompt[:100]}..."
        )
    else:
        logger.warning(f"  All act-break variants failed for Act {act_number}.")

    return variant_records, prompt

def _make_act_break_plain(act_number: str, story_dna: Dict,
                           arc_state: Dict) -> Image.Image:
    """Fallback: typeset act-break card with no AI image (used if pipe unavailable)."""
    act_labels = {'1': 'One', '2': 'Two', '3': 'Three', '4': 'Four', '5': 'Five'}
    act_word = act_labels.get(str(act_number), str(act_number))
    label = f"ACT {act_word.upper()}"

    # Use a very dark background tinted with the arc palette rather than blank white
    bg = (18, 18, 24)   # near-black default; the arc palette is set by the image
    return _render_matter_page(
        [{'text': label, 'size': 60, 'color': (235, 228, 210), 'gap_before': 0}],
        bg=bg, top_rule=True,
    )


def insert_act_breaks(script: List[Dict],
                       layouts: List['PageLayout'],
                       manifest: Dict,
                       project: 'ComicBookProject',
                       pipe,
                       panels_dir: str,
                       emotional_arc: Optional[Dict] = None) -> Tuple[List[Dict], List['PageLayout'], Dict]:
    """Insert illustrated act-break pages at every act transition.

    Act breaks are structural signposts that only earn their page when the
    book is long enough to need them. A 10-page story reads as a continuous
    piece — inserting an "Act One" title card wastes a full page and
    interrupts the flow. The threshold matches extract_required_beats:
      ≤20 story pages → no act breaks (single act)
      21-50           → up to 2 acts
      51-100          → up to 3 acts
      101+            → up to 4 acts

    Detects act boundaries by scanning consecutive pages for an act-number
    change, inserts one break page between them, and renumbers all subsequent
    pages so the manifest, script, and layouts stay consistent.

    Returns updated (script, layouts, manifest).
    """
    emotional_arc = emotional_arc or {}

    # Count story pages (exclude any existing act-break pages)
    story_pages = [p for p in script if not p.get('_act_break')]
    n_story = len(story_pages)

    # Minimum thresholds — mirrors extract_required_beats logic
    if n_story <= 20:
        logger.info(
            f"  Skipping act breaks: {n_story}-page book reads as a single "
            f"continuous piece (threshold: >20 pages)."
        )
        return script, layouts, manifest

    # Find act transition points: (insert_before_page_num, act_label).
    # Forward-only detection (shared with _compute_final_page_numbers and
    # _find_act_boundaries) so non-linear flashback pages can't insert a
    # spurious backward "Act I" break mid-book or duplicate a break.
    _fwd = _forward_act_transitions(story_pages)
    _act_at_page = {int(p.get('page', 0)): str(p.get('act', '1')) for p in story_pages}
    transitions: List[Tuple[int, str]] = [
        (pg, _act_at_page.get(pg, '1')) for pg in _fwd
    ]

    # For books that warrant act breaks, prepend an Act One opener at page 1
    # ONLY when there are genuine act transitions (i.e. the book actually has
    # multiple acts). A single-act book (all beats act='1') gets no breaks even
    # if it is >20 pages — the threshold above already filtered the trivial case.
    has_multiple_acts = len(set(str(p.get('act','1')) for p in story_pages)) > 1
    # First real story page (NOT the prologue) — the Act One title card goes
    # after the prologue, never before it.
    _real_story = [p for p in story_pages
                   if not p.get('_prologue')
                   and p.get('importance') != 'prologue']
    first_page_num    = min((int(p.get('page', 1)) for p in _real_story),
                            default=min((int(p.get('page', 1)) for p in story_pages), default=1))
    has_act_one_break = any(p.get('_act_break') and str(p.get('act','')) == '1'
                            for p in script)

    if has_multiple_acts and not has_act_one_break:
        transitions = [(first_page_num, '1')] + list(transitions)

    if not transitions:
        logger.info("  No act transitions detected; no act breaks inserted.")
        return script, layouts, manifest

    logger.info(f"  Inserting {len(transitions)} act-break page(s): "
                f"{[f'Act {a}' for _, a in transitions]}")

    # Pre-compute the final page numbers once, before the loop modifies the
    # script.  generate_panel_images() used the same map to name all panel
    # image files AND set the manifest keys, so the story-panel manifest keys
    # are ALREADY correct — we must NOT shift them again.  We only need this
    # map to derive the correct manifest key for each newly-inserted act-break
    # page (= final_page_map[first_story_page_of_act] - 1).
    final_page_map = _compute_final_page_numbers(script)

    # Insert in reverse page order so offsets don't cascade
    for insert_before, act_number in reversed(transitions):
        # The act-break's own final page number (= one slot before the first
        # story page of the act it introduces). Computed here, before image
        # generation, so the saved file can be named with it — see the
        # act-break filename note below for why this matters.
        act_break_final_num = final_page_map.get(insert_before, insert_before) - 1

        # ── generate the break image variants ────────────────────────────────
        arc_state  = emotional_arc.get(insert_before, {})
        variant_records: List[Dict] = []
        act_break_prompt: str = ''
        if pipe is not None:
            # Collect the first few beats of this act to build image_description
            act_pages = [p for p in script
                         if str(p.get('act', '')) == str(act_number)
                         and not p.get('_act_break')]
            variant_records, act_break_prompt = _render_act_break_image(
                act_number, project.story_dna, arc_state,
                project.story_idea, pipe, panels_dir,
                act_pages=act_pages,
                final_page_num=act_break_final_num,
            )
        if not variant_records:
            # Fallback: typeset plain card for every expected variant slot
            pil = _make_act_break_plain(act_number, project.story_dna, arc_state)
            for v in range(ACT_BREAK_VARIANTS):
                variant_num = v + 1
                # NOTE: filename carries the FINAL PAGE NUMBER, not just the act
                # number. Act-break files used to be named only
                # "act_break_{act_number}_variant_*.jpg" — since there's exactly
                # one such file per act regardless of book length, regenerating
                # "page 19" (say, the Act 1 break card) silently overwrote
                # act_break_1_variant_01.jpg with no "19" anywhere in the name,
                # which is why a page-targeted regenerate looked like it
                # "updated Act 1 images" instead of "page 19". Including the
                # page number makes the file's identity unambiguous and keeps
                # regenerate_images_with_model's page_range/page_number filters
                # mapping to the file a human would actually expect.
                fname      = (
                    f"page_{act_break_final_num:03d}_act_break_{act_number}"
                    f"_variant_{variant_num:02d}.jpg"
                )
                break_path = os.path.join(panels_dir, fname)
                pil.save(break_path, format='JPEG',
                         quality=PRINT_PANEL_JPEG_QUALITY, optimize=True)
                variant_records.append({'index': variant_num, 'path': break_path, 'seed': 0})
            if not act_break_prompt:
                _fallback_act_word = {'1': 'One', '2': 'Two', '3': 'Three',
                                       '4': 'Four', '5': 'Five'}.get(
                    str(act_number), str(act_number))
                act_break_prompt = (
                    f"[Typeset fallback — no AI image generated] "
                    f"Act {_fallback_act_word} title card."
                )

        # ── renumber all pages ≥ insert_before ──────────────────────────────
        for pg in script:
            pnum = int(pg.get('page', 0))
            if pnum >= insert_before:
                pg['page'] = pnum + 1
        for lo in layouts:
            if lo.page_number >= insert_before:
                lo.page_number += 1
        # Fix manifest keys
        # NOTE: Story-panel manifest keys are already set to their final page
        # numbers by generate_panel_images() via _compute_final_page_numbers().
        # Renaming them here would double-shift them (file names page_002_* would
        # end up under key page_003, etc.).  We leave story-panel keys untouched
        # and only renumber the script + layouts below.
        # Fix emotional arc keys
        if emotional_arc:
            new_arc: Dict = {}
            for pnum, state in emotional_arc.items():
                new_key = pnum + 1 if pnum >= insert_before else pnum
                new_arc[new_key] = state
            emotional_arc.clear()
            emotional_arc.update(new_arc)

        # ── build the break-page script entry ────────────────────────────────
        act_labels = {'1': 'One', '2': 'Two', '3': 'Three',
                      '4': 'Four', '5': 'Five'}
        act_word  = act_labels.get(str(act_number), str(act_number))
        act_roman = {'1':'I','2':'II','3':'III','4':'IV','5':'V'}.get(
            str(act_number), str(act_number))
        break_pg: Dict = {
            'page':           insert_before,
            'title':          f'Act {act_word}',
            'setting':        '',
            'characters_present': [],
            'beat':           f'Act {act_word} begins.',
            'beat_id':        '',
            'emotional_tone': arc_state.get('key_emotion', ''),
            'visual_hook':    f'Act {act_word} title card',
            'cliffhanger':    False,
            'importance':     'splash',
            'act':            act_number,
            '_act_break':     True,
            'panels': [{
                'panel_index':         1,
                'description':         f'Full-bleed illustrated Act {act_word} title card.',
                'composition':         'splash',
                'camera_angle':        'eye_level',
                'mood':                arc_state.get('key_emotion', ''),
                'characters_in_frame': [],
                'sensory_anchor':      '',
                'importance':          'splash',
                'dialogue':            [],
                'sfx':                 [],
            }],
        }

        # ── build the break-page layout ───────────────────────────────────────
        break_layout = PageLayout(
            page_number  = insert_before,
            template_name = 'splash_1',
            panel_count  = 1,
            panel_boxes  = [(0.0, 0.0, 1.0, 1.0)],
            page_title   = f'Act {act_word}',
            page_mood    = arc_state.get('key_emotion', ''),
            cliffhanger  = False,
        )

        # ── build the break-page manifest entry ───────────────────────────────
        # act_break_final_num was already computed at the top of this loop
        # iteration (needed earlier so the image filename could carry it too).
        # final_page_map[insert_before] is where that story page lands in the
        # final numbering; we subtracted 1 to get the act-break's manifest key.
        page_key = f"page_{act_break_final_num:03d}"
        manifest[page_key] = {
            '_label':        f"Act {act_word}",
            '_page_type':    'act_break',
            '_act':          str(act_number),
            '_page_number':  act_break_final_num,
            '_is_act_break': True,
            'panel_01': {
                'active_variant': 1,
                'prompt':         act_break_prompt,
                'description':    f'Act {act_word} break page.',
                'variants':       variant_records,
                'aspect_ratio':   0.7,
                'gen_dims':       [768, 1024],
            }
        }

        # ── insert into script + layouts (sorted) ────────────────────────────
        # Note: panel files are already named with final page numbers because
        # generate_panel_images uses _compute_final_page_numbers. No rename needed.
        script.insert(
            next((i for i, p in enumerate(script)
                  if int(p.get('page', 0)) >= insert_before), len(script)),
            break_pg,
        )
        layouts.insert(
            next((i for i, lo in enumerate(layouts)
                  if lo.page_number >= insert_before), len(layouts)),
            break_layout,
        )

    script.sort(key=lambda p: int(p.get('page', 0)))
    layouts.sort(key=lambda lo: lo.page_number)
    logger.info(f"  Act-break insertion complete. Total pages now: {len(script)}")
    return script, layouts, manifest


# =============================================================================
# POST-GENERATION STORY ENHANCEMENT PASSES (edit / review)
# =============================================================================
# These polish a fully-formed, coherent script ONE ASPECT AT A TIME, the way the
# art-director and dialogue reviews do — rather than complicating the core
# generation. Each is additive and degrades gracefully (any failure leaves the
# script untouched), and each can be run on its own, during synthesis or on an
# already-generated book via ``enhance_existing_comic``. They edit the script in
# place; the artwork then reflects them on the next (re)generation.
# =============================================================================

def _story_panels_in_order(script: List[Dict]):
    """Yield (page, panel, panel_id, position_fraction) for story panels only."""
    flat = []
    for pi, page in enumerate(script or []):
        if page.get('_act_break'):
            continue
        page_num = page.get('page', pi + 1)
        for panel in (page.get('panels', []) or []):
            pidx = panel.get('panel_index', len(flat) + 1)
            flat.append((page, panel, f"p{page_num}_{pidx}"))
    total = max(1, len(flat))
    for i, (page, panel, pid) in enumerate(flat):
        yield page, panel, pid, round((i + 1) / total, 3)


def enhance_visual_motifs(script: List[Dict], story_idea, characters=None,
                          story_dna=None, max_motifs: int = 2,
                          visual_bible=None) -> Dict:
    """Find the story's strongest recurring VISUAL motif(s) and weave deliberate
    echoes into later beats — especially the climax/resolution — so the artwork
    pays the theme off the way intentional comics do (a recurring object, image,
    gesture, or symbol that gains meaning by repetition).

    Edits the chosen panels' descriptions in place and records the motifs on
    ``story_dna['_visual_motifs']`` when provided. When a ``visual_bible`` is
    supplied, each identified motif is also registered as a VisualBibleEntry so
    it gets the same canonical-description injection and cross-panel consistency
    treatment as any other recurring visual element — this stops the motif's
    appearance from drifting between the panels where it recurs. Returns a
    summary dict. Safe: any failure leaves the script unchanged.
    """
    panels = [(pid, panel, (panel.get('description') or '').strip())
              for _pg, panel, pid, _pos in _story_panels_in_order(script)]
    panels_pos = {pid: pos for _pg, _panel, pid, pos in _story_panels_in_order(script)}
    panels = [(pid, panel, d) for (pid, panel, d) in panels if d]
    if len(panels) < 6:
        return {}

    by_id = {pid: panel for (pid, panel, _d) in panels}
    idx_block = "\n".join(
        f'{{"id":"{pid}","pos":{panels_pos.get(pid,0)},"desc":{json.dumps(d[:240])}}}'
        for (pid, _panel, d) in panels
    )
    themes = ', '.join(getattr(story_idea, 'themes', []) or [])
    premise = getattr(story_idea, 'premise', '') or ''

    ident_prompt = (
        "You are a comic art director finding the VISUAL MOTIFS that make a book "
        "feel authored. A motif is a single concrete recurring image — an object, "
        "a gesture, a light, a symbol — that gains emotional meaning by recurring, "
        "and that pays off when it returns at a turning point.\n\n"
        f"PREMISE: {premise[:300]}\nTHEMES: {themes}\n\n"
        "PANELS (id, story position 0..1, description):\n" + idx_block + "\n\n"
        f"Identify up to {max_motifs} motif(s) ALREADY present or strongly implied. "
        "For each, give a short name, the precise VISUAL to render it consistently "
        "(one phrase, concrete), the ids where it already appears, and 1-3 LATER "
        "panels (high position, ideally near the climax/ending) where echoing it "
        "would create payoff WITHOUT contradicting that panel's action.\n"
        'Return ONLY JSON: [{"name":"...","visual":"...","appears_in":["p3_2"],'
        '"echo_in":["p20_1"]}]. Choose only genuinely meaningful motifs; return [] '
        "if none are strong."
    )
    try:
        raw = get_openai_prompt_response(
            ident_prompt, temperature=0.5, max_completion_tokens=1200,
            openai_model=openai_model_large, use_grok=USE_GROK,
        )
        motifs = parse_json_response(raw)
        if not isinstance(motifs, list) or not motifs:
            logger.info("  [Motif] No strong visual motif identified; leaving script as-is.")
            return {}
    except Exception as e:
        logger.warning(f"  [Motif] Identification failed ({e}); leaving script as-is.")
        return {}

    motifs = motifs[:max_motifs]
    # Build the set of (panel, motif) echoes to weave, only into LATER panels.
    targets: List[Tuple[Dict, str, str]] = []   # (panel, motif_name, motif_visual)
    for m in motifs:
        if not isinstance(m, dict):
            continue
        visual = (m.get('visual') or '').strip()
        name = (m.get('name') or '').strip()
        if not visual:
            continue
        for pid in (m.get('echo_in') or []):
            panel = by_id.get(str(pid))
            if panel is not None and panels_pos.get(str(pid), 0) >= 0.45:
                targets.append((panel, name, visual))

    if not targets:
        if story_dna is not None:
            story_dna['_visual_motifs'] = motifs
        return {'motifs': motifs, 'echoes_woven': 0}

    # Weave each motif echo into its target panel's description (batched).
    woven = 0
    for i in range(0, len(targets), 8):
        batch = targets[i: i + 8]
        items = [
            f'{{"id":"{j}","desc":{json.dumps((p.get("description") or "").strip())},'
            f'"motif":{json.dumps(name)},"visual":{json.dumps(vis)}}}'
            for j, (p, name, vis) in enumerate(batch)
        ]
        weave_prompt = (
            "Weave a recurring visual motif into each panel as a NATURAL part of "
            "the scene — a background presence, a held or nearby object, a quality "
            "of light — so it reads as a deliberate callback, not a sticker. Do NOT "
            "change the staged action, the characters present (keep at most two "
            "humans), the setting, or the emotional beat; only fold the motif in. "
            "Keep 2-4 sentences, describe only what the camera sees, no dialogue or "
            "on-screen text.\n\nPANELS:\n" + "\n".join(items) + "\n\n"
            'Return ONLY JSON: [{"id":"0","description":"..."}].'
        )
        try:
            raw = get_openai_prompt_response(
                weave_prompt, temperature=0.55, max_completion_tokens=2500,
                openai_model=openai_model_large, use_grok=USE_GROK,
            )
            parsed = parse_json_response(raw)
            rewrites = {str(it.get('id')): (it.get('description') or '').strip()
                        for it in parsed if isinstance(it, dict)} if isinstance(parsed, list) else {}
            for j, (panel, _n, _v) in enumerate(batch):
                nd = rewrites.get(str(j), '')
                if len(nd) > 20:
                    panel['description'] = nd
                    woven += 1
        except Exception as e:
            logger.warning(f"  [Motif] Weave batch failed ({e}); those panels unchanged.")

    if story_dna is not None:
        story_dna['_visual_motifs'] = motifs

    # Register each motif in the Visual Bible so its canonical appearance is
    # locked and injected consistently wherever it recurs — the same treatment
    # every other recurring prop gets. Without this, a motif described only in
    # prose can drift between its echo panels. Guarded so a bible without the
    # expected API, or a duplicate label, never breaks the pass.
    if visual_bible is not None:
        try:
            from comic_book_art_director import VisualBibleEntry
            existing_labels = {
                (e.label or '').strip().lower()
                for e in getattr(visual_bible, 'entries', [])
            }
            for m in motifs:
                if not isinstance(m, dict):
                    continue
                name = (m.get('name') or '').strip()
                visual = (m.get('visual') or '').strip()
                if not name or not visual:
                    continue
                if name.lower() in existing_labels:
                    continue
                # Aliases: the motif name plus its most distinctive noun so the
                # matcher catches references in panel descriptions.
                aliases = [name.lower()]
                _first_noun = name.lower().split()
                if _first_noun and _first_noun[-1] not in aliases:
                    aliases.append(_first_noun[-1])
                visual_bible.add_entry(VisualBibleEntry(
                    label=name,
                    canonical=visual,
                    aliases=aliases,
                    owner="",
                    category="motif",
                ))
                existing_labels.add(name.lower())
            logger.info(
                f"  [Motif] Registered {len(motifs)} motif(s) in the Visual Bible "
                f"for consistent cross-panel rendering."
            )
        except Exception as _e:
            logger.warning(f"  [Motif] Visual Bible registration skipped ({_e}).")

    logger.info(f"  [Motif] {len(motifs)} motif(s); wove {woven} echo(es) into later beats.")
    return {'motifs': motifs, 'echoes_woven': woven}


def _apply_character_emotion_arc(script: List[Dict], character: str,
                                 authored: Dict[str, str]) -> int:
    """Deterministically set the persistent `emotion` facet for one character
    across their panels, following the authored {panel_id: emotion} turning
    points. The emotion persists forward until the next authored turn (the
    emotion facet does not reset on a scene cut), and a change is recorded so the
    compose step shows the transition and locks the new register. Only existing
    tracked appearance entries are modified. Returns the number of changes set."""
    changes = 0
    current = ''
    last_applied = None      # the emotion most recently WRITTEN for this character
    for _pg, panel, pid, _pos in _story_panels_in_order(script):
        frame = [
            (c.get('name') if isinstance(c, dict) else str(c))
            for c in (panel.get('characters_in_frame', []) or [])
        ]
        if not any((character.lower() == (f or '').lower()
                    or (f and character.lower().split()[:1] == f.lower().split()[:1]))
                   for f in frame):
            continue
        if pid in authored and authored[pid].strip():
            current = authored[pid].strip()
        if not current:
            continue
        state = panel.get('_appearance_state')
        if not isinstance(state, dict):
            continue
        # Resolve the character's key in the tracked state (exact / first-name).
        key = None
        for k in state:
            if k.lower() == character.lower() or (
                    k.lower().split()[:1] == character.lower().split()[:1]):
                key = k
                break
        if key is None:
            continue
        # Persist the current register on every appearance.
        state[key]['emotion'] = current
        # Record a transition only when the register actually TURNS (differs from
        # the value we last wrote for this character), so the compose step shows
        # the shift and locks the new register — not on every panel.
        if current != last_applied:
            ch = panel.setdefault('_appearance_changes', [])
            if isinstance(ch, list):
                ch.append({'character': key, 'attribute': 'emotion',
                           'transition': f"their expression shifting to {current}",
                           'new_value': current})
            changes += 1
            last_applied = current
    return changes


def review_character_arcs(script: List[Dict], characters, story_idea,
                          graph=None, emotional_arc=None, max_leads: int = 3) -> Dict:
    """Give each lead a coherent on-page emotional arc so their feeling EVOLVES
    with the story instead of reading flat. Authors each lead's trajectory (LLM,
    informed by their wound/longing) then sets the persistent `emotion` facet
    across their panels via the continuity system. Edits the tracked state in
    place. Safe: any failure leaves the script unchanged.
    """
    noncorporeal = _noncorporeal_names(characters)
    # Frequency of each human character across story panels, plus their panel ids.
    freq: Dict[str, int] = {}
    app_ids: Dict[str, List[Tuple[str, float, str]]] = {}
    for _pg, panel, pid, pos in _story_panels_in_order(script):
        desc = (panel.get('description') or '')[:160]
        for c in (panel.get('characters_in_frame', []) or []):
            nm = (c.get('name') if isinstance(c, dict) else str(c)) or ''
            nm = nm.strip()
            if not nm or not _is_human_name(nm, noncorporeal):
                continue
            freq[nm] = freq.get(nm, 0) + 1
            app_ids.setdefault(nm, []).append((pid, pos, desc))
    if not freq:
        return {}
    leads = sorted(freq, key=lambda n: freq[n], reverse=True)[:max_leads]

    # Wound / longing context from the character graph, when available.
    def _ctx(name: str) -> str:
        if graph is not None and getattr(graph, 'nodes', None):
            for k, node in graph.nodes.items():
                if k.lower() == name.lower() or k.lower().split()[:1] == name.lower().split()[:1]:
                    return (f"wound={getattr(node,'core_wound','')[:80]}; "
                            f"longing={getattr(node,'core_longing','')[:80]}")
        return ''

    lead_blocks = []
    for nm in leads:
        apps = app_ids.get(nm, [])
        # Sample up to ~14 appearances spread across the book to keep prompt lean.
        if len(apps) > 14:
            step = len(apps) / 14.0
            apps = [apps[int(i * step)] for i in range(14)]
        pts = "; ".join(f'{pid}@{pos}:{json.dumps(d[:90])}' for pid, pos, d in apps)
        lead_blocks.append(f'{{"character":{json.dumps(nm)},"context":{json.dumps(_ctx(nm))},'
                           f'"appears":"{pts}"}}')

    arc_prompt = (
        "You are a story editor shaping each lead's EMOTIONAL ARC so their on-page "
        "feeling evolves with the story — a starting state, genuine turning points, "
        "and a resolution that differs from where they began. Flat, unchanging "
        "emotion is the failure to avoid.\n\n"
        f"GENRE/MOOD: {getattr(story_idea,'genre','')} | {getattr(story_idea,'mood','')}\n\n"
        "LEADS (character, wound/longing, and appearances as id@position:desc):\n"
        + "\n".join(lead_blocks) + "\n\n"
        "For each lead, choose the panels that are EMOTIONAL TURNING POINTS and "
        "assign a concise emotional register to each (1-3 words, an adjective the "
        "artist can draw: 'guarded', 'breaking', 'quietly hopeful', 'hardened'). "
        "Pick only true turns — the register persists between them, so 3-6 points "
        "across the book is plenty. The register at the end must differ from the "
        "start.\n"
        'Return ONLY JSON: [{"character":"...","points":[{"id":"p3_2","emotion":"guarded"}]}].'
    )
    try:
        raw = get_openai_prompt_response(
            arc_prompt, temperature=0.5, max_completion_tokens=1800,
            openai_model=openai_model_large, use_grok=USE_GROK,
        )
        parsed = parse_json_response(raw)
        if not isinstance(parsed, list):
            logger.warning("  [Arc] LLM returned non-list; leaving emotion unchanged.")
            return {}
    except Exception as e:
        logger.warning(f"  [Arc] Authoring failed ({e}); leaving emotion unchanged.")
        return {}

    total = 0
    summary: Dict[str, int] = {}
    for entry in parsed:
        if not isinstance(entry, dict):
            continue
        nm = (entry.get('character') or '').strip()
        if not nm:
            continue
        authored = {}
        for p in (entry.get('points') or []):
            if isinstance(p, dict) and p.get('id') and p.get('emotion'):
                authored[str(p['id'])] = str(p['emotion']).strip()
        if not authored:
            continue
        n = _apply_character_emotion_arc(script, nm, authored)
        total += n
        summary[nm] = n
    logger.info(f"  [Arc] Authored emotional arcs for {len(summary)} lead(s); "
                f"set {total} emotion turn(s).")
    return {'leads': summary, 'turns_set': total}


def enhance_existing_comic(working_dir: str, output_dir: str,
                           do_motifs: bool = True, do_arcs: bool = True,
                           regenerate: bool = True, image_model: str = None,
                           project_pickle: str = None, cbz_path: str = None,
                           panel_variants: int = None) -> Dict[str, str]:
    """Apply the story-enhancement review passes to an ALREADY-GENERATED comic,
    one at a time, then optionally regenerate the affected artwork. This is the
    'edit/review after bulk generation' workflow: a finished book is polished
    aspect by aspect (visual motifs, then per-character emotional arcs) without
    re-running the whole pipeline.

    The passes edit script.json in place; with regenerate=True the artwork is
    re-rendered to reflect them (continuity re-tracking is skipped during that
    regeneration so the authored arcs survive). Returns the regenerate/rebuild
    result dict, or {'script': path} when regenerate=False.
    """
    script_path  = os.path.join(working_dir, "script.json")
    project_path = project_pickle or os.path.join(working_dir, "project.pkl")
    if not os.path.exists(project_path) and cbz_path and os.path.exists(cbz_path):
        try:
            with zipfile.ZipFile(cbz_path, 'r') as zf:
                if '_project/project.pkl' in zf.namelist():
                    zf.extract('_project/project.pkl', working_dir)
                    extracted = os.path.join(working_dir, '_project', 'project.pkl')
                    if os.path.exists(extracted):
                        os.replace(extracted, project_path)
        except Exception as e:
            logger.warning(f"  [Enhance] CBZ extraction failed: {e}")
    for required in (script_path, project_path):
        if not os.path.exists(required):
            raise FileNotFoundError(f"Required artifact missing: {required}")

    with open(script_path, encoding='utf-8') as f:
        script = json.load(f)
    with open(project_path, 'rb') as f:
        project_data = pickle.load(f)
    project = project_data['project']

    if do_motifs:
        logger.info("[Enhance] Pass 1/2 — visual motifs & callbacks…")
        try:
            enhance_visual_motifs(script, project.story_idea, project.characters,
                                  story_dna=getattr(project, 'story_dna', None))
            # Refresh continuity after description edits so locks stay accurate.
            track_appearance_continuity(
                script, project.characters,
                registry=project.character_registry,
                visual_bible=getattr(project, 'visual_bible', None),
                graph=graph,  # 'project' not defined yet; 'graph' set by synthesize_comic_story() above
            )
            track_world_continuity(
                script, project.characters,
                registry=project.character_registry,
                visual_bible=getattr(project, 'visual_bible', None),
            )
            track_style_continuity(
                script, story_idea=getattr(project, 'story_idea', None),
                story_dna=getattr(project, 'story_dna', None),
            )
            resolve_ambiguous_character_names(
                script, project.character_registry, project.characters,
            )
        except Exception as e:
            logger.warning(f"  [Enhance] Motif pass skipped ({e}).")

    if do_arcs:
        logger.info("[Enhance] Pass 2/2 — per-character emotional arcs…")
        try:
            review_character_arcs(
                script, project.characters, project.story_idea,
                graph=graph,  # 'project' not defined yet; 'graph' set by synthesize_comic_story() above
                emotional_arc=(getattr(project, 'story_dna', {}) or {}).get('_emotional_arc', {}),
            )
        except Exception as e:
            logger.warning(f"  [Enhance] Arc pass skipped ({e}).")

    with open(script_path, 'w', encoding='utf-8') as f:
        json.dump(script, f, indent=2, ensure_ascii=False)

    if not regenerate:
        return {'script': script_path}

    import novel_generator as _ng
    model = image_model or getattr(_ng, 'IMAGE_MODEL', 'ZIMAGE')
    # Skip continuity re-tracking inside regeneration so the authored emotional
    # arcs (already written into the saved script) are not overwritten.
    return regenerate_images_with_model(
        working_dir, output_dir, image_model=model,
        project_pickle=project_path, cbz_path=cbz_path,
        panel_variants=panel_variants, regenerate_cover=False,
        regenerate_act_breaks=False, retrack=False,
    )


# =============================================================================
# MAIN ENTRY POINT
# =============================================================================

def synthesize_comic_book(
    story_idea_str: str,
    target_pages = 24,
    panels_per_page_avg: int = 4,
    creative_seeds: Dict = None,
    cast_size: str = "medium",
    save_dir: str = "./SynthesizedComics",
    cover_variants: int = COVER_VARIANTS,
    panel_variants: int = PANEL_VARIANTS,
    pipe = None,
    load_previous: bool = False,
    previous_pickle: str = None,
    use_grok: bool = None,
    image_model: str = None,
    scene_diversity = 'auto',
) -> Dict[str, str]:
    """End-to-end comic book synthesis.
    
    Args:
        story_idea_str:      Free-form story concept.
        target_pages:        Story pages (excluding cover/title/credits). Pass an
                             int for an exact length, or 'auto' to let the AI
                             storyboard the concept and choose the best length
                             from the story's actual structural needs.
        panels_per_page_avg: Average panels per page (1-9, default 4).
        creative_seeds:      Optional dict of human creative inputs.
        cast_size:           'small' (~8) | 'medium' (~18) | 'large' (~35) |
                             'extra_large' (~48) named chars, a
                             (tier1, tier2, tier3) tuple for exact counts, or
                             'auto' to let the AI recommend the cast size from
                             the story's scope and genre.
        save_dir:            Where to save outputs.
        cover_variants:      Number of cover image variants to generate.
        panel_variants:      Number of image variants per panel.
        pipe:                Optional pre-loaded image generation pipeline.
        load_previous:       Skip text synthesis and load from previous_pickle.
        previous_pickle:     Path to a previous run's project.pkl.
        use_grok:            Override the USE_GROK setting in novel_generator
                             for this run only. True = Grok/xAI API,
                             False = OpenAI. Defaults to the module-level value.
        image_model:         Override the IMAGE_MODEL setting in novel_generator
                             for this run only. 'ZIMAGE', 'ERNIE', 'CHROMA',
                             'LENS', or 'KLEIN2'. Defaults
                             to the module-level value.
        scene_diversity:     Controls the scene/character diversity pass that
                             stops one presence (e.g. a leviathan) appearing in
                             every panel. 'auto'/True = sensible defaults
                             (no single character/entity in >60% of content
                             panels; a dominant non-human entity is kept central
                             but its manifestation is varied). False = disable.
                             A float (0-1) sets the max per-entity panel share.
                             A dict fine-tunes: {'max_share', 'min_breathing_frac',
                             'vary_manifestation', 'strategy'} where strategy is
                             'vary' (default) | 'thin' | a float share.
    
    Returns:
        dict with paths: {docx, pdf, cbz, working_dir, manifest}
    """
    # Apply per-call overrides to the novel_generator module globals so every
    # internal call that reads USE_GROK / IMAGE_MODEL picks up the right value
    # without threading args through dozens of helper functions. We restore the
    # originals at the end so repeated calls with different settings work correctly.
    import novel_generator as _ng
    _orig_use_grok    = _ng.USE_GROK
    _orig_image_model = _ng.IMAGE_MODEL
    if use_grok is not None:
        _ng.USE_GROK    = bool(use_grok)
        globals()['USE_GROK'] = _ng.USE_GROK
    if image_model is not None:
        if image_model not in ('ZIMAGE', 'ERNIE', 'CHROMA', 'LENS', 'KLEIN2'):
            raise ValueError(
                f"image_model must be 'ZIMAGE', 'ERNIE', 'CHROMA', 'LENS', or 'KLEIN2', got {image_model!r}"
            )
        _ng.IMAGE_MODEL = image_model
    logger.info(
        f"  Runtime config: USE_GROK={_ng.USE_GROK}  IMAGE_MODEL={_ng.IMAGE_MODEL}"
    )

    # Resolve the scene/character diversity policy for this run (defaults work
    # out of the box; pass scene_diversity=False to disable, a float to set the
    # max per-entity panel share, or a dict to fine-tune).
    _div_cfg = set_scene_diversity(scene_diversity)
    if _div_cfg.get('enabled', True):
        logger.info(
            f"  Scene diversity: ON (max_share={_div_cfg['max_share']:.0%}, "
            f"strategy={_div_cfg['strategy']}, "
            f"vary_manifestation={_div_cfg['vary_manifestation']})"
        )
    else:
        logger.info("  Scene diversity: OFF")

    create_directory_if_not_exists(save_dir)

    # Start a fresh Grok prompt-cache partition for this run. Every LLM call in
    # this synthesis then shares the x-grok-conv-id, so the large prefix common
    # to the outline/storyboard/dialogue/enrichment loops (system persona +
    # story, cast, and DNA context) is served from cache at a discount instead
    # of being re-billed on each call. Also resets cache telemetry.
    if USE_GROK:
        try:
            _conv = set_grok_conv_id()
            logger.info(f"  [Cache] Grok prompt-cache conv id for this run: {_conv}")
        except Exception as _cc_e:
            logger.warning(f"  [Cache] Could not set Grok conv id ({_cc_e}).")

    if load_previous:
        if not previous_pickle or not os.path.exists(previous_pickle):
            raise FileNotFoundError(f"Cannot load previous: {previous_pickle}")
        with open(previous_pickle, 'rb') as f:
            saved = pickle.load(f)
        project = saved['project']
        script = saved['script']
        layouts = saved['layouts']
        logger.info(f"Loaded previous project: {project.title}")
    else:
        # === Phase 1-4: Story + cast + graph ===
        story_idea, characters, graph, registry, visual_bible = synthesize_comic_story(
            story_idea_str, creative_seeds, cast_size
        )

        # ── Auto target-pages: storyboard the concept to size the book ────────
        # When target_pages == 'auto', run a lightweight storyboard pass now —
        # the story idea and full cast exist, but no page-dependent work has
        # happened yet, so this is the ideal point to resolve the page count.
        # Detect explicit act structure first so the page-count recommendation
        # can size each act independently (a 5-act epic gets 5 × ~20 pages,
        # not the flat 24-page default).
        _act_structure = _detect_act_structure(story_idea_str)
        if _act_structure.get('has_explicit_acts'):
            logger.info(
                f"  Detected {_act_structure['num_acts']}-act structure: "
                + " | ".join(_act_structure['act_titles'][:8])
            )

        if isinstance(target_pages, str) and target_pages.strip().lower() == "auto":
            _was_auto = True
            target_pages = _recommend_target_pages(
                story_idea, story_idea_str,
                characters=characters,
                panels_per_page_avg=panels_per_page_avg,
                act_structure=_act_structure,
            )
        else:
            _was_auto = False
            target_pages = int(target_pages)

        # Extract required beats — with multi-act storyboarding when the concept
        # contains explicit act structure. Each act gets a full storyboard pass
        # using master storytelling techniques (Gaiman planted mysteries, King
        # dread cascades, Pratchett philosophical asides, etc.) plus mandatory
        # side-plot beats for texture.
        logger.info("[4.5/8] Extracting required story beats from concept...")
        required_beats = extract_required_story_beats(
            story_idea, story_idea_str,
            target_pages=target_pages,
            act_structure=_act_structure,
            characters=characters,
            graph=graph,
        )

        # ── Reconcile target_pages to actual beat coverage ───────────────────
        # Beat extraction gives us ground-truth story coverage. If the beats
        # only cover pp.1-62 but target_pages is 86, the script LLM would invent
        # 24 pages of filler with no required beats to anchor it. Snapping the
        # page count to actual coverage prevents this. The reconciler also catches
        # the reverse case: if beats overflow the estimate it expands accordingly.
        # Only applies when target_pages was set via 'auto' (the estimation path);
        # when the user specified an explicit integer we respect their choice.
        if isinstance(target_pages, int) and _was_auto:
            target_pages = _reconcile_target_pages_to_beats(
                required_beats, target_pages,
                panels_per_page_avg=panels_per_page_avg,
            )

        # ── Story enrichment BEFORE script generation ───────────────────────
        # Backstory/showcase/world-building beats must exist before
        # generate_comic_script() expands the outline into pages and panels.
        # The previous after-script improvement pass could record these beats in
        # metadata, but it could not add new storyboard pages.
        _pre_story_enrichment_data: Dict[str, Any] = {}
        logger.info(
            "[4.6/8] Adding story-driven side arcs, backstories, and world-building beats..."
        )
        try:
            required_beats, _pre_story_enrichment_data = generate_story_enrichment_beats(
                story_idea=story_idea,
                characters=characters,
                story_idea_str=story_idea_str,
                required_beats=required_beats,
                target_pages=target_pages,
                get_llm_response=get_openai_prompt_response,
                parse_json=parse_json_response,
                sanitize=sanitize_text_for_prompt,
                llm_model=openai_model_large,
                use_grok=USE_GROK,
                panels_per_page_avg=panels_per_page_avg,
            )
            # The enrichment pass GROWS the page budget when it adds beats, so
            # every backstory / side event earns its own pages instead of being
            # crammed into the existing book. Adopt the grown count here so the
            # storyboard and the script are generated against it.
            _grown = int(_pre_story_enrichment_data.get('target_pages', target_pages) or target_pages)
            if _grown > target_pages:
                logger.info(
                    "  [PageGrowth] Adopting expanded page count %d (was %d) after "
                    "adding %d enrichment beat(s).",
                    _grown, target_pages,
                    _pre_story_enrichment_data.get('added_count', 0),
                )
                target_pages = _grown
            if _pre_story_enrichment_data.get('added_count', 0):
                logger.info(
                    "  [PreStoryboardEnrichment] %d beat(s) added before page expansion.",
                    _pre_story_enrichment_data.get('added_count', 0),
                )
        except Exception as _e:
            logger.warning(f"  [PreStoryboardEnrichment] skipped ({_e}).")
            _pre_story_enrichment_data = {}

        # ── Act-structure normalization ──────────────────────────────────────
        # Enrichment can leave the beats with non-contiguous act numbers (a
        # backstory beat the LLM tagged "act": "6" or "14"). Collapse them to a
        # clean 1..K progression, with enrichment beats inheriting the act of
        # their page position, so every act reliably gets its opening act-break
        # card and its after-act narration page — and they appear in order.
        required_beats = _normalize_act_structure(required_beats)

        # ── Growth guarantee ─────────────────────────────────────────────────
        # The beat allocator gives every beat its own content-aware pages and
        # GROWS the book to fit them, so the beats may now span more pages than
        # the recommended/explicit target. The page count downstream MUST cover
        # the full beat span (the outline generates exactly target_pages pages),
        # so snap target_pages up to the realised span. This grows only; an
        # explicit target acts as a floor, never a cap that starves a beat.
        _beat_span = _max_beat_end(required_beats)
        if _beat_span > target_pages:
            logger.info(
                "  Growing target_pages %d -> %d so every beat keeps its own "
                "content-aware pages.", target_pages, _beat_span
            )
            target_pages = _beat_span

        # ── Voice profiles BEFORE the first draft (recommendation A) ──────────
        # Build the enriched per-character voice profiles (origin, heritage-
        # informed idiom, signature lexicon, cadence, tics) now, so the very
        # first pass of dialogue is written IN each character's voice rather than
        # rewritten into it later by the review pass. The project object does not
        # exist yet at this point in the fresh-build path, so the profiles are
        # held in a local and cached onto the project once it is created below.
        try:
            _voice_profiles = build_voice_profiles(
                characters or [], story_idea=story_idea, graph=graph,
            )
        except Exception as _vp_e:
            logger.warning(f"  [Voice] Early profile build skipped ({_vp_e}).")
            _voice_profiles = {}

        script_raw = generate_comic_script(
            story_idea, characters, graph, target_pages, panels_per_page_avg,
            required_beats=required_beats,
            story_idea_str=story_idea_str,
            visual_bible=visual_bible,        # art director disambiguation pass
            voice_profiles=_voice_profiles,   # first-draft dialogue in-voice (A)
        )

        # Report how much of the story-generation prompt volume came back from
        # the Grok prompt cache (the shared prefix across the many loop calls).
        if USE_GROK:
            try:
                _cs = get_grok_cache_stats()
                if _cs.get("prompt_tokens"):
                    logger.info(
                        "  [Cache] Grok prompt cache: %s of %s prompt tokens served "
                        "from cache across %d call(s) (%.0f%% hit rate).",
                        f"{_cs['cached_tokens']:,}", f"{_cs['prompt_tokens']:,}",
                        _cs.get("calls", 0), 100.0 * _cs.get("cache_hit_rate", 0.0),
                    )
            except Exception:
                pass

        # Propagate act numbers from required_beats into every page entry.
        # This makes act-boundary detection reliable during insert_act_breaks().
        _propagate_act_numbers(script_raw, required_beats)

        # Two-humans-per-image enforcement — the panel-expansion prompt already
        # asks for ≤2 human characters per panel, but this is the hard guarantee:
        # any panel still staging more than two humans is re-staged (focal two
        # kept, others moved off-panel, description rewritten) BEFORE continuity
        # tracking, so the tracker and the figure count both see the final cast.
        # Diffusion models garble crowded frames; this keeps every image clean.
        try:
            enforce_two_character_limit(script_raw, characters, story_idea)
        except Exception as _e:
            logger.warning(f"  [CharLimit] Enforcement skipped ({_e}).")

        # Simultaneity continuity — a "meanwhile / across town" cut means two
        # scenes happen at the same time in different places, so a character
        # cannot appear in both. Detect these cuts and strip any character who
        # was just seen in the scene we left from the simultaneous scene, then
        # repair the affected descriptions. Runs BEFORE continuity tracking so
        # the tracker and image gen see the corrected cast, and after the
        # two-character enforcement so both cast-editing passes agree.
        try:
            _n_sim = enforce_simultaneity_continuity(script_raw)
            if _n_sim:
                repair_simultaneity_descriptions(script_raw)
        except Exception as _e:
            logger.warning(f"  [Simultaneity] Enforcement skipped ({_e}).")

        # Visual-motif enhancement — find the story's strongest recurring image
        # and weave deliberate echoes into later beats for thematic payoff. Runs
        # BEFORE continuity tracking so the motif additions are reflected in the
        # tracked state and the saved script.
        try:
            enhance_visual_motifs(script_raw, story_idea, characters,
                                  visual_bible=visual_bible)
        except Exception as _e:
            logger.warning(f"  [Motif] Enhancement skipped ({_e}).")

        # Appearance Continuity pass — walk the script in narrative order and
        # track how each character's MUTABLE appearance (clothing, hair,
        # condition, held items, worn emotion, applied markings) evolves
        # panel-by-panel. This annotates each panel with the resolved CURRENT
        # state so the image generator enforces the *evolving* appearance —
        # honouring intentional changes (a removed jacket stays removed) while
        # still preventing unintentional drift.
        # Runs AFTER the art director disambiguation (inside generate_comic_script)
        # so it reads the cleaned descriptions, and BEFORE script.json is saved
        # so the annotations survive into the rebuild workflow.
        try:
            script_raw = track_appearance_continuity(
                script_raw, characters,
                registry=registry,
                visual_bible=visual_bible,
                graph=graph,  # 'project' not defined yet; 'graph' set by synthesize_comic_story() above
            )
        except Exception as _e:
            logger.warning(f"  Appearance continuity tracking skipped ({_e}).")

        # World-State Continuity pass — evolves the WORLD around the characters:
        # object/prop/vehicle/structure appearance (a blue car repainted red),
        # multi-stage progressive changes (rendered stage-by-stage so the change
        # is shown happening, not teleported), and character apparent AGE
        # (anchored hard so it can't drift, shifted coherently across time-jumps
        # so a childhood flashback and the present day never get mixed up). Runs
        # AFTER appearance tracking (so it reads the disambiguated descriptions
        # and the resolved character frame) and BEFORE script.json is saved so
        # the _world_state / _age_state annotations survive into the rebuild
        # workflow. Its LLM call reads the previous AND next page for context.
        try:
            script_raw = track_world_continuity(
                script_raw, characters,
                registry=registry,
                visual_bible=visual_bible,
            )
        except Exception as _e:
            logger.warning(f"  World continuity tracking skipped ({_e}).")

        # Ambiguous-name disambiguation — runs ONCE now that the full script
        # exists, BEFORE image generation. Proactively probes every name the
        # script uses against the registry; for any that come back ambiguous
        # or unmatched (e.g. "Elena Morales" sharing a first name with both
        # registered "Elena Petrova" and "Elena Vasquez"), it reads that name's
        # actual panel context and asks for one confident, auditable decision.
        # A confident match is registered as a permanent alias, so the rest of
        # the run resolves correctly and the appearance lock is never silently
        # dropped for that character. Anything the pass itself is unsure about
        # is left exactly as unresolved as before — see resolve_ambiguous_
        # character_names() in comic_book_art_director.py for the safety
        # guarantees.
        try:
            resolve_ambiguous_character_names(script_raw, registry, characters)
        except Exception as _e:
            logger.warning(f"  Ambiguous-name resolution skipped ({_e}).")

        # Build the project skeleton
        project = ComicBookProject(
            title="(pending)",
            story_idea=story_idea,
            characters=characters,
            character_registry=registry,
            character_graph=graph,
            working_dir="(pending)",
            output_dir=save_dir,
        )
        project.visual_bible = visual_bible   # art director will use this in image gen
        # Cache the voice profiles built earlier (before the first-draft script)
        # so the later per-act dialogue review reuses the same profiles.
        project.voice_profiles = _voice_profiles
        # Store required_beats so the narration weave (Phase 6.7) can access
        # full beat descriptions for foreshadowing and dramatic captions.
        project.story_dna['_required_beats'] = required_beats
        
        # Title
        project.title = generate_comic_title(project, script_raw)
        safe_title = cleanup_special_chars(project.title)
        project.working_dir = os.path.join(save_dir, f"_work_{safe_title}")
        create_directory_if_not_exists(project.working_dir)
        logger.info(f"Title: {project.title}")
        
        # Marketing
        marketing = generate_comic_marketing(project)
        project.tagline = marketing.get('tagline', '')
        project.back_cover_blurb = marketing.get('back_cover_blurb', '')
        project.genre_labels = marketing.get('genre_labels', [])
        project.about_this_book = marketing.get('about_this_book', '')
        
        # Story DNA
        logger.info("Building Story DNA (visual identity)...")
        project.story_dna = build_story_dna(story_idea, characters)
        logger.info(f"  Art style: {project.story_dna.get('art_style', '')}")

        # Style Continuity — resolve the book's canonical rendering MEDIUM from
        # the Story DNA and lock it onto every panel, so the artwork can't
        # randomly drift from the illustrated look into a photograph or a 3D
        # render between panels. Panels the script deliberately renders in a
        # different medium (a memory shown as a faded photograph, a nightmare in
        # stark photoreal) are detected and HONOURED — the lock suppresses
        # accidental drift, not intentional dramatic shifts. Runs right after
        # build_story_dna (its only input) and before script.json is saved so the
        # _style_lock annotations travel into the rebuild workflow.
        try:
            track_style_continuity(
                script_raw, story_idea=story_idea, story_dna=project.story_dna
            )
        except Exception as _e:
            logger.warning(f"  Style continuity locking skipped ({_e}).")

        # Emotional Arc: one art-director pass over the WHOLE outline so palette,
        # light and intensity evolve across the book and the artwork reads as a
        # continuous emotional journey. Stored on story_dna so it travels with
        # the project (pickle) and is reused by panel generation.
        logger.info("Authoring Emotional Arc (book-wide curve)...")
        # Emotional-dynamics profile — the SHAPE of the journey (roller coaster,
        # smooth slide, descending spiral, rising tide, escalating waves),
        # chosen from genre/tone. Set before the arc so authoring + shaping both
        # use it; logged so the chosen journey shape is visible in the run.
        try:
            _dyn = emotional_dynamics_for(story_idea)
            project.story_dna['_emotional_dynamics'] = _dyn
            logger.info("  [Dynamics] Emotional journey shaped as a %s.",
                        _dyn.get('label', 'gentle wave'))
        except Exception as _dy_e:
            logger.warning(f"  [Dynamics] Profile selection skipped ({_dy_e}).")
        try:
            project.story_dna['_emotional_arc'] = build_emotional_arc(
                story_idea, script_raw, project.story_dna
            )
        except Exception as e:
            logger.warning(f"  Emotional arc authoring failed ({e}); will fall back at render time.")
            project.story_dna['_emotional_arc'] = {}

        # Bridge the beat critic → the panel emotion layer: pages covered by
        # emotionally powerful (or critic-amplified) beats get their arc
        # intensity lifted, so amplify_panel_expressions pushes passion/drama
        # hardest exactly where the story critic said the feeling lives.
        try:
            reinforce_arc_from_beat_critic(
                project.story_dna.get('_emotional_arc', {}),
                required_beats,
                target_pages=target_pages,
            )
        except Exception as _ar_e:
            logger.warning(f"  [ArcReinforce] Skipped ({_ar_e}).")

        # Genre narrative lens — select ONCE from the story's genre/tone and
        # store it so structure (outline), art (page DNA), and voice (dialogue
        # review) all pull from one coherent tradition.
        try:
            _lens = genre_lens_for(story_idea)
            project.story_dna['_genre_lens'] = _lens
            if _lens:
                logger.info("  [GenreLens] Applying '%s' tradition across "
                            "structure, art, and dialogue.", _lens.get('_genre', '?'))
        except Exception as _gl_e:
            logger.warning(f"  [GenreLens] Skipped ({_gl_e}).")
            project.story_dna['_genre_lens'] = {}

        # Setup/payoff ledger (recommendation E) — verify planted elements
        # (Chekhov's guns) actually pay off within their act or by the climax,
        # and surface orphans for repair. Reporting/gate pass; writes a sidecar.
        try:
            _ledger = build_setup_payoff_ledger(
                script_raw, required_beats,
                get_openai_prompt_response, parse_json_response,
                llm_model=openai_model_large, use_grok=USE_GROK,
            )
            if _ledger.get('planted'):
                with open(os.path.join(project.working_dir,
                                       "setup_payoff_ledger.json"),
                          'w', encoding='utf-8') as f:
                    json.dump(_ledger, f, indent=2, ensure_ascii=False)
        except Exception as _sp_e:
            logger.warning(f"  [SetupPayoff] Skipped ({_sp_e}).")

        # Design the book's narrative voice — the narration weave (Phase
        # 6.7) and any earlier captions both draw on this spec.
        try:
            project.story_dna['_narrative_voice'] = design_narrative_voice(
                story_idea, project.story_dna
            )
        except Exception as e:
            logger.warning(f"  Narrative voice design failed ({e}); using default.")
            project.story_dna['_narrative_voice'] = _DEFAULT_NARRATIVE_VOICE

        # Per-character emotional arcs — give each lead a coherent on-page
        # emotional journey by setting the persistent `emotion` facet across
        # their panels. Runs AFTER continuity tracking (so the tracked state
        # exists to write into) and AFTER the book-wide arc (so it can align
        # with it), and BEFORE expression amplification (which then scales the
        # intensity of whatever register each panel carries).
        try:
            review_character_arcs(
                script_raw, characters, story_idea,
                graph=project.character_graph,
                emotional_arc=project.story_dna.get('_emotional_arc', {}),
            )
        except Exception as _e:
            logger.warning(f"  [Arc] Per-character arc pass skipped ({_e}).")

        # Emotional continuity (recommendation B) — flag panels where a
        # character's feeling jumps between adjacent panels of the same scene
        # with no transition shown, so the art renders the shift instead of
        # snapping. Runs AFTER the per-character arcs set the emotion facet and
        # BEFORE amplification, so the transition note is amplified too.
        try:
            track_emotional_continuity(
                script_raw,
                emotional_arc=project.story_dna.get('_emotional_arc', {}),
            )
        except Exception as _e:
            logger.warning(f"  [EmotionContinuity] Skipped ({_e}).")

        # Trait signature gestures (visual counterpart of trait-voice) — stamp a
        # recurring characteristic pose onto sparse focal panels so each lead has
        # a physical tell that both characterizes them and aids visual
        # consistency across panels.
        try:
            stamp_trait_gestures(script_raw, characters)
        except Exception as _tg_e:
            logger.warning(f"  [TraitGesture] Skipped ({_tg_e}).")

        # Physical-signature identity lock — stamp each lead's always-visible
        # markers (scar/tattoo/distinctive feature) onto every panel they appear
        # in, so the reader reads the SAME person across the whole book.
        try:
            stamp_signature_locks(script_raw, characters,
                                  graph=getattr(project, 'character_graph', None))
        except Exception as _sl_e:
            logger.warning(f"  [SignatureLock] Skipped ({_sl_e}).")

        # Relational gaze — turn the relationship graph's directed feeling into a
        # concrete LOOK (how A looks at B) on two-character panels, so the eyeline
        # carries the same emotional truth the dialogue subtext does, and shifts
        # as the relationship shifts across the book.
        try:
            stamp_relational_gaze(script_raw,
                                  getattr(project, 'character_graph', None),
                                  characters)
        except Exception as _rg_e:
            logger.warning(f"  [RelationalGaze] Skipped ({_rg_e}).")

        # Expression amplification — now ARC-AWARE. Runs after the emotional arc
        # is authored so it can scale exaggeration by each page's intensity
        # (climax beats pushed hardest, quiet beats kept restrained) and borrow
        # the arc's coherent key_emotion. Mutates script_raw in place, before
        # script.json is saved, so the `_expression_amplify` sidecars persist
        # into the rebuild workflow.
        try:
            script_raw = amplify_panel_expressions(
                script_raw, story_idea,
                emotional_arc=project.story_dna.get('_emotional_arc', {}),
            )
        except Exception as _e:
            logger.warning(f"  Expression amplification skipped ({_e}).")

        # Dramatic-hook shaping — place page-turn hooks on physical right-hand
        # pages, set a strong opening hook, ramp hook density toward the climax,
        # and resolve the ending. Then mark the pre-turn reveal panels. Both run
        # here (after the arc is shaped) so hooks escalate to the real climax.
        try:
            script_raw = _shape_dramatic_hooks(
                script_raw, project.story_dna.get('_emotional_arc', {}))
            script_raw = _mark_page_turn_reveals(script_raw)
        except Exception as _e:
            logger.warning(f"  Dramatic-hook shaping skipped ({_e}).")

        # ── Story enrichment improvements ─────────────────────────────────
        # Runs AFTER arc shaping and expression amplification (so enrichment
        # beats inherit the arc) and BEFORE layout planning (so chapter titles
        # and injected captions are in the script the layouts are built from).
        logger.info("[5.5/8] Applying story enrichment improvements...")
        try:
            script_raw, required_beats, _imp_data = apply_all_improvements(
                story_idea=story_idea,
                characters=characters,
                story_idea_str=story_idea_str,
                required_beats=required_beats,
                script=script_raw,
                target_pages=target_pages,
                get_llm_response=get_openai_prompt_response,
                parse_json=parse_json_response,
                sanitize=sanitize_text_for_prompt,
                llm_model=openai_model,
                llm_model_large=openai_model_large,
                use_grok=USE_GROK,
                narrative_voice=project.story_dna.get('_narrative_voice', ''),
                # Enrichment beats already ran BEFORE script generation above.
                # Do not generate them again here; this pass now handles captions,
                # chapter titles, prologue, and other post-script polish.
                enable_backstory=False,
                enable_showcases=False,
                enable_worldbuilding=False,
            )
            if _pre_story_enrichment_data:
                _imp_data['pre_storyboard_enrichment'] = _pre_story_enrichment_data
            project.story_dna['_improvement_data'] = _imp_data
            project.story_dna['_required_beats'] = required_beats
            if _imp_data.get('prologue_page'):
                project.story_dna['_prologue_page'] = _imp_data['prologue_page']
                # Inject the prologue into the script as a real, first-class
                # page (single full-page text panel) so it flows through layout
                # planning, the manifest, the editor, and the normal renderer —
                # exactly like a narration-splash page. This makes it editable
                # in comic_book_editor.py. The old Phase 7.5 prepend path is
                # disabled below to avoid a duplicate prologue page.
                try:
                    _pro_src = _imp_data['prologue_page']
                    # Prefer the multi-page segment list (each segment is a
                    # page-sized text block with its own image concept). Fall
                    # back to the single _prologue_content block for older data.
                    _pro_segments = _pro_src.get('_prologue_segments') or []
                    if not _pro_segments:
                        _blob = (_pro_src.get('_prologue_content') or '').strip()
                        if _blob:
                            _pro_segments = [{
                                "content": _blob,
                                "visual_note": _pro_src.get('_prologue_visual_note', ''),
                                "title": _pro_src.get('title', '') or '',
                            }]
                    if _pro_segments:
                        _n_seg = len(_pro_segments)
                        _pro_pages = []
                        for _si, _seg in enumerate(_pro_segments):
                            _seg_text = str(_seg.get('content', '')).strip()
                            if not _seg_text:
                                continue
                            _seg_visual = (str(_seg.get('visual_note', '')).strip()
                                           or _pro_src.get('_prologue_visual_note', '')
                                           or "A quiet, atmospheric opening image with "
                                              "generous negative space for text.")
                            _hdr = "PROLOGUE" if _si == 0 else "PROLOGUE (cont.)"
                            _pro_pages.append({
                                "page": 0,  # renumbered after all inserts
                                "title": (_seg.get('title', '') if _si == 0 else '') or '',
                                "setting": "Opening Text Page",
                                "characters_present": [],
                                "beat": "Prologue / Opening text page.",
                                "beat_id": "prologue" if _n_seg == 1 else f"prologue_{_si+1}",
                                "beat_type": "prologue",
                                "emotional_tone": _pro_src.get('emotional_tone', ''),
                                "visual_hook": _seg_visual,
                                "cliffhanger": False,
                                "importance": "prologue",
                                "act": "1",
                                "_prologue": True,
                                "_prologue_style": _pro_src.get('_prologue_style', 'A'),
                                "_prologue_content": _seg_text,
                                "_prologue_font_note": _pro_src.get('_prologue_font_note', ''),
                                "_prologue_visual_note": _seg_visual,
                                "_prologue_narrator_voice": _pro_src.get('_prologue_narrator_voice', ''),
                                "_prologue_purpose": _pro_src.get('_prologue_purpose', ''),
                                # Continuation pages carry the same header eyebrow
                                # marked "(cont.)" so the sequence reads as one unit.
                                "_interstitial_header": _hdr,
                                "_prologue_part": _si + 1,
                                "_prologue_parts_total": _n_seg,
                                "panels": [
                                    {
                                        "panel_index": 1,
                                        "panel_type": "narration",
                                        # Each page's own visual concept drives its
                                        # own generated image.
                                        "description": _seg_visual,
                                        "characters_in_frame": [],
                                        "importance": "splash",
                                        "dialogue_density": "interstitial_story_page",
                                        "visual_keywords": [],
                                        "dialogue": [
                                            {
                                                "speaker": "NARRATOR",
                                                "text": _seg_text,
                                                "bubble_type": "caption",
                                            }
                                        ],
                                    }
                                ],
                            })
                        # Insert all prologue pages at the very front, in order,
                        # before story page 1.
                        for _off, _pp in enumerate(_pro_pages):
                            script_raw.insert(_off, _pp)
                        for _i, _p in enumerate(script_raw):
                            _p['page'] = _i + 1
                        _tot_words = sum(len(str(s.get('content', '')).split())
                                         for s in _pro_segments)
                        logger.info(
                            "  [Prologue] Injected opening as %d editable script "
                            "page(s) (%d words total), each with its own image.",
                            len(_pro_pages), _tot_words,
                        )
                except Exception as _pro_inj_e:
                    logger.warning(f"  [Prologue] Script injection skipped ({_pro_inj_e}).")
        except Exception as _imp_e:
            logger.warning(f"  [Improvements] Pass skipped ({_imp_e}).")

        # Panel-story relationship passes — BEFORE layout planning so panel
        # scripts and layouts agree. Order matters: splash promotion first
        # (peak pages collapse to one panel and are exempt from splitting),
        # then dialogue-heavy panels split into shot/reverse-shot pairs.
        try:
            script_raw, _ = promote_emotional_splash_pages(
                script_raw, project.story_dna.get('_emotional_arc', {}))
        except Exception as _e:
            logger.warning(f"  Splash promotion skipped ({_e}).")
        try:
            script_raw, _ = split_dialogue_heavy_panels(script_raw)
        except Exception as _e:
            logger.warning(f"  Dialogue-heavy panel split skipped ({_e}).")

        # Re-propagate act numbers AFTER all the passes that add or reorder
        # pages (apply_all_improvements adds prologue / character-intro /
        # backstory / worldbuilding / chapter pages and merges new enrichment
        # beats; splash promotion and dialogue split can reshape pages). Those
        # newly-inserted pages do NOT carry an `act` field, and the merged
        # enrichment beats may lack acts too — which makes _find_act_boundaries
        # see an inconsistent or single-act script and generate NO interstitial
        # pages. Re-running propagation here guarantees every page has a correct
        # act label at the exact moment boundary detection runs below.
        try:
            _propagate_act_numbers(script_raw, required_beats)
            _acts_after = sorted({str(p.get('act', '1')) for p in script_raw
                                  if not p.get('_act_break') and not p.get('_prologue')})
            logger.info(
                f"  [Acts] Re-propagated act numbers after enrichment passes; "
                f"acts present: {_acts_after}"
            )
        except Exception as _ap_e:
            logger.warning(f"  [Acts] Re-propagation skipped ({_ap_e}).")

        # === Dedicated narration + act-context pages ===
        # These insert NEW full pages into the script. They MUST run here —
        # before layout planning, the script.json/layouts.json save, and panel
        # image generation — so each injected page flows through the normal
        # pipeline: it gets a layout, is persisted to the JSON artifacts the
        # editor reads, and receives a generated background image + manifest
        # entry like any other page. Injecting them after image generation
        # (as an earlier design did) left them imageless ([panel missing]) and
        # invisible to comic_book_editor.py.
        #
        # Narration splash: single dramatic image + one extended caption,
        # placed where narration is otherwise sparse.
        try:
            _narration_gaps = detect_narration_gaps(script_raw)
            if _narration_gaps:
                logger.info(
                    f"  [NarrationSplash] Detected {len(_narration_gaps)} gap(s) "
                    f"at script positions: {_narration_gaps}"
                )
                _narration_splash_pages = generate_narration_splash_pages(
                    gap_script_indices=_narration_gaps,
                    script=script_raw,
                    story_idea=story_idea,
                    story_idea_str=story_idea_str,
                    characters=characters,
                    required_beats=required_beats,
                    emotional_arc=project.story_dna.get('_emotional_arc', {}),
                    narrative_voice=project.story_dna.get('_narrative_voice', ''),
                    get_llm_response=get_openai_prompt_response,
                    parse_json=parse_json_response,
                    sanitize=sanitize_text_for_prompt,
                    llm_model=openai_model_large or openai_model,
                    use_grok=USE_GROK,
                )
                if _narration_splash_pages:
                    script_raw = inject_narration_splash_pages(
                        script_raw, _narration_splash_pages
                    )
            else:
                logger.info("  [NarrationSplash] No narration gaps detected.")
        except Exception as _ne:
            logger.warning(f"  [NarrationSplash] Pass skipped ({_ne}).")

        # Act-interstitial: text-rich story-context page after each act, giving
        # the reader recap / orientation / bridge / setup so the whole story
        # reads with comprehension and emotional payoff.
        try:
            # Diagnostic: log the act structure so we can see WHY interstitials
            # are or aren't generated (the #1 cause of "no story-context pages"
            # is the script collapsing to a single act).
            _story_pages_dbg = [p for p in script_raw
                                if not p.get('_act_break') and not p.get('_prologue')
                                and not p.get('_narration_splash')
                                and not p.get('_act_interstitial')]
            _acts_seen = {}
            for _p in _story_pages_dbg:
                _a = str(_p.get('act', '1'))
                _acts_seen[_a] = _acts_seen.get(_a, 0) + 1
            _boundaries_dbg = _find_act_boundaries(script_raw)
            logger.info(
                f"  [ActInterstitial] Act distribution across "
                f"{len(_story_pages_dbg)} story pages: "
                f"{dict(sorted(_acts_seen.items()))} — "
                f"{len(_boundaries_dbg)} transition(s) detected."
            )
            if not _boundaries_dbg and len(_story_pages_dbg) >= _ACT_INTERSTITIAL_CONFIG['min_book_pages']:
                logger.warning(
                    "  [ActInterstitial] No act transitions found despite a "
                    "book long enough for them. Act numbers may not be set — "
                    "story-context pages cannot be placed."
                )

            _interstitial_pages = generate_act_interstitial_pages(
                script=script_raw,
                story_idea=story_idea,
                story_idea_str=story_idea_str,
                characters=characters,
                required_beats=required_beats,
                emotional_arc=project.story_dna.get('_emotional_arc', {}),
                narrative_voice=project.story_dna.get('_narrative_voice', ''),
                get_llm_response=get_openai_prompt_response,
                parse_json=parse_json_response,
                sanitize=sanitize_text_for_prompt,
                llm_model=openai_model_large or openai_model,
                use_grok=USE_GROK,
            )
            if _interstitial_pages:
                script_raw = inject_act_interstitial_pages(
                    script_raw, _interstitial_pages
                )
                # Verify the injection actually landed — count interstitial
                # pages now present in the script so a silent drop is visible.
                _n_inter = sum(1 for p in script_raw if p.get('_act_interstitial'))
                logger.info(
                    f"  [ActInterstitial] Verified {_n_inter} story-context "
                    f"page(s) now in script "
                    f"(expected {len(_interstitial_pages)})."
                )
                if _n_inter != len(_interstitial_pages):
                    logger.warning(
                        f"  [ActInterstitial] MISMATCH: generated "
                        f"{len(_interstitial_pages)} but only {_n_inter} are in "
                        f"the script after injection."
                    )
            else:
                logger.info("  [ActInterstitial] No act transitions to bridge.")
        except Exception as _ie:
            import traceback as _tb
            logger.warning(f"  [ActInterstitial] Pass skipped ({_ie}).")
            logger.warning(f"  [ActInterstitial] Traceback: {_tb.format_exc()}")

        # Layouts — dramaturgical, driven by the emotional arc
        layouts = plan_page_layouts(
            script_raw, project.story_dna.get('_emotional_arc', {})
        )
        
        # Persist script + layouts for rebuild workflow
        with open(os.path.join(project.working_dir, "script.json"),
                  'w', encoding='utf-8') as f:
            json.dump(script_raw, f, indent=2, ensure_ascii=False)
        
        layouts_serializable = []
        for l in layouts:
            layouts_serializable.append({
                'page_number': l.page_number,
                'template_name': l.template_name,
                'panel_count': l.panel_count,
                'panel_boxes': [list(b) for b in l.panel_boxes],
                'page_title': l.page_title,
                'page_mood': l.page_mood,
                'cliffhanger': l.cliffhanger,
            })
        with open(os.path.join(project.working_dir, "layouts.json"),
                  'w', encoding='utf-8') as f:
            json.dump(layouts_serializable, f, indent=2, ensure_ascii=False)
        
        script = script_raw

    # =========================================================================
    # PRE-IMAGE CHECKPOINT — save all content needed to resume image generation
    # =========================================================================
    # Written right before any pixels are generated so that
    # regenerate_images_with_model() can be called immediately against this
    # working directory. Files written here mirror exactly what
    # regenerate_images_with_model expects on disk:
    #   • script.json        — finalised panel descriptions + appearance state
    #   • layouts.json       — page layout geometry
    #   • project.pkl        — full project object (story, characters, DNA, etc.)
    #   • panel_manifest.json — fully populated with prompts, geometry, and seeds
    #                           for every panel; images not yet generated.
    # =========================================================================
    _checkpoint_dir = project.working_dir
    try:
        _checkpoint_script_path = os.path.join(_checkpoint_dir, "script.json")
        with open(_checkpoint_script_path, 'w', encoding='utf-8') as _f:
            json.dump(script, _f, indent=2, ensure_ascii=False)

        _checkpoint_layouts_serializable = [
            {
                'page_number':   _lo.page_number,
                'template_name': _lo.template_name,
                'panel_count':   _lo.panel_count,
                'panel_boxes':   [list(_b) for _b in _lo.panel_boxes],
                'page_title':    _lo.page_title,
                'page_mood':     _lo.page_mood,
                'cliffhanger':   _lo.cliffhanger,
            }
            for _lo in layouts
        ]
        _checkpoint_layouts_path = os.path.join(_checkpoint_dir, "layouts.json")
        with open(_checkpoint_layouts_path, 'w', encoding='utf-8') as _f:
            json.dump(_checkpoint_layouts_serializable, _f, indent=2, ensure_ascii=False)

        _checkpoint_project_data = {
            'project': project,
            'script':  script,
            'layouts': layouts,
            'cover_paths': [],
        }
        _checkpoint_pkl_path = os.path.join(_checkpoint_dir, "project.pkl")
        with open(_checkpoint_pkl_path, 'wb') as _f:
            pickle.dump(_checkpoint_project_data, _f)

        # Build all image prompts, geometry, and seeds for every panel NOW,
        # before the GPU pipeline is loaded. Lets you inspect/edit prompts
        # before any compute is spent on images.
        _checkpoint_manifest = build_panel_manifest_prompts(project, script, layouts)
        _checkpoint_manifest_path = os.path.join(_checkpoint_dir, "panel_manifest.json")

        logger.info(
            f"[PRE-IMAGE CHECKPOINT] Saved to {_checkpoint_dir}\n"
            f"  script.json      → {_checkpoint_script_path}\n"
            f"  layouts.json     → {_checkpoint_layouts_path}\n"
            f"  project.pkl      → {_checkpoint_pkl_path}\n"
            f"  manifest+prompts → {_checkpoint_manifest_path}\n"
            f"  Edit prompts in panel_manifest.json now if desired, then:\n"
            f"    regenerate_images_with_model(\n"
            f"        working_dir={_checkpoint_dir!r},\n"
            f"        output_dir=<your_output_dir>,\n"
            f"        image_model='ZIMAGE',\n"
            f"    )"
        )
    except Exception as _ckpt_err:
        logger.warning(f"[PRE-IMAGE CHECKPOINT] Write failed (non-fatal): {_ckpt_err}")

    # === Phase 5: Generate panel images ===
    own_pipe = pipe is None
    if own_pipe:
        logger.info("Loading image generation pipeline...")
        pipe = load_ImageZ_pipe()
    
    try:
        # Cover variants
        cover_paths = generate_comic_cover(project, pipe, num_variants=cover_variants)
        
        # Panel manifest
        manifest_path = os.path.join(project.working_dir, "panel_manifest.json")
        if load_previous and os.path.exists(manifest_path):
            logger.info("Loading existing manifest (skipping panel generation)...")
            with open(manifest_path, encoding='utf-8') as f:
                manifest = json.load(f)
        else:
            manifest = generate_panel_images(
                project, script, layouts, pipe,
                variants_per_panel=panel_variants
            )

        # ── Inject cover variants into manifest so they can be edited ─────────
        # Stored under the reserved key "cover" (not a page_NNN key) so
        # rebuild_from_manifest and the assemblers can find the active variant.
        # Each variant carries its style-group metadata (concept_index / style /
        # variant_in_concept) so the editor can present the candidates grouped as
        # N styles x M images, while active_variant remains a flat 1-based index.
        _cover_meta = (project.story_dna.get('_cover_variant_meta')
                       if isinstance(project.story_dna, dict) else None) or []
        _meta_by_path = {m.get("path"): m for m in _cover_meta}
        _cover_variants = []
        for i, p in enumerate(cover_paths):
            entry = {"index": i + 1, "path": p}
            m = _meta_by_path.get(p)
            if m:
                entry.update({
                    "concept_index": m.get("concept_index"),
                    "concept_label": m.get("concept_label"),
                    "style": m.get("style"),
                    "variant_in_concept": m.get("variant_in_concept"),
                    "features_characters": m.get("features_characters"),
                })
            _cover_variants.append(entry)
        manifest["cover"] = {
            "_label":       "Cover",
            "_page_type":   "cover",
            "active_variant": 1,
            "_style_count": project.story_dna.get('_cover_style_count') if isinstance(project.story_dna, dict) else None,
            "_images_per_style": project.story_dna.get('_cover_images_per_style') if isinstance(project.story_dna, dict) else None,
            "variants": _cover_variants,
            "prompt": "Cover image — distinct styles x images; see covers/ directory for all candidates.",
        }
        logger.info(
            "  Cover candidates (%d across %s style(s)) added to manifest.",
            len(cover_paths),
            project.story_dna.get('_cover_style_count', '?') if isinstance(project.story_dna, dict) else '?',
        )

        # === Act-break pages: insert illustrated act-title cards ===
        # Done AFTER panel generation (pipe is warm, no extra load) and BEFORE
        # page composition so the breaks render cleanly into the final layout.
        logger.info("Inserting act-break pages...")
        panels_dir = os.path.join(project.working_dir, "panels")
        create_directory_if_not_exists(panels_dir)
        script, layouts, manifest = insert_act_breaks(
            script, layouts, manifest, project, pipe, panels_dir,
            emotional_arc=project.story_dna.get('_emotional_arc', {}),
        )

        # Re-save manifest now that cover + act-break variants have been added.
        # Sort so cover is first, act-break pages sort in page order among story
        # pages, making the JSON easy to read and edit top-to-bottom.
        manifest = _sort_manifest(manifest)
        with open(manifest_path, 'w', encoding='utf-8') as f:
            json.dump(manifest, f, indent=2, ensure_ascii=False)
        logger.info(f"  Manifest (cover-first, page order) saved: {manifest_path}")

        # Re-save script.json and layouts.json with act-break pages included so
        # rebuild_from_manifest loads the final, renumbered versions and produces
        # the correct number of composed pages (including act-break full pages).
        with open(os.path.join(project.working_dir, "script.json"),
                  'w', encoding='utf-8') as f:
            json.dump(script, f, indent=2, ensure_ascii=False)
        layouts_serializable = [
            {
                'page_number':   lo.page_number,
                'template_name': lo.template_name,
                'panel_count':   lo.panel_count,
                'panel_boxes':   [list(b) for b in lo.panel_boxes],
                'page_title':    lo.page_title,
                'page_mood':     lo.page_mood,
                'cliffhanger':   lo.cliffhanger,
            }
            for lo in layouts
        ]
        with open(os.path.join(project.working_dir, "layouts.json"),
                  'w', encoding='utf-8') as f:
            json.dump(layouts_serializable, f, indent=2, ensure_ascii=False)
        logger.info("  script.json + layouts.json re-saved (with act-break pages).")

        # Save project state INSIDE the try block so the pkl is written even
        # if page composition or output assembly later raises an exception.
        # The pkl is the rebuild artefact — losing it means losing the ability
        # to swap variants or re-run validate without full resynthesis.
        project_data = {
            'project':     project,
            'script':      script,
            'layouts':     layouts,
            'cover_paths': cover_paths,
        }
        project_pkl = os.path.join(project.working_dir, "project.pkl")
        with open(project_pkl, 'wb') as f:
            pickle.dump(project_data, f)
        logger.info(f"  Project state saved: {project_pkl}")

    finally:
        if own_pipe:
            del pipe
            reset_memory(device)
    
    # === Phase 6.5: Dialog review & enhancement ===
    # Tag scene-transition panels first so the reviewer's context carries
    # [FILL NEEDED - SCENE TRANSITION] markers for orienting captions.
    try:
        _tag_scene_transition_panels(script)
    except Exception as _e:
        logger.warning(f"  Scene-transition tagging skipped ({_e}).")
    # Tonal beats — seed sparse wisdom / levity / heat opportunities so the
    # dialogue reviewer varies register (Uncle-Iroh wisdom where a sage is
    # present, comic relief, romantic/erotic charge) instead of one flat tone.
    try:
        tag_beat_tones(
            script,
            graph=getattr(project, 'character_graph', None),
            characters=getattr(project, 'characters', None),
            emotional_arc=project.story_dna.get('_emotional_arc', {}),
        )
    except Exception as _tt_e:
        logger.warning(f"  [ToneModes] Skipped ({_tt_e}).")
    script, _dialog_revisions = review_and_enhance_dialog(
        script, project,
        emotional_arc=project.story_dna.get('_emotional_arc', {}),
    )

    # === Phase 6.7: Narration weave (the book's storytelling voice) ===
    # After review (sees final dialogue + filled captions, avoids doubles),
    # before callbacks and the density fit (added captions get budget-fit).
    try:
        script, _ = weave_narration_pass(
            script, project,
            emotional_arc=project.story_dna.get('_emotional_arc', {}),
        )
    except Exception as _e:
        logger.warning(f"  [Narration] weave skipped ({_e}).")
    # Final coverage validation — voice AND narration cadence, post-weave.
    try:
        audit_dialogue_coverage(script, label='final')
    except Exception:
        pass

    # === Phase 6.75: Repetition guard (say it once, then enjoy the art) ===
    # Every text pass above (base script, intro captions, dialogue review,
    # narration weave) adds lines without comparing them to what an adjacent
    # panel already says, so identical captions/lines can land back-to-back.
    # This deterministic pass removes those near-adjacent repeats (dropping the
    # redundant copy — the first occurrence already did the job) while leaving
    # far-apart recurrences alone. It runs BEFORE the callback pass below so the
    # deliberate plant-and-payoff echoes that pass adds are never stripped.
    try:
        script, _rep = dedupe_repeated_dialogue(
            script,
            story_dna=getattr(project, 'story_dna', None),
            working_dir=getattr(project, 'working_dir', None),
        )
    except Exception as _e:
        logger.warning(f"  [Repetition] guard skipped ({_e}).")

    # NOTE: Narration-splash and act-interstitial PAGE injection now runs
    # earlier in synthesis (before layout planning and image generation) so the
    # injected pages flow through the normal save/manifest/render path and are
    # visible to comic_book_editor.py. The narration weave above still adds
    # captions to existing story pages; it does not insert new pages.

    # === Phase 6.6: Verbal callbacks (plant-and-payoff dialogue echoes) ===
    # Runs AFTER review (so anchors are final, polished lines) and BEFORE the
    # density guard (so any added echo line is included in the word-budget fit).
    try:
        script, _ = weave_dialogue_callbacks(
            script, project,
            emotional_arc=project.story_dna.get('_emotional_arc', {}),
        )
    except Exception as _e:
        logger.warning(f"  [Callbacks] pass skipped ({_e}).")

    # === Phase 6.9: Book-level dialogue director (final re-polish) ===
    # The senior/managing-editor read of the WHOLE book at once — the pass no
    # per-act reviewer can do. It fingerprints every voice, flags cross-act
    # drift, book-wide phrasing crutches, narrator opener crutches, on-the-nose
    # lines, and long-range accidental twins, then re-polishes the dialogue AND
    # narration in token-budgeted windows for imaginative, character-true,
    # non-repetitive writing. Runs LAST (after callbacks, which it preserves via
    # ⟨KEEP-VERBATIM⟩ reconciliation) and BEFORE the density fit so any rewrite
    # or cut is included in the word-budget fit. Fails soft, window by window.
    try:
        script, _ed = polish_book_dialogue(script, project)
    except Exception as _e:
        logger.warning(f"  [Director] book-level re-polish skipped ({_e}).")

    # Dialogue density guard — tighten any panel whose text would overflow its
    # slot (and otherwise be silently truncated at render time), so every
    # intended line stays on the page and the art isn't buried under balloons.
    try:
        script, _ = fit_dialogue_density(script, layouts, project)
    except Exception as _e:
        logger.warning(f"  [Dialogue density] guard skipped ({_e}).")

    # Final Grok prompt-cache summary — the mid-pipeline log (after the
    # storyboard loop) predates the dialogue review, narration weave, and the
    # book-level director, which are the heaviest callers and whose front-loaded
    # stable prefixes are the biggest cache beneficiaries. Log the run TOTAL here
    # so the full performance/cost saving is visible.
    if USE_GROK:
        try:
            _cs = get_grok_cache_stats()
            if _cs.get("prompt_tokens"):
                logger.info(
                    "  [Cache] Grok prompt cache (run total): %s of %s prompt "
                    "tokens served from cache across %d call(s) (%.0f%% hit rate).",
                    f"{_cs['cached_tokens']:,}", f"{_cs['prompt_tokens']:,}",
                    _cs.get("calls", 0), 100.0 * _cs.get("cache_hit_rate", 0.0),
                )
        except Exception:
            pass

    # === Final working-directory sync ===
    # Re-save script.json, layouts.json, and project.pkl with the FULLY
    # PROCESSED script — after all narration weave, narration-splash, and
    # act-interstitial injections (Phases 6.7 / 6.75 / 6.78). The PRE-IMAGE
    # CHECKPOINT saved these files before image generation (Phase 5), so they
    # reflect the pre-narration state. Any tool — rebuild_from_manifest, the
    # editor, a runner script — that reads the working directory after synthesis
    # must see the complete script. Without this re-save, calling
    # rebuild_from_manifest on the working directory produces output that is
    # missing narration, story-context pages, and act-interstitials, which is
    # exactly what causes the unwanted *_validated.* files to appear smaller.
    try:
        _final_script_path = os.path.join(project.working_dir, "script.json")
        with open(_final_script_path, 'w', encoding='utf-8') as _f:
            json.dump(script, _f, indent=2, ensure_ascii=False)

        _final_layouts_serializable = [
            {
                'page_number':   _lo.page_number,
                'template_name': _lo.template_name,
                'panel_count':   _lo.panel_count,
                'panel_boxes':   [list(_b) for _b in _lo.panel_boxes],
                'page_title':    _lo.page_title,
                'page_mood':     _lo.page_mood,
                'cliffhanger':   _lo.cliffhanger,
            }
            for _lo in layouts
        ]
        _final_layouts_path = os.path.join(project.working_dir, "layouts.json")
        with open(_final_layouts_path, 'w', encoding='utf-8') as _f:
            json.dump(_final_layouts_serializable, _f, indent=2, ensure_ascii=False)

        _final_project_data = {
            'project':     project,
            'script':      script,
            'layouts':     layouts,
            'cover_paths': cover_paths,
        }
        _final_pkl_path = os.path.join(project.working_dir, "project.pkl")
        with open(_final_pkl_path, 'wb') as _f:
            pickle.dump(_final_project_data, _f)

        # Re-save the manifest too so it reflects any narration_settings or
        # panel additions that happened in Phase 6.x passes.
        _final_manifest_path = os.path.join(project.working_dir, "panel_manifest.json")
        _sorted_manifest = _sort_manifest(manifest)
        with open(_final_manifest_path, 'w', encoding='utf-8') as _f:
            json.dump(_sorted_manifest, _f, indent=2, ensure_ascii=False)

        logger.info(
            f"  [Final sync] Working-directory artifacts updated with "
            f"complete post-narration script ({len(script)} pages, "
            f"{len(layouts)} layouts)."
        )
    except Exception as _fs_err:
        logger.warning(f"  [Final sync] Working-directory re-save failed (non-fatal): {_fs_err}")

    # === Phase 7: Compose pages ===
    page_paths = compose_all_pages(project, script, layouts, manifest)

    # === Phase 7.5: Render prologue / opening text page(s) ===
    # NOTE: The prologue is now injected into the script as a real first-class
    # page (see the [Prologue] injection in Phase 5.5), so it already renders
    # through the normal page pipeline, appears in the manifest, and is editable
    # in the editor. The legacy prepend path below is therefore DISABLED to
    # avoid producing a duplicate prologue page. It is kept (guarded) only as a
    # fallback for older working dirs where the prologue was not injected into
    # the script.
    _prologue_in_script = any(
        (isinstance(p, dict) and p.get('_prologue')) for p in script
    )
    _prologue_data = project.story_dna.get('_prologue_page')
    if _prologue_data and not _prologue_in_script:
        try:
            _pro_result = compose_prologue_page(
                _prologue_data,
                page_w_px=int(COMIC_PAGE_WIDTH_IN * COMIC_DPI),
                page_h_px=int(COMIC_PAGE_HEIGHT_IN * COMIC_DPI),
            )
            _pro_imgs = (
                _pro_result if isinstance(_pro_result, list)
                else ([_pro_result] if _pro_result is not None else [])
            )
            _pro_paths = []
            for _pi, _pimg in enumerate(_pro_imgs):
                if _pimg is not None:
                    _pro_path = os.path.join(
                        project.working_dir, f"prologue_page_{_pi:02d}.jpg"
                    )
                    _pimg.save(
                        _pro_path, format='JPEG',
                        quality=PRINT_PAGE_JPEG_QUALITY, optimize=True
                    )
                    _pro_paths.append(_pro_path)
            if _pro_paths:
                page_paths = _pro_paths + list(page_paths)
                logger.info(
                    f"  [Prologue] Prepended {len(_pro_paths)} opening text "
                    f"page(s) to output."
                )
        except Exception as _pro_e:
            logger.warning(f"  [Prologue] Render skipped ({_pro_e}).")

    # === Phase 8: Output assembly ===
    safe_title = cleanup_special_chars(project.title)
    docx_path = os.path.join(save_dir, f"{safe_title}_comic.docx")
    pdf_path = os.path.join(save_dir, f"{safe_title}_comic.pdf")
    cbz_path = os.path.join(save_dir, f"{safe_title}_comic.cbz")

    assemble_docx(project, page_paths, cover_paths, docx_path, manifest=manifest, page_count=len(page_paths), script=script, layouts=layouts)
    assemble_pdf(page_paths, cover_paths, pdf_path, project, manifest=manifest)
    assemble_cbz(page_paths, cover_paths, cbz_path, project_pkl=project_pkl, manifest=manifest)

    # === Clean up stale _validated files ===
    # Some runner scripts call rebuild_from_manifest (or a validation pass) on
    # the working directory immediately after synthesis, before narration-weave
    # and act-interstitial pages are baked in. This produces *_validated.docx /
    # *_validated.pdf / *_validated.cbz files that are SMALLER than the final
    # outputs (they lack narration, story-context pages, and other late-pipeline
    # content) and should never be delivered to the reader. Delete any such
    # stale validated files from save_dir so only the complete outputs remain.
    _validated_suffixes = (
        f"{safe_title}_comic_validated.docx",
        f"{safe_title}_comic_validated.pdf",
        f"{safe_title}_comic_validated.cbz",
        # Also handle common runner-script variants
        f"{safe_title}_validated_comic.docx",
        f"{safe_title}_validated_comic.pdf",
        f"{safe_title}_validated_comic.cbz",
    )
    for _vf in _validated_suffixes:
        _vpath = os.path.join(save_dir, _vf)
        if os.path.exists(_vpath):
            try:
                os.remove(_vpath)
                logger.info(f"  [Cleanup] Removed stale validated file: {_vpath}")
            except Exception as _ve:
                logger.warning(f"  [Cleanup] Could not remove {_vpath}: {_ve}")

    # === Phase 9: Amazon KDP publishing summary ===
    logger.info("[9/9] Generating Amazon KDP publishing summary...")
    try:
        _page_count = len(page_paths) + len(cover_paths)
        kdp_data = generate_amazon_kdp_summary(project, page_count=_page_count,
                                                story_idea_str=story_idea_str,
                                                creative_seeds=creative_seeds)
        kdp_md_path = write_amazon_kdp_md(kdp_data, project, save_dir,
                                           page_count=_page_count,
                                           story_idea_str=story_idea_str,
                                           creative_seeds=creative_seeds)
    except Exception as _e:
        logger.warning(f"  Amazon KDP summary failed (non-fatal): {_e}")
        kdp_md_path = None

    # Print summary
    logger.info("=" * 60)
    logger.info(f"COMIC BOOK COMPLETE: {project.title}")
    logger.info("=" * 60)
    logger.info(f"  DOCX (editable):  {docx_path}")
    logger.info(f"  PDF (final):      {pdf_path}")
    logger.info(f"  CBZ (archive):    {cbz_path}")
    logger.info(f"  Manifest:         {manifest_path}")
    logger.info(f"  Project pickle:   {project_pkl}")
    logger.info(f"  Working dir:      {project.working_dir}")
    if kdp_md_path:
        logger.info(f"  Amazon KDP MD:    {kdp_md_path}")
    logger.info("")
    logger.info("To swap variants (panels, act breaks, or cover):")
    logger.info(f"  1. Open {manifest_path}")
    logger.info(f"  2. For panels:     change 'active_variant' (1-{panel_variants}) under page_NNN/panel_NN")
    logger.info(f"     For act breaks: change 'active_variant' (1-{ACT_BREAK_VARIANTS}) under page_NNN/panel_01 (_act_break pages)")
    logger.info(f"     For cover:      change 'active_variant' (1-{cover_variants * COVER_IMAGES_PER_STYLE}) under the top-level 'cover' key ({cover_variants} styles x {COVER_IMAGES_PER_STYLE} images)")
    logger.info(f"  3. Run: rebuild_from_manifest('{project.working_dir}', '{save_dir}')")
    revisions_log = os.path.join(project.working_dir, 'dialog_revisions.json')
    if os.path.exists(revisions_log):
        logger.info(f"  Dialog revisions sidecar: {revisions_log}")
    
    revisions_path = os.path.join(project.working_dir, 'dialog_revisions.json')
    _result = {
        'title': project.title,
        'docx': docx_path,
        'pdf': pdf_path,
        'cbz': cbz_path,
        'manifest': manifest_path,
        'kdp_md': kdp_md_path,
        'dialog_revisions': revisions_path if os.path.exists(revisions_path) else None,
        'working_dir': project.working_dir,
        'project_pickle': project_pkl,
        # Resolved story-page count. When target_pages was 'auto' this reflects
        # the storyboard recommendation reconciled to actual beat coverage;
        # otherwise it echoes the int passed in.
        'target_pages': target_pages if isinstance(target_pages, int) else None,
    }
    # Restore module-level globals so other callers in the same process
    # are not affected by this run's overrides.
    _ng.USE_GROK    = _orig_use_grok
    _ng.IMAGE_MODEL = _orig_image_model
    globals()['USE_GROK'] = _orig_use_grok
    return _result


# =============================================================================
# EXAMPLE USAGE
# =============================================================================

if __name__ == "__main__":
    # Example story idea — replace with your own
    STORY_IDEA = """
    A neuroscientist who studies grief in mice discovers that her own dead 
    daughter has been leaving messages in her experimental data. As she 
    decides whether to follow the breadcrumbs or destroy them, the line 
    between scientific rigor and desperate hope dissolves.
    """
    
    CREATIVE_SEEDS = {
        'core_question': 'What if grief is information, not just feeling?',
        'impossible_elements': 'Statistical anomalies that spell out words; lab mice that remember being someone else',
        'cross_domain_sources': 'neuroscience research + ghost story tradition + cryptography',
        'uncomfortable_truth': 'The grieving will accept evidence that the rational would reject',
        'permission_granted': 'Feel hope without shame, even when it costs you',
        'emotional_core': 'The ache of believing in something that might break you',
        'universal_connection': 'Holding on past the point of reason',
        'sensory_palette': 'fluorescent lab light, antiseptic + grass, paper rustle, the soft red of an LED on a microscope',
        'dramatic_engine': 'Truth vs. the comfort of believing',
    }
    
    result = synthesize_comic_book(
        story_idea_str=STORY_IDEA,
        target_pages=24,
        panels_per_page_avg=4,
        creative_seeds=CREATIVE_SEEDS,
        cast_size="small",
        save_dir="./SynthesizedComics",
        cover_variants=COVER_VARIANTS,
        panel_variants=4,
    )
    
    print("\nDone!")
    print(f"Open {result['docx']} to review and edit.")
